// Arrow legends on the Cardputer keys: ';' up  '.' down  ',' left  '/' right
static bool isUp(char c)    { return c == ';'; }
static bool isDown(char c)  { return c == '.'; }
static bool isLeft(char c)  { return c == ','; }
static bool isRight(char c) { return c == '/'; }
static bool isBack(char c, bool del) { return c == '`' || del; }

// ---------------------------------------------------------------------------
// Forward declaration; the definition sits just above drawHome() further down.
extern const char* const HOME_ITEMS[];

void App::keyHome(char c, bool enter, bool back) {
  const int N = 20;
  if (isUp(c))   homeSel = (homeSel + N - 1) % N;
  if (isDown(c)) homeSel = (homeSel + 1) % N;
  if (isLeft(c) || isRight(c)) homeSel = (homeSel + 10) % N;   // hop columns
  // First-letter jump: a letter moves the highlight to the next menu item starting
  // with it (case-insensitive, wraps; repeated presses cycle matches, e.g. S for
  // Satellites / Sun / Space Wx / Settings). Letters are otherwise unused here.
  if (c >= 'a' && c <= 'z') {
    for (int k = 1; k <= N; ++k) {
      int i = (homeSel + k) % N;
      char f = HOME_ITEMS[i][0];
      if (f >= 'A' && f <= 'Z') f += 32;
      if (f == c) { homeSel = i; lastDrawMs = 0; return; }
    }
  }
  if (enter) {
    switch (homeSel) {
      case 0: buildSatView(); screen = SCR_SATLIST; break;
      case 1: schedSel = 0; buildSchedule(); screen = SCR_SCHEDULE; break;
      case 2: // passes for selected sat
      case 3: { // track selected sat
        SatEntry* s = activeSat();
        if (!s) { setStatus("No sats. Update first."); break; }
        pred.setSite(loc.obs());
        pred.setSat(*s);
        if (homeSel == 2) {
          computePasses();
          passesReturn = SCR_HOME;
          screen = SCR_PASSES;
        } else {
          bool sameTracked = (s->norad == trackedNorad);
          ensureTransponders(*s);
          // Returning to the bird already tracking? Preserve the operator's
          // transponder/tuning/cal and the engaged radio+rotator. Only re-init
          // and reset output when starting a different satellite.
          if (!sameTracked) {
            onTransponderChanged();
            radioOut = false; rotOut = false;
          }
          loadCalForSat(s->norad);
          loadNoteForSat(s->norad);
          trackReturn = SCR_HOME;
          screen = SCR_TRACK;
        }
      } break;
      case 4: mapHi = -1; mapReturn = SCR_HOME; screen = SCR_WORLDMAP; lastDrawMs = 0; break;  // all footprints
      case 5: screen = SCR_SUNMOON; lastDrawMs = 0; break;
      case 6: spaceWxEnter(); break;  // space weather (NOAA SWPC)
      case 7: weatherEnter(); break;  // local terrestrial weather (open-meteo)
      case 8: hamsatEnter(); break;   // upcoming activations (hams.at)
      case 9: buildAmsatStatusView(); amStatSel = 0; amStatScroll = 0; screen = SCR_AMSATSTAT; lastDrawMs = 0; break;
      case 10: ovhValid = false; ovhScroll = 0; screen = SCR_OVERHEAD; lastDrawMs = 0; break;  // what's overhead now
      case 11: gcRotOut = false; screen = SCR_GRIDCALC; lastDrawMs = 0; break;   // grid distance/bearing
      case 12: qrzHaveResult = false; qrzScroll = 0; screen = SCR_QRZ; lastDrawMs = 0; break;
      case 13: screen = SCR_LOCATION; break;
      case 14: screen = SCR_UPDATE; break;
      case 15: setSel = 0; setCat = -1; screen = SCR_SETTINGS; break;
      case 16: logMenuSel = 0; screen = SCR_LOG; break;
      case 17: msgScroll = 0; screen = SCR_MESSAGES; lastDrawMs = 0; break;
      case 18: screen = SCR_ABOUT; break;
      case 19: enterChargeMode(); screen = SCR_CHARGE; break;
    }
  }
}

// ---- Voice-memo browser (SCR_MEMOS) ---------------------------------------
// (Re)enumerate the memos on the SD card into memos[], newest first.
void App::buildMemoList() {
  memoN = VoiceMemo::listMemos(memos, MEMO_LIST_MAX);
  if (memoSel >= memoN) memoSel = memoN > 0 ? memoN - 1 : 0;
}

// Poll the keyboard directly for a cancel during blocking playback. Any keypress
// (or the back/ESC key) cancels. Static so it can be passed as a plain function
// pointer to VoiceMemo::playMemo.
static bool memoPlaybackCancel() {
  M5Cardputer.update();
  return M5Cardputer.Keyboard.isChange() && M5Cardputer.Keyboard.isPressed();
}

void App::drawMemos() {
  header("Voice Memos");
  canvas.setTextSize(1);

  if (!Store::onSD()) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 44); canvas.print("SD card required for voice memos.");
    footer("` back");
    return;
  }

  // While a standalone recording is running, show a prominent REC banner; the
  // blinking badge is also drawn by drawMemoIndicator() via the normal overlay.
  if (memo.isRecording()) {
    canvas.fillRect(0, 40, 240, 40, CL_BLACK);
    canvas.setTextColor(CL_RED, CL_BLACK);
    canvas.setTextSize(2);
    canvas.setCursor(40, 48);
    canvas.printf("REC  %lus", (unsigned long)memo.elapsedMs() / 1000);
    canvas.setTextSize(1);
    canvas.setTextColor(CL_WHITE, CL_BLACK);
    canvas.setCursor(30, 70); canvas.print("Recording a standalone memo");
    footer("any key = stop & save");
    return;
  }

  if (memoN == 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 42); canvas.print("No voice memos yet.");
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(6, 54); canvas.print("n = record  ('v' on a Track screen too)");
    footer("n new  r refresh  ` back");
    return;
  }

  // Column header.
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, 18); canvas.print("Date   Time   Satellite    Len");

  const int VIS = 8;
  if (memoSel < memoScroll)            memoScroll = memoSel;
  if (memoSel > memoScroll + VIS - 1)  memoScroll = memoSel - VIS + 1;
  if (memoScroll < 0) memoScroll = 0;

  for (int r = 0; r < VIS && (memoScroll + r) < memoN; ++r) {
    int i = memoScroll + r, y = 30 + r * 11;
    const VoiceMemo::MemoEntry& m = memos[i];
    if (i == memoSel) { canvas.fillRect(0, y - 2, 240, 11, CL_SELBG);
                        canvas.setTextColor(CL_BLACK, CL_SELBG); }
    else                canvas.setTextColor(CL_WHITE, CL_BLACK);
    char line[48];
    char sat[10];
    snprintf(sat, sizeof(sat), "%-9.9s", m.sat[0] ? m.sat : "-");
    if (m.haveTime)
      snprintf(line, sizeof(line), "%02d-%02d  %02d:%02d  %s %lu:%02lu",
               m.mon, m.day, m.hh, m.mm, sat,
               (unsigned long)(m.secs / 60), (unsigned long)(m.secs % 60));
    else
      snprintf(line, sizeof(line), "  --     --   %s %lu:%02lu", sat,
               (unsigned long)(m.secs / 60), (unsigned long)(m.secs % 60));
    canvas.setCursor(4, y); canvas.print(line);
  }

  canvas.setTextColor(CL_GREY, CL_BLACK);
  if (memoScroll > 0)              { canvas.setCursor(232, 30);  canvas.print("^"); }
  if (memoScroll + VIS < memoN)    { canvas.setCursor(232, 118); canvas.print("v"); }

  if (memoConfirmDel) {
    canvas.fillRect(20, 50, 200, 34, CL_BLACK);
    canvas.drawRect(20, 50, 200, 34, CL_RED);
    canvas.setTextColor(CL_RED, CL_BLACK);
    canvas.setCursor(28, 56); canvas.print("Delete this memo?");
    canvas.setTextColor(CL_WHITE, CL_BLACK);
    canvas.setCursor(28, 70); canvas.print("ENT = delete   ` = cancel");
    footer("");
  } else {
    footer("ENT play n new d del r refr `back");
  }
}

void App::keyMemos(char c, bool enter, bool back) {
  // If a standalone recording (started here with 'n') is in progress, any key
  // stops it and refreshes the list. This mirrors the toggle behavior on the
  // Track screens but keeps the user on the browser.
  if (memo.isRecording()) {
    memo.stop();
    setStatus("Memo saved");
    buildMemoList();
    memoSel = 0; memoScroll = 0;
    lastDrawMs = 0;
    return;
  }

  if (memoConfirmDel) {
    if (enter) {
      if (memoSel >= 0 && memoSel < memoN) {
        if (VoiceMemo::deleteMemo(memos[memoSel].file)) setStatus("Memo deleted");
        else                                            setStatus("Delete failed");
        buildMemoList();
      }
      memoConfirmDel = false;
    } else if (back) {
      memoConfirmDel = false;
    }
    lastDrawMs = 0;
    return;
  }

  if (isBack(c, back)) { logMenuSel = 5; screen = SCR_LOG; lastDrawMs = 0; return; }

  if (memoN > 0) {
    if (isUp(c))   memoSel = (memoSel + memoN - 1) % memoN;
    if (isDown(c)) memoSel = (memoSel + 1) % memoN;
  }
  if (c == 'n') {                       // record a new standalone memo (no satellite)
    if (memo.start(nullptr)) setStatus("Recording... (any key stops)");
    else                     setStatus(String("Memo: ") + memo.lastError());
    lastDrawMs = 0;
    return;
  }
  if (c == 'r') { buildMemoList(); setStatus("Memo list refreshed"); }
  if (c == 'd' && memoN > 0) { memoConfirmDel = true; }
  if (enter && memoN > 0 && memoSel < memoN) {
    setStatus("Playing... (any key stops)");
    draw();                              // show the status before we block
    bool ok = memo.playMemo(memos[memoSel].file, &memoPlaybackCancel, cfg.spkVolume);
    setStatus(ok ? "Playback done" : (String("Play: ") + memo.lastError()));
  }
  lastDrawMs = 0;
}

void App::keyOscar(char c, bool enter, bool back) {
  if (isBack(c, back)) { buildSatView(); screen = SCR_SATLIST; lastDrawMs = 0; return; }
  if (c == 'm') { oscarMode = (oscarMode == 0) ? 1 : 0; lastDrawMs = 0; }   // QTH <-> polar
}

void App::keyGlobe(char c, bool enter, bool back) {
  if (isBack(c, back)) { buildSatView(); screen = SCR_SATLIST; lastDrawMs = 0; return; }
  if (enter) { globeFollow = true; lastDrawMs = 0; return; }   // re-snap to the sat
  if (c == 'g') {                                              // enter a DX grid (2nd location)
    editTarget = 104; editTitle = "DX grid (Maidenhead)"; editBuf = ""; screen = SCR_EDIT;
    return;
  }
  if (c == 'G') { dxGrid[0] = 0; setStatus("DX cleared"); lastDrawMs = 0; return; }  // clear DX
  // Arrow keys nudge the view; this drops out of auto-follow into free-look.
  const double STEP = 15.0;
  if (isUp(c))    { globeFollow = false; globeViewLat += STEP; if (globeViewLat >  90) globeViewLat =  90; lastDrawMs = 0; }
  if (isDown(c))  { globeFollow = false; globeViewLat -= STEP; if (globeViewLat < -90) globeViewLat = -90; lastDrawMs = 0; }
  if (isLeft(c))  { globeFollow = false; globeViewLon -= STEP; if (globeViewLon < -180) globeViewLon += 360; lastDrawMs = 0; }
  if (isRight(c)) { globeFollow = false; globeViewLon += STEP; if (globeViewLon >  180) globeViewLon -= 360; lastDrawMs = 0; }
}

void App::keySchedule(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_HOME; return; }
  if (isUp(c)   && schedN) schedSel = (schedSel + schedN - 1) % schedN;
  if (isDown(c) && schedN) schedSel = (schedSel + 1) % schedN;
  if (c == 'r') { setStatus("Computing passes..."); draw(); buildSchedule();
                  lastSchedMs = millis(); setStatus("Schedule updated"); }
  if (c == 'z') { sleepUntilNextPass(); return; }     // deep-sleep until AOS
  if (c == 'm') { mapReturn = SCR_SCHEDULE; screen = SCR_WORLDMAP; lastDrawMs = 0; return; }  // live world map
  if (c == 't') { buildSkyGlance(); screen = SCR_SKYGLANCE; lastDrawMs = 0; return; }            // sky-at-a-glance timeline
  if (enter && schedN > 0) {
    int idx = db.indexOfNorad(sched[schedSel].norad);
    if (idx >= 0) {
      satSel = idx;
      SatEntry* s = &db.at(idx);
      bool sameTracked = (s->norad == trackedNorad);
      pred.setSite(loc.obs()); pred.setSat(*s);
      ensureTransponders(*s);
      // Preserve tuning + engaged radio/rotator when returning to the tracked
      // bird; only re-init and reset output when switching satellites.
      if (!sameTracked) {
        onTransponderChanged();
        radioOut = false; rotOut = false;
      }
      loadCalForSat(s->norad);
      loadNoteForSat(s->norad);
      lastDoppMs = 0;
      trackReturn = SCR_SCHEDULE;
      screen = SCR_TRACK;
    }
  }
}

// ===========================================================================
//  "Sky at a glance" -- a horizontal timeline of upcoming passes for ALL
//  favourites over the next SKY_HOURS. Time runs left to right; each favourite
//  with a pass in the window gets a row, and every pass is a bar coloured by
//  peak elevation (green >= 30 deg, yellow below) -- the same convention as the
//  Overhead-now screen. Reuses the existing pass predictor; all state is
//  fixed-size (.bss), no heap.
// ===========================================================================

void App::buildSkyGlance() {
  skyBarN = 0; skyRowN = 0;
  skyStart = nowUtc();
  skyBuiltMs = millis();
  if (!timeIsSet()) return;
  pred.setSite(loc.obs());
  time_t winEnd = skyStart + (time_t)SKY_HOURS * 3600;

  for (int i = 0; i < favN && skyRowN < SKY_ROWS && skyBarN < SKY_BARS; ++i) {
    int idx = db.indexOfNorad(favs[i]);
    if (idx < 0) continue;
    SatEntry& s = db.at(idx);
    if (!pred.setSat(s)) continue;

    // Collect this favourite's passes in the window (including one in progress).
    PassPredict pp[6];
    int n = pred.predictPasses(skyStart, cfg.minPassEl, pp, 6, winEnd);
    if (n <= 0) continue;

    int rowSlot = skyRowN;             // tentatively this row
    bool anyBar = false;
    for (int k = 0; k < n && skyBarN < SKY_BARS; ++k) {
      time_t a = pp[k].aos, b = pp[k].los;
      if (b <= skyStart || a >= winEnd) continue;     // outside window
      SkyBar& bar = skyBars[skyBarN++];
      bar.row = (uint8_t)rowSlot;
      bar.aos = a; bar.los = b; bar.maxEl = pp[k].maxEl;
      bool vis = false; visEvalPass(a, b, pp[k].maxEl, vis); bar.vis = vis;
      anyBar = true;
    }
    if (anyBar) {
      strncpy(skyName[rowSlot], s.name, sizeof(skyName[rowSlot]) - 1);
      skyName[rowSlot][sizeof(skyName[rowSlot]) - 1] = 0;
      skyRowNorad[rowSlot] = s.norad;
      skyRowN++;
    }
  }
  // Restore the propagator to the user's active satellite.
  SatEntry* act = activeSat();
  if (act) { pred.setSite(loc.obs()); pred.setSat(*act); }
}

void App::drawSkyGlance() {
  header("Sky at a glance");
  canvas.setTextSize(1);
  if (favN == 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 42); canvas.print("No favorites yet.");
    canvas.setCursor(6, 54); canvas.print("Star sats with 'f' in Satellites.");
    footer("` back");
    return;
  }
  if (!timeIsSet()) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 42); canvas.print("Clock not set (NTP or GPS).");
    footer("r refresh  ` back");
    return;
  }

  // Timeline geometry: a label gutter on the left, then the time axis.
  const int gutter = 56;                 // x of the axis start (names to its left)
  const int axisX = gutter, axisW = 240 - gutter - 2;
  const int y0 = 30, rowH = 8;
  const time_t span = (time_t)SKY_HOURS * 3600;

  // Hour gridlines + labels along the top. Ticks at each whole hour from now.
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(2, 18); canvas.printf("next %dh", SKY_HOURS);
  {
    struct tm tmn; time_t t0 = skyStart; gmtime_r(&t0, &tmn);
    // First whole hour after skyStart.
    int minsPast = tmn.tm_min;
    time_t firstHour = skyStart + (time_t)((60 - minsPast) % 60) * 60;
    if (firstHour == skyStart) firstHour += 3600;
    for (time_t t = firstHour; t < skyStart + span; t += 3600) {
      int x = axisX + (int)(axisW * (t - skyStart) / span);
      canvas.drawFastVLine(x, y0 - 2, rowH * skyRowN + 2, CL_DGREY);
      struct tm tmh; gmtime_r(&t, &tmh);
      canvas.setTextColor(CL_GREY, CL_BLACK);
      canvas.setCursor(x - 5, 19); canvas.printf("%02d", tmh.tm_hour);
    }
  }
  // "Now" marker at the left edge of the axis.
  canvas.drawFastVLine(axisX, y0 - 2, rowH * skyRowN + 2, CL_GREEN);

  if (skyRowN == 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 60); canvas.printf("No passes in the next %dh.", SKY_HOURS);
    footer("r refresh  ` back");
    return;
  }

  // One row per favourite with a pass; draw its bars.
  for (int r = 0; r < skyRowN; ++r) {
    int ry = y0 + r * rowH;
    canvas.setTextColor(CL_WHITE, CL_BLACK);
    canvas.setCursor(2, ry); canvas.printf("%-8.8s", skyName[r]);
    canvas.drawFastHLine(axisX, ry + rowH - 1, axisW, CL_DGREY);   // row baseline
  }
  for (int i = 0; i < skyBarN; ++i) {
    SkyBar& bar = skyBars[i];
    if (bar.row >= skyRowN) continue;
    time_t a = (bar.aos > skyStart) ? bar.aos : skyStart;
    time_t b = (bar.los < skyStart + span) ? bar.los : skyStart + span;
    if (b <= a) continue;
    int x1 = axisX + (int)(axisW * (a - skyStart) / span);
    int x2 = axisX + (int)(axisW * (b - skyStart) / span);
    int w = (x2 - x1 < 2) ? 2 : x2 - x1;
    int ry = y0 + bar.row * rowH;
    uint16_t col = (bar.maxEl >= 30.0f) ? CL_GREEN : CL_YELLOW;   // Overhead-now colours
    canvas.fillRect(x1, ry, w, rowH - 2, col);
    if (bar.vis) {                          // visually observable: white tick on the bar
      canvas.drawFastVLine(x1 + w / 2, ry, rowH - 2, CL_WHITE);
    }
  }
  footer("r refresh  ; sched  ` back");
}

void App::keySkyGlance(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { screen = SCR_SCHEDULE; lastDrawMs = 0; return; }
  if (c == 'r') { setStatus("Computing timeline..."); draw(); buildSkyGlance();
                  setStatus("Timeline updated"); lastDrawMs = 0; return; }
  if (isUp(c) || isDown(c) || c == ';' || c == '.') {     // back to the list view
    screen = SCR_SCHEDULE; lastDrawMs = 0; return;
  }
}

void App::keySatList(char c, bool enter, bool back) {
  if (isBack(c, back)) {
    satDelArm = false;
    if (logPickSat) { logPickSat = false; screen = SCR_LOGENTRY; lastDrawMs = 0; return; }
    screen = SCR_HOME; return;
  }
  if (c != 'x') satDelArm = false;             // any key other than x disarms the delete
  if (c == 'n') {                              // new manual GP entry
    mtSat = SatEntry();
    editTarget = 310; editTitle = "Sat name"; editBuf = ""; screen = SCR_EDIT;
    return;
  }
  if (c == 'v') { favOnly = !favOnly; buildSatView();
                  setStatus(favOnly ? "Favorites only" : "All satellites"); return; }
  if (c == 's') {                              // AMSAT activity status window
    buildAmsatStatusView(); amStatSel = 0; amStatScroll = 0;
    screen = SCR_AMSATSTAT; lastDrawMs = 0; return;
  }
  int n = viewN;
  if (n == 0) return;
  if (isUp(c)   && viewSel > 0)     { viewSel--; satDelArm = false; }
  if (isDown(c) && viewSel < n - 1) { viewSel++; satDelArm = false; }
  if (c == '{') viewSel = max(0, viewSel - 10);
  if (c == '}') viewSel = min(n - 1, viewSel + 10);
  if (c == 'f') {                              // toggle favorite for selected
    toggleFav(db.at(view[viewSel]).norad);
    if (favOnly) buildSatView();               // may shrink the list
  }
  if (c == 'x' && viewN > 0) {                  // delete a hand-entered (manual) sat
    uint32_t nd = db.at(view[viewSel]).norad;
    if (!db.isManualGp(nd)) { setStatus("Only manually-added sats can be deleted");
                              satDelArm = false; return; }
    if (!satDelArm) { satDelArm = true; setStatus("Press x again to delete this sat");
                      return; }
    satDelArm = false;
    if (db.removeManualGp(nd)) {
      // Rebuild the in-memory catalog from the cached GP file + remaining manual
      // sats so the deleted entry is gone without a fragile in-place array removal.
      db.loadGpFromFile(FILE_GP);
      db.loadManualGpFile();
      if (isFav(nd)) toggleFav(nd);             // drop it from favorites too
      buildSatView();
      if (viewSel >= viewN) viewSel = viewN > 0 ? viewN - 1 : 0;
      setStatus("Satellite deleted");
    } else setStatus("Delete failed");
    return;
  }
  if (viewSel < satScroll)      satScroll = viewSel;
  if (viewSel > satScroll + 9)  satScroll = viewSel - 9;
  if (viewN > 0) satSel = view[viewSel];
  if (c == 'o' && viewN > 0) {                     // open the orbital analysis screen
    orbitPage = 0; buildOrbit(); screen = SCR_ORBIT; lastDrawMs = 0; return;
  }
  if (c == 'y' && viewN > 0) {                     // open the simulation screen (was 's';
    // 's' is AMSAT status -- see the guard above. 'y' keeps sim reachable here.)
    simTime = timeIsSet() ? nowUtc() : 0; screen = SCR_SIM; lastDrawMs = 0; return;
  }
  if (c == 't' && viewN > 0) {                      // browse the transponder database
    SatEntry* s = activeSat();
    if (s) { ensureTransponders(*s); txDbScroll = 0; txDbSel = 0; txDbDelArm = false;
             screen = SCR_TXDB; lastDrawMs = 0; }
    return;
  }
  if (c == 'e' && viewN > 0) {                      // EQX table (OSCARLOCATOR)
    eqxDescending = false; buildEqx(); screen = SCR_EQX; lastDrawMs = 0;
    return;
  }
  if (c == 'k' && viewN > 0) {                      // OSCARLOCATOR live polar view
    oscarMode = 1; oscarArcN = 0; oscarArcTriedMs = 0; screen = SCR_OSCAR; lastDrawMs = 0;
    return;
  }
  if (c == '3' && viewN > 0) {                      // 3D globe view (auto-follow)
    globeFollow = true; oscarArcN = 0; oscarArcTriedMs = 0; screen = SCR_GLOBE; lastDrawMs = 0;
    return;
  }
  if (c == '2' && viewN > 0) {                      // sat-to-sat visibility finder
    satsatOther = 0; satsatSel = 0; screen = SCR_SATSAT; lastDrawMs = 0;
    satsatPicking = true;                           // choose the 2nd sat first; calc on ENTER
    satsatComputed = false; satsatN = 0;
    return;
  }
  if (c == 'd' && viewN > 0) {                      // 10-day pass overview
    visReturn = SCR_SATLIST; visDayOff = 0; buildVis();
    screen = SCR_VIS; lastDrawMs = 0; return;
  }
  if (c == 'i' && viewN > 0) {                      // 60-day illumination raster
    visReturn = SCR_SATLIST; illumDayOff = 0; buildIllum();
    screen = SCR_ILLUM; lastDrawMs = 0; return;
  }
  if (enter && viewN > 0) {
    SatEntry* s = activeSat();
    pred.setSite(loc.obs());
    pred.setSat(*s);
    ensureTransponders(*s);
    onTransponderChanged();
    if (logPickSat) {            // chose a satellite for a log entry
      logPickSat = false;
      seedQsoSatDefaults();      // sat + mode + non-Doppler centre/nominal freqs
      if (logEditIdx >= 0) qso.uploaded = 0;   // changing the sat re-arms upload
      logSel = 0; screen = SCR_LOGENTRY; lastDrawMs = 0; return;
    }
    computePasses();
    passesReturn = SCR_SATLIST;
    screen = SCR_PASSES;
  }
}

void App::keyPasses(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = passesReturn; lastDrawMs = 0; return; }
  int visN = (passN < 9) ? passN : 9;            // only the visible rows
  if (isUp(c)   && visN) passSel = (passSel + visN - 1) % visN;
  if (isDown(c) && visN) passSel = (passSel + 1) % visN;
  if (passSel >= visN) passSel = 0;
  if (c == 'n') {                       // add a transponder manually for this sat
    mtxDl = mtxUl = mtxDlHigh = mtxUlHigh = 0; mtxInv = false;
    editTarget = 320; editTitle = "Downlink low Hz"; editBuf = ""; screen = SCR_EDIT;
    return;
  }
  if (c == 'r') {  // recompute
    computePasses();
  }
  if (c == 'd' && passN > 0 && passSel < passN) {  // open the pass-detail plot
    passDetailReturn = SCR_PASSES;
    buildPassDetail(passes[passSel]);
    screen = SCR_PASSDETAIL; lastDrawMs = 0;
    return;
  }
  if (c == 'x') {                       // mutual-window vs a remote DX grid
    editTarget = 330; editTitle = "DX grid (4 or 6 char)"; editBuf = "";
    screen = SCR_EDIT; return;
  }
  if (c == 'g' && passN > 0 && passSel < passN) {     // workable grids on this pass
    setStatus("Computing pass grids..."); draw();
    gridLive = false; gridScroll = 0; buildGrids(passes[passSel].aos, passes[passSel].los);
    setStatus(""); screen = SCR_GRID; lastDrawMs = 0; return;
  }
  if (c == 'w' && passN > 0 && passSel < passN) {     // workable US states on this pass
    setStatus("Computing pass states..."); draw();
    stateLive = false; stateScroll = 0; buildStates(passes[passSel].aos, passes[passSel].los);
    setStatus(""); screen = SCR_STATES; lastDrawMs = 0; return;
  }
  if (c == 'e' && passN > 0 && passSel < passN) {     // workable DXCC entities on this pass
    setStatus("Computing pass DXCC..."); draw();
    dxccLive = false; dxccScroll = 0; buildDxcc(passes[passSel].aos, passes[passSel].los);
    setStatus(""); screen = SCR_DXCC; lastDrawMs = 0; return;
  }
  if (c == 'v') { visReturn = SCR_PASSES; visDayOff = 0; buildVis();   screen = SCR_VIS;   lastDrawMs = 0; return; }
  if (c == 'V') { buildVisList(); screen = SCR_VISLIST; lastDrawMs = 0; return; }  // visible-pass LIST (10 days)
  if (c == 'i') { visReturn = SCR_PASSES; illumDayOff = 0; buildIllum(); screen = SCR_ILLUM; lastDrawMs = 0; return; }
  if (enter || c == 't') {     // enter tracking
    SatEntry* s = activeSat();
    if (s) { loadCalForSat(s->norad); loadNoteForSat(s->norad); }
    // Keep radio/rotator engaged when re-entering the bird already tracking in
    // the background; only reset output when this is a different satellite.
    if (!s || s->norad != trackedNorad) { radioOut = false; rotOut = false; }
    lastDoppMs = 0;
    trackReturn = SCR_PASSES;
    screen = SCR_TRACK;
  }
}

void App::keyPassDetail(char c, bool enter, bool back) {
  if (c == 'p') { screen = SCR_PASSPOLAR; lastDrawMs = 0; return; }  // polar of this pass
  if (isBack(c, back) || enter) { screen = passDetailReturn; lastDrawMs = 0; }
}

void App::keyTrack(char c, bool enter, bool back) {
  if (c == 'q' && millis() < losPromptUntil) {   // post-LOS handoff: sleep to next pass
    losPromptUntil = 0; sleepUntilNextPass(); return;
  }
  if (c == 'i') {                                // "I heard it": one-key AMSAT report
    SatEntry* s2 = activeSat();
    if (!s2) return;
    int idx = satSel;
    if (millis() < rptArmUntil && rptArmName[0]) {           // second tap: send
      rptArmUntil = 0;
      postAmsatReport(rptArmName, "Heard");
      return;
    }
    bool amb = false;
    const char* nm = amsPickNameFor(idx, amb);
    if (amb) {                                   // multi-mode, no clear fit: picker
      pickSatIdx = idx; pickNameSel = 0; pickSel = 0; pickStat = 0;
      pickReturn = SCR_TRACK; screen = SCR_AMSRPICK; lastDrawMs = 0; return;
    }
    if (!nm) { setStatus("No AMSAT catalog name for this sat"); return; }
    strncpy(rptArmName, nm, sizeof(rptArmName) - 1); rptArmName[sizeof(rptArmName) - 1] = 0;
    rptArmUntil = millis() + 3500;
    setStatus(String("Report ") + nm + " Heard? press i again", 3500);
    return;
  }
  if (c == 'v') { toggleMemo(); return; }            // SD voice memo (record/stop)
  if (c == 'a') { screen = SCR_ARROW; lastDrawMs = 0; return; }  // point-here arrow (radio/rotor keep running)
  if (isBack(c, back)) {
    // Leaving the Track screen no longer stops tracking: if the radio and/or
    // rotator are engaged, they keep running in the background (the loop's
    // Doppler/rotator service is gated on radioOut/rotOut, not on the screen),
    // and the header shows a RAD/ROT/R+R tag so it's visible elsewhere. Use the
    // 'r' / 'o' toggles to stop. When neither is engaged this is a plain exit.
    screen = trackReturn; lastDrawMs = 0;
    return;
  }

  bool linear = (activeTxCount > 0) && activeTx[curTx].isLinear &&
                activeTx[curTx].bandwidth() > 0;

  if (c == 'm') {                                    // toggle TUNE / CAL
    if (linear) trackMode ^= 1;
    else { trackMode = 1; setStatus("Not linear: CAL only"); }
  }

  if (c == 'd') {                                    // cycle the Doppler tune mode
    if (!linear) setStatus("Tune modes: linear birds only");
    else {
      bool canRead = rig && rig->canReadFreq();
      do { tuneMode = (TuneMode)((tuneMode + 1) & 3); }   // FULL/DL need knob read
      while (!canRead && (tuneMode == TM_FULL || tuneMode == TM_DL));
      lastRxSet = 0; lastUlHz = 0;                    // re-sync both legs to the knob
      setStatus(tuneMode == TM_FULL ? "Tune: FULL knob=passband (OTR)"
              : tuneMode == TM_DL   ? "Tune: downlink only (OTR)"
              : tuneMode == TM_UL   ? "Tune: uplink only"
                                    : "Tune: hold both legs");
    }
  }

  if (trackMode == 0 && linear && tuneMode != TM_FULL && tuneMode != TM_DL) {
    // ---- TUNE mode: move within the transponder passband via device keys ----
    int32_t bw = (int32_t)activeTx[curTx].bandwidth();
    if (isLeft(c))  pbOffset -= tuneStep;            // tune down in passband
    if (isRight(c)) pbOffset += tuneStep;            // tune up in passband
    if (pbOffset < 0)  pbOffset = 0;
    if (pbOffset > bw) pbOffset = bw;
    if (c == 's')                                    // cycle tune step
      tuneStep = (tuneStep == 100) ? 1000 : (tuneStep == 1000 ? 5000 : 100);
    if (c == 'x') pbOffset = bw / 2;                 // recenter passband
  } else {
    // ---- CAL mode: trim radio/satellite oscillator offset ----
    if (isLeft(c))  calDl -= calStep;
    if (isRight(c)) calDl += calStep;
    if (isUp(c))    calUl += calStep;
    if (isDown(c))  calUl -= calStep;
    if (c == 's')                                    // cycle cal step
      calStep = (calStep == 10) ? 100 : (calStep == 100 ? 1000 : 10);
    if (c == 'x') { calDl = 0; calUl = 0; }          // zero calibration
  }

  if (c == 't' && activeTxCount > 0) {               // cycle transponder
    curTx = (curTx + 1) % activeTxCount;
    onTransponderChanged();
    if (radioOut && rig) {                           // refresh rig sat-mode + modes
      rig->enableSatMode(cfg.satMode && !txReceiveOnly());   // off for receive-only birds
      applyTransponderModes(activeTx[curTx]);
      lastRxSet = 0; lastUlHz = 0; uplinkDeferTicks = 0;     // re-sync after the routing change
    }
  }
  if (c == 'N') {                                    // edit this satellite's operating note
    SatEntry* s = activeSat();
    if (s) {
      loadNoteForSat(s->norad);
      editTarget = 260; editTitle = "Note (operating reminder)";
      editBuf = satNote; screen = SCR_EDIT; lastDrawMs = 0;
    }
    return;
  }
  if (c == 'n' && activeTxCount > 0) {               // jump to the beacon
    // A beacon is a downlink-only entry (uplink == 0). Prefer one whose desc
    // mentions "beacon"; otherwise the first downlink-only entry; else say none.
    int found = -1, firstDlOnly = -1;
    for (int i = 0; i < activeTxCount; ++i) {
      if (activeTx[i].uplink == 0 && activeTx[i].downlink != 0) {
        if (firstDlOnly < 0) firstDlOnly = i;
        String d = activeTx[i].desc; d.toLowerCase();
        if (d.indexOf("beacon") >= 0 || d.indexOf("bcn") >= 0) { found = i; break; }
      }
    }
    if (found < 0) found = firstDlOnly;
    if (found >= 0) {
      curTx = found; onTransponderChanged();
      if (radioOut && rig) {                          // beacon is receive-only: sat mode off, RX on MAIN
        rig->enableSatMode(cfg.satMode && !txReceiveOnly());
        applyTransponderModes(activeTx[curTx]);
        lastRxSet = 0; lastUlHz = 0; uplinkDeferTicks = 0;
      }
      setStatus(String("Beacon: ") + activeTx[curTx].desc);
    } else setStatus("No beacon listed for this sat");
  }
  if (c == 'k' && activeTxCount > 0) {               // toggle CW on both legs (linear)
    Transponder& t = activeTx[curTx];
    if (!t.isLinear) { setStatus("CW: linear birds only"); }
    else {
      cwMode = !cwMode;
      if (radioOut && rig) applyTransponderModes(t);  // re-apply modes now
      setStatus(cwMode ? "CW both legs" : "SSB (auto)");
    }
  }
  if (c == 'c' && activeTxCount > 0) {               // set/clear CTCSS tone (per sat)
    float cur = activeTx[curTx].toneHz;
    editTarget = 340;
    editTitle  = "CTCSS Hz (0=off, blank=auto)";
    editBuf    = (cur > 0) ? String(cur, 1) : "";
    screen = SCR_EDIT; return;
  }
  if (c == 'r') {                                    // toggle radio output
    radioOut = !radioOut;
    if (radioOut) {
      { SatEntry* ts = activeSat(); trackedNorad = ts ? ts->norad : 0; }  // lock tracking to this bird
      // Command the rig's satellite mode (a no-op on rigs without one). A
      // receive-only transponder (beacon/telemetry, no uplink) turns satellite
      // mode OFF and tunes the downlink on MAIN; a two-way transponder turns it on
      // per the Sat Mode setting. Which physical VFO carries up/downlink otherwise
      // follows the VFO Type setting (see the rigSet*/rigSelect* helpers).
      if (rig) rig->enableSatMode(cfg.satMode && !txReceiveOnly());
      // On rigs that can assign MAIN/SUB bands over CAT (IC-9100/9700), put the
      // correct band on each VFO once, now, so the uplink/downlink land on the
      // right bands without the operator pre-arranging them. Two-way transponders
      // only (need both legs to know both bands); fired once at engage, never per
      // tick. No-op on every other radio. UNTESTED on hardware.
      if (rig && rig->canAssignBand() && activeTxCount > 0) {
        uint32_t up = activeTx[curTx].uplink, dn = activeTx[curTx].downlink;
        if (up && dn) {
          uint32_t mainHz = dlOnSub() ? up : dn;   // MAIN carries uplink in Main-Up/Sub-Dn
          uint32_t subHz  = dlOnSub() ? dn : up;
          rig->assignBands(mainHz, subHz);
        }
      }
      if (activeTxCount > 0) applyTransponderModes(activeTx[curTx]);
      lastDoppMs = 0; lastRxSet = 0; lastUlHz = 0; uplinkDeferTicks = 0;   // re-sync tracking cleanly
      // Bound how long any single CAT read may block the cooperative loop, so a
      // laggy rig (especially the LAN backend) degrades to "no knob update this
      // cycle" instead of stalling the UI/rotator. ~3 reads fit in one cycle.
      if (rig) rig->setReadBudgetMs((uint16_t)constrain((int)effectiveCatRateMs() / 4, 60, 200));
      setStatus("Radio ON");
    } else {
      if (rig && rig->ready() && rig->hasTone() && toneApplied > 0) {
        rigSelectUplink();         // tone lives on the uplink VFO
        rig->setCtcss(false, 0);   // don't leave an encode tone on the operator's rig
      }
      toneApplied = -2.0f;         // force re-apply next time radio goes ON
      setStatus("Radio OFF");
    }
  }
  if (c == 'o') {                                    // toggle rotator pointing
    if (!cfg.rotEnable || !rot) setStatus("Rotator: enable in Settings");
    else {
      if (!rot->ready()) rot->begin();   // (re)establish the link/bridge on demand
      if (!rot->ready())
        setStatus(cfg.rotType == ROT_PST  ? "Rotator: no PstRotator link"
                  : cfg.rotType == ROT_NET ? "Rotator: no rotctl link"
                                           : "Rotator: bridge not found");
      else {
        rotOut = !rotOut;
        if (rotOut) {
          { SatEntry* ts = activeSat(); trackedNorad = ts ? ts->norad : 0; }  // lock tracking to this bird
          smOut = false; emeRotOut = false; gcRotOut = false;  // sat tracking takes the rotator
          lastRotMs = 0; lastAzCmd = lastElCmd = -999.0f;
          lastUnwrappedAz = -999.0f; rotParked = false; rotFlipUntil = 0;
          setStatus("Rotator ON");
        } else {
          rotPoint((float)cfg.rotParkAz, (float)cfg.rotParkEl);
          rotParked = true; setStatus("Rotator OFF (parked)");
        }
      }
    }
  }
  if (c == 'l') { beginQso(); return; }              // log a QSO (radio keeps tracking)
  if (c == 'f') {                                    // open Manual (no-radio) freq calc
    liveReturn = SCR_MANUAL; screen = SCR_MANUAL; lastDrawMs = 0; return;
  }
  if (c == 'g') { gridLive = true; gridScroll = 0; gridBuiltMs = 0;   // workable grids now (radio/rotor keep running)
                  liveReturn = SCR_TRACK; screen = SCR_GRID; lastDrawMs = 0; return; }
  if (c == 'w') { stateLive = true; stateScroll = 0; stateBuiltMs = 0;  // workable US states now
                  liveReturn = SCR_TRACK; screen = SCR_STATES; lastDrawMs = 0; return; }
  if (c == 'e') { dxccLive = true; dxccScroll = 0; dxccBuiltMs = 0;     // workable DXCC entities now
                  liveReturn = SCR_TRACK; screen = SCR_DXCC; lastDrawMs = 0; return; }
  if (c == 'p') { polarPathValid = false; liveReturn = SCR_TRACK; screen = SCR_POLAR;
                  lastDrawMs = 0; return; }                   // live polar
  if (c == 'z') { screen = SCR_BIG; lastDrawMs = 0; return; }  // large-font readout
  if (c == 'y') {                                    // toggle tilt tuning on the fly
    if (!imuReady) setStatus("Tilt: no IMU on this board");
    else {
      cfg.tiltTune = !cfg.tiltTune; cfg.save();
      tiltAccum = 0; lastTiltMs = millis();
      setStatus(cfg.tiltTune ? "Tilt tuning ON" : "Tilt tuning OFF");
    }
  }
  if (enter) {  // persist calibration for THIS satellite (per-sat store)
    SatEntry* s = activeSat();
    if (s) { saveCalForSat(s->norad);
             setStatus("Cal saved: " + String(s->name)); }
  }
}

// Manual (no-radio) mode keys: passband/cal tuning like Track, leg toggle, and
// access to log/polar/grids (which return here), but NO radio or rotator keys.
void App::keyManual(char c, bool enter, bool back) {
  if (c == 'v') { toggleMemo(); return; }            // SD voice memo (record/stop)
  if (isBack(c, back) || c == 'f') { screen = SCR_TRACK; lastDrawMs = 0; return; }

  bool linear = (activeTxCount > 0) && activeTx[curTx].isLinear &&
                activeTx[curTx].bandwidth() > 0;
  bool haveUp = (activeTxCount > 0) && activeTx[curTx].uplink != 0;

  if (c == 'u' && haveUp) {                          // toggle which leg is fixed
    manFixUp = !manFixUp;
    setStatus(manFixUp ? "Fix uplink (hold TX)" : "Fix downlink (hold RX)");
  }

  if (c == 'm') {                                    // toggle TUNE / CAL
    if (linear) trackMode ^= 1;
    else { trackMode = 1; setStatus("Not linear: CAL only"); }
  }

  if (trackMode == 0 && linear) {
    // ---- TUNE: move within the passband (fixed leg the operator dials) ----
    int32_t bw = (int32_t)activeTx[curTx].bandwidth();
    if (isLeft(c))  pbOffset -= tuneStep;
    if (isRight(c)) pbOffset += tuneStep;
    if (pbOffset < 0)  pbOffset = 0;
    if (pbOffset > bw) pbOffset = bw;
    if (c == 's') tuneStep = (tuneStep == 100) ? 1000 : (tuneStep == 1000 ? 5000 : 100);
    if (c == 'x') pbOffset = bw / 2;                 // recenter passband
  } else {
    // ---- CAL: trim oscillator offsets (shared with Track, same store) ----
    if (isLeft(c))  calDl -= calStep;
    if (isRight(c)) calDl += calStep;
    if (isUp(c))    calUl += calStep;
    if (isDown(c))  calUl -= calStep;
    if (c == 's') calStep = (calStep == 10) ? 100 : (calStep == 100 ? 1000 : 10);
    if (c == 'x') { calDl = 0; calUl = 0; }
  }

  if (c == 't' && activeTxCount > 0) {               // cycle transponder
    curTx = (curTx + 1) % activeTxCount;
    onTransponderChanged();
  }
  if (c == 'l') { beginQso(); return; }              // log a QSO (returns here)
  if (c == 'g') { gridLive = true; gridScroll = 0; gridBuiltMs = 0;
                  liveReturn = SCR_MANUAL; screen = SCR_GRID; lastDrawMs = 0; return; }
  if (c == 'w') { stateLive = true; stateScroll = 0; stateBuiltMs = 0;
                  liveReturn = SCR_MANUAL; screen = SCR_STATES; lastDrawMs = 0; return; }
  if (c == 'e') { dxccLive = true; dxccScroll = 0; dxccBuiltMs = 0;
                  liveReturn = SCR_MANUAL; screen = SCR_DXCC; lastDrawMs = 0; return; }
  if (c == 'p') { polarPathValid = false; liveReturn = SCR_MANUAL; screen = SCR_POLAR;
                  lastDrawMs = 0; return; }
  if (c == 'z') { screen = SCR_MANUALBIG; lastDrawMs = 0; return; }  // large-font Manual
  if (enter) {                                       // persist calibration for THIS sat
    SatEntry* s = activeSat();
    if (s) { saveCalForSat(s->norad);
             setStatus("Cal saved: " + String(s->name)); }
  }
}

void App::keyPolar(char c, bool enter, bool back) {
  if (c == 'v') { toggleMemo(); return; }            // SD voice memo (record/stop)
  if (c == 'l') { beginQso(); return; }          // log a QSO (radio keeps tracking)
  // Any of back / ENTER / 'p' returns to the tracking screen.
  if (isBack(c, back) || enter || c == 'p') { screen = liveReturn; lastDrawMs = 0; }
}

// ---- Polar view of one selected pass (from the pass-detail screen) ---------
void App::drawPassPolar() {
  SatEntry* s = activeSat();
  header(s ? String(s->name) : String("Pass polar"));
  canvas.setTextSize(1);
  if (!pdValid) { canvas.setTextColor(CL_YELLOW, CL_BLACK);
                  canvas.setCursor(6, 50); canvas.print("No pass data.");
                  footer("` back"); return; }

  const int cx = 66, cy = 70, R = 44;
  drawPolarGrid(cx, cy, R);
  drawPolarArc(cx, cy, R, pdAz, pdEl, PD_SAMPLES);

  // Live position marker if this pass is currently in progress.
  if (timeIsSet() && pdPass.los > pdPass.aos) {
    time_t now = nowUtc();
    if (now >= pdPass.aos && now <= pdPass.los) {
      double f = (double)(now - pdPass.aos) / (double)(pdPass.los - pdPass.aos);
      int i = (int)lround(f * (PD_SAMPLES - 1));
      if (i < 0) i = 0; if (i >= PD_SAMPLES) i = PD_SAMPLES - 1;
      if (pdEl[i] >= 0) {
        double e = pdEl[i] > 90 ? 90 : pdEl[i];
        double rr = R * (90.0 - e) / 90.0, a = pdAz[i] * (M_PI / 180.0);
        canvas.fillCircle(cx + (int)lround(rr*sin(a)), cy - (int)lround(rr*cos(a)),
                          3, CL_GREEN);
      }
    }
  }

  int rx = 128;
  canvas.setTextColor(CL_WHITE, CL_BLACK);
  canvas.setCursor(rx, 24); canvas.printf("AOS %s", fmtHM(pdPass.aos).c_str());
  canvas.setCursor(rx, 36); canvas.printf("LOS %s", fmtHM(pdPass.los).c_str());
  canvas.setCursor(rx, 48); canvas.printf("Dur %ldm", (long)((pdPass.los-pdPass.aos)/60));
  canvas.setCursor(rx, 60); canvas.printf("Max el %.0f", pdPass.maxEl);
  canvas.setTextColor(CL_GREEN, CL_BLACK);
  canvas.setCursor(rx, 78); canvas.printf("A az %03.0f", pdPass.azAos);
  canvas.setTextColor(CL_ORANGE, CL_BLACK);
  canvas.setCursor(rx, 90); canvas.printf("L az %03.0f", pdPass.azLos);
  footer("p plot   ` back");
}

void App::keyPassPolar(char c, bool enter, bool back) {
  if (c == 'p') { screen = SCR_PASSDETAIL; lastDrawMs = 0; return; }  // toggle to elev plot
  if (isBack(c, back) || enter) { screen = passDetailReturn; lastDrawMs = 0; }
}

// ---- Mutual (co-visibility) windows vs a remote DX grid --------------------
void App::computeMutual(const String& grid) {
  double dlat, dlon;
  if (!Location::gridToLatLon(grid, dlat, dlon)) {
    setStatus("Bad grid (e.g. FM18lw)"); screen = SCR_PASSES; return;
  }
  if (!timeIsSet()) { setStatus("Set the clock first"); screen = SCR_PASSES; return; }
  SatEntry* s = activeSat();
  if (!s) { setStatus("No satellite"); screen = SCR_PASSES; return; }

  // This is the Passes-screen mutual flow, NOT an activation. Clear the activation flag so
  // the shared mutual/DX-Doppler code uses the active satellite (and my/DX sites) rather
  // than an activation's, and reload THIS satellite's transponders into activeTx -- viewing
  // an activation earlier may have left a different sat's transponders loaded, which would
  // otherwise show up in the DX Doppler table for this pass.
  mdFromActivation = false;
  ensureTransponders(*s);

  String g = grid; g.trim(); g.toUpperCase();
  strncpy(dxGrid, g.c_str(), sizeof(dxGrid) - 1); dxGrid[sizeof(dxGrid)-1] = 0;
  dxLat = dlat; dxLon = dlon;

  setStatus("Computing mutual windows..."); draw();
  Observer dx; dx.lat = dlat; dx.lon = dlon; dx.altM = 0; dx.valid = true;
  pred.setSite(loc.obs()); pred.setSat(*s);
  mutualN = pred.mutualWindows(nowUtc(), dx, 0.0f, mutual, MUTUAL_MAX);
  mutualSel = 0; screen = SCR_MUTUAL; lastDrawMs = 0;
  setStatus(mutualN ? (String(mutualN) + " mutual window(s)") : "No mutual windows");
}

void App::drawMutual() {
  SatEntry* s = activeSat();
  header(s ? (String(s->name) + " mutual") : String("Mutual"));
  canvas.setTextSize(1);
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, 18);
  canvas.printf("me %s  DX %s",
                Location::toGrid(loc.obs().lat, loc.obs().lon).c_str(), dxGrid);

  if (mutualN == 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 44); canvas.print("No co-visibility windows.");
    footer("` back"); return;
  }
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, 28); canvas.print("Start UTC    Dur   me  dx");

  const int VIS = 8;
  int scroll = (mutualSel >= VIS) ? (mutualSel - VIS + 1) : 0;
  for (int v = 0; v < VIS && (scroll + v) < mutualN; ++v) {
    int i = scroll + v;
    MutualWindow& m = mutual[i];
    long secs = (long)(m.end - m.start);
    int y = 38 + v*10;
    if (i == mutualSel) { canvas.fillRect(0, y-1, 240, 10, CL_SELBG);
                          canvas.setTextColor(CL_BLACK, CL_SELBG); }
    else                  canvas.setTextColor(CL_WHITE, CL_BLACK);
    canvas.setCursor(4, y);
    canvas.printf("%s %ld:%02ld %3.0f %3.0f", fmtMDHM(m.start).c_str(),
                  secs/60, secs%60, m.myMaxEl, m.dxMaxEl);
  }
  footer(";/. select  ENT detail  d Doppler  ` back");
}

void App::keyMutual(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_PASSES; return; }
  if (mutualN) {
    if (isUp(c))   mutualSel = (mutualSel + mutualN - 1) % mutualN;
    if (isDown(c)) mutualSel = (mutualSel + 1) % mutualN;
    if (enter) {                             // open the polar-plot detail for this window
      if (!activeSat()) { setStatus("No satellite"); return; }
      mdFromActivation = false;
      buildMutualArcs(mutual[mutualSel]);
      screen = SCR_MUTUALDETAIL; lastDrawMs = 0;
      return;
    }
    if (c == 'd') {                          // Doppler table for this window (direct)
      if (!activeSat()) { setStatus("No satellite"); return; }
      dxdWin = mutualSel; dxdRow = 0; dxdAnchorHz = 0;   // no activation anchor on this path
      dxdCenterPassband();                   // start at the centre of a linear passband
      dxdReturn = SCR_MUTUAL;
      screen = SCR_DXDOPP; lastDrawMs = 0;
      return;
    }
  }
}

// ===========================================================================
//  Activation footprint + shared mutual-window detail (0.9.43)
// ===========================================================================

// Resolve a satellite name (as listed by hams.at) to a DB index, or -1.
static int dbIndexByName(SatDb& db, const char* name) {
  if (!name || !name[0]) return -1;
  for (int i = 0; i < db.count(); ++i)
    if (strcasecmp(db.at(i).name, name) == 0) return i;
  // Loose match: ignore case and any trailing junk after a space (e.g. "AO-91 ").
  for (int i = 0; i < db.count(); ++i)
    if (strncasecmp(db.at(i).name, name, strlen(db.at(i).name)) == 0) return i;
  return -1;
}

// Look up a satellite by NORAD catalog number. The NORAD ID is invariant across every
// station's database regardless of the display name it happens to use, so it is the
// reliable key for cross-station references (a satellite may be "RS95S" in one DB and
// "QMR-KWT2" in another, but the NORAD number is the same). Returns -1 if not present.
static int dbIndexByNorad(SatDb& db, uint32_t norad) {
  if (norad == 0) return -1;
  for (int i = 0; i < db.count(); ++i)
    if (db.at(i).norad == norad) return i;
  return -1;
}

// Resolve a satellite reference that carries BOTH a name and (optionally) a NORAD number,
// as decoded from a LoRa message. Prefer the NORAD number (name-agnostic); fall back to
// the name only when there is no NORAD or the NORAD isn't in this DB. This is what makes
// #SAT / !SAT references work between stations whose DBs name the same object differently.
static int dbResolveSat(SatDb& db, const char* name, uint32_t norad) {
  int i = dbIndexByNorad(db, norad);
  if (i >= 0) return i;
  return dbIndexByName(db, name);
}

// Scan a text field for the first token that reads as a VHF/UHF frequency in MHz
// (e.g. "145.950", "435.180") or bare kHz, returning it in Hz (0 = none found).
// Only decimals that look like a real ham-sat frequency are accepted so stray
// numbers ("73", "2024", "59") don't match.
static uint32_t scanFreqHz(const char* text) {
  if (!text) return 0;
  const char* p = text;
  while (*p) {
    if ((*p >= '0' && *p <= '9')) {
      // Parse a number with optional single '.'; measure integer-part digits.
      const char* start = p;
      int intDigits = 0; bool dot = false; int fracDigits = 0;
      char buf[16]; int bi = 0;
      while (*p && bi < 15 && ((*p >= '0' && *p <= '9') || (*p == '.' && !dot))) {
        if (*p == '.') dot = true;
        else if (!dot) intDigits++;
        else fracDigits++;
        buf[bi++] = *p++;
      }
      buf[bi] = 0;
      double val = atof(buf);
      uint32_t hz = 0;
      if (dot && intDigits >= 2 && intDigits <= 4) {
        // MHz value (e.g. 145.950 or 1268.300)
        hz = (uint32_t)llround(val * 1e6);
      } else if (!dot && intDigits >= 6 && intDigits <= 9) {
        // bare Hz (e.g. 145950000) or kHz? treat 6-9 digits as Hz if plausible band
        hz = (uint32_t)strtoul(buf, nullptr, 10);
      }
      // Accept only if inside the amateur satellite VHF/UHF/L bands (broad gates).
      if ((hz >= 28000000UL  && hz <= 30000000UL)  ||   // 10 m
          (hz >= 144000000UL && hz <= 148000000UL) ||   // 2 m
          (hz >= 220000000UL && hz <= 226000000UL) ||   // 1.25 m
          (hz >= 430000000UL && hz <= 440000000UL) ||   // 70 cm
          (hz >= 1240000000UL&& hz <= 1300000000UL))     // 23 cm
        return hz;
      (void)fracDigits; (void)start;
    } else {
      p++;
    }
  }
  return 0;
}

// From an activation's freq field (then comment), find a frequency and match it
// to one of the ACTIVE satellite's TWO-WAY transponders (both uplink & downlink
// present). If it lands in a transponder's downlink range -> fixed DX downlink;
// in its uplink range -> fixed DX uplink. Sets actTxIdx/actFixMode/actFixHz.
// Returns true on a successful match, false to fall back to the default table.
bool App::parseActivationFreq(const Activation& a) {
  actTxIdx = -1; actFixMode = 0; actFixHz = 0;
  if (activeTxCount == 0) return false;
  uint32_t hz = scanFreqHz(a.freq);
  if (!hz) hz = scanFreqHz(a.comment);
  if (!hz) return false;

  const uint32_t TOL = 20000;   // +/-20 kHz tolerance for single-channel matches
  for (int i = 0; i < activeTxCount; ++i) {
    const Transponder& t = activeTx[i];
    bool twoWay = (t.downlink != 0 && t.uplink != 0);
    if (!twoWay) continue;
    // Downlink leg
    uint32_t dLo = t.downlink, dHi = t.downlinkHigh ? t.downlinkHigh : t.downlink;
    if (dHi < dLo) { uint32_t tmp = dLo; dLo = dHi; dHi = tmp; }
    if (hz >= (dLo > TOL ? dLo - TOL : 0) && hz <= dHi + TOL) {
      actTxIdx = i; actFixMode = 1; actFixHz = hz; return true;
    }
    // Uplink leg
    uint32_t uLo = t.uplink, uHi = t.uplinkHigh ? t.uplinkHigh : t.uplink;
    if (uHi < uLo) { uint32_t tmp = uLo; uLo = uHi; uHi = tmp; }
    if (hz >= (uLo > TOL ? uLo - TOL : 0) && hz <= uHi + TOL) {
      actTxIdx = i; actFixMode = 2; actFixHz = hz; return true;
    }
  }
  return false;
}

// Run the +/-30-min mutual-window search for the selected activation. Fills
// actFpWin with the window nearest the listed start, sets actDxLat/Lon, and
// returns actFpState: 1 = have window, 2 = none near listed time, 3 = can't
// (no grid / sat not in DB / clock unset).
int App::activationFootprint() {
  actFpState = 3; actCommentScroll = 0;
  const Activation& a = hamsatList[hamsatSel];
  if (!timeIsSet()) return actFpState;                 // 3: need the clock
  if (!a.grid[0]) return actFpState;                   // 3: no activator grid
  if (!Location::gridToLatLon(String(a.grid), actDxLat, actDxLon)) return actFpState;
  int si = dbIndexByName(db, a.sat);
  if (si < 0) return actFpState;                       // 3: satellite not in DB

  // Listed start as a UTC epoch.
  if (strlen(a.date) < 10 || !a.start[0]) return actFpState;
  struct tm tmv; memset(&tmv, 0, sizeof(tmv));
  int Y=0,Mo=0,D=0,h=0,m=0,sec=0;
  if (sscanf(a.date, "%d-%d-%d", &Y,&Mo,&D) != 3) return actFpState;
  if (sscanf(a.start, "%d:%d:%d", &h,&m,&sec) < 2) return actFpState;
  tmv.tm_year=Y-1900; tmv.tm_mon=Mo-1; tmv.tm_mday=D; tmv.tm_hour=h; tmv.tm_min=m; tmv.tm_sec=sec;
  time_t listed = mktime(&tmv);
  if (listed <= 0) return actFpState;

  // Search from 30 min before the listed start; accept the first co-visibility
  // window whose start is within +/-30 min of the listed time.
  SatEntry& s = db.at(si);
  Observer dx; dx.lat = actDxLat; dx.lon = actDxLon; dx.altM = 0; dx.valid = true;
  pred.setSite(loc.obs()); pred.setSat(s);
  MutualWindow tmp[MUTUAL_MAX];
  int n = pred.mutualWindows(listed - 1800, dx, 0.0f, tmp, MUTUAL_MAX);
  actFpState = 2;                                      // assume none until found
  for (int i = 0; i < n; ++i) {
    long delta = (long)(tmp[i].start - listed);
    if (delta >= -1800 && delta <= 1800) { actFpWin = tmp[i]; actFpState = 1; break; }
    if (tmp[i].start > listed + 1800) break;          // past the window; stop
  }
  // Restore predictor to my active sat so the rest of the UI is unaffected.
  if (activeSat()) { pred.setSite(loc.obs()); pred.setSat(*activeSat()); }
  return actFpState;
}

// Sample the satellite's az/el as seen from BOTH my site and the DX site across a
// mutual window, into the actMu*[] arrays, for the polar plot.
void App::buildMutualArcs(const MutualWindow& w) {
  for (int i = 0; i < ACTMU_PTS; ++i) {
    actMuAzMe[i] = actMuElMe[i] = actMuAzDx[i] = actMuElDx[i] = -1;
  }
  SatEntry* s = activeSat();
  // The activation flow may be for a sat that isn't the active one; prefer the
  // activation's sat if we resolved it, else the active sat.
  SatEntry* use = s;
  if (mdFromActivation) {
    int si = dbIndexByName(db, hamsatList[hamsatSel].sat);
    if (si >= 0) use = &db.at(si);
  }
  if (!use) return;
  double span = (double)(w.end - w.start); if (span < 1) span = 1;
  Observer dxObs; dxObs.lat = (mdFromActivation ? actDxLat : dxLat);
  dxObs.lon = (mdFromActivation ? actDxLon : dxLon); dxObs.altM = 0; dxObs.valid = true;
  pred.setSat(*use);
  for (int i = 0; i < ACTMU_PTS; ++i) {
    time_t t = w.start + (time_t)llround(span * i / (double)(ACTMU_PTS - 1));
    double az, el;
    pred.setSite(loc.obs()); if (pred.azelAt(t, az, el)) { actMuAzMe[i]=(float)az; actMuElMe[i]=(float)el; }
    pred.setSite(dxObs);     if (pred.azelAt(t, az, el)) { actMuAzDx[i]=(float)az; actMuElDx[i]=(float)el; }
  }
  // restore
  pred.setSite(loc.obs());
  if (s) pred.setSat(*s);
}

// A color-parameterized polar arc (the shared helper drawPolarArc is hard-wired
// to one color; here me and DX need distinct colors on the same grid).
static void polarArcColored(M5Canvas& cv, int cx, int cy, int R,
                            const float* az, const float* el, int n,
                            uint8_t color, char tag, uint8_t tagColor) {
  int prevx=-1, prevy=-1, firstI=-1, lastI=-1;
  auto XY=[&](int i,int&x,int&y){ double e=el[i]; if(e>90)e=90;
    double rr=R*(90.0-e)/90.0, a=az[i]*(M_PI/180.0);
    x=cx+(int)lround(rr*sin(a)); y=cy-(int)lround(rr*cos(a)); };
  for (int i=0;i<n;++i){ if(el[i]<0){prevx=-1;continue;} int px,py;XY(i,px,py);
    if(prevx>=0) cv.drawLine(prevx,prevy,px,py,color); prevx=px;prevy=py;
    if(firstI<0)firstI=i; lastI=i; }
  if (firstI<0) return;
  int lx,ly; XY(lastI,lx,ly);
  cv.fillCircle(lx,ly,2,color);
  cv.setTextColor(tagColor, CL_BLACK); cv.setCursor(lx+3, ly-3); cv.print(tag);
}

// Shared render: the polar plot (me + DX arcs) plus the AOS/LOS/max-el/duration
// text. Used by both SCR_ACTMUTUAL and SCR_MUTUALDETAIL.
void App::drawMutualDetailBody(const MutualWindow& w) {
  const int cx = 60, cy = 74, R = 46;
  drawPolarGrid(cx, cy, R);
  // me = cyan, dx = orange
  polarArcColored(canvas, cx, cy, R, actMuAzMe, actMuElMe, ACTMU_PTS, CL_CYAN,   'M', CL_CYAN);
  polarArcColored(canvas, cx, cy, R, actMuAzDx, actMuElDx, ACTMU_PTS, CL_ORANGE, 'D', CL_ORANGE);

  // Right-hand text column.
  int rx = 120;
  long dur = (long)(w.end - w.start);
  canvas.setTextColor(CL_WHITE, CL_BLACK);
  canvas.setCursor(rx, 20); canvas.printf("%s", fmtMDHM(w.start).c_str());
  canvas.setTextColor(CL_GREEN, CL_BLACK);
  canvas.setCursor(rx, 33); canvas.printf("AOS %s", fmtHM(w.start).c_str());
  canvas.setTextColor(CL_ORANGE, CL_BLACK);
  canvas.setCursor(rx, 46); canvas.printf("LOS %s", fmtHM(w.end).c_str());
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(rx, 59); canvas.printf("Dur %ld:%02ld", dur/60, dur%60);
  canvas.setTextColor(CL_CYAN, CL_BLACK);
  canvas.setCursor(rx, 74); canvas.printf("me  el %.0f", w.myMaxEl);
  canvas.setTextColor(CL_ORANGE, CL_BLACK);
  canvas.setCursor(rx, 87); canvas.printf("DX  el %.0f", w.dxMaxEl);
}

// ---- Activation mutual-window detail screen (SCR_ACTMUTUAL) ----------------
// Same body as SCR_MUTUALDETAIL, but 'd' opens the TAILORED DX Doppler seeded
// from the activation's freq/comment parse.
void App::drawActMutual() {
  const Activation& a = hamsatList[hamsatSel];
  header(a.sat[0] ? (String(a.sat) + " window") : String("Mutual window"));
  canvas.setTextSize(1);
  drawMutualDetailBody(actFpWin);
  // Parse THIS activation's frequency here so the note reflects the current row
  // (actFixMode is otherwise left over from a previous DX-Doppler entry). Only
  // shows when a real frequency matched one of the sat's two-way transponders.
  bool matched = parseActivationFreq(a);
  if (matched && actFixMode != 0) {
    // Right-hand column, continuing under the pass-detail rows (which end at y=87).
    int rx = 120;
    canvas.setTextColor(CL_DGREEN, CL_BLACK);
    canvas.setCursor(rx, 102); canvas.printf("%s DX", actFixMode == 1 ? "fix DL" : "fix UL");
    canvas.setCursor(rx, 113); canvas.printf("%.3f MHz", actFixHz / 1e6);
  }
  footer("d DX Doppler   ` back");
}

void App::keyActMutual(char c, bool enter, bool back) {
  if (isBack(c, back)) { hamsatDetail = true; screen = SCR_HAMSAT; lastDrawMs = 0; return; }
  if (c == 'd' || enter) {
    // Seed the shared DX-Doppler state for the ACTIVATION's satellite + window,
    // then open the tailored screen. This reuses the existing table/doppler code
    // with the activation's data (the normal DX-Doppler entry path is untouched).
    int si = dbIndexByName(db, hamsatList[hamsatSel].sat);
    if (si >= 0) { satSel = si; ensureTransponders(db.at(si)); }   // make it the active sat
    // Install the single found window as mutual[0] and point the table at it.
    mutual[0] = actFpWin; mutualN = 1; dxdWin = 0; dxdRow = 0;
    dxLat = actDxLat; dxLon = actDxLon;
    // Apply the parse: matched transponder + fixed downlink/uplink, else default.
    if (parseActivationFreq(hamsatList[hamsatSel]) && actTxIdx >= 0) {
      curTx = actTxIdx;
      dxdMode = actFixMode;                 // 1 = fixed DL, 2 = fixed UL
      dxdAnchor = (actFixMode == 1) ? 2 : 3;// 2 = dx-RX (downlink), 3 = dx-TX (uplink)
      dxdAnchorHz = actFixHz;               // remember it so a transponder cycle can re-apply it
      dxdCenterPassband();
      dxdStepAnchorToHz(actFixHz);          // park the anchored dial on the listed freq
    } else {
      dxdMode = 0; dxdAnchor = 0; dxdAnchorHz = 0; curTx = (curTx < activeTxCount ? curTx : 0);
      dxdCenterPassband();
    }
    screen = SCR_ACTDOPP; lastDrawMs = 0;
    return;
  }
}

// ---- Shared mutual-window detail from the existing finder (SCR_MUTUALDETAIL) -
// Same body; 'd' opens the EXISTING DX Doppler (SCR_DXDOPP), untouched.
void App::drawMutualDetail() {
  SatEntry* s = activeSat();
  header(s ? (String(s->name) + " window") : String("Mutual window"));
  canvas.setTextSize(1);
  drawMutualDetailBody(mutual[mutualSel]);
  footer("d DX Doppler   ` back");
}

void App::keyMutualDetail(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_MUTUAL; lastDrawMs = 0; return; }
  if (c == 'd' || enter) {
    if (!activeSat()) { setStatus("No satellite"); return; }
    dxdWin = mutualSel; dxdRow = 0; dxdAnchorHz = 0;     // no activation anchor on this path
    dxdCenterPassband();
    dxdReturn = SCR_MUTUALDETAIL;           // back returns to the detail view
    screen = SCR_DXDOPP; lastDrawMs = 0;    // the existing DX Doppler
    return;
  }
}

// From the SCR_HAMSAT detail screen: build the polar arcs and open the tailored
// mutual-window detail. Assumes actFpState == 1 (a window was found).
void App::openActMutual() {
  mdFromActivation = true;
  // Make the activation's satellite active and load ITS transponders, so the
  // frequency note on this screen (and the DX-Doppler seeding on 'd') match the
  // right bird rather than whatever sat happened to be selected.
  int si = dbIndexByName(db, hamsatList[hamsatSel].sat);
  if (si >= 0) { satSel = si; ensureTransponders(db.at(si)); }
  buildMutualArcs(actFpWin);
  screen = SCR_ACTMUTUAL; lastDrawMs = 0;
}

// Tailored DX Doppler (SCR_ACTDOPP): reuse the existing table renderer with the
// seeded activation state, but keep it a distinct screen so 'back' returns to the
// activation window and the existing DX-Doppler screen is left untouched.
void App::drawActDopp() {
  drawDxDopp();   // renders from the shared state we seeded in keyActMutual
}

void App::keyActDopp(char c, bool enter, bool back) {
  if (isBack(c, back)) { mdFromActivation = true; screen = SCR_ACTMUTUAL; lastDrawMs = 0; return; }
  // Reuse the full DX-Doppler control set, but suppress its back (handled above).
  if (!isBack(c, back)) keyDxDopp(c, enter, back);
  // keyDxDopp's own back target is SCR_MUTUAL; guard so it can't leak through.
  if (screen == SCR_MUTUAL) { screen = SCR_ACTMUTUAL; lastDrawMs = 0; }
}



// ===========================================================================
//  DX Doppler table (SCR_DXDOPP)
//
//  For the selected mutual window and transponder, predict the RX (downlink) and
//  TX (uplink) dial frequencies for BOTH this station and the DX station, every
//  30 s across the window. Three modes:
//    0 TRUE RULE      - operating point fixed in the satellite passband; every
//                       dial Doppler-tracks (each station with its own range-rate)
//    1 FIXED DOWNLINK - the ANCHOR station's RX dial is held constant in real RF;
//                       the passband operating point drifts to absorb its downlink
//                       Doppler, and the other three dials follow.
//    2 FIXED UPLINK   - the ANCHOR station's TX dial is held constant in real RF;
//                       the operating point drifts, the other three dials follow.
//  The anchor (whose dial is fixed, or whose passband point you set in true rule)
//  is one of: my RX, my TX, DX RX, DX TX.
// ===========================================================================

// Set the DX Doppler passband operating point to the centre of the currently
// selected transponder. For a linear (tunable-passband) transponder that is the
// middle of the downlink passband (bandwidth/2 from the low edge); for an FM or
// single-channel transponder there is no passband to offset, so it is 0. This
// mirrors onTransponderChanged() so the DX Doppler table opens on the same
// nominal channel the on-device tracker would centre on.
void App::dxdCenterPassband() {
  if (activeTxCount > 0) {
    Transponder& t = activeTx[curTx];
    if (t.isLinear && t.bandwidth() > 0) { dxdPbOff = (int32_t)(t.bandwidth() / 2); return; }
  }
  dxdPbOff = 0;
}

// DXD_ANCHOR_NAME is defined here (rather than next to drawDxDopp) because
// dxdStepAnchorDial below references it; a file-scope static const array must be
// defined before first use. DXD_MODE_NAME stays near drawDxDopp.
static const char* DXD_ANCHOR_NAME[4] = { "me RX", "me TX", "DX RX", "DX TX" };

// Step the passband so the ANCHORED dial moves to the next round 1 kHz value
// (dir = -1 down, +1 up). Only meaningful in a fixed mode (the anchor is the dial
// the operator is parking). The grid is round kHz, so the anchored dial reads e.g.
// 145.949 / 145.950 / 145.951 MHz, never 145.9502. We target
// round(currentDial/1k)*1k + dir*1k, then converge dxdPbOff onto it (the iteration
// absorbs the ~0.4% Doppler dial/passband ratio so the dial lands within ~1 Hz).
// True-rule mode does not call this -- it keeps the plain 1 kHz passband nudge.
void App::dxdStepAnchorDial(int dir) {
  if (activeTxCount == 0 || mutualN == 0) return;
  Transponder& tp = activeTx[curTx];
  if (!tp.isLinear || tp.bandwidth() == 0) return;     // FM/single-channel: nothing to step

  time_t tRef = mutual[dxdWin].start;                  // anchored dial is defined here
  uint32_t mRx, mTx, dRx, dTx;
  dxDoppFreqs(tRef, mRx, mTx, dRx, dTx);
  uint32_t dial = (dxdAnchor == 0) ? mRx : (dxdAnchor == 1) ? mTx
                : (dxdAnchor == 2) ? dRx : dTx;
  if (dial == 0) { setStatus("Step: anchor has no TX"); return; }

  const int32_t g = 1000;                              // 1 kHz grid
  int64_t base = ((int64_t)dial + g / 2) / g * g;      // nearest round kHz
  int64_t tgt  = base + (int64_t)dir * g;              // one step from there
  if (tgt < 0) return;

  int32_t  bw = (int32_t)tp.bandwidth();
  bool anchorIsTx = (dxdAnchor == 1 || dxdAnchor == 3);
  for (int pass = 0; pass < 4; ++pass) {
    int32_t diff = (int32_t)(tgt - (int64_t)dial);     // Hz the dial must still move
    if (diff > -2 && diff < 2) break;                  // within ~1 Hz
    int32_t step = (anchorIsTx && tp.invert) ? -diff : diff;
    int32_t want = dxdPbOff + step;
    if (want < 0) want = 0; if (want > bw) want = bw;   // clamp inside the passband
    if (want == dxdPbOff) break;                        // hit an edge; can't get closer
    dxdPbOff = want;
    dxDoppFreqs(tRef, mRx, mTx, dRx, dTx);
    dial = (dxdAnchor == 0) ? mRx : (dxdAnchor == 1) ? mTx
         : (dxdAnchor == 2) ? dRx : dTx;
  }
  setStatus(String(DXD_ANCHOR_NAME[dxdAnchor]) + " " + String((double)tgt / 1e6, 3) + " MHz");
}

// Park the anchored dial on a specific target frequency (Hz) rather than the next
// round-kHz step. Used by the activation flow to lock the DX dial to the listed
// frequency. For a linear transponder it converges dxdPbOff; single-channel
// transponders have no passband to move, so the fixed dial is already exact.
void App::dxdStepAnchorToHz(uint32_t targetHz) {
  if (activeTxCount == 0 || mutualN == 0 || targetHz == 0) return;
  Transponder& tp = activeTx[curTx];
  if (!tp.isLinear || tp.bandwidth() == 0) return;     // FM/single-channel: nothing to converge
  time_t tRef = mutual[dxdWin].start;
  uint32_t mRx, mTx, dRx, dTx;
  int32_t  bw = (int32_t)tp.bandwidth();
  bool anchorIsTx = (dxdAnchor == 1 || dxdAnchor == 3);
  for (int pass = 0; pass < 6; ++pass) {
    dxDoppFreqs(tRef, mRx, mTx, dRx, dTx);
    uint32_t dial = (dxdAnchor == 0) ? mRx : (dxdAnchor == 1) ? mTx
                  : (dxdAnchor == 2) ? dRx : dTx;
    if (dial == 0) return;
    int32_t diff = (int32_t)((int64_t)targetHz - (int64_t)dial);
    if (diff > -2 && diff < 2) break;
    int32_t step = (anchorIsTx && tp.invert) ? -diff : diff;
    int32_t want = dxdPbOff + step;
    if (want < 0) want = 0; if (want > bw) want = bw;
    if (want == dxdPbOff) break;
    dxdPbOff = want;
  }
}

// Re-apply the stored anchor frequency (dxdAnchorHz, e.g. seeded from an activation)
// to the CURRENT transponder after a transponder change. If the frequency falls in the
// current transponder's downlink leg -> fixed DL; in its uplink leg -> fixed UL; then
// converge the dial onto it. If it fits neither leg (this transponder isn't the one the
// frequency belongs to), leave fixed mode off with the passband centered so the operator
// can keep cycling. Does nothing when no anchor frequency is stored.
void App::dxdReanchorToStored() {
  if (dxdAnchorHz == 0 || activeTxCount == 0) return;
  const Transponder& tp = activeTx[curTx];
  const uint32_t TOL = 20000;
  uint32_t hz = dxdAnchorHz;
  // Downlink leg
  uint32_t dLo = tp.downlink, dHi = tp.downlinkHigh ? tp.downlinkHigh : tp.downlink;
  if (dHi < dLo) { uint32_t t = dLo; dLo = dHi; dHi = t; }
  bool inDl = tp.downlink && hz >= (dLo > TOL ? dLo - TOL : 0) && hz <= dHi + TOL;
  // Uplink leg
  uint32_t uLo = tp.uplink, uHi = tp.uplinkHigh ? tp.uplinkHigh : tp.uplink;
  if (uHi < uLo) { uint32_t t = uLo; uLo = uHi; uHi = t; }
  bool inUl = tp.uplink && hz >= (uLo > TOL ? uLo - TOL : 0) && hz <= uHi + TOL;
  if (inDl)      { dxdMode = 1; dxdAnchor = 2; }        // fixed DX downlink
  else if (inUl) { dxdMode = 2; dxdAnchor = 3; }        // fixed DX uplink
  else { dxdMode = 0; dxdAnchor = 0; return; }          // not this transponder's frequency
  dxdCenterPassband();
  dxdStepAnchorToHz(hz);
}

// Core per-step calculator. Fills the four dial frequencies (Hz) at time t.
void App::dxDoppFreqs(time_t t, uint32_t& myRx, uint32_t& myTx,
                      uint32_t& dxRx, uint32_t& dxTx) {
  myRx = myTx = dxRx = dxTx = 0;
  SatEntry* s = activeSat();
  if (!s) return;
  Transponder& tp = activeTx[curTx];

  // Operating point in the passband (satellite frame), before Doppler.
  uint32_t dlOp, ulOp;
  Predictor::passbandFreqs(tp, dxdPbOff, dlOp, ulOp);

  // Range-rate for each station at t (km/s). Switch the predictor site, sample,
  // then restore to my site so the rest of the UI is unaffected.
  pred.setSat(*s);
  Observer dxObs; dxObs.lat = dxLat; dxObs.lon = dxLon; dxObs.altM = 0; dxObs.valid = true;
  pred.setSite(loc.obs());  double rrMe = pred.rangeRateAt((double)t);
  pred.setSite(dxObs);      double rrDx = pred.rangeRateAt((double)t);
  pred.setSite(loc.obs());
  const double C = 299792458.0;
  double bMe = rrMe * 1000.0 / C, bDx = rrDx * 1000.0 / C;

  if (dxdMode == 0) {
    // True rule: same operating point for both, each with its own Doppler.
    Predictor::dopplerFreqs(dlOp, ulOp, rrMe, calDl, calUl, myRx, myTx);
    Predictor::dopplerFreqs(dlOp, ulOp, rrDx, calDl, calUl, dxRx, dxTx);
    return;
  }

  // Fixed-dial modes: the ANCHOR station's chosen dial is locked to a single
  // real-RF value across the whole window, and the satellite-frame operating
  // point drifts so that, at THIS step's beta, the anchor's dial reproduces that
  // locked value. Everybody else then follows from the drifted operating point.
  //
  // The lock value is captured ONCE at a fixed reference instant (the window
  // start), not recomputed each step -- that was the bug: deriving the "parked"
  // dial from the live per-step beta made it collapse to zero drift, so the
  // supposedly-fixed dial actually swung with Doppler across the pass.
  bool anchorIsDx = (dxdAnchor == 2 || dxdAnchor == 3);

  // Anchor beta at the reference instant (window start).
  time_t tRef = mutual[dxdWin].start;
  pred.setSite(anchorIsDx ? dxObs : loc.obs());
  double rrRef = pred.rangeRateAt((double)tRef);
  pred.setSite(loc.obs());
  double aBetaRef = rrRef * 1000.0 / C;

  // Anchor beta at THIS step.
  double aBeta = anchorIsDx ? bDx : bMe;

  // Solve the drifted satellite-frame operating pair so the locked dial holds.
  double dlSat, ulSat;
  if (dxdMode == 1) {
    // FIXED DOWNLINK: lock the anchor's RX dial = dlOp*(1-aBetaRef)+calDl.
    // At this step we need dlSat with dlSat*(1-aBeta)+calDl == lock, so
    // dlSat = dlOp*(1-aBetaRef)/(1-aBeta).
    double oneMinusStep = 1.0 - aBeta; if (oneMinusStep == 0.0) oneMinusStep = 1e-12;
    dlSat = (double)dlOp * (1.0 - aBetaRef) / oneMinusStep;
    double delta = dlSat - (double)dlOp;                 // passband drift on the downlink
    ulSat = tp.invert ? ((double)ulOp - delta) : ((double)ulOp + delta);
  } else {
    // FIXED UPLINK: lock the anchor's TX dial = ulOp/(1-aBetaRef)+calUl.
    // At this step ulSat/(1-aBeta)+calUl == lock, so ulSat = ulOp*(1-aBeta)/(1-aBetaRef).
    double oneMinusRef = 1.0 - aBetaRef; if (oneMinusRef == 0.0) oneMinusRef = 1e-12;
    ulSat = ulOp ? ((double)ulOp * (1.0 - aBeta) / oneMinusRef) : 0.0;
    double delta = ulOp ? (ulSat - (double)ulOp) : 0.0;  // passband drift on the uplink
    dlSat = tp.invert ? ((double)dlOp - delta) : ((double)dlOp + delta);
  }

  // Now each station's dials from the drifted satellite-frame pair, own Doppler.
  myRx = (uint32_t)llround(dlSat * (1.0 - bMe) + (double)calDl);
  myTx = ulOp ? (uint32_t)llround(ulSat / (1.0 - bMe) + (double)calUl) : 0;
  dxRx = (uint32_t)llround(dlSat * (1.0 - bDx) + (double)calDl);
  dxTx = ulOp ? (uint32_t)llround(ulSat / (1.0 - bDx) + (double)calUl) : 0;
}

static const char* DXD_MODE_NAME[3] = { "True rule", "Fixed DL", "Fixed UL" };

void App::drawDxDopp() {
  SatEntry* s = activeSat();
  header(s ? (String(s->name) + " DX Dopp") : String("DX Doppler"));
  canvas.setTextSize(1);
  if (!s) { footer("` back"); return; }
  if (dxdWin >= mutualN) { dxdWin = 0; }
  if (mutualN == 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 50); canvas.print("No mutual window.");
    footer("` back"); return;
  }
  if (activeTxCount == 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 50); canvas.print("No transponder. Pick one");
    canvas.setCursor(6, 62); canvas.print("with 't' on Satellites.");
    footer("` back"); return;
  }
  Transponder& tp = activeTx[curTx];
  MutualWindow& w = mutual[dxdWin];

  // Header line: transponder + mode + anchor.
  canvas.setTextColor(CL_CYAN, CL_BLACK);
  canvas.setCursor(2, 18); canvas.printf("%.18s", tp.desc);
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(2, 28);
  canvas.printf("%s", DXD_MODE_NAME[dxdMode]);
  if (dxdMode != 0) canvas.printf("  anc:%s", DXD_ANCHOR_NAME[dxdAnchor]);
  if (tp.isLinear && tp.bandwidth() > 0) {
    canvas.setTextColor(CL_DGREEN, CL_BLACK);
    int32_t fromCtr = dxdPbOff - (int32_t)(tp.bandwidth() / 2);   // +/- from passband center
    if (fromCtr == 0)      canvas.printf("  ctr");
    else                   canvas.printf("  %+.1fk", fromCtr / 1000.0f);
  }

  // Column headers.
  canvas.setTextColor(CL_WHITE, CL_BLACK);
  canvas.setCursor(2, 40);   canvas.print("UTC");
  canvas.setCursor(56, 40);  canvas.print("RX (MHz)");
  canvas.setCursor(150, 40); canvas.print("TX (MHz)");
  canvas.drawLine(0, 49, 240, 49, CL_DGREY);

  // Rows: each 30 s step takes TWO lines (me, then DX) so the four frequencies
  // never run together on the 240 px display. me = green, DX = cyan; the time is
  // printed once per step on the "me" line.
  time_t span = w.end - w.start; if (span < 0) span = 0;
  int nSteps = (int)(span / 30) + 1;
  const int rowH = 9, firstY = 51, maxSteps = 4;   // 4 steps * 2 lines = 8 lines
  for (int r = 0; r < maxSteps; ++r) {
    int step = dxdRow + r;
    if (step >= nSteps) break;
    time_t t = w.start + (time_t)step * 30;
    if (t > w.end) t = w.end;
    uint32_t mRx, mTx, dRx, dTx;
    dxDoppFreqs(t, mRx, mTx, dRx, dTx);
    int yMe = firstY + (r * 2)     * rowH;
    int yDx = firstY + (r * 2 + 1) * rowH;
    // me line: time + RX + TX
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(2, yMe);  canvas.print(fmtHM(t).c_str());
    canvas.setTextColor(CL_GREEN, CL_BLACK);
    canvas.setCursor(40, yMe); canvas.print("me");
    canvas.setCursor(56, yMe); canvas.printf("%.4f", mRx / 1e6);
    if (mTx) { canvas.setCursor(150, yMe); canvas.printf("%.4f", mTx / 1e6); }
    // DX line: RX + TX (no time; aligned under me)
    canvas.setTextColor(CL_CYAN, CL_BLACK);
    canvas.setCursor(40, yDx); canvas.print("DX");
    canvas.setCursor(56, yDx); canvas.printf("%.4f", dRx / 1e6);
    if (dTx) { canvas.setCursor(150, yDx); canvas.printf("%.4f", dTx / 1e6); }
  }

  footer("t m a   ,// dial 1k   ;/. `bk");
}

void App::keyDxDopp(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = dxdReturn; lastDrawMs = 0; return; }
  if (mutualN == 0 || activeTxCount == 0) return;
  MutualWindow& w = mutual[dxdWin];
  time_t span = w.end - w.start; if (span < 0) span = 0;
  int nSteps = (int)(span / 30) + 1;
  Transponder& tp = activeTx[curTx];

  if (c == 'm') { dxdMode = (dxdMode + 1) % 3; dxdAnchorHz = 0; lastDrawMs = 0; return; }
  if (c == 't') {                                  // cycle the selected transponder
    if (activeTxCount > 0) {
      curTx = (curTx + 1) % activeTxCount;
      dxdCenterPassband();
      // If a fixed frequency was seeded (e.g. from an activation), don't lose it on a
      // transponder change: re-apply it to the new transponder when the frequency falls
      // in one of its legs. Otherwise the passband just re-centers (above).
      dxdReanchorToStored();
    }
    lastDrawMs = 0; return;
  }
  if (c == 'a') { dxdAnchor = (dxdAnchor + 1) % 4; lastDrawMs = 0; return; }
  if (isUp(c))   { if (dxdRow > 0) dxdRow--; lastDrawMs = 0; return; }
  if (isDown(c)) { if (dxdRow < nSteps - 1) dxdRow++; lastDrawMs = 0; return; }
  // Passband operating point (linear only). In a FIXED mode the left/right keys
  // step the ANCHORED dial to the next round 1 kHz (so you park on, e.g.,
  // 145.950 MHz, not 145.9502); in true-rule mode they nudge the passband
  // operating point by a plain 1 kHz.
  if (tp.isLinear && tp.bandwidth() > 0) {
    int32_t bw = (int32_t)tp.bandwidth();
    if (dxdMode != 0) {                              // fixed DL / fixed UL
      if (isLeft(c))  { dxdStepAnchorDial(-1); lastDrawMs = 0; }
      if (isRight(c)) { dxdStepAnchorDial(+1); lastDrawMs = 0; }
    } else {                                         // true rule: plain passband nudge
      if (isLeft(c))  { dxdPbOff -= 1000; if (dxdPbOff < 0)  dxdPbOff = 0;  lastDrawMs = 0; }
      if (isRight(c)) { dxdPbOff += 1000; if (dxdPbOff > bw) dxdPbOff = bw; lastDrawMs = 0; }
    }
  }
}


// ===========================================================================
//  10-day pass overview (InstantTrack "Multiple Days for Single Satellite")
// ===========================================================================
void App::buildVis() {
  visN = 0;
  SatEntry* s = activeSat();
  if (!s || !timeIsSet()) return;
  building = true;
  pred.setSite(loc.obs()); pred.setSat(*s);
  // Window starts at UTC midnight of (today + visDayOff) and spans VIS_DAYS *full*
  // days, so every day-row of the chart is completely filled (the horizon is not
  // cut off partway through the last day at the request time).
  time_t today0 = nowUtc() - (nowUtc() % 86400);
  time_t winStart = today0 + (time_t)visDayOff * 86400;
  time_t winEnd   = winStart + (time_t)VIS_DAYS * 86400;
  visN = pred.predictPasses(winStart, cfg.minPassEl, visPasses, VIS_PASS_MAX, winEnd);
  building = false;
  setStatus("");
}

void App::drawVis() {
  SatEntry* s = activeSat();
  { String hd = s ? (String(s->name) + " 10-day") : String("10-day passes");
    if (visDayOff) hd += " +" + String(visDayOff) + "d";
    header(hd); }
  canvas.setTextSize(1);
  if (building) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 56); canvas.print("Computing passes...");
    footer("` back"); return;
  }
  if (visN == 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 56); canvas.print("No passes in this 10-day window.");
    footer(";/. +/-1d  r recomp  ` bk"); return;
  }
  const int barX0 = 40, barW = 196;          // 196 px = 24 h
  const int y0 = 19, rowH = 10;
  time_t today0 = nowUtc() - (nowUtc() % 86400);
  time_t mid0   = today0 + (time_t)visDayOff * 86400;   // UTC midnight of the first row
  for (int h = 6; h <= 18; h += 6)           // 06/12/18 h gridlines behind the bars
    canvas.drawFastVLine(barX0 + barW * h / 24, y0, rowH * VIS_DAYS, CL_DGREY);
  for (int d = 0; d < VIS_DAYS; ++d) {
    time_t dayStart = mid0 + (time_t)d * 86400;
    int ry = y0 + d * rowH;
    struct tm tmv; gmtime_r(&dayStart, &tmv);
    char lbl[8]; snprintf(lbl, sizeof(lbl), "%02d/%02d", tmv.tm_mon + 1, tmv.tm_mday);
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(2, ry + 1); canvas.print(lbl);
    canvas.drawFastHLine(barX0, ry + rowH - 1, barW, CL_DGREY);
    for (int i = 0; i < visN; ++i) {
      time_t a = visPasses[i].aos, b = visPasses[i].los;
      time_t s0 = (a > dayStart) ? a : dayStart;
      time_t s1 = (b < dayStart + 86400) ? b : dayStart + 86400;
      if (s1 <= s0) continue;
      int x1 = barX0 + (int)(barW * (s0 - dayStart) / 86400);
      int x2 = barX0 + (int)(barW * (s1 - dayStart) / 86400);
      int w  = (x2 - x1 < 1) ? 1 : x2 - x1;
      float me = visPasses[i].maxEl;
      uint16_t col = (me < 15.0f) ? CL_DGREEN : (me < 40.0f ? CL_GREEN : CL_YELLOW);
      canvas.fillRect(x1, ry + 1, w, rowH - 3, col);
    }
  }
  // "Now" marker only on today's row (first row when not scrolled into the future).
  if (visDayOff == 0)
    canvas.drawFastVLine(barX0 + (int)(barW * (nowUtc() - mid0) / 86400), y0, rowH, CL_RED);
  footer(";/. +/-1d  r recomp  ` bk");
}

void App::keyVis(char c, bool enter, bool back) {
  if (isBack(c, back) || enter) { screen = visReturn; lastDrawMs = 0; return; }
  if (c == 'r') { buildVis(); lastDrawMs = 0; return; }
  if (isDown(c)) { visDayOff++; buildVis(); lastDrawMs = 0; return; }              // . scroll 1 day forward
  if (isUp(c) && visDayOff > 0) { visDayOff--; buildVis(); lastDrawMs = 0; return; } // ; scroll 1 day back (>= today)
}

// ---- Visible-passes LIST (SCR_VISLIST) -----------------------------------
// A scrollable list of OPTICALLY-VISIBLE passes (sunlit satellite, dark sky,
// peak elevation over the visMinEl gate) for the active satellite across the
// next VIS_DAYS days. Unlike the 10-day chart (SCR_VIS), this filters to only
// the passes you could actually see, and lists each with its time and geometry.
void App::buildVisList() {
  vlN = 0; vlSel = 0; vlScroll = 0;
  SatEntry* s = activeSat();
  if (!s || !timeIsSet() || !loc.obs().valid) return;
  building = true;
  setStatus("Finding visible passes..."); draw();
  pred.setSite(loc.obs()); pred.setSat(*s);
  time_t now = nowUtc();
  time_t winEnd = now + (time_t)VIS_DAYS * 86400;
  // Scan the 10-day span in 1-day windows and keep only the optically-visible
  // passes. Windowing avoids predictPasses' VIS_PASS_MAX cap silently dropping
  // the tail of the span for high-pass-rate LEO sats (~15 passes/day x 10 days
  // would exceed a single 128-pass batch). vlPasses[] holds only the VISIBLE
  // passes, which are far fewer, so its cap is rarely a constraint.
  static PassPredict day[VIS_PASS_MAX];
  time_t from = now;
  while (from < winEnd && vlN < VIS_PASS_MAX) {
    time_t segEnd = from + 86400; if (segEnd > winEnd) segEnd = winEnd;
    int n = pred.predictPasses(from, cfg.minPassEl, day, VIS_PASS_MAX, segEnd);
    if (n <= 0) { from = segEnd; continue; }
    for (int i = 0; i < n && vlN < VIS_PASS_MAX; ++i) {
      bool vis = false;
      if (visEvalPass(day[i].aos, day[i].los, day[i].maxEl, vis) == 1 && vis)
        vlPasses[vlN++] = day[i];
    }
    // Advance past the last pass found so the next window doesn't re-list it.
    time_t lastLos = day[n - 1].los;
    from = (lastLos > from) ? lastLos + 1 : segEnd;
  }
  building = false;
  setStatus("");
}

void App::drawVisList() {
  SatEntry* s = activeSat();
  header(s ? (String(s->name) + " visible") : String("Visible passes"));
  canvas.setTextSize(1);
  if (building) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 56); canvas.print("Finding visible passes...");
    footer("` back"); return;
  }
  if (!timeIsSet()) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 44); canvas.print("Clock not set (NTP or GPS).");
    footer("` back"); return;
  }
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, 18); canvas.print("AOS (UTC)    Dur El  Rise");
  if (vlN == 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 44); canvas.print("No visible passes in the");
    canvas.setCursor(6, 56); canvas.printf("next %d days.", VIS_DAYS);
    footer("r recompute  ` back");
    return;
  }
  const int VISROWS = 9;
  if (vlSel < vlScroll) vlScroll = vlSel;
  if (vlSel >= vlScroll + VISROWS) vlScroll = vlSel - VISROWS + 1;
  for (int r = 0; r < VISROWS && (vlScroll + r) < vlN; ++r) {
    int i = vlScroll + r;
    int y = 30 + r*10;
    PassPredict& p = vlPasses[i];
    long mins = (p.los - p.aos) / 60;
    if (i == vlSel) { canvas.fillRect(0, y-1, 240, 10, CL_SELBG);
                      canvas.setTextColor(CL_BLACK, CL_SELBG); }
    else canvas.setTextColor(CL_YELLOW, CL_BLACK);   // all rows are visible passes
    canvas.setCursor(4, y);
    canvas.printf("%s  %2ldm %3.0f %-3s",
                  fmtMDHM(p.aos).c_str(), mins, p.maxEl,
                  windDirName((int)(p.azAos + 0.5f)));
    // Mid-pass cloud cover from the weather fetch: the go/no-go a visible pass
    // actually hinges on. Severity-colored; omitted outside the 48 h window.
    int cld = cloudAtUnix(p.aos + (p.los - p.aos) / 2);
    if (cld >= 0) {
      uint16_t bg = (i == vlSel) ? CL_SELBG : CL_BLACK;
      uint16_t fg = (i == vlSel) ? CL_BLACK
                  : (cld < 30 ? CL_GREEN : (cld < 70 ? CL_WHITE : CL_ORANGE));
      canvas.setTextColor(fg, bg);
      canvas.setCursor(200, y); canvas.printf("%3d%%c", cld);
    }
  }
  footer("ENT detail  r recomp  ` back");
}

void App::keyVisList(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_PASSES; lastDrawMs = 0; return; }
  if (c == 'r') { buildVisList(); lastDrawMs = 0; return; }
  if (vlN == 0) return;
  if (isUp(c))   { if (vlSel > 0) vlSel--; lastDrawMs = 0; }
  if (isDown(c)) { if (vlSel < vlN - 1) vlSel++; lastDrawMs = 0; }
  if (enter) {                                   // open the selected pass's detail plot
    SatEntry* s = activeSat();
    if (s) { pred.setSite(loc.obs()); pred.setSat(*s);
             passDetailReturn = SCR_VISLIST;
             buildPassDetail(vlPasses[vlSel]); screen = SCR_PASSDETAIL; lastDrawMs = 0; }
  }
}

// ===========================================================================
//  60-day illumination (DK3WN "illum"): date x orbit-phase sun/shadow raster
// ===========================================================================
void App::buildIllum() {
  illumValid = false;
  SatEntry* s = activeSat();
  if (!s || !timeIsSet() || s->meanMotion <= 0) return;
  building = true;
  setStatus("Computing illumination..."); draw();
  pred.setSite(loc.obs()); pred.setSat(*s);
  illumPeriodMin = 1440.0f / (float)s->meanMotion;
  double periodSec = (double)illumPeriodMin * 60.0;
  // Raster starts at UTC midnight of (today + illumDayOff); each column is one day.
  time_t today0 = nowUtc() - (nowUtc() % 86400);
  time_t now = today0 + (time_t)illumDayOff * 86400;
  const int RB = (ILLUM_ROWS + 7) / 8;
  for (int c = 0; c < ILLUM_DAYS; ++c) {
    for (int b = 0; b < RB; ++b) illumBits[c][b] = 0;
    time_t base = now + (time_t)c * 86400;            // one orbit starting this day
    for (int r = 0; r < ILLUM_ROWS; ++r) {
      time_t t = base + (time_t)llround(periodSec * r / ILLUM_ROWS);
      if (!pred.sunlitAt(t)) illumBits[c][r >> 3] |= (1 << (r & 7));  // set = eclipse
    }
  }
  // current-orbit eclipse fraction (column 0) + live status
  int eclRows = 0;
  for (int r = 0; r < ILLUM_ROWS; ++r)
    if (illumBits[0][r >> 3] & (1 << (r & 7))) eclRows++;
  illumEclMin = illumPeriodMin * eclRows / ILLUM_ROWS;
  illumEclPct = 100.0f * eclRows / ILLUM_ROWS;
  illumSunNow = pred.sunlitAt(now);
  illumNextEclipse = !illumSunNow;
  illumNextSec = -1;
  for (long dt = 15; dt <= (long)periodSec + 120; dt += 15)
    if (pred.sunlitAt(now + dt) != illumSunNow) { illumNextSec = dt; break; }
  building = false;
  illumValid = true;
  setStatus("");
}

void App::drawIllum() {
  SatEntry* s = activeSat();
  { String hd = s ? (String(s->name) + " illum 60d") : String("Illumination");
    if (illumDayOff) hd += " +" + String(illumDayOff) + "d";
    header(hd); }
  canvas.setTextSize(1);
  if (building) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 56); canvas.print("Computing illumination...");
    footer("` back"); return;
  }
  if (!illumValid) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 56);
    canvas.print((s && s->meanMotion > 0) ? "No passes / orbit data." : "No orbit data.");
    footer("r recompute  ` back"); return;
  }
  const int px0 = 24, py0 = 18, cw = 3, ph = ILLUM_ROWS;   // 60*3 = 180 wide
  const int pw = ILLUM_DAYS * cw;
  canvas.fillRect(px0, py0, pw, ph, CL_BLACK);             // eclipse = dark ground
  canvas.drawRect(px0 - 1, py0 - 1, pw + 2, ph + 2, CL_GREY);
  for (int c = 0; c < ILLUM_DAYS; ++c) {                   // run-length sunlit spans
    int x = px0 + c * cw, r = 0;
    while (r < ILLUM_ROWS) {
      bool ecl = illumBits[c][r >> 3] & (1 << (r & 7));
      int r0 = r;
      while (r < ILLUM_ROWS &&
             (bool)(illumBits[c][r >> 3] & (1 << (r & 7))) == ecl) r++;
      if (!ecl) canvas.fillRect(x, py0 + r0, cw, r - r0, CL_YELLOW);   // sunlit
    }
  }
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(px0 - 4, py0 + ph + 2);
  if (illumDayOff == 0) canvas.print("now");
  else                  canvas.printf("+%dd", illumDayOff);
  canvas.setCursor(px0 + pw - 22, py0 + ph + 2);
  canvas.printf("+%dd", illumDayOff + ILLUM_DAYS);
  canvas.setCursor(px0 + pw + 5, py0);           canvas.print("1 orbit");
  canvas.setCursor(px0 + pw + 5, py0 + 10);      canvas.printf("%.0fm", illumPeriodMin);
  canvas.setCursor(4, py0 + ph + 11);
  canvas.setTextColor(illumSunNow ? CL_YELLOW : CL_CYAN, CL_BLACK);
  canvas.print(illumSunNow ? "SUN" : "SHADOW");
  canvas.setTextColor(CL_WHITE, CL_BLACK);
  canvas.printf("  ecl %.0fm/orbit (%.0f%%)", illumEclMin, illumEclPct);
  if (illumNextSec > 0) {
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(4, py0 + ph + 20);
    canvas.printf("-> %s in %ldm", illumNextEclipse ? "shadow" : "sun",
                  illumNextSec / 60);
  }
  footer(",// +/-60d  r recomp  ` bk");
}

void App::keyIllum(char c, bool enter, bool back) {
  if (isBack(c, back) || enter) { screen = visReturn; lastDrawMs = 0; return; }
  if (c == 'r') { buildIllum(); lastDrawMs = 0; return; }
  if (isRight(c)) { illumDayOff += ILLUM_DAYS; buildIllum(); lastDrawMs = 0; return; }   // / next 60-day window
  if (isLeft(c)) {                                                                       // , previous 60-day window (>= today)
    illumDayOff = (illumDayOff >= ILLUM_DAYS) ? illumDayOff - ILLUM_DAYS : 0;
    buildIllum(); lastDrawMs = 0; return;
  }
}

void App::keyLocation(char c, bool enter, bool back) {
  if (isBack(c, back)) { pred.setSite(loc.obs()); screen = SCR_HOME; return; }
  if (enter) { screen = SCR_GPS; lastDrawMs = 0; return; }   // GPS data + sky plot
  if (c == 'p') {                       // toggle GPS use
    cfg.useGps = !cfg.useGps; cfg.save();
    if (cfg.useGps) startGps();
    setStatus(cfg.useGps ? "GPS enabled" : "GPS off");
  }
  if (c == 's') {                       // cycle GPS source
    cfg.gpsSource = (cfg.gpsSource + 1) % GPS_SRC_COUNT;
    cfg.save();
    if (cfg.useGps) startGps();         // re-open on the new port/baud
    setStatus(String("GPS: ") + GPS_PROFILES[cfg.gpsSource].name);
  }
  if (c == 'e') { editTarget = 100; editTitle = "Latitude (deg)";
                  editBuf = String(cfg.lat, 5); screen = SCR_EDIT; }
  if (c == 'o') { editTarget = 101; editTitle = "Longitude (deg)";
                  editBuf = String(cfg.lon, 5); screen = SCR_EDIT; }
  if (c == 'a') { editTarget = 102; editTitle = "Altitude (m)";
                  editBuf = String(cfg.altM, 1); screen = SCR_EDIT; }
  if (c == 'g') { editTarget = 103; editTitle = "Grid (Maidenhead)";
                  editBuf = ""; screen = SCR_EDIT; }
  if (c == 'c') { editTarget = 300; editTitle = "UTC YYYY-MM-DD HH:MM:SS";
                  editBuf = ""; screen = SCR_EDIT; }
  if (c == 'v') { screen = SCR_GPSPOS; lastDrawMs = 0; return; }  // live DMS position
}

void App::keyUpdate(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_HOME; return; }
  if (c == 'k' || enter) {
    if (!netCooldownOk()) return;               // gate button-mashed repeats (pool drain)
    doUpdateGp();
    // Piggyback an activations refresh on the full update: WiFi is already up if
    // the GP fetch succeeded, so this is cheap and keeps the hams.at list current.
    if (net.connected()) { String s = status; fetchHamsat(); setStatus(s); }
  }
  if (c == 'f') { if (netCooldownOk()) doFastUpdate(); }  // GP + favorites' transponders only
  if (c == 'a') { if (netCooldownOk()) doCacheAllTransponders(); }  // cache all TX for offline use
  if (c == 'w') {
    setStatus(connectWifiCfg() ? "WiFi connected" : "WiFi failed");
  }
}

// Settings are grouped into categories for a two-level menu. The per-row value
// logic in adj()/ENTER stays keyed by absolute row index; these tables only map
// a category + cursor position to that absolute index. Every populated row index
// appears in exactly one category -- reorganizing is purely a table edit.
static const int SET_CAT_N = 6;
static const char* const SET_CAT_NAME[SET_CAT_N] = {
  "Radio / CAT", "Rotator", "Passes / alerts", "Display / sound",
  "Station / logging", "Network / data"
};
static const int SET_RADIO[] = {0,30,1,2,63,31,32,33,34,21,65,22,23,24,44,45,46,36,37,62,64};
static const int SET_ROTOR[] = {8,9,10,11,12,18,47,19,16,17,13,14,15,35,38,39};
static const int SET_PASS[]  = {3,66,67,68,40,7,84,54,61};
static const int SET_DISP[]  = {48,82,25,43,49,77,79,81};
static const int SET_LOG[]   = {26,69,70,71,72,73,78,74,75,76};
static const int SET_NET[]   = {4,5,50,51,6,20,41,42,52,53,55,60,56,57,58,59,80,83,27,28,29};
static const int* const SET_CAT_ROWS[SET_CAT_N] = { SET_RADIO, SET_ROTOR, SET_PASS,
                                                    SET_DISP, SET_LOG, SET_NET };
static const int SET_CAT_LEN[SET_CAT_N] = {
  (int)(sizeof(SET_RADIO)/sizeof(int)), (int)(sizeof(SET_ROTOR)/sizeof(int)),
  (int)(sizeof(SET_PASS)/sizeof(int)),  (int)(sizeof(SET_DISP)/sizeof(int)),
  (int)(sizeof(SET_LOG)/sizeof(int)),   (int)(sizeof(SET_NET)/sizeof(int))
};

void App::keySettings(char c, bool enter, bool back) {
  const int N = 40;
  // Top-level category list.
  if (setCat < 0) {
    if (isBack(c, back)) { applyRadioFromCfg(); applyRotatorFromCfg();
                           screen = SCR_HOME; return; }
    if (isUp(c))   setSel = (setSel + SET_CAT_N - 1) % SET_CAT_N;
    if (isDown(c)) setSel = (setSel + 1) % SET_CAT_N;
    if (enter) { setCat = setSel; setSel = 0; }
    return;
  }
  // Inside a category submenu: cursor runs over the category's row list.
  (void)N;
  const int len = SET_CAT_LEN[setCat];
  if (isBack(c, back)) { applyRadioFromCfg(); applyRotatorFromCfg();
                         setSel = setCat; setCat = -1; return; }   // back to category list
  if (isUp(c))   setSel = (setSel + len - 1) % len;
  if (isDown(c)) setSel = (setSel + 1) % len;
  if (c == '{')  { setSel -= 9; if (setSel < 0) setSel = 0; }          // page up
  if (c == '}')  { setSel += 9; if (setSel > len - 1) setSel = len - 1; }  // page down
  const int sel = SET_CAT_ROWS[setCat][setSel];                   // absolute row index
  if (c == 's' && sel == 4) { startWifiScan(); return; }          // scan from the SSID row

  auto adj = [&](int dir){
    switch (sel) {
      case 0: { int m = (cfg.radioModel + dir + RIG_COUNT) % RIG_COUNT;
                cfg.radioModel = m; cfg.civAddr = RADIOS[m].civAddr;
                cfg.civBaud = RADIOS[m].defaultBaud; cfg.save();
                applyRadioFromCfg(); } break;
      case 2: { uint32_t bs[] = {1200,4800,9600,19200,38400,57600,115200};
                int idx=2; for (int i=0;i<7;i++) if (bs[i]==cfg.civBaud) idx=i;
                idx = (idx + dir + 7) % 7; cfg.civBaud = bs[idx];
                cfg.save(); applyRadioFromCfg(); } break;
      case 63: cfg.civPinMode = (uint8_t)((cfg.civPinMode + dir + 3) % 3);
               cfg.save(); applyRadioFromCfg(); break;   // 0 TX/RX, 1 G2, 2 G1
      case 3: cfg.minPassEl = constrain(cfg.minPassEl + dir, 0, 30); cfg.save(); break;
      case 66: cfg.visPasses = !cfg.visPasses; cfg.save(); break;
      case 67: {  // cycle darkness gate -6 -> -12 -> -18
        int g = cfg.visSunElMax;
        g = (g >= -6) ? -12 : (g >= -12) ? -18 : -6;
        cfg.visSunElMax = (int8_t)g; cfg.save(); break; }
      case 68: cfg.visMinEl = constrain(cfg.visMinEl + dir, 0, 40); cfg.save(); break;
      case 40: cfg.solarAct = (uint8_t)((cfg.solarAct + dir + 4) % 4); cfg.save(); break;
      case 43: cfg.wxUnits = (uint8_t)((cfg.wxUnits + dir + 3) % 3); cfg.save(); break;
      case 7: cfg.aosAlarm = !cfg.aosAlarm; cfg.save(); break;
      case 83: {   // AMSAT status window: 3/6/12/24/48/72 h
        static const uint8_t W[] = {3,6,12,24,48,72}; int n = 6, i = 0;
        for (int k = 0; k < n; ++k) if (W[k] == cfg.amsatWindowH) { i = k; break; }
        i = (i + (dir > 0 ? 1 : n - 1)) % n; cfg.amsatWindowH = W[i]; cfg.save();
      } break;
      case 84: {   // AOS lead alert: off/2/5/10/15 min
        static const uint8_t L[] = {0,2,5,10,15}; int n = 5, i = 0;
        for (int k = 0; k < n; ++k) if (L[k] == cfg.aosLeadMin) { i = k; break; }
        i = (i + (dir > 0 ? 1 : n - 1)) % n; cfg.aosLeadMin = L[i]; cfg.save();
      } break;
      case 54: cfg.irBeacon = !cfg.irBeacon; cfg.save(); break;
      case 55: cfg.loraEnable = !cfg.loraEnable; cfg.save();
               if (cfg.loraEnable) loraStart(); break;
      case 56: { long f = (long)cfg.loraFreqKHz + dir * 100;   // 100 kHz steps
                 if (f < 150000) f = 150000; if (f > 960000) f = 960000;
                 cfg.loraFreqKHz = (uint32_t)f; cfg.save();
                 if (lora.ready()) lora.setRadio(cfg.loraFreqKHz, cfg.loraSf,
                                                 cfg.loraBwHz, cfg.loraTxDbm); } break;
      case 57: { int sf = (int)cfg.loraSf + dir; if (sf < 7) sf = 12; if (sf > 12) sf = 7;
                 cfg.loraSf = (uint8_t)sf; cfg.save();
                 if (lora.ready()) lora.setRadio(cfg.loraFreqKHz, cfg.loraSf,
                                                 cfg.loraBwHz, cfg.loraTxDbm); } break;
      case 58: { uint32_t bws[] = {62500, 125000, 250000}; int idx = 1;
                 for (int i = 0; i < 3; ++i) if (cfg.loraBwHz == bws[i]) idx = i;
                 idx = (idx + dir + 3) % 3; cfg.loraBwHz = bws[idx]; cfg.save();
                 if (lora.ready()) lora.setRadio(cfg.loraFreqKHz, cfg.loraSf,
                                                 cfg.loraBwHz, cfg.loraTxDbm); } break;
      case 59: { int p = (int)cfg.loraTxDbm + dir; if (p < 0) p = 0; if (p > 22) p = 22;
                 cfg.loraTxDbm = (int8_t)p; cfg.save();
                 if (lora.ready()) lora.setRadio(cfg.loraFreqKHz, cfg.loraSf,
                                                 cfg.loraBwHz, cfg.loraTxDbm); } break;
      case 60: { int r = ((int)cfg.loraRegion + dir + 3) % 3;
                 cfg.loraApplyRegion((uint8_t)r); cfg.save();
                 if (lora.ready()) lora.setRadio(cfg.loraFreqKHz, cfg.loraSf,
                                                 cfg.loraBwHz, cfg.loraTxDbm); } break;
      case 61: { int v = ((int)cfg.msgNotify + dir + 3) % 3;
                 cfg.msgNotify = (uint8_t)v; cfg.save(); } break;
      case 80: cfg.autoPosReply = !cfg.autoPosReply; cfg.save(); break;
      case 8: cfg.rotEnable = !cfg.rotEnable; cfg.save(); applyRotatorFromCfg(); break;
      case 9: cfg.rotType = (uint8_t)((cfg.rotType + dir + 8) % 8);
              cfg.save(); applyRotatorFromCfg(); break;
      case 11: { long p = (long)cfg.rotPort + dir; if (p < 1) p = 65535;
                 if (p > 65535) p = 1; cfg.rotPort = (uint16_t)p; cfg.save(); } break;
      case 12: { uint32_t bs[] = {1200,4800,9600};
                int idx=2; for (int i=0;i<3;i++) if (bs[i]==cfg.rotBaud) idx=i;
                idx = (idx + dir + 3) % 3; cfg.rotBaud = bs[idx];
                cfg.save(); applyRotatorFromCfg(); } break;
      case 13: cfg.rotDeadband = constrain((int)cfg.rotDeadband + dir, 1, 15);
               cfg.save(); break;
      case 14: { int a = (int)cfg.rotParkAz + dir*5; while (a<0) a+=360; a%=360;
                 cfg.rotParkAz = (uint16_t)a; cfg.save(); } break;
      case 15: { const uint16_t opts[] = {0,30,60,120,180,300}; int idx=3;
                 for (int i=0;i<6;i++) if (opts[i]==cfg.rotLeadSec) idx=i;
                 idx = (idx + dir + 6) % 6; cfg.rotLeadSec = opts[idx];
                 cfg.save(); rotPassValid = false; } break;
      case 16: cfg.rotAzOff = constrain((int)cfg.rotAzOff + dir, -180, 180);
               cfg.save(); break;
      case 17: cfg.rotElOff = constrain((int)cfg.rotElOff + dir, -30, 30);
               cfg.save(); break;
      case 18: cfg.rotAzRange = (uint8_t)((cfg.rotAzRange + dir + 3) % 3);
               cfg.save(); lastAzCmd = lastUnwrappedAz = -999.0f; break;
      case 19: cfg.rotFlip = !cfg.rotFlip; cfg.save();
               lastAzCmd = lastElCmd = -999.0f; break;
      case 21: cfg.vfoType = (cfg.vfoType == VFO_MAIN_UP_SUB_DOWN)
                             ? VFO_MAIN_DOWN_SUB_UP : VFO_MAIN_UP_SUB_DOWN;
               cfg.save(); break;
      case 65: cfg.rxOnlyVfo = (uint8_t)((cfg.rxOnlyVfo + dir + 3) % 3);
               cfg.save(); break;
      case 22: cfg.satMode = !cfg.satMode; cfg.save(); break;
      case 23: { long v = (long)cfg.catRateMs + dir*10; if (v < 10) v = 10;
                 cfg.catRateMs = (uint32_t)v; cfg.save(); } break;
      case 24: { long v = (long)cfg.catDelayMs + dir*2; if (v < 0) v = 0;
                 if (v > 200) v = 200; cfg.catDelayMs = (uint16_t)v; cfg.save();
                 if (rig) rig->setCmdDelay(cfg.catDelayMs); } break;
      case 25: { const uint16_t opts[] = {0,30,60,120,300}; int idx=0;
                 for (int i=0;i<5;i++) if (opts[i]==cfg.dimSecs) idx=i;
                 idx = (idx + dir + 5) % 5; cfg.dimSecs = opts[idx];
                 cfg.save(); lastInputMs = millis(); } break;
      case 30: cfg.catType = (uint8_t)((cfg.catType + dir + 3) % 3);
               cfg.save(); applyRadioFromCfg(); break;
      case 32: { long p = (long)cfg.catPort + dir; if (p < 1) p = 65535;
                 if (p > 65535) p = 1; cfg.catPort = (uint16_t)p;
                 cfg.save(); applyRadioFromCfg(); } break;
      case 36: cfg.rigdEnable = !cfg.rigdEnable; cfg.save(); break;
      case 37: { long p = (long)cfg.rigdPort + dir; if (p < 1) p = 65535;
                 if (p > 65535) p = 1; cfg.rigdPort = (uint16_t)p; cfg.save(); } break;
      case 38: cfg.rotdEnable = !cfg.rotdEnable; cfg.save(); break;
      case 39: { long p = (long)cfg.rotdPort + dir; if (p < 1) p = 65535;
                 if (p > 65535) p = 1; cfg.rotdPort = (uint16_t)p; cfg.save(); } break;
      case 53: { long p = (long)cfg.webPort + dir; if (p < 1) p = 65535;
                 if (p > 65535) p = 1; cfg.webPort = (uint16_t)p; cfg.save(); } break;
      case 44: { long v = (long)cfg.doppThreshFmHz + dir*25; if (v < 0) v = 0;
                 if (v > 2000) v = 2000; cfg.doppThreshFmHz = (uint16_t)v; cfg.save(); } break;
      case 45: { long v = (long)cfg.doppThreshLinHz + dir*10; if (v < 0) v = 0;
                 if (v > 1000) v = 1000; cfg.doppThreshLinHz = (uint16_t)v; cfg.save(); } break;
      case 46: { long v = (long)cfg.doppLeadMs + dir*5; if (v < 0) v = 0;
                 if (v > 100) v = 100; cfg.doppLeadMs = (uint16_t)v; cfg.save(); } break;
      case 47: { long v = (long)cfg.rotAzLookSec + dir; if (v < 0) v = 0;
                 if (v > 10) v = 10; cfg.rotAzLookSec = (uint8_t)v; cfg.save(); } break;
      case 48: { long v = (long)cfg.bright + dir*16; if (v < 10) v = 10;
                 if (v > 255) v = 255; cfg.bright = (uint8_t)v;
                 M5Cardputer.Display.setBrightness(cfg.bright);   // live preview
                 cfg.save(); } break;
      case 82: { long v = (long)cfg.spkVolume + dir*24; if (v < 0) v = 0;
                 if (v > 255) v = 255; cfg.spkVolume = (uint8_t)v;
                 cfg.save();
                 // Live feedback: apply the new volume and play a short blip so the
                 // user hears the level as they adjust (silent if set to 0).
                 M5Cardputer.Speaker.stop();
                 M5Cardputer.Speaker.setVolume(cfg.spkVolume);
                 if (cfg.spkVolume > 0) M5Cardputer.Speaker.tone(1200, 70); } break;
      case 49: if (!imuReady) setStatus("No IMU on this board");
               else { cfg.tiltTune = !cfg.tiltTune; cfg.save();
                      tiltAccum = 0; lastTiltMs = millis(); } break;
      case 77: if (!imuReady) setStatus("No IMU on this board");
               else { cfg.gameTilt = !cfg.gameTilt; cfg.save(); } break;
      case 79: cfg.gameSound = !cfg.gameSound; cfg.save();
               if (cfg.gameSound) { M5Cardputer.Speaker.stop();
                                    M5Cardputer.Speaker.tone(1500, 60); }  // confirm blip
               break;
      case 81: cfg.morseSwap = !cfg.morseSwap; cfg.save(); break;
    }
  };
  if (isLeft(c))  adj(-1);
  if (isRight(c)) adj(+1);
  if (enter) {
    switch (sel) {
      case 1: editTarget = 200; editTitle = "CI-V addr (hex)";
              editBuf = String(cfg.civAddr, HEX); screen = SCR_EDIT; break;
      case 4: editTarget = 201; editTitle = "WiFi SSID";
              editBuf = cfg.ssid; screen = SCR_EDIT; break;
      case 5: editTarget = 202; editTitle = "WiFi password";
              editBuf = cfg.pass; screen = SCR_EDIT; break;
      case 50: editTarget = 217; editTitle = "WiFi 2 SSID";
               editBuf = cfg.ssid2; screen = SCR_EDIT; break;
      case 51: editTarget = 218; editTitle = "WiFi 2 password";
               editBuf = cfg.pass2; screen = SCR_EDIT; break;
      case 52: cfg.webEnable = !cfg.webEnable; cfg.save();
               setStatus(cfg.webEnable ? "Web control ON" : "Web control OFF"); break;
      case 6: setStatus(connectWifiCfg() ? "WiFi OK" : "WiFi FAIL");
              break;
      case 62: runCatTest(); break;
      case 64: enterCatMon(); break;   // open the CAT serial terminal/monitor
      case 7: cfg.aosAlarm = !cfg.aosAlarm; cfg.save();
              setStatus(cfg.aosAlarm ? "AOS alarm on" : "AOS alarm off"); break;
      case 83: {   // AMSAT status window (cycle forward on ENTER)
        static const uint8_t W[] = {3,6,12,24,48,72}; int n = 6, i = 0;
        for (int k = 0; k < n; ++k) if (W[k] == cfg.amsatWindowH) { i = k; break; }
        cfg.amsatWindowH = W[(i + 1) % n]; cfg.save();
        setStatus(String("AMSAT window: ") + (int)cfg.amsatWindowH + " h - re-fetch to apply", 2500);
      } break;
      case 84: {   // AOS lead alert (cycle forward on ENTER)
        static const uint8_t L[] = {0,2,5,10,15}; int n = 5, i = 0;
        for (int k = 0; k < n; ++k) if (L[k] == cfg.aosLeadMin) { i = k; break; }
        cfg.aosLeadMin = L[(i + 1) % n]; cfg.save();
        setStatus(cfg.aosLeadMin ? (String("AOS lead alert: ") + (int)cfg.aosLeadMin + " min")
                                 : String("AOS lead alert off"));
      } break;
      case 54: cfg.irBeacon = !cfg.irBeacon; cfg.save(); break;
      case 55: cfg.loraEnable = !cfg.loraEnable; cfg.save();
               if (cfg.loraEnable) loraStart(); break;
      case 56: editTarget = 701; editTitle = "LoRa freq (MHz)";
               editBuf = String(cfg.loraFreqKHz / 1000.0, 3); screen = SCR_EDIT; break;
      case 57: { int sf = (int)cfg.loraSf + 1; if (sf > 12) sf = 7;
                 cfg.loraSf = (uint8_t)sf; cfg.save();
                 if (lora.ready()) lora.setRadio(cfg.loraFreqKHz, cfg.loraSf,
                                                 cfg.loraBwHz, cfg.loraTxDbm); } break;
      case 58: { uint32_t bws[] = {62500, 125000, 250000}; int idx = 1;
                 for (int i = 0; i < 3; ++i) if (cfg.loraBwHz == bws[i]) idx = i;
                 idx = (idx + 1) % 3; cfg.loraBwHz = bws[idx]; cfg.save();
                 if (lora.ready()) lora.setRadio(cfg.loraFreqKHz, cfg.loraSf,
                                                 cfg.loraBwHz, cfg.loraTxDbm); } break;
      case 59: editTarget = 702; editTitle = "LoRa TX power (dBm 0-22)";
               editBuf = String(cfg.loraTxDbm); screen = SCR_EDIT; break;
      case 60: { int r = ((int)cfg.loraRegion + 1) % 3;
                 cfg.loraApplyRegion((uint8_t)r); cfg.save();
                 if (lora.ready()) lora.setRadio(cfg.loraFreqKHz, cfg.loraSf,
                                                 cfg.loraBwHz, cfg.loraTxDbm);
                 setStatus(r == 0 ? "US 33cm 906.875" : r == 1 ? "EU 70cm 433.775"
                                                               : "JP 430 431.000"); } break;
      case 61: { int v = ((int)cfg.msgNotify + 1) % 3; cfg.msgNotify = (uint8_t)v; cfg.save();
                 setStatus(v == 0 ? "Msg notify off" : v == 2 ? "Msg notify banner+beep"
                                                              : "Msg notify banner"); } break;
      case 80: cfg.autoPosReply = !cfg.autoPosReply; cfg.save();
               setStatus(cfg.autoPosReply ? "Auto position reply ON" : "Auto position reply off"); break;
      case 11: editTarget = 206; editTitle = "Net rotator port";
               editBuf = String(cfg.rotPort); screen = SCR_EDIT; break;
      case 8: cfg.rotEnable = !cfg.rotEnable; cfg.save(); applyRotatorFromCfg(); break;
      case 10: editTarget = 205; editTitle = "Net rotator host (IP)";
               editBuf = cfg.rotHost; screen = SCR_EDIT; break;
      case 20: gpSrcSel = 0; gpSrcScroll = 0; screen = SCR_GPSRC; lastDrawMs = 0; break;
      case 26: editTarget = 204; editTitle = "My callsign";
               editBuf = cfg.myCall; screen = SCR_EDIT; break;
      case 41: editTarget = 214; editTitle = "QRZ username";
               editBuf = cfg.qrzUser; screen = SCR_EDIT; break;
      case 42: editTarget = 215; editTitle = "QRZ password";
               editBuf = cfg.qrzPass; screen = SCR_EDIT; break;
      case 69: lotwPickEnter(LP_DXCC); break;   // DXCC entity picker (full list, subdiv-bearing first)
      case 70: editTarget = 221; editTitle = "LoTW CQ zone";
               editBuf = cfg.lotwCqz; screen = SCR_EDIT; break;
      case 71: editTarget = 222; editTitle = "LoTW ITU zone";
               editBuf = cfg.lotwItuz; screen = SCR_EDIT; break;
      case 72: lotwPickEnter(LP_PRIMARY); break;   // primary subdivision (state/province/oblast/...)
      case 73: lotwPickEnter(LP_SECONDARY); break;   // secondary subdivision (county/city)
      case 74: editTarget = 225; editTitle = "Cloudlog URL (https://...)";
               editBuf = cfg.clUrl; screen = SCR_EDIT; break;
      case 75: editTarget = 226; editTitle = "Cloudlog API key (read-write)";
               editBuf = cfg.clKey; screen = SCR_EDIT; break;
      case 76: editTarget = 227; editTitle = "Cloudlog station ID (number)";
               editBuf = cfg.clStation; screen = SCR_EDIT; break;
      case 78: editTarget = 228; editTitle = "LoTW IOTA ref (e.g. NA-005)";
               editBuf = cfg.lotwIota; screen = SCR_EDIT; break;
      case 27: {
        bool ok = copyFile(FILE_CFG, FILE_CFG_BAK) && copyFile(FILE_FAVS, FILE_FAVS_BAK);
        setStatus(ok ? "Backed up to SD" : "Backup failed");
      } break;
      case 28: {
        if (!Store::fs().exists(FILE_CFG_BAK)) { setStatus("No backup found"); break; }
        bool ok = copyFile(FILE_CFG_BAK, FILE_CFG);
        copyFile(FILE_FAVS_BAK, FILE_FAVS);
        if (ok) { cfg.load(); calDl = cfg.calDlHz; calUl = cfg.calUlHz;
                  loadFavs(); applyRadioFromCfg(); applyRotatorFromCfg();
                  buildSatView(); if (timeIsSet() && favN) buildSchedule();
                  setStatus("Restored from SD"); }
        else setStatus("Restore failed");
      } break;
      case 29: editTarget = 400; editTitle = "Type ERASE to wipe all";
               editBuf = ""; screen = SCR_EDIT; break;
      case 30: cfg.catType = (uint8_t)((cfg.catType + 1) % 3);
               cfg.save(); applyRadioFromCfg(); break;
      case 31: editTarget = 207;
               editTitle = (cfg.catType == CAT_RIGCTL) ? "rigctld host (IP)" : "Radio LAN host (IP)";
               editBuf = cfg.catHost; screen = SCR_EDIT; break;
      case 32: editTarget = 211;
               editTitle = (cfg.catType == CAT_RIGCTL) ? "rigctld port" : "Radio LAN port";
               editBuf = String(cfg.catPort); screen = SCR_EDIT; break;
      case 33: editTarget = 208; editTitle = "Radio LAN user";
               editBuf = cfg.catUser; screen = SCR_EDIT; break;
      case 34: editTarget = 209; editTitle = "Radio LAN password";
               editBuf = cfg.catPass; screen = SCR_EDIT; break;
      case 35: {                              // manual rotator control screen
        rotOut = false; smOut = false;        // manual takes over from auto-track
        float a, e;
        if (rot && rot->readPos(a, e)) { manAz = a; manEl = e; }
        else { manAz = (float)cfg.rotParkAz; manEl = (float)cfg.rotParkEl; }
        screen = SCR_ROTMAN; lastDrawMs = 0;
      } break;
      default: adj(+1); break;
    }
  }
}

static Screen editHome(int t) {
  if (t == 700) return SCR_MESSAGES;    // LoRa message compose (cancel)
  if (t == 704 || t == 705) return SCR_MESSAGES;  // LoRa sked-send date/time prompts (cancel)
  if (t == 710) return SCR_NOTES;       // note name prompt (cancel -> browser)
  if (t == 729) return SCR_GRID;        // workable-grids prefix filter (cancel)
  if (t >= 720) return SCR_SKEDENTRY;   // manual activation/sked entry fields (cancel)
  if (t == 250) return SCR_CATMON;      // CAT monitor: raw hex send (cancel/commit)
  if (t == 260) return SCR_TRACK;       // per-satellite operating note
  if (t == 600) return SCR_LOG;         // LoTW SAT_NAME prompt (abort export)
  if (t >= 500) return SCR_LOGENTRY;    // QSO log field edit
  if (t == 340) return SCR_TRACK;       // CTCSS tone override
  if (t >= 400) return SCR_SETTINGS;    // reset confirmation
  if (t >= 320) return SCR_PASSES;      // manual transponder
  if (t >= 310) return SCR_SATLIST;     // manual GP entry
  if (t >= 300) return SCR_LOCATION;    // manual time
  if (t == 216) return SCR_QRZ;         // QRZ callsign prompt
  if (t == 230) return SCR_LOTW;        // LoTW key password prompt (cancel -> LoTW screen)
#if CARDSAT_HAS_LORARX
  if (t == 240) return SCR_LORARX;      // LoRa RX monitor: frequency-in-MHz entry
#endif
  if (t == 104) return SCR_GLOBE;       // DX grid entered from the globe
  if (t >= 200) return SCR_SETTINGS;    // radio / WiFi
  if (t >= 100) return SCR_LOCATION;    // location fields
  return SCR_HOME;
}

void App::keyEdit(char c, bool enter, bool back) {
  if (c == '`') { screen = editHome(editTarget); return; }      // cancel
  // Backspace: handle the DEL key whether the keyboard reports it via ks.del
  // (back) or delivers it as a raw backspace/delete character code.
  if (back || c == 8 || c == 127) {
    if (editBuf.length()) editBuf.remove(editBuf.length() - 1);
    return;
  }
  if (enter) {
    switch (editTarget) {
      case 100: cfg.lat = editBuf.toFloat(); break;
      case 101: cfg.lon = editBuf.toFloat(); break;
      case 102: cfg.altM = editBuf.toFloat(); break;
      case 103: loc.setFromGrid(editBuf);
                cfg.lat = loc.obs().lat; cfg.lon = loc.obs().lon; break;
      case 104: {                                   // DX grid for the globe / mutual
        double dlat, dlon; String g = editBuf; g.trim(); g.toUpperCase();
        if (Location::gridToLatLon(g, dlat, dlon)) {
          strncpy(dxGrid, g.c_str(), sizeof(dxGrid) - 1); dxGrid[sizeof(dxGrid)-1] = 0;
          dxLat = dlat; dxLon = dlon;
          setStatus(String("DX set: ") + dxGrid);
        } else setStatus("Bad grid (e.g. FM18lw)");
      } break;
      case 200: cfg.civAddr = (uint8_t)strtol(editBuf.c_str(), nullptr, 16); break;
      case 250: catMonSendHex(editBuf); break;   // CAT monitor: transmit typed hex
      case 260: {                                 // per-satellite operating note
        SatEntry* s = activeSat();
        if (s) saveNoteForSat(s->norad, editBuf.c_str());
        break; }
      case 201: strncpy(cfg.ssid, editBuf.c_str(), sizeof(cfg.ssid)-1);
                cfg.ssid[sizeof(cfg.ssid)-1] = 0; break;
      case 202: strncpy(cfg.pass, editBuf.c_str(), sizeof(cfg.pass)-1);
                cfg.pass[sizeof(cfg.pass)-1] = 0; break;
      case 217: strncpy(cfg.ssid2, editBuf.c_str(), sizeof(cfg.ssid2)-1);
                cfg.ssid2[sizeof(cfg.ssid2)-1] = 0; break;
      case 218: strncpy(cfg.pass2, editBuf.c_str(), sizeof(cfg.pass2)-1);
                cfg.pass2[sizeof(cfg.pass2)-1] = 0; break;
      case 203: strncpy(cfg.gpUrl, editBuf.c_str(), sizeof(cfg.gpUrl)-1);
                cfg.gpUrl[sizeof(cfg.gpUrl)-1] = 0; break;
      case 204: { String v = editBuf; v.trim(); v.toUpperCase();   // callsigns are upper-case
                  strncpy(cfg.myCall, v.c_str(), sizeof(cfg.myCall)-1);
                  cfg.myCall[sizeof(cfg.myCall)-1] = 0; break; }
      case 214: strncpy(cfg.qrzUser, editBuf.c_str(), sizeof(cfg.qrzUser)-1);
                cfg.qrzUser[sizeof(cfg.qrzUser)-1] = 0; qrzSessionKey = ""; break;
      case 215: strncpy(cfg.qrzPass, editBuf.c_str(), sizeof(cfg.qrzPass)-1);
                cfg.qrzPass[sizeof(cfg.qrzPass)-1] = 0; qrzSessionKey = ""; break;
      case 221: strncpy(cfg.lotwCqz, editBuf.c_str(), sizeof(cfg.lotwCqz)-1);
                cfg.lotwCqz[sizeof(cfg.lotwCqz)-1] = 0; break;
      case 222: strncpy(cfg.lotwItuz, editBuf.c_str(), sizeof(cfg.lotwItuz)-1);
                cfg.lotwItuz[sizeof(cfg.lotwItuz)-1] = 0; break;
      case 225: { String u = editBuf; u.trim();
                  // strip a trailing slash so we can append the API path cleanly
                  while (u.length() && u.charAt(u.length()-1) == '/') u.remove(u.length()-1);
                  strncpy(cfg.clUrl, u.c_str(), sizeof(cfg.clUrl)-1);
                  cfg.clUrl[sizeof(cfg.clUrl)-1] = 0; } break;
      case 226: strncpy(cfg.clKey, editBuf.c_str(), sizeof(cfg.clKey)-1);
                cfg.clKey[sizeof(cfg.clKey)-1] = 0; break;
      case 227: strncpy(cfg.clStation, editBuf.c_str(), sizeof(cfg.clStation)-1);
                cfg.clStation[sizeof(cfg.clStation)-1] = 0; break;
      case 228: { String u = editBuf; u.trim(); u.toUpperCase();   // IOTA ref e.g. NA-005
                  strncpy(cfg.lotwIota, u.c_str(), sizeof(cfg.lotwIota)-1);
                  cfg.lotwIota[sizeof(cfg.lotwIota)-1] = 0; } break;
      case 210: { double v = editBuf.toFloat(); if (v >= 0.1 && v <= 50000.0) cfg.beaconMHz = v;
                  cfg.save(); screen = SCR_ORBIT; orbitPage = 4; lastDrawMs = 0;
                  setStatus("Saved"); return; }
      case 216: {                                   // QRZ callsign lookup
        String call = editBuf; call.trim(); call.toUpperCase();
        screen = SCR_QRZ; lastDrawMs = 0;
        if (call.length() == 0) { qrzHaveResult = false; return; }
        setStatus("QRZ: looking up " + call + "..."); draw();
        String err;
        if (qrzLookup(call, err)) { qrzHaveResult = true; setStatus(""); }
        else { qrzHaveResult = false; setStatus("QRZ: " + err); }
        return; }

#if CARDSAT_HAS_LORARX
      case 240:                                     // LoRa RX monitor: freq in MHz
        lorarx.setFreqMHz(editBuf);
        screen = SCR_LORARX; lastDrawMs = 0;
        return;
#endif

      case 230: {                                   // LoTW key password -> upload
        String pass = editBuf;
        screen = SCR_LOTW; lastDrawMs = 0;
        // Iterate batches here, at ONE stack depth, rather than letting each batch
        // recurse into the next (which stacked a full TLS+signing frame per batch and
        // overflowed the stack on the 3rd). doLotwUpload sets lotwMoreBatches when QSOs
        // remain; loop until it's clear. A hard cap guards against any accounting bug
        // that fails to make progress (each batch sends up to LOTW_BATCH_QSOS).
        int guard = 0;
        do {
          lotwMoreBatches = false;
          doLotwUpload(pass);
        } while (lotwMoreBatches && ++guard < 1000);
        return; }

      case 710: {                                   // note name -> create/open editor
        char nm[NOTE_NAME_MAX];
        strncpy(nm, editBuf.c_str(), sizeof(nm) - 1); nm[sizeof(nm) - 1] = 0;
        if (!Notes::sanitizeName(nm, sizeof(nm))) {
          setStatus("Bad name"); screen = SCR_NOTES; lastDrawMs = 0; return;
        }
        if (noteIsNew && Notes::exists(nm)) {        // don't silently clobber on 'new'
          setStatus("Name exists - pick another");
          editTarget = 710; editTitle = "New note name"; editBuf = "";
          screen = SCR_EDIT; lastDrawMs = 0; return;
        }
        noteName = nm;
        if (noteIsNew) {                             // fresh blank note
          noteBuf = ""; noteCur = 0; noteTopLine = 0; noteDirty = false;
          Notes::write(nm, "");                      // create the file now
          noteIsNew = false;
          setStatus(String("New note: ") + nm);
        } else {                                     // naming an existing unnamed buffer
          noteSave();
        }
        screen = SCR_NOTEEDIT; lastDrawMs = 0;
        return; }

      // ---- manual activation/sked entry fields (write back to skedDraft) ----
      case 720: { String v = editBuf; v.trim();
                  strncpy(skedDraft.date, v.c_str(), sizeof(skedDraft.date)-1);
                  skedDraft.date[sizeof(skedDraft.date)-1] = 0;
                  screen = SCR_SKEDENTRY; lastDrawMs = 0; return; }
      case 721: { String v = editBuf; v.trim(); v.toUpperCase();
                  strncpy(skedDraft.call, v.c_str(), sizeof(skedDraft.call)-1);
                  skedDraft.call[sizeof(skedDraft.call)-1] = 0;
                  screen = SCR_SKEDENTRY; lastDrawMs = 0; return; }
      case 722: { String v = editBuf; v.trim();
                  strncpy(skedDraft.sat, v.c_str(), sizeof(skedDraft.sat)-1);
                  skedDraft.sat[sizeof(skedDraft.sat)-1] = 0;
                  screen = SCR_SKEDENTRY; lastDrawMs = 0; return; }
      case 723: { String v = editBuf; v.trim(); v.toUpperCase();
                  strncpy(skedDraft.grid, v.c_str(), sizeof(skedDraft.grid)-1);
                  skedDraft.grid[sizeof(skedDraft.grid)-1] = 0;
                  screen = SCR_SKEDENTRY; lastDrawMs = 0; return; }
      case 724: { String v = editBuf; v.trim();
                  strncpy(skedDraft.start, v.c_str(), sizeof(skedDraft.start)-1);
                  skedDraft.start[sizeof(skedDraft.start)-1] = 0;
                  screen = SCR_SKEDENTRY; lastDrawMs = 0; return; }
      case 725: { String v = editBuf; v.trim();
                  strncpy(skedDraft.end, v.c_str(), sizeof(skedDraft.end)-1);
                  skedDraft.end[sizeof(skedDraft.end)-1] = 0;
                  screen = SCR_SKEDENTRY; lastDrawMs = 0; return; }
      case 726: { String v = editBuf; v.trim(); v.toUpperCase();
                  strncpy(skedDraft.mode, v.c_str(), sizeof(skedDraft.mode)-1);
                  skedDraft.mode[sizeof(skedDraft.mode)-1] = 0;
                  screen = SCR_SKEDENTRY; lastDrawMs = 0; return; }
      case 727: { String v = editBuf; v.trim();
                  strncpy(skedDraft.freq, v.c_str(), sizeof(skedDraft.freq)-1);
                  skedDraft.freq[sizeof(skedDraft.freq)-1] = 0;
                  screen = SCR_SKEDENTRY; lastDrawMs = 0; return; }
      case 728: { String v = editBuf; v.trim();
                  strncpy(skedDraft.comment, v.c_str(), sizeof(skedDraft.comment)-1);
                  skedDraft.comment[sizeof(skedDraft.comment)-1] = 0;
                  screen = SCR_SKEDENTRY; lastDrawMs = 0; return; }

      // ---- workable-grids prefix filter (respects the grid capitalization rule) ----
      case 729: {
        String v = editBuf; v.trim(); v.toUpperCase();     // grids are upper-case
        if (v.length() > 4) v = v.substring(0, 4);          // a full 4-char grid at most
        // Keep only well-formed prefix characters: positions 0-1 are field letters
        // (A-R), positions 2-3 are square digits (0-9). Stop at the first bad char so
        // a stray keystroke just truncates rather than filtering to nothing.
        char f[5] = {0}; int n = 0;
        for (int i = 0; i < (int)v.length() && n < 4; ++i) {
          char ch = v[i]; bool ok = (n < 2) ? (ch >= 'A' && ch <= 'R')
                                             : (ch >= '0' && ch <= '9');
          if (!ok) break;
          f[n++] = ch;
        }
        strncpy(gridFilter, f, sizeof(gridFilter) - 1);
        gridFilter[sizeof(gridFilter) - 1] = 0;
        gridScroll = 0;
        if (gridFilter[0]) setStatus(String("Grid filter: ") + gridFilter);
        else               setStatus("Grid filter cleared");
        screen = SCR_GRID; lastDrawMs = 0; return; }

      // ---- rotctld (network rotator) host / port ----
      case 205: strncpy(cfg.rotHost, editBuf.c_str(), sizeof(cfg.rotHost)-1);
                cfg.rotHost[sizeof(cfg.rotHost)-1] = 0;
                cfg.save(); applyRotatorFromCfg();
                screen = SCR_SETTINGS; setStatus("Saved"); return;
      case 206: { long p = editBuf.toInt(); if (p < 1) p = 1; if (p > 65535) p = 65535;
                  cfg.rotPort = (uint16_t)p; cfg.save(); applyRotatorFromCfg();
                  screen = SCR_SETTINGS; setStatus("Saved"); return; }

      // ---- Icom LAN (network CAT) host / user / password / port ----
      case 207: strncpy(cfg.catHost, editBuf.c_str(), sizeof(cfg.catHost)-1);
                cfg.catHost[sizeof(cfg.catHost)-1] = 0;
                cfg.save(); applyRadioFromCfg();
                screen = SCR_SETTINGS; setStatus("Saved"); return;
      case 208: strncpy(cfg.catUser, editBuf.c_str(), sizeof(cfg.catUser)-1);
                cfg.catUser[sizeof(cfg.catUser)-1] = 0;
                cfg.save(); applyRadioFromCfg();
                screen = SCR_SETTINGS; setStatus("Saved"); return;
      case 209: strncpy(cfg.catPass, editBuf.c_str(), sizeof(cfg.catPass)-1);
                cfg.catPass[sizeof(cfg.catPass)-1] = 0;
                cfg.save(); applyRadioFromCfg();
                screen = SCR_SETTINGS; setStatus("Saved"); return;
      case 211: { long p = editBuf.toInt(); if (p < 1) p = 1; if (p > 65535) p = 65535;
                  cfg.catPort = (uint16_t)p; cfg.save(); applyRadioFromCfg();
                  screen = SCR_SETTINGS; setStatus("Saved"); return; }

      // ---- mutual co-visibility vs a DX grid ----
      case 330: computeMutual(editBuf); return;

      // ---- EME mutual-Moon window vs a DX grid ----
      case 360: {
        editBuf.trim(); editBuf.toUpperCase();
        strncpy(emeMutGrid, editBuf.c_str(), sizeof(emeMutGrid) - 1); emeMutGrid[sizeof(emeMutGrid) - 1] = 0;
        emeComputeMutual(String(emeMutGrid)); emeMutShown = true;
        screen = SCR_EME; lastDrawMs = 0; return;
      }

      // ---- grid distance/bearing calculator: the target grid ----
      case 350: {
        editBuf.trim(); editBuf.toUpperCase();
        strncpy(gcGrid, editBuf.c_str(), sizeof(gcGrid) - 1); gcGrid[sizeof(gcGrid) - 1] = 0;
        gcCompute(); screen = SCR_GRIDCALC; lastDrawMs = 0; return;
      }

      // ---- QRZ-to-grid lookup: the callsign ----
      case 351: {
        editBuf.trim(); editBuf.toUpperCase();
        strncpy(qgCall, editBuf.c_str(), sizeof(qgCall) - 1); qgCall[sizeof(qgCall) - 1] = 0;
        screen = SCR_QRZGRID; qgHave = false; qgStatus = "Looking up..."; lastDrawMs = 0;
        draw();                               // show the screen before the blocking lookup
        qrzGridLookup(); lastDrawMs = 0; return;
      }

      // ---- per-satellite CTCSS tone override ----
      case 340: {
        SatEntry* s = activeSat();
        if (!s) { screen = SCR_TRACK; return; }
        String b = editBuf; b.trim();
        if (b.length() == 0) {                        // blank -> revert to auto
          saveToneOverride(s->norad, -1.0f);
          setStatus("CTCSS: auto (built-in)");
        } else {
          float hz = b.toFloat();
          if (hz <= 0) {                              // 0 -> force tone off
            saveToneOverride(s->norad, 0.0f);
            setStatus("CTCSS off for this sat");
          } else {
            int idx = ctcssToneIndex(hz);             // snap to nearest standard
            if (idx < 0) { setStatus("Not a standard CTCSS tone");
                           screen = SCR_TRACK; return; }
            hz = ctcssToneHz(idx);
            saveToneOverride(s->norad, hz);
            setStatus("CTCSS " + String(hz, 1) + " Hz set");
          }
        }
        retagTones(s->norad);                         // apply now + re-assert
        screen = SCR_TRACK; return;
      }

      // ---- manual UTC time entry ----
      case 300: {
        struct tm tmv; memset(&tmv, 0, sizeof(tmv));
        if (sscanf(editBuf.c_str(), "%d-%d-%d %d:%d:%d",
                   &tmv.tm_year, &tmv.tm_mon, &tmv.tm_mday,
                   &tmv.tm_hour, &tmv.tm_min, &tmv.tm_sec) >= 5) {
          tmv.tm_year -= 1900; tmv.tm_mon -= 1;
          time_t epoch = mktime(&tmv);            // TZ=UTC0, so this is UTC
          struct timeval tv; tv.tv_sec = epoch; tv.tv_usec = 0;
          settimeofday(&tv, nullptr);
          setStatus("Clock set (UTC)");
        } else setStatus("Use YYYY-MM-DD HH:MM:SS");
        screen = SCR_LOCATION; return;
      }

      // ---- manual GP entry: name then each orbital element ----
      case 310: strncpy(mtSat.name, editBuf.c_str(), sizeof(mtSat.name)-1);
                mtSat.name[sizeof(mtSat.name)-1] = 0;
                editTarget = 311; editTitle = "NORAD ID"; editBuf = ""; return;
      case 311: mtSat.norad = strtoul(editBuf.c_str(), nullptr, 10);
                editTarget = 312; editTitle = "EPOCH YYYY-MM-DD HH:MM:SS";
                editBuf = ""; return;
      case 312: mtSat.epochUnix = SatDb::gpEpochToUnix(editBuf.c_str());
                editTarget = 313; editTitle = "Inclination (deg)";
                editBuf = ""; return;
      case 313: mtSat.incl = atof(editBuf.c_str());
                editTarget = 314; editTitle = "RAAN (deg)"; editBuf = ""; return;
      case 314: mtSat.raan = atof(editBuf.c_str());
                editTarget = 315; editTitle = "Eccentricity (0.xxxxxxx)";
                editBuf = ""; return;
      case 315: mtSat.ecc = atof(editBuf.c_str());
                editTarget = 316; editTitle = "Arg of perigee (deg)";
                editBuf = ""; return;
      case 316: mtSat.argp = atof(editBuf.c_str());
                editTarget = 317; editTitle = "Mean anomaly (deg)";
                editBuf = ""; return;
      case 317: mtSat.ma = atof(editBuf.c_str());
                editTarget = 318; editTitle = "Mean motion (rev/day)";
                editBuf = ""; return;
      case 318: mtSat.meanMotion = atof(editBuf.c_str());
                editTarget = 319; editTitle = "BSTAR (0 if unknown)";
                editBuf = ""; return;
      case 319: {
        mtSat.bstar = atof(editBuf.c_str());
        bool ok = db.addGp(mtSat);
        buildSatView();
        setStatus(ok ? (String("Added ") + mtSat.name)
                     : "Invalid (check NORAD / mean motion)");
        screen = SCR_SATLIST; return;
      }

      // ---- manual transponder entry ----
      //   dl low -> ul low -> dl high (0=single) -> [ul high -> invert] -> mode
      case 320: mtxDl = strtoul(editBuf.c_str(), nullptr, 10);
                editTarget = 321; editTitle = "Uplink low Hz (0=none)";
                editBuf = ""; return;
      case 321: mtxUl = strtoul(editBuf.c_str(), nullptr, 10);
                editTarget = 323; editTitle = "Downlink high Hz (0=single)";
                editBuf = ""; return;
      case 323: mtxDlHigh = strtoul(editBuf.c_str(), nullptr, 10);
                if (mtxDlHigh > mtxDl && mtxUl) {     // linear -> ask the rest
                  editTarget = 324; editTitle = "Uplink high Hz (0=same BW)";
                } else {                              // single channel -> mode
                  mtxDlHigh = 0; editTarget = 322; editTitle = "Mode (FM/USB/CW)";
                }
                editBuf = ""; return;
      case 324: mtxUlHigh = strtoul(editBuf.c_str(), nullptr, 10);
                editTarget = 325; editTitle = "Inverting? y/n";
                editBuf = ""; return;
      case 325: mtxInv = (editBuf.length() &&
                          (editBuf[0]=='y' || editBuf[0]=='Y' || editBuf[0]=='1'));
                editTarget = 322; editTitle = "Mode (FM/USB/CW)";
                editBuf = ""; return;
      case 322: {
        Transponder t;
        t.downlink = mtxDl; t.uplink = mtxUl;
        t.downlinkHigh = mtxDlHigh; t.uplinkHigh = mtxUlHigh;
        t.invert = mtxInv;
        t.isLinear = (mtxDlHigh > mtxDl) && (mtxUl != 0);
        strncpy(t.mode, editBuf.length() ? editBuf.c_str() : "FM", sizeof(t.mode)-1);
        t.mode[sizeof(t.mode)-1] = 0;
        snprintf(t.desc, sizeof(t.desc), t.isLinear ? "manual lin" : "manual");
        SatEntry* s = activeSat();
        if (s) {
          saveManualTx(s->norad, t);
          if (activeTxCount < MAX_TX_PER_SAT) activeTx[activeTxCount++] = t;
          setStatus(t.isLinear ? "Linear TX added" : "Transponder added");
        }
        screen = SCR_PASSES; return;
      }
      // ---- QSO log fields ----
      case 500: { String v = editBuf; v.trim(); v.toUpperCase();   // callsigns are upper-case
                  strncpy(qso.call, v.c_str(), sizeof(qso.call)-1);
                  qso.call[sizeof(qso.call)-1]=0;
                  if (logEditIdx >= 0) qso.uploaded = 0; screen=SCR_LOGENTRY; return; }
      case 501: strncpy(qso.rstS, editBuf.c_str(), sizeof(qso.rstS)-1);
                qso.rstS[sizeof(qso.rstS)-1]=0;
                if (logEditIdx >= 0) qso.uploaded = 0; screen=SCR_LOGENTRY; return;
      case 502: strncpy(qso.rstR, editBuf.c_str(), sizeof(qso.rstR)-1);
                qso.rstR[sizeof(qso.rstR)-1]=0;
                if (logEditIdx >= 0) qso.uploaded = 0; screen=SCR_LOGENTRY; return;
      case 503: { String v = editBuf; v.trim(); v.toUpperCase();   // grids are upper-case
                  strncpy(qso.grid, v.c_str(), sizeof(qso.grid)-1);
                  qso.grid[sizeof(qso.grid)-1]=0;
                  if (logEditIdx >= 0) qso.uploaded = 0; screen=SCR_LOGENTRY; return; }
      case 504: strncpy(qso.notes, editBuf.c_str(), sizeof(qso.notes)-1);
                qso.notes[sizeof(qso.notes)-1]=0;
                if (logEditIdx >= 0) qso.uploaded = 0; screen=SCR_LOGENTRY; return;
      case 505: {   // Date YYYY-MM-DD (UTC); keep the time-of-day
        int Y, Mo, D;
        if (sscanf(editBuf.c_str(), "%d-%d-%d", &Y, &Mo, &D) == 3) {
          time_t base = qso.utc ? (time_t)qso.utc
                                : (timeIsSet() ? nowUtc() : (time_t)1735689600);
          struct tm g; gmtime_r(&base, &g);
          g.tm_year = Y - 1900; g.tm_mon = Mo - 1; g.tm_mday = D;
          qso.utc = (uint32_t)mktime(&g);            // TZ=UTC0 -> UTC epoch
          if (logEditIdx >= 0) qso.uploaded = 0;
        } else setStatus("Use YYYY-MM-DD");
        screen = SCR_LOGENTRY; return;
      }
      case 506: {   // Time HH:MM:SS (UTC); keep the date
        int H, Mi, S = 0;
        if (sscanf(editBuf.c_str(), "%d:%d:%d", &H, &Mi, &S) >= 2) {
          time_t base = qso.utc ? (time_t)qso.utc
                                : (timeIsSet() ? nowUtc() : (time_t)1735689600);
          struct tm g; gmtime_r(&base, &g);
          g.tm_hour = H; g.tm_min = Mi; g.tm_sec = S;
          qso.utc = (uint32_t)mktime(&g);
          if (logEditIdx >= 0) qso.uploaded = 0;
        } else setStatus("Use HH:MM:SS");
        screen = SCR_LOGENTRY; return;
      }
      case 507: { double m = atof(editBuf.c_str());
                  qso.dlHz = (uint32_t)llround(m * 1e6);
                  if (logEditIdx >= 0) qso.uploaded = 0; screen = SCR_LOGENTRY; return; }
      case 508: { double m = atof(editBuf.c_str());
                  qso.ulHz = (uint32_t)llround(m * 1e6);
                  if (logEditIdx >= 0) qso.uploaded = 0; screen = SCR_LOGENTRY; return; }

      // ---- LoTW SAT_NAME prompt during ADIF export ----
      case 600: {
        String sn = editBuf; sn.trim();
        if (!sn.length()) { setStatus("Enter a SAT_NAME (max 6)"); return; }
        bool isNew = !Store::fs().exists(FILE_LOTW);
        File lf = Store::fs().open(FILE_LOTW, "a");
        if (lf) {
          if (isNew) lf.print("SAT_NAME,AMSAT_NAME\n");
          lf.print(sn); lf.print(","); lf.print(exportSats[exportPendIdx]);
          lf.print("\n"); lf.close();
        }
        exportPendIdx++;
        if (exportPendIdx < exportPendN) { promptNextLotw(); return; }
        bool ok = exportAdif();
        setStatus(ok ? "Exported qso_log.adi" : "Export failed");
        screen = SCR_LOG; return;
      }

      // ---- factory reset confirmation ----
      case 400: {
        if (editBuf == "ERASE") { factoryReset(); return; }  // formats + reboots
        setStatus("Reset cancelled");
        screen = SCR_SETTINGS; return;
      }

      // ---- send a LoRa text message (broadcast) ----
      case 700: {
        String t = editBuf;
        if (t.length()) loraSendCurrent(t.c_str());
        screen = SCR_MESSAGES; lastDrawMs = 0; return;
      }
      // ---- LoRa sked-send: date entered -> validate, then prompt for time ----
      case 704: {
        String dstr = editBuf; dstr.trim();
        if (dstr.length() != 10 || dstr[4] != '-' || dstr[7] != '-') {
          setStatus("Date must be YYYY-MM-DD", 2500);
          editTarget = 704; editTitle = "Sked date (YYYY-MM-DD)"; screen = SCR_EDIT; return;
        }
        strncpy(ssDate, dstr.c_str(), sizeof(ssDate) - 1); ssDate[sizeof(ssDate) - 1] = 0;
        editBuf = "";                              // now prompt for the time
        editTarget = 705; editTitle = "Sked time (HH:MM UTC)"; screen = SCR_EDIT; return;
      }
      // ---- LoRa sked-send: time entered -> compose "!SAT date time" and transmit ----
      case 705: {
        String tstr = editBuf; tstr.trim();
        if (tstr.length() != 5 || tstr[2] != ':') {
          setStatus("Time must be HH:MM", 2500);
          editTarget = 705; editTitle = "Sked time (HH:MM UTC)"; screen = SCR_EDIT; return;
        }
        char msg[MSG_TEXT_MAX + 1];
        // Include the NORAD after the name (name/norad, no space) so the far end resolves
        // the satellite by its invariant catalog number regardless of display name.
        if (ssNorad) snprintf(msg, sizeof(msg), "!%s/%lu %s %s", ssSat, (unsigned long)ssNorad, ssDate, tstr.c_str());
        else         snprintf(msg, sizeof(msg), "!%s %s %s", ssSat, ssDate, tstr.c_str());
        loraSendCurrent(msg);
        screen = SCR_MESSAGES; lastDrawMs = 0; return;
      }
      // ---- LoRa frequency (MHz) ----
      case 701: {
        double mhz = editBuf.toFloat();
        if (mhz >= 150.0 && mhz <= 960.0) {
          cfg.loraFreqKHz = (uint32_t)lround(mhz * 1000.0); cfg.save();
          if (lora.ready()) lora.setRadio(cfg.loraFreqKHz, cfg.loraSf,
                                          cfg.loraBwHz, cfg.loraTxDbm);
          setStatus("LoRa freq set");
        } else setStatus("Range 150-960 MHz");
        screen = SCR_SETTINGS; return;
      }
      // ---- LoRa TX power (dBm) ----
      case 702: {
        int p = editBuf.toInt(); if (p < 0) p = 0; if (p > 22) p = 22;
        cfg.loraTxDbm = (int8_t)p; cfg.save();
        if (lora.ready()) lora.setRadio(cfg.loraFreqKHz, cfg.loraSf,
                                        cfg.loraBwHz, cfg.loraTxDbm);
        setStatus("LoRa TX power set");
        screen = SCR_SETTINGS; return;
      }
    }
    if (editTarget <= 200 && editTarget != 104) {
      loc.setManual(cfg.lat, cfg.lon, cfg.altM);
      pred.setSite(loc.obs());
    }
    cfg.save();
    applyRadioFromCfg();
    screen = editHome(editTarget);
    setStatus("Saved");
    return;
  }
  if (c >= 32 && c < 127) {
    // Grid-square and callsign fields uppercase-by-default as you type (shift gives
    // lowercase). Every editTarget here is a Maidenhead grid or an amateur callsign;
    // they also uppercase on commit, so this only aligns the on-screen typing with the
    // stored result. Keep this list in sync when adding a grid/callsign entry field.
    if (editTarget == 103 || editTarget == 104 || editTarget == 204 || editTarget == 216 ||
        editTarget == 330 || editTarget == 228 ||
        editTarget == 500 || editTarget == 503 || editTarget == 600 ||
        editTarget == 350 || editTarget == 351 || editTarget == 360 ||
        editTarget == 721 || editTarget == 723 || editTarget == 729) {
      if      (c >= 'a' && c <= 'z') c -= 32;   // uppercase by default ...
      else if (c >= 'A' && c <= 'Z') c += 32;   // ... with shift for lowercase
    }
    if (!(editTarget == 600 && editBuf.length() >= 6) &&
        !(editTarget == 260 && (int)editBuf.length() >= NOTE_MAX) &&
        !(editTarget == 710 && (int)editBuf.length() >= NOTE_NAME_MAX - 1) &&
        !(editTarget == 700 && (int)editBuf.length() >= MSG_TEXT_MAX)) editBuf += c;  // caps
  }
}

// ===========================================================================
//  Rendering
// ===========================================================================
void App::header(const String& t) {
  canvas.fillRect(0, 0, 240, 16, CL_BLUE);

  // Battery indicator (top-right). getBatteryLevel() is <0 if unknown.
  int lvl = M5.Power.getBatteryLevel();
  const int bx = 216, by = 3, bw = 18, bh = 9;
  canvas.drawRect(bx, by, bw, bh, CL_WHITE);
  canvas.fillRect(bx + bw, by + 2, 2, bh - 4, CL_WHITE);    // terminal nub
  if (lvl >= 0) {
    if (lvl > 100) lvl = 100;
    int fw = (lvl * (bw - 2)) / 100;
    uint16_t col = (lvl > 50) ? CL_GREEN : (lvl > 20 ? CL_YELLOW : CL_RED);
    if (fw > 0) canvas.fillRect(bx + 1, by + 1, fw, bh - 2, col);
  }

  // Clock (left of the battery). Build it first so the title can be fit to the
  // space that's left over.
  String clk;
  int clkX = 0;                                 // where the clock text is drawn
  int rightLimit = bx;                          // title must stop before the battery
  // Unread LoRa-message indicator: a small envelope + count just left of the
  // battery, shown on every screen when there are unread messages. Silent and
  // always-on; the banner/beep (see loraPoll) is the active alert.
  int msgLeft = bx;                             // left edge of the envelope cluster (bx = none)
  if (msgUnread > 0) {
    int ex = bx - 26, ey = 4, ew = 12, eh = 8;   // envelope box left of battery
    canvas.drawRect(ex, ey, ew, eh, CL_YELLOW);
    canvas.drawLine(ex, ey, ex + ew/2, ey + eh - 2, CL_YELLOW);     // flap
    canvas.drawLine(ex + ew, ey, ex + ew/2, ey + eh - 2, CL_YELLOW);
    canvas.setTextColor(CL_YELLOW, CL_BLUE);
    canvas.setTextSize(1);
    int cnt = msgUnread > 9 ? 9 : (int)msgUnread;  // single digit (or +)
    canvas.setCursor(ex - 7, 4); canvas.print(msgUnread > 9 ? "+" : String(cnt).c_str());
    msgLeft = ex - 7;                             // count digit is the leftmost part
    rightLimit = msgLeft - 2;                     // keep the title clear of it
  }
  if (timeIsSet()) {
    clk = fmtClock(nowUtc()) + "Z";
    // Sit the clock to the LEFT of the envelope cluster (or the battery if there's
    // no envelope) so the two never overlap.
    clkX = msgLeft - (int)clk.length() * 6 - 5;
    rightLimit = clkX - 3;                        // …and the title before the clock
  }
  String trk;                                   // background Sun/Moon tracking tag
  int trkX = 0;
  if (smOut && screen != SCR_SUNMOON) {
    trk = smSel ? "MOON" : "SUN";
    trkX = rightLimit - (int)trk.length() * 6 - 6;
    rightLimit = trkX;
  }
  // Background satellite tracking tag: radio and/or rotator are still engaged
  // while off the Track/Big screen, so the user can see (and that the rig may be
  // transmitting). Shown on every other screen; cleared by the r/o toggles.
  String btrk; int btrkX = 0;
  if ((radioOut || rotOut) && screen != SCR_TRACK && screen != SCR_BIG) {
    btrk = (radioOut && rotOut) ? "R+R" : (radioOut ? "RAD" : "ROT");
    btrkX = rightLimit - (int)btrk.length() * 6 - 6;
    rightLimit = btrkX;
  }

  // Title (satellite name) at text size 2 = 12 px/char. Truncate to whatever
  // fits before the clock/battery so a long name can't overwrite them.
  const int titleX = 3, charW = 12, gap = 4;
  int maxChars = (rightLimit - gap - titleX) / charW;
  if (maxChars < 1) maxChars = 1;
  String title = ((int)t.length() > maxChars) ? t.substring(0, maxChars) : t;
  canvas.setTextColor(CL_WHITE, CL_BLUE);
  canvas.setTextSize(2);
  canvas.setCursor(titleX, 1);
  canvas.print(title);
  canvas.setTextSize(1);

  if (clk.length()) {
    canvas.setTextColor(CL_WHITE, CL_BLUE);
    canvas.setCursor(clkX, 4);                              // left of the envelope/battery
    canvas.print(clk);
  }
  if (trk.length()) {                           // Sun/Moon tracking runs in background
    canvas.setTextColor(CL_ORANGE, CL_BLUE);
    canvas.setCursor(trkX, 4);
    canvas.print(trk);
  }
  if (btrk.length()) {                          // radio/rotator tracking runs in background
    canvas.setTextColor(CL_GREEN, CL_BLUE);
    canvas.setCursor(btrkX, 4);
    canvas.print(btrk);
  }
}
void App::drawAbout() {
  header("About");
  canvas.setTextSize(1);
  int y = 22; const int dy = 11;
  auto line = [&](const String& s){
    canvas.setTextColor(CL_WHITE, CL_BLACK);
    canvas.setCursor(6, y); canvas.print(s); y += dy;
  };
  line(String("CardSat v") + FW_VERSION);
  line("by Paul Stoetzer, N8HM");
  line(String("Built ") + __DATE__);
  line(String("Storage: ") + (Store::onSD() ? "microSD" : "internal flash"));
  {
    double minAge = -1.0;
    for (int i = 0; i < db.count(); ++i) {
      double a = gpAgeDays(db.at(i));
      if (minAge < 0 || a < minAge) minAge = a;
    }
    String g = String("GP: ") + db.count() + " sats";
    if (db.count() && timeIsSet() && minAge >= 0) g += ", " + String(minAge, 1) + "d old";
    line(g);
  }
  line(String("WiFi: ") + (net.connected() ? WiFi.localIP().toString() : String("not connected")));
  {
    int b = M5.Power.getBatteryLevel();
    String s = String("Battery: ") + (b < 0 ? String("n/a") : String(b) + "%");
    if ((int)M5.Power.isCharging() == 1) s += " (charging)";  // 1=charging; ignore "unknown" (2)
    line(s);
  }
  line(String("Free heap: ") + String(ESP.getFreeHeap() / 1024) + " KB");
  {
    uint32_t up = millis() / 1000;
    char b[28];
    snprintf(b, sizeof(b), "Uptime: %luh %lum",
             (unsigned long)(up / 3600), (unsigned long)((up % 3600) / 60));
    line(String(b));
  }
  footer("r ready  t tools  l license  z game  ` back");
}

void App::keyAbout(char c, bool enter, bool back) {
  if (c == 'l') { licScroll = 0; screen = SCR_LICENSE; lastDrawMs = 0; return; }
  if (c == 'z') { gamesSel = 0; screen = SCR_GAMES; lastDrawMs = 0; return; }   // Games menu
  if (c == 'r') { screen = SCR_READY; lastDrawMs = 0; return; }                 // station readiness
  if (c == 't') { toolsSel = 0; screen = SCR_TOOLS; lastDrawMs = 0; return; }    // Tools hub
  if (isBack(c, back) || enter) screen = SCR_HOME;
}

// Network-recovery reboot prompt. Shown when the socket-failure recovery path has
// exhausted its hard WiFi resets and the connection still won't come back -- a
// reboot is the last-resort cure, but we ask rather than reboot under the user.
void App::drawNetReboot() {
  header("Network problem");
  canvas.setTextSize(1);
  canvas.setTextColor(CL_RED, CL_BLACK);
  canvas.setCursor(6, 26); canvas.print("WiFi/socket recovery failed.");
  canvas.setTextColor(CL_WHITE, CL_BLACK);
  canvas.setCursor(6, 44); canvas.print("Repeated connections were");
  canvas.setCursor(6, 54); canvas.print("refused and resetting WiFi");
  canvas.setCursor(6, 64); canvas.print("did not recover it.");
  canvas.setCursor(6, 82); canvas.print("A reboot usually clears this.");
  canvas.setTextColor(CL_YELLOW, CL_BLACK);
  canvas.setCursor(6, 102); canvas.print("ENTER / y = reboot now");
  canvas.setCursor(6, 112); canvas.print("`  /  n = keep running");
  footer("ENTER reboot   ` cancel");
}

void App::keyNetReboot(char c, bool enter, bool back) {
  if (enter || c == 'y') {
    setStatus("Rebooting..."); draw(); delay(300);
    ESP.restart();
    return;
  }
  if (isBack(c, back) || c == 'n') {
    net.failedResets = 0;                    // user declined; reset the reboot counter
    screen = netRebootReturn; lastDrawMs = 0;
  }
}

// ===================== QSO logging =========================================
static const char* bandFor(double mhz) {            // ADIF 3.1.7 Band enumeration
  if (mhz >= 28    && mhz <= 29.7)  return "10m";
  if (mhz >= 50    && mhz <= 54)    return "6m";
  if (mhz >= 144   && mhz <= 148)   return "2m";
  if (mhz >= 222   && mhz <= 225)   return "1.25m";
  if (mhz >= 420   && mhz <= 450)   return "70cm";
  if (mhz >= 902   && mhz <= 928)   return "33cm";
  if (mhz >= 1240  && mhz <= 1300)  return "23cm";
  if (mhz >= 2300  && mhz <= 2450)  return "13cm";
  if (mhz >= 3300  && mhz <= 3500)  return "9cm";
  if (mhz >= 5650  && mhz <= 5925)  return "6cm";
  if (mhz >= 10000 && mhz <= 10500) return "3cm";
  return "";
}
static void adifField(String& out, const char* name, const String& val) {
  if (!val.length()) return;
  out += "<"; out += name; out += ":"; out += String(val.length()); out += ">";
  out += val; out += " ";
}

static void writeQsoCsv(File& f, const PendingQso& q) {
  auto cl = [](const char* s) {
    String o = s; o.replace(",", " "); o.replace("\n", " "); o.replace("\r", " ");
    return o;
  };
  String notes = q.notes; notes.replace("\n", " "); notes.replace("\r", " ");
  f.printf("%lu,%s,%s,%s,%lu,%lu,%s,%s,%s,%s,%s,%s,%u\n",
           (unsigned long)q.utc, cl(q.call).c_str(), cl(q.sat).c_str(),
           cl(q.mode).c_str(), (unsigned long)q.dlHz, (unsigned long)q.ulHz,
           cl(q.rstS).c_str(), cl(q.rstR).c_str(), cl(q.myGrid).c_str(),
           cl(q.grid).c_str(), cl(q.myCall).c_str(), notes.c_str(),
           (unsigned)(q.uploaded & 0x3));   // bit0=LoTW, bit1=Cloudlog (persist BOTH)
}

static bool parseQsoCsv(const String& line, PendingQso& q) {
  String f[13]; int n = 0, start = 0;
  for (int i = 0; i < (int)line.length() && n < 12; ++i)
    if (line[i] == ',') { f[n++] = line.substring(start, i); start = i + 1; }
  f[n++] = line.substring(start);
  if (n < 11) return false;
  memset(&q, 0, sizeof(q));
  q.utc = strtoul(f[0].c_str(), nullptr, 10);
  strncpy(q.call,   f[1].c_str(),  sizeof(q.call)-1);
  strncpy(q.sat,    f[2].c_str(),  sizeof(q.sat)-1);
  strncpy(q.mode,   f[3].c_str(),  sizeof(q.mode)-1);
  q.dlHz = strtoul(f[4].c_str(), nullptr, 10);
  q.ulHz = strtoul(f[5].c_str(), nullptr, 10);
  strncpy(q.rstS,   f[6].c_str(),  sizeof(q.rstS)-1);
  strncpy(q.rstR,   f[7].c_str(),  sizeof(q.rstR)-1);
  strncpy(q.myGrid, f[8].c_str(),  sizeof(q.myGrid)-1);
  strncpy(q.grid,   f[9].c_str(),  sizeof(q.grid)-1);
  if (n >= 12) {                                   // new schema: mycall before notes
    strncpy(q.myCall, f[10].c_str(), sizeof(q.myCall)-1);
    strncpy(q.notes,  f[11].c_str(), sizeof(q.notes)-1);
  } else {                                         // legacy schema: no mycall column
    strncpy(q.notes,  f[10].c_str(), sizeof(q.notes)-1);
  }
  if (n >= 13) q.uploaded = (uint8_t)(strtoul(f[12].c_str(), nullptr, 10) & 0x3);  // bit0=LoTW, bit1=Cloudlog
  return true;
}

// Fill qso.sat / qso.mode and the *non-Doppler* default frequencies (the centre
// of a linear transponder's passband, or the nominal downlink/uplink for an FM /
// single-channel bird) from the currently active satellite + transponder. Used
// for manual log entries; leaves dl/ul at 0 if the sat has no transponders.
void App::seedQsoSatDefaults() {
  SatEntry* s = activeSat();
  if (!s) return;
  strncpy(qso.sat, s->name, sizeof(qso.sat) - 1); qso.sat[sizeof(qso.sat) - 1] = 0;
  if (activeTxCount > 0) {
    Transponder& t = activeTx[curTx];
    strncpy(qso.mode, t.isLinear ? "SSB" : (t.mode[0] ? t.mode : "FM"),
            sizeof(qso.mode) - 1); qso.mode[sizeof(qso.mode) - 1] = 0;
    int32_t off = (t.isLinear && t.bandwidth() > 0) ? (int32_t)(t.bandwidth() / 2) : 0;
    uint32_t dl, ul; Predictor::passbandFreqs(t, off, dl, ul);
    qso.dlHz = dl; qso.ulHz = ul;
  }
}

// Snapshot the auto fields (time, my grid/call) and open the entry screen. When
// invoked while actively working a pass (from the Track/Polar screen, clock set),
// the frequencies are the live Doppler-corrected values. Otherwise -- e.g. "New
// QSO entry" from the Log menu -- the satellite, frequencies, time and date all
// start as editable defaults (non-Doppler centre/nominal), so a QSO can be logged
// after the fact. Radio control, if engaged, keeps running.
void App::beginQso() {
  logReturn = screen;
  bool live = (screen == SCR_TRACK || screen == SCR_BIG || screen == SCR_POLAR || screen == SCR_MANUAL || screen == SCR_MANUALBIG);
  memset(&qso, 0, sizeof(qso));
  strncpy(qso.rstS, "59", sizeof(qso.rstS) - 1);
  strncpy(qso.rstR, "59", sizeof(qso.rstR) - 1);
  qso.utc = timeIsSet() ? (uint32_t)nowUtc() : 0;
  String mg = loc.toGrid(loc.obs().lat, loc.obs().lon);
  strncpy(qso.myGrid, mg.c_str(), sizeof(qso.myGrid) - 1);
  strncpy(qso.myCall, cfg.myCall, sizeof(qso.myCall) - 1);
  SatEntry* s = activeSat();
  if (s && live && activeTxCount > 0 && timeIsSet()) {
    strncpy(qso.sat, s->name, sizeof(qso.sat) - 1);
    Transponder& t = activeTx[curTx];
    strncpy(qso.mode, t.isLinear ? "SSB" : (t.mode[0] ? t.mode : "FM"),
            sizeof(qso.mode) - 1);
    pred.setSite(loc.obs()); pred.setSat(*s);
    LiveLook L = pred.look(nowUtc());
    struct timeval tv; gettimeofday(&tv, nullptr);
    L.rangeRate = pred.rangeRateAt((double)tv.tv_sec + tv.tv_usec * 1e-6);
    uint32_t dlOp, ulOp, rx, tx;
    Predictor::passbandFreqs(t, pbOffset, dlOp, ulOp);
    Predictor::dopplerFreqs(dlOp, ulOp, L.rangeRate, calDl, calUl, rx, tx);
    qso.dlHz = rx; qso.ulHz = tx;
  } else if (activeTxCount > 0) {
    seedQsoSatDefaults();          // pre-fill from the selected sat (non-Doppler)
  }
  // Entering from a live tracking screen (the common "work a station now" case):
  // pre-select the Call field so a callsign can be typed immediately. Field index 5
  // is "Call" in drawLogEntry's label/value arrays. Other entry points (e.g. the log
  // menu) start at the top (Date) as before.
  logSel = live ? 5 : 0;
  logEditIdx = -1;
  screen = SCR_LOGENTRY;
}

bool App::saveQso() {
  bool isNew = !Store::fs().exists(FILE_LOG);
  File f = Store::fs().open(FILE_LOG, "a");
  if (!f) return false;
  if (isNew) f.print("utc,call,sat,mode,dl,ul,rsts,rstr,mygrid,grid,mycall,notes\n");
  writeQsoCsv(f, qso);
  f.close();
  return true;
}

// One-key QSO capture: called when a voice memo starts from an operating screen.
// Appends a log stub -- time, my call/grid, satellite, mode, the live frequencies,
// callsign left blank, and a note naming the memo file -- so the contact can be
// finished after LOS instead of typed mid-pass. Uses a snapshot so an in-progress
// Log-entry edit is never clobbered. Delete unwanted stubs from Log > list (x x).
void App::logCreateStub(const char* memoPath) {
  if (!timeIsSet()) return;                       // a stub without a timestamp helps nobody
  PendingQso saved = qso;
  memset(&qso, 0, sizeof(qso));
  strncpy(qso.rstS, "59", sizeof(qso.rstS) - 1);
  strncpy(qso.rstR, "59", sizeof(qso.rstR) - 1);
  qso.utc = (uint32_t)nowUtc();
  String mg = loc.toGrid(loc.obs().lat, loc.obs().lon);
  strncpy(qso.myGrid, mg.c_str(), sizeof(qso.myGrid) - 1);
  strncpy(qso.myCall, cfg.myCall, sizeof(qso.myCall) - 1);
  seedQsoSatDefaults();                            // sat + mode + freqs, if a sat is active
  String note = "voice memo";
  if (memoPath && memoPath[0]) {
    const char* b = strrchr(memoPath, '/');
    note += String(" ") + (b ? b + 1 : memoPath);
  }
  strncpy(qso.notes, note.c_str(), sizeof(qso.notes) - 1);
  saveQso();
  qso = saved;
}


int App::qsoCount() {
  if (!Store::fs().exists(FILE_LOG)) return 0;
  File f = Store::fs().open(FILE_LOG, "r");
  if (!f) return 0;
  int n = 0;
  while (f.available()) {
    String l = f.readStringUntil('\n'); l.trim();
    if (l.length() && !l.startsWith("utc,")) n++;
  }
  f.close();
  return n;
}

// -- LoTW SAT_NAME mapping ---------------------------------------------------
// LoTW limits SAT_NAME to 6 chars and uses its own names, so CardSat's (AMSAT)
// satellite name often needs translating. The external /CardSat/lotw_sats.csv
// ("SAT_NAME,AMSAT_NAME" rows) is consulted first so it can be updated without
// reflashing; then this built-in table of the non-identity cases.
static const struct { const char* amsat; const char* lotw; } LOTW_SATS[] = {
  {"AO-07","AO-7"}, {"ISS","ARISS"}, {"LILACSAT-2","CAS-3H"},
  {"SONATE-2","SONATE"}, {"Taurus 1","TAURUS"},
  {"TEVEL2-1","TEV2-1"}, {"TEVEL2-2","TEV2-2"}, {"TEVEL2-3","TEV2-3"},
  {"TEVEL2-4","TEV2-4"}, {"TEVEL2-5","TEV2-5"}, {"TEVEL2-6","TEV2-6"},
  {"TEVEL2-7","TEV2-7"}, {"TEVEL2-8","TEV2-8"}, {"TEVEL2-9","TEV2-9"},
};
static const int LOTW_SATS_N = sizeof(LOTW_SATS) / sizeof(LOTW_SATS[0]);

// Resolve to a LoTW SAT_NAME. Returns 0 if resolved (a mapping was found, or the
// name already fits in 6 chars), or 1 if there is no mapping and the name is too
// long to use as-is (caller should prompt). 'out' always gets a usable value.
static int lotwSatResolve(const char* amsat, char out[7]) {
  File f = Store::fs().open(FILE_LOTW, "r");
  if (f) {
    while (f.available()) {
      String line = f.readStringUntil('\n'); line.trim();
      if (!line.length() || line.startsWith("SAT_NAME")) continue;
      int comma = line.indexOf(',');
      if (comma < 0) continue;
      String sn = line.substring(0, comma);     sn.trim();
      String an = line.substring(comma + 1);     an.trim();
      if (an.equalsIgnoreCase(amsat)) {
        strncpy(out, sn.c_str(), 6); out[6] = 0;
        f.close(); return 0;
      }
    }
    f.close();
  }
  for (int i = 0; i < LOTW_SATS_N; ++i)
    if (!strcasecmp(LOTW_SATS[i].amsat, amsat)) {
      strncpy(out, LOTW_SATS[i].lotw, 6); out[6] = 0; return 0;
    }
  strncpy(out, amsat, 6); out[6] = 0;
  return (strlen(amsat) > 6) ? 1 : 0;
}

// Non-static wrapper so lotw.cpp can reuse the same sat-name mapping the ADIF
// export uses (keeps the .tq8 and the exported ADIF in agreement).
int lotwSatResolveExt(const char* amsat, char out[7]) {
  return lotwSatResolve(amsat, out);
}

void App::promptNextLotw() {
  editTarget = 600;
  editTitle  = String("LoTW name: ") + exportSats[exportPendIdx];
  editBuf    = "";
  screen     = SCR_EDIT;
}

// Export entry point from the Log menu: find any logged satellites whose LoTW
// SAT_NAME can't be resolved automatically and prompt for each (persisting the
// answer to lotw_sats.csv), then write the ADIF.
void App::beginAdifExport() {
  exportPendN = 0; exportPendIdx = 0;
  String seen[24]; int seenN = 0;
  File f = Store::fs().open(FILE_LOG, "r");
  if (f) {
    while (f.available()) {
      String line = f.readStringUntil('\n');
      while (line.length() && (line[line.length()-1]=='\r' || line[line.length()-1]=='\n'))
        line.remove(line.length()-1);
      if (!line.length() || line.startsWith("utc,")) continue;
      PendingQso q;
      if (!parseQsoCsv(line, q) || !q.sat[0]) continue;
      bool dup = false;
      for (int i = 0; i < seenN; ++i) if (seen[i].equalsIgnoreCase(q.sat)) { dup = true; break; }
      if (dup) continue;
      if (seenN < 24) seen[seenN++] = q.sat;
      char nm[7];
      if (lotwSatResolve(q.sat, nm) && exportPendN < 16)   // 1 => needs a prompt
        exportSats[exportPendN++] = q.sat;
    }
    f.close();
  }
  if (exportPendN == 0) {
    bool ok = exportAdif();
    setStatus(ok ? "Exported qso_log.adi" : "No log to export");
    return;
  }
  promptNextLotw();
}

bool App::exportAdif() {
  File in = Store::fs().open(FILE_LOG, "r");
  if (!in) return false;
  File out = Store::fs().open(FILE_ADIF, "w");
  if (!out) { in.close(); return false; }
  out.print("CardSat ADIF export\n");
  out.print("<ADIF_VER:5>3.1.7 <PROGRAMID:7>CardSat ");
  { String ver = FW_VERSION;                          // <PROGRAMVERSION:len>value
    out.print("<PROGRAMVERSION:"); out.print(ver.length()); out.print(">");
    out.print(ver); out.print(" "); }
  if (timeIsSet()) {                                  // <CREATED_TIMESTAMP:15>YYYYMMDD HHMMSS
    time_t now = time(nullptr); struct tm* g = gmtime(&now);
    char ts[16]; strftime(ts, sizeof(ts), "%Y%m%d %H%M%S", g);
    out.print("<CREATED_TIMESTAMP:15>"); out.print(ts); out.print(" ");
  }
  out.print("<EOH>\n");
  while (in.available()) {
    String line = in.readStringUntil('\n');
    while (line.length() && (line[line.length()-1] == '\r' ||
                             line[line.length()-1] == '\n'))
      line.remove(line.length() - 1);
    if (!line.length() || line.startsWith("utc,")) continue;
    PendingQso q;
    if (!parseQsoCsv(line, q)) continue;
    time_t tt = (time_t)q.utc; struct tm* g = gmtime(&tt);
    char d[9] = "", tm6[7] = "";
    if (g) { strftime(d, sizeof(d), "%Y%m%d", g); strftime(tm6, sizeof(tm6), "%H%M%S", g); }
    double dlM = q.dlHz / 1e6, ulM = q.ulHz / 1e6;
    String rec;
    adifField(rec, "CALL", q.call);
    if (q.utc) { adifField(rec, "QSO_DATE", String(d)); adifField(rec, "TIME_ON", String(tm6)); }
    adifField(rec, "MODE", q.mode);
    char satnm[7]; lotwSatResolve(q.sat, satnm);
    adifField(rec, "SAT_NAME", satnm);
    adifField(rec, "PROP_MODE", "SAT");
    if (ulM > 0) { adifField(rec, "FREQ", String(ulM, 4)); adifField(rec, "BAND", bandFor(ulM)); }
    if (dlM > 0) { adifField(rec, "FREQ_RX", String(dlM, 4)); adifField(rec, "BAND_RX", bandFor(dlM)); }
    adifField(rec, "RST_SENT", q.rstS);
    adifField(rec, "RST_RCVD", q.rstR);
    adifField(rec, "GRIDSQUARE", q.grid);
    adifField(rec, "MY_GRIDSQUARE", q.myGrid);
    adifField(rec, "STATION_CALLSIGN", q.myCall);
    adifField(rec, "COMMENT", q.notes);
    rec += "<EOR>\n";
    out.print(rec);
  }
  in.close(); out.close();
  return true;
}

void App::drawLog() {
  header("Log");
  canvas.setTextSize(1);
  // Core logging functions first; the non-core Voice Memos / Notes tools at the bottom.
  // Cloudlog sits next to LoTW as the two upload options (uploading to Cloudlog can feed
  // LoTW, so they're alternatives). The list scrolls since it no longer fits at once.
  const char* items[] = { "New QSO entry", "View / edit log", "Export to ADIF",
                          "Sign & upload to LoTW", "Upload to Cloudlog",
                          "Voice Memos", "Notes", "Awards", "Fill grids (QRZ)" };
  const int N = 9;
  const int VIS = 6;                              // rows visible at once (leaves room
                                                  // for the count line + footer)
  int top = 0;
  if (logMenuSel >= VIS) top = logMenuSel - VIS + 1;
  if (top > N - VIS) top = N - VIS;
  if (top < 0) top = 0;
  for (int v = 0; v < VIS && top + v < N; ++v) {
    int i = top + v;
    int y = 22 + v*14;
    if (i == logMenuSel) { canvas.fillRect(0, y-2, 240, 13, CL_SELBG);
                           canvas.setTextColor(CL_BLACK, CL_SELBG); }
    else                   canvas.setTextColor(CL_WHITE, CL_BLACK);
    canvas.setCursor(6, y); canvas.print(items[i]);
  }
  // Scroll hint arrows when there's content above/below the window.
  canvas.setTextColor(CL_GREY, CL_BLACK);
  if (top > 0)            { canvas.setCursor(230, 22); canvas.print("^"); }
  if (top + VIS < N)      { canvas.setCursor(230, 22 + (VIS-1)*14); canvas.print("v"); }
  canvas.setCursor(6, 22 + VIS*14 + 2);
  canvas.printf("%d logged  (qso_log.csv)", qsoCount());
  footer("; / . move  ENT  ` back");
}

void App::keyLog(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_HOME; return; }
  const int N = 9;
  if (isUp(c))   logMenuSel = (logMenuSel + N - 1) % N;
  if (isDown(c)) logMenuSel = (logMenuSel + 1) % N;
  if (enter) {
    if (logMenuSel == 0) beginQso();
    else if (logMenuSel == 1) { loadLog(); screen = SCR_LOGLIST; }
    else if (logMenuSel == 2) beginAdifExport();
    else if (logMenuSel == 3) { lotwReturn = SCR_LOG; lotwEnter(); }
    else if (logMenuSel == 4) { cloudlogEnter(); }
    else if (logMenuSel == 5) { buildMemoList(); memoSel = 0; memoScroll = 0; memoConfirmDel = false;
           screen = SCR_MEMOS; lastDrawMs = 0; }
    else if (logMenuSel == 6) { notesEnter(); }
    else if (logMenuSel == 7) { setStatus("Scanning log..."); draw(); buildAwards();
           status = ""; screen = SCR_AWARDS; lastDrawMs = 0; }   // Awards (clear the scan banner)
    else if (logMenuSel == 8) { fillGridsQrz(); }
  }
}

// ===================== LoTW upload screen ==================================
// Counts the un-uploaded QSOs and opens the LoTW screen. Sat QSOs only (CardSat
// logs are all satellite QSOs; PROP_MODE=SAT is emitted for every record).
void App::lotwEnter() {
  lotwBusy = false; lotwLastSent = 0; lotwStatus = "";
  lotwPending = 0; lotwTotal = 0;
  if (Store::fs().exists(FILE_LOG)) {
    File f = Store::fs().open(FILE_LOG, "r");
    if (f) {
      while (f.available()) {
        String l = f.readStringUntil('\n'); l.trim();
        if (!l.length() || l.startsWith("utc,")) continue;
        PendingQso q;
        if (parseQsoCsv(l, q) && q.call[0]) {
          lotwTotal++;
          if (!(q.uploaded & 1)) lotwPending++;
        }
      }
      f.close();
    }
  }
  screen = SCR_LOTW; lastDrawMs = 0;
}

void App::drawLotw() {
  header("LoTW upload");
  canvas.setTextSize(1);
  canvas.setTextColor(CL_WHITE, CL_BLACK);
  int y = 20;
  bool haveCred = Lotw::credentialPresent();
  bool haveCard = Store::ready();

  canvas.setCursor(6, y); y += 12;
  canvas.printf("SD card: %s", haveCard ? "yes" : "NO (required)");
  canvas.setCursor(6, y); y += 12;
  canvas.printf("Key+cert: %s", haveCred ? "found" : "not on SD");
  canvas.setCursor(6, y); y += 12;
  canvas.printf("Station: DXCC %s CQ %s ITU %s",
                cfg.lotwDxcc[0] ? cfg.lotwDxcc : "-",
                cfg.lotwCqz[0]  ? cfg.lotwCqz  : "-",
                cfg.lotwItuz[0] ? cfg.lotwItuz : "-");
  canvas.setCursor(6, y); y += 14;
  int toSend = lotwResend ? lotwTotal : lotwPending;
  if (lotwResend)
    canvas.printf("Re-send ALL QSOs: %d", lotwTotal);
  else
    canvas.printf("Un-uploaded QSOs: %d", lotwPending);

  canvas.setTextColor(CL_GREY, CL_BLACK);
  if (lotwStatus.length()) {
    canvas.setCursor(6, y); y += 12;
    // clip to the screen width
    String s = lotwStatus; if (s.length() > 38) s = s.substring(0, 38);
    canvas.print(s);
  }

  if (lotwRebootPrompt) footer("ENT reboot + upload   ` cancel");
  else if (!haveCard)        footer("` back   (insert SD card)");
  else if (!haveCred)   footer("` back   (no LoTW key on SD)");
  else if (toSend)      footer(lotwResend ? "u upload ALL  a un-uploaded only  ` back"
                                          : "u sign & upload  a re-send all  ` back");
  else if (lotwTotal)   footer("a re-send all   ` back");
  else                  footer("` back   (nothing to upload)");
}

void App::keyLotw(char c, bool enter, bool back) {
  // Answer the reboot-and-upload prompt (after a -1 connect): ENTER confirms, ` cancels.
  if (lotwRebootPrompt) {
    if (enter) { lotwRebootPrompt = false; lotwRebootUpload(); return; }
    if (isBack(c, back)) {
      lotwRebootPrompt = false;
      lotwStatus = "Upload cancelled - QSOs still pending";
      lastDrawMs = 0; draw(); return;
    }
    return;   // ignore other keys while the prompt is up
  }
  if (isBack(c, back)) { screen = lotwReturn; lastDrawMs = 0; return; }
  if (lotwBusy) return;
  // 'a' toggles re-send mode: include QSOs already marked uploaded. Useful when a
  // previous upload didn't actually post (e.g. a format LoTW didn't accept) and the
  // QSOs need to be sent again. Only meaningful if there are any QSOs at all.
  if (c == 'a' && lotwTotal > 0) {
    lotwResend = !lotwResend; lotwStatus = ""; lastDrawMs = 0; return;
  }
  int toSend = lotwResend ? lotwTotal : lotwPending;
  if (c == 'u' && Store::ready() && Lotw::credentialPresent() && toSend > 0) {
    // Fresh user-initiated upload: clear any stale batch state so a new run starts clean
    // (the resend cursor especially must begin at 0).
    scrubLotwBatchState();
    // Prompt for the key password (blank if the key is unencrypted).
    editTarget = 230; editTitle = "Key password (blank=none)";
    editBuf = ""; screen = SCR_EDIT; lastDrawMs = 0; return;
  }
}

// ---- Unified LoTW location picker (DXCC -> primary -> secondary) -----------------
// LoTW's station location is a dependency chain: DXCC entity gates the primary
// subdivision (state/province/oblast/prefecture/...), which (for the US and Japan)
// gates a secondary (county / city-gun-ku). One context-aware picker handles all
// three levels, driven by lotwPickKind, reading the flash tables in lotw_subdiv.h.

// Friendly label for a LoTW field name (for Settings rows / picker headers).
static String lotwFieldLabel(const char* field) {
  if (!field || !field[0]) return "subdivision";
  if (!strcmp(field, "US_STATE"))      return "state";
  if (!strcmp(field, "CA_PROVINCE"))   return "province";
  if (!strcmp(field, "RU_OBLAST"))     return "oblast";
  if (!strcmp(field, "JA_PREFECTURE")) return "prefecture";
  if (!strcmp(field, "CN_PROVINCE"))   return "province";
  if (!strcmp(field, "AU_STATE"))      return "state";
  if (!strcmp(field, "FI_KUNTA"))      return "kunta";
  if (!strcmp(field, "US_COUNTY"))     return "county";
  if (!strcmp(field, "JA_CITY_GUN_KU"))return "city/gun/ku";
  return "subdivision";
}

// Look up a DXCC entity row in DXCC_LIST by its number. Returns nullptr if not found.
static const DxccEntry* lotwFindDxcc(const char* dxcc) {
  if (!dxcc || !dxcc[0]) return nullptr;
  int d = atoi(dxcc);
  for (int i = 0; i < DXCC_LIST_N; i++)
    if (DXCC_LIST[i].id == d) return &DXCC_LIST[i];
  return nullptr;
}

// Map a primary FIELD NAME to its choice table (the per-entity primary list).
static const SubdivEntry* lotwPrimaryTable(const char* field, int* n) {
  *n = 0;
  if (!field || !field[0]) return nullptr;
  if (!strcmp(field, "US_STATE"))      { *n = SUB_US_STATE_N;      return SUB_US_STATE; }
  if (!strcmp(field, "CA_PROVINCE"))   { *n = SUB_CA_PROVINCE_N;   return SUB_CA_PROVINCE; }
  if (!strcmp(field, "RU_OBLAST"))     { *n = SUB_RU_OBLAST_N;     return SUB_RU_OBLAST; }
  if (!strcmp(field, "JA_PREFECTURE")) { *n = SUB_JA_PREFECTURE_N; return SUB_JA_PREFECTURE; }
  if (!strcmp(field, "CN_PROVINCE"))   { *n = SUB_CN_PROVINCE_N;   return SUB_CN_PROVINCE; }
  if (!strcmp(field, "AU_STATE"))      { *n = SUB_AU_STATE_N;      return SUB_AU_STATE; }
  if (!strcmp(field, "FI_KUNTA"))      { *n = SUB_FI_KUNTA_N;      return SUB_FI_KUNTA; }
  return nullptr;
}

const char* App::lotwPrimaryField(const char* dxcc, const SubdivEntry** list, int* n) {
  if (list) *list = nullptr;
  if (n) *n = 0;
  const DxccEntry* e = lotwFindDxcc(dxcc);
  if (!e || !e->primaryField[0]) return "";
  int cnt = 0; const SubdivEntry* tbl = lotwPrimaryTable(e->primaryField, &cnt);
  if (list) *list = tbl;
  if (n) *n = cnt;
  return e->primaryField;
}

const char* App::lotwSecondaryField(const char* dxcc, const char* primaryCode,
                                    const SubdivEntry** list, int* n) {
  if (list) *list = nullptr;
  if (n) *n = 0;
  const DxccEntry* e = lotwFindDxcc(dxcc);
  if (!e || !e->secondaryField[0]) return "";
  if (!primaryCode || !primaryCode[0]) return e->secondaryField;  // field exists but no list yet
  if (!strcmp(e->secondaryField, "US_COUNTY")) {
    // county list gated by the 2-letter state code
    for (int i = 0; i < US_COUNTY_INDEX_N; i++)
      if (!strcasecmp(US_COUNTY_INDEX[i].state, primaryCode)) {
        if (list) *list = US_COUNTY_INDEX[i].list;
        if (n) *n = US_COUNTY_INDEX[i].n;
        break;
      }
  } else if (!strcmp(e->secondaryField, "JA_CITY_GUN_KU")) {
    // city list gated by the 2-digit prefecture code
    for (int i = 0; i < JA_CITY_INDEX_N; i++)
      if (!strcmp(JA_CITY_INDEX[i].pref, primaryCode)) {
        if (list) *list = JA_CITY_INDEX[i].list;
        if (n) *n = JA_CITY_INDEX[i].n;
        break;
      }
  }
  return e->secondaryField;
}

// ---- typeahead filter over the active list ----
bool App::lotwRowMatches(const char* code, const char* name) {
  if (lotwPickFilter.length() == 0) return true;
  String f = lotwPickFilter; f.toLowerCase();
  String c = code ? String(code) : ""; c.toLowerCase();
  String nm = name ? String(name) : ""; nm.toLowerCase();
  return c.indexOf(f) >= 0 || nm.indexOf(f) >= 0;
}

// Number of rows in the active context that pass the filter.
int App::lotwFilteredCount() {
  if (lotwPickKind == LP_DXCC) {
    int k = 0;
    for (int i = 0; i < DXCC_LIST_N; i++)
      if (lotwRowMatches(nullptr, DXCC_LIST[i].name)) k++;
    return k;
  }
  if (!lotwSubList) return 0;
  int k = 0;
  for (int i = 0; i < lotwSubN; i++)
    if (lotwRowMatches(lotwSubList[i].code, lotwSubList[i].name)) k++;
  return k;
}

// Underlying table index of the Nth filtered row (-1 if out of range).
int App::lotwFilteredIndex(int pos) {
  int k = 0;
  if (lotwPickKind == LP_DXCC) {
    for (int i = 0; i < DXCC_LIST_N; i++)
      if (lotwRowMatches(nullptr, DXCC_LIST[i].name)) { if (k == pos) return i; k++; }
    return -1;
  }
  if (!lotwSubList) return -1;
  for (int i = 0; i < lotwSubN; i++)
    if (lotwRowMatches(lotwSubList[i].code, lotwSubList[i].name)) { if (k == pos) return i; k++; }
  return -1;
}

void App::lotwPickEnter(LotwPick kind) {
  lotwPickKind = kind;
  lotwPickFilter = "";
  lotwSubList = nullptr; lotwSubN = 0;
  lotwSubSel = 0; lotwSubScroll = 0;
  const char* curCode = "";
  if (kind == LP_DXCC) {
    lotwSubFieldName = "DXCC entity";
    curCode = cfg.lotwDxcc;   // (numeric; preselect handled below by id match)
  } else if (kind == LP_PRIMARY) {
    const SubdivEntry* list = nullptr; int n = 0;
    const char* fld = lotwPrimaryField(cfg.lotwDxcc, &list, &n);
    lotwSubList = list; lotwSubN = n;
    lotwSubFieldName = fld[0] ? fld : "";
    // primary is stored in lotwState for US_STATE entities, else lotwSubdiv
    const DxccEntry* e = lotwFindDxcc(cfg.lotwDxcc);
    bool usState = e && !strcmp(e->primaryField, "US_STATE");
    curCode = usState ? cfg.lotwState : cfg.lotwSubdiv;
  } else { // LP_SECONDARY
    const DxccEntry* e = lotwFindDxcc(cfg.lotwDxcc);
    bool usState = e && e->primaryField[0] && !strcmp(e->primaryField, "US_STATE");
    const char* primaryCode = usState ? cfg.lotwState : cfg.lotwSubdiv;
    const SubdivEntry* list = nullptr; int n = 0;
    const char* fld = lotwSecondaryField(cfg.lotwDxcc, primaryCode, &list, &n);
    lotwSubList = list; lotwSubN = n;
    lotwSubFieldName = fld[0] ? fld : "";
    bool usCounty = e && !strcmp(e->secondaryField, "US_COUNTY");
    curCode = usCounty ? cfg.lotwCnty : cfg.lotwSubdiv2;
  }
  // Preselect the currently-stored value within the (unfiltered) list.
  if (kind == LP_DXCC) {
    int d = atoi(cfg.lotwDxcc);
    for (int i = 0; i < DXCC_LIST_N; i++)
      if (DXCC_LIST[i].id == d) { lotwSubSel = i; break; }
  } else if (lotwSubList && curCode && curCode[0]) {
    for (int i = 0; i < lotwSubN; i++)
      if (!strcasecmp(lotwSubList[i].code, curCode)) { lotwSubSel = i; break; }
  }
  screen = SCR_LOTWSUB; lastDrawMs = 0;
}

void App::drawLotwSub() {
  // Title reflects the context.
  const char* title = (lotwPickKind == LP_DXCC) ? "LoTW DXCC"
                    : (lotwPickKind == LP_PRIMARY) ? "LoTW primary"
                    : "LoTW secondary";
  header(title);
  canvas.setTextSize(1);

  // For primary/secondary: if there's no list, the entity simply has no division here.
  if (lotwPickKind != LP_DXCC && (lotwSubN == 0 || lotwSubList == nullptr)) {
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(6, 40);
    if (!cfg.lotwDxcc[0]) canvas.print("Set LoTW DXCC first.");
    else if (lotwPickKind == LP_SECONDARY && lotwSubFieldName.length() == 0)
                          canvas.print("No secondary division here.");
    else if (lotwPickKind == LP_SECONDARY)
                          canvas.print("Pick the primary first.");
    else                  canvas.print("No subdivision for this entity.");
    canvas.setCursor(6, 56);
    canvas.print("LoTW needs none - leave blank.");
    footer("` back");
    return;
  }

  int total = lotwFilteredCount();
  // Header line: field/context label + filter echo + position.
  canvas.setTextColor(CL_CYAN, CL_BLACK);
  canvas.setCursor(6, 16);
  { String h = lotwSubFieldName.length() ? lotwSubFieldName
                                         : (lotwPickKind == LP_DXCC ? String("entity") : String());
    if (lotwPickFilter.length()) h += " /" + lotwPickFilter;
    if (h.length() > 30) h = h.substring(0, 30);
    canvas.print(h); }
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(196, 16);
  canvas.printf("%d/%d", total ? lotwSubSel + 1 : 0, total);

  const int ROWS = 7;
  if (lotwSubSel >= total) lotwSubSel = total > 0 ? total - 1 : 0;
  if (lotwSubSel < lotwSubScroll) lotwSubScroll = lotwSubSel;
  if (lotwSubSel >= lotwSubScroll + ROWS) lotwSubScroll = lotwSubSel - ROWS + 1;

  for (int i = 0; i < ROWS && lotwSubScroll + i < total; ++i) {
    int filteredPos = lotwSubScroll + i;
    int idx = lotwFilteredIndex(filteredPos);
    if (idx < 0) continue;
    int y = 30 + i*13;
    bool sel = (filteredPos == lotwSubSel);
    if (sel) { canvas.fillRect(0, y-2, 240, 12, CL_SELBG);
               canvas.setTextColor(CL_BLACK, CL_SELBG); }
    else       canvas.setTextColor(CL_WHITE, CL_BLACK);
    canvas.setCursor(4, y);
    if (lotwPickKind == LP_DXCC) {
      const DxccEntry& e = DXCC_LIST[idx];
      // Mark entities that have a subdivision with a '>' so users see which gate further.
      char tag = e.primaryField[0] ? '>' : ' ';
      canvas.printf("%c%-34.34s", tag, e.name);
    } else {
      const SubdivEntry& e = lotwSubList[idx];
      canvas.printf("%-5.5s %-29.29s", e.code, e.name);
    }
  }
  footer("type=filter  ;/. move  ENT pick  ` back");
}

void App::keyLotwSub(char c, bool enter, bool back) {
  if (isBack(c, back)) {
    // Back-out: if a filter is active, the first ` clears it instead of leaving.
    if (lotwPickFilter.length()) { lotwPickFilter = ""; lotwSubSel = 0; lotwSubScroll = 0; lastDrawMs = 0; return; }
    screen = SCR_SETTINGS; lastDrawMs = 0; return;
  }
  int total = lotwFilteredCount();
  if (isUp(c))   { if (total) lotwSubSel = (lotwSubSel + total - 1) % total; lastDrawMs = 0; return; }
  if (isDown(c)) { if (total) lotwSubSel = (lotwSubSel + 1) % total; lastDrawMs = 0; return; }
  // Backspace edits the typeahead filter.
  if (c == 8 || c == 127) {
    if (lotwPickFilter.length()) { lotwPickFilter.remove(lotwPickFilter.length()-1);
                                   lotwSubSel = 0; lotwSubScroll = 0; lastDrawMs = 0; }
    return;
  }
  // Printable -> extend the filter (letters/digits/space match names and codes).
  if (c >= 32 && c < 127 && !enter) {
    if (lotwPickFilter.length() < 24) { lotwPickFilter += c; lotwSubSel = 0; lotwSubScroll = 0; lastDrawMs = 0; }
    return;
  }
  if (enter) {
    if (total == 0) return;
    int idx = lotwFilteredIndex(lotwSubSel);
    if (idx < 0) return;
    if (lotwPickKind == LP_DXCC) {
      const DxccEntry& e = DXCC_LIST[idx];
      char buf[8]; snprintf(buf, sizeof(buf), "%d", e.id);
      // Changing DXCC invalidates any previously-chosen subdivisions.
      if (strcmp(cfg.lotwDxcc, buf) != 0) {
        cfg.lotwState[0] = 0; cfg.lotwCnty[0] = 0;
        cfg.lotwSubdiv[0] = 0; cfg.lotwSubdiv2[0] = 0;
      }
      strncpy(cfg.lotwDxcc, buf, sizeof(cfg.lotwDxcc)-1); cfg.lotwDxcc[sizeof(cfg.lotwDxcc)-1] = 0;
      cfg.save();
      setStatus(String("DXCC ") + buf);
      screen = SCR_SETTINGS; lastDrawMs = 0;
      return;
    }
    const SubdivEntry& e = lotwSubList[idx];
    const DxccEntry* ent = lotwFindDxcc(cfg.lotwDxcc);
    if (lotwPickKind == LP_PRIMARY) {
      bool usState = ent && !strcmp(ent->primaryField, "US_STATE");
      if (usState) { strncpy(cfg.lotwState, e.code, sizeof(cfg.lotwState)-1); cfg.lotwState[sizeof(cfg.lotwState)-1]=0; }
      else         { strncpy(cfg.lotwSubdiv, e.code, sizeof(cfg.lotwSubdiv)-1); cfg.lotwSubdiv[sizeof(cfg.lotwSubdiv)-1]=0; }
      // Changing the primary clears any stale secondary.
      cfg.lotwCnty[0] = 0; cfg.lotwSubdiv2[0] = 0;
    } else { // LP_SECONDARY
      bool usCounty = ent && !strcmp(ent->secondaryField, "US_COUNTY");
      if (usCounty) {
        // US county is stored as "ST,County" (the signing path expects that form).
        const char* st = cfg.lotwState[0] ? cfg.lotwState : "";
        String v = String(st) + "," + e.name;   // county VALUE is the name (e.code is numeric id)
        strncpy(cfg.lotwCnty, v.c_str(), sizeof(cfg.lotwCnty)-1); cfg.lotwCnty[sizeof(cfg.lotwCnty)-1]=0;
      } else {
        strncpy(cfg.lotwSubdiv2, e.code, sizeof(cfg.lotwSubdiv2)-1); cfg.lotwSubdiv2[sizeof(cfg.lotwSubdiv2)-1]=0;
      }
    }
    cfg.save();
    setStatus(String("Set ") + e.code);
    screen = SCR_SETTINGS; lastDrawMs = 0;
  }
}

// Build the .tq8 from all un-uploaded QSOs, POST it, and -- on an accepted
// upload -- mark those QSOs uploaded so they aren't sent again.
void App::doLotwUpload(const String& keyPass) {
  lotwBusy = true; lastDrawMs = 0;
  lotwStatus = "Collecting QSOs..."; draw();

  // Gather QSOs into a heap array. Normally only un-uploaded ones; in re-send mode
  // (user opted in) include QSOs already marked uploaded too. Capped to keep the
  // uncompressed .tq8 text (~600 B/QSO) within a safe heap budget on the no-PSRAM
  // S3; any remainder is sent on the next upload (un-uploaded ones stay un-flagged).
  // Cap this batch at a size-safe QSO count so the compressed .tq8 body stays under the
  // TCP_SND_BUF send ceiling. Any remaining un-uploaded QSOs are picked up by the next
  // batch (which runs in a fresh boot -- see the RTC batch state and continueLotwBatch).
  const int CAP = LOTW_BATCH_QSOS;
  PendingQso* batch = (PendingQso*)malloc(sizeof(PendingQso) * CAP);
  if (!batch) { lotwStatus = "Out of memory"; lotwBusy = false; return; }
  int n = 0;
  int skipRemaining = lotwResend ? (int)g_lotwResendSkip : 0;  // resend: skip already-sent batches
  if (Store::fs().exists(FILE_LOG)) {
    File f = Store::fs().open(FILE_LOG, "r");
    if (f) {
      while (f.available() && n < CAP) {
        String l = f.readStringUntil('\n'); l.trim();
        if (!l.length() || l.startsWith("utc,")) continue;
        PendingQso q;
        if (parseQsoCsv(l, q) && q.call[0] && (lotwResend || !(q.uploaded & 1))) {
          if (skipRemaining > 0) { skipRemaining--; continue; }  // already sent in an earlier batch
          batch[n++] = q;
        }
      }
      f.close();
    }
  }
  if (n == 0) { free(batch); lotwStatus = "Nothing to upload"; lotwBusy = false; return; }

  LotwStation st;
  st.call = cfg.myCall;
  st.dxcc = cfg.lotwDxcc;
  st.grid = loc.toGrid(loc.obs().lat, loc.obs().lon);
  st.cqz  = cfg.lotwCqz;
  st.ituz = cfg.lotwItuz;
  st.state = cfg.lotwState;
  st.cnty  = cfg.lotwCnty;
  // Resolve primary + secondary subdivisions for this DXCC from the unified tables.
  // The US path is unchanged: US_STATE entities keep using state/cnty above, so we only
  // set st.subdiv for NON-US primaries (province/oblast/prefecture/...). The secondary
  // (st.subdiv2) carries the JA city/gun/ku code; US county stays in st.cnty.
  { const DxccEntry* e = lotwFindDxcc(cfg.lotwDxcc);
    if (e && e->primaryField[0]) {
      bool usState = !strcmp(e->primaryField, "US_STATE");
      if (!usState && cfg.lotwSubdiv[0]) {
        st.subdiv = cfg.lotwSubdiv; st.subdivField = e->primaryField;
      }
      // Secondary: only JA_CITY_GUN_KU lives in lotwSubdiv2 (US county is in cnty).
      if (e->secondaryField[0] && !strcmp(e->secondaryField, "JA_CITY_GUN_KU")
          && cfg.lotwSubdiv2[0]) {
        st.subdiv2 = cfg.lotwSubdiv2; st.subdiv2Field = e->secondaryField;
      }
    }
  }
  st.iota = cfg.lotwIota;

  // Sign and stage the .tq8, then POST it. The gzip step uses stored (uncompressed)
  // framing so it needs no working memory, and the TLS upload fits the same
  // contiguous block the other HTTPS fetches use -- so the drawing sprite stays
  // resident throughout and the screen keeps updating normally.
  lotwStatus = "Signing " + String(n) + " QSOs..."; draw();
  Serial.printf("[lotw] signing %d QSOs (heap free %u, largest %u)\n",
                n, (unsigned)ESP.getFreeHeap(),
                (unsigned)heap_caps_get_largest_free_block(MALLOC_CAP_8BIT));

  String err; size_t gz = 0;
  bool built = Lotw::buildTq8(batch, n, st, keyPass, err, &gz);
  free(batch);
  if (!built) {
    lotwStatus = "Sign failed: " + err; lotwBusy = false; lastDrawMs = 0; return;
  }

  // POST the staged .tq8 to LoTW.
  lotwStatus = "Uploading (" + String((unsigned)gz) + " B)..."; draw();
  String resp;
  bool posted = net.httpsPostMultipart(LOTW_UPLOAD_URL, "upfile",
                                       LOTW_TQ8_OUT, "cardsat.tq8",
                                       "application/octet-stream", resp);
  if (!posted) {
    // Negative lastCode = transport/connect failure (the -1 a churned heap can cause),
    // not a server response -- a clean-boot reboot is the cure. Offer it (confirm first;
    // a reboot drops a live pass / CAT link, and LoTW will re-prompt for the key
    // passphrase after boot since it is never stored). A positive code is a real server
    // reply a reboot won't fix.
    if (net.lastCode < 0) {
      lotwRebootPrompt = true;
      lotwStatus = (net.lastCode == Net::HEAP_ABORT_CODE)
                 ? "Low memory after fetches. Reboot to upload? ENT=yes  `=no"
                 : "Connect failed. Reboot to upload? ENT=yes  `=no";
      lotwBusy = false; lastDrawMs = 0; draw(); return;
    }
    lotwStatus = "Upload failed: " + net.lastErr;
    lotwBusy = false; lastDrawMs = 0; draw(); return;
  }

  // Log the FULL server response to serial. "Accepted" at the HTTP layer does not
  // guarantee the QSO is processed -- LoTW can accept the upload and then silently
  // ignore a record whose station fields (STATE, SAT_NAME, DXCC, ...) don't match
  // the certificate or its accepted-satellite list. The response body is where the
  // real outcome (and any per-QSO complaint) is reported, so dump it verbatim to aid
  // diagnosis of a QSO that uploads but never appears. Chunked so long bodies aren't
  // truncated by the serial line buffer.
  Serial.printf("[lotw] response (%u bytes):\n", (unsigned)resp.length());
  for (size_t i = 0; i < resp.length(); i += 200) Serial.println(resp.substring(i, i + 200));
  Serial.println("[lotw] --- end response ---");

  // Parse LoTW's response for the per-upload status marker.
  int accepted = lotwParseAccepted(resp, n);
  if (accepted > 0) {
    if (lotwResend) {
      // Re-send mode: the QSOs were already flagged uploaded; nothing new to flag.
      lotwLastSent = accepted;
      lotwStatus = "Re-sent " + String(n) + ", queued " + String(accepted);
      // Advance the resend cursor by the QSOs sent this batch. If more remain beyond the
      // cursor, continue in a fresh boot (carrying the cursor + passphrase in RTC).
      int sentSoFar = (int)g_lotwResendSkip + n;
      int remainAfter = lotwTotal - sentSoFar;   // resend covers ALL logged QSOs
      Serial.printf("[lotw] resend batch n=%d (cap=%d), sent=%d/%d, remaining=%d\n",
                    n, CAP, sentSoFar, lotwTotal, remainAfter);
      if (remainAfter > 0) {
        g_lotwResendSkip = (uint16_t)sentSoFar;   // advance the cursor for the next batch
        lotwResend = true;
        lotwStatus = "Batch sent; " + String(remainAfter) + " left...";
        lotwMoreBatches = true;   // top-level loop re-invokes doLotwUpload (no recursion)
        lotwBusy = false; lastDrawMs = 0; draw();
        return;
      }
      lotwResend = false;   // whole resend run complete
    } else {
      // Flag the n QSOs we actually put in the .tq8 -- whether LoTW counted them as
      // newly accepted or as duplicates, they've reached LoTW and must not be re-sent.
      int marked = markLogUploaded(n, 0x1);
      lotwLastSent = accepted;
      // "Accepted" here means LoTW queued the file for processing; per-QSO results are
      // determined server-side afterward (check your LoTW account).
      lotwStatus = "Queued " + String(accepted) + " at LoTW";
      lotwPending -= marked; if (lotwPending < 0) lotwPending = 0;
      // More un-uploaded QSOs than this batch could hold? Continue in a fresh boot: the
      // .tq8 body must stay under the send ceiling AND a second TLS handshake can't run
      // in this session, so we reboot per batch, carrying the passphrase in RTC RAM.
      int remainAfter = countUnuploadedLotw();
      Serial.printf("[lotw] batch marked=%d (cap=%d), remaining un-uploaded=%d\n",
                    marked, CAP, remainAfter);
      if (remainAfter > 0) {
        lotwResend = false;
        lotwStatus = "Batch sent; " + String(remainAfter) + " left...";
        lotwMoreBatches = true;   // top-level loop re-invokes doLotwUpload (no recursion)
        lotwBusy = false; lastDrawMs = 0; draw();
        return;
      }
    }
  } else {
    lotwStatus = "Server rejected upload";
  }
  lotwBusy = false; lastDrawMs = 0;
  draw();   // repaint with the final result: SCR_LOTW is static, so the loop won't
            // auto-refresh it; without this it stays on "Uploading..." until a keypress.
}

// Count QSOs in the log that still need LoTW upload (uploaded bit0 clear). Streams the
// log; no whole-file buffer. Used to decide whether another batch reboot is needed.
int App::countUnuploadedLotw() {
  int n = 0;
  if (!Store::fs().exists(FILE_LOG)) return 0;
  File f = Store::fs().open(FILE_LOG, "r");
  if (!f) return 0;
  while (f.available()) {
    String l = f.readStringUntil('\n'); l.trim();
    if (!l.length() || l.startsWith("utc,")) continue;
    PendingQso q;
    if (parseQsoCsv(l, q) && q.call[0] && !(q.uploaded & 1)) n++;
  }
  f.close();
  return n;
}

// Count QSOs still needing Cloudlog upload (uploaded bit1 / mask 0x2 clear).
int App::countUnuploadedCloudlog() {
  int n = 0;
  if (!Store::fs().exists(FILE_LOG)) return 0;
  File f = Store::fs().open(FILE_LOG, "r");
  if (!f) return 0;
  while (f.available()) {
    String l = f.readStringUntil('\n'); l.trim();
    if (!l.length() || l.startsWith("utc,")) continue;
    PendingQso q;
    if (parseQsoCsv(l, q) && q.call[0] && !(q.uploaded & 0x2)) n++;
  }
  f.close();
  return n;
}

// Scrub the RTC-held batch state (including the passphrase). Called when a multi-batch
// run finishes or aborts, so the passphrase never lingers in RTC RAM longer than needed.
void App::scrubLotwBatchState() {
  g_lotwBatchActive = false;
  g_lotwBatchResend = false;
  g_lotwBatchMagic  = 0;
  g_lotwResendSkip  = 0;
  memset(g_lotwBatchPass, 0, sizeof(g_lotwBatchPass));
}

// Continue a multi-batch LoTW upload after this batch: stash the passphrase + flags in
// RTC RAM (survives the deliberate restart, not power loss) and reboot. The fresh boot's
// resumeLotwIfPending() sees the active flag and runs the next batch WITHOUT re-prompting.
// resend=true carries the "upload ALL" mode across the reboot; the resend cursor
// (g_lotwResendSkip) is set by the caller before calling this.
// Continue a multi-batch LoTW upload IN THE SAME SESSION. This used to cache the
// passphrase in RTC RAM and ESP.restart() between batches, because (a) a second TLS
// handshake couldn't run in one session under mbedTLS and (b) a large .tq8 could exceed
// the TCP send ceiling. After the ESP_SSLClient (BearSSL) migration BOTH are resolved --
// on-device the unit runs 91 back-to-back handshakes with zero failures, and uploads
// stream with zeroWrites=0 -- so we simply send the next batch directly. Batching itself
// is kept (each .tq8 holds <= LOTW_BATCH_QSOS QSOs) to bound the RAM used building the
// file, not because of any per-session limit. Depth is one frame per batch; realistic
// logs are a handful of batches, and the large per-batch allocations (the QSO array, the
// staged .tq8) are freed before this re-invocation, so the frame cost is small.
// (The former continueLotwBatch() is gone: multi-batch LoTW uploads are now driven by an
// iterative loop at the case-230 call site, which re-invokes doLotwUpload at a constant
// stack depth. The old recursive version stacked a full TLS+signing frame per batch and
// overflowed the loopTask stack on the 3rd batch of a 14-QSO resend.)


// Reboot-then-upload for LoTW, mirroring the Cloudlog path but WITHOUT persisting the
// key passphrase: the passphrase is never stored, so we only drop a one-shot marker and
// restart. resumeLotwIfPending() in setup() then re-opens the LoTW screen and re-prompts
// for the passphrase in the clean boot. The marker is consumed before anything else.
void App::lotwRebootUpload() {
  File f = Store::fs().open(FILE_LOTW_RESUME, "w");
  if (f) { f.println("1"); f.close(); }
  Serial.println("[lotw] reboot-to-upload requested; restarting");
  setStatus("Rebooting to upload...", 2000);
  draw(); delay(1500);
  ESP.restart();
}

// setup(): if the LoTW reboot-upload marker is present, this is the pristine boot we
// rebooted for. Clear the marker FIRST (one-shot), bring up WiFi, open the LoTW screen,
// and re-prompt for the key passphrase (editTarget 230) -- entering it runs the upload
// in this clean-heap boot. The passphrase is re-entered, never stored.
void App::resumeLotwIfPending() {
  // Multi-batch LoTW uploads now continue in the SAME session (see continueLotwBatch),
  // so the old RTC-carried batch-continuation across reboots is retired. Scrub any RTC
  // batch state that an OLDER firmware (or garbage RTC after a flash) might present, so
  // it can never spuriously trigger an upload here.
  if (g_lotwBatchMagic == LOTW_BATCH_MAGIC && g_lotwBatchActive) {
    Serial.println("[lotw] clearing stale RTC batch state (in-session batching now)");
    scrubLotwBatchState();
  }

  if (!Store::fs().exists(FILE_LOTW_RESUME)) return;
  Store::fs().remove(FILE_LOTW_RESUME);        // one-shot: consume before doing anything
  Serial.println("[lotw] resuming upload in fresh boot");
  lotwEnter();                                 // counts pending + sets screen = SCR_LOTW
  screen = SCR_LOTW; lastDrawMs = 0; draw();
  if (!net.connected() && !connectWifiCfg()) {
    lotwStatus = "WiFi failed (upload after reboot)"; lastDrawMs = 0; draw(); return;
  }
  int toSend = lotwResend ? lotwTotal : lotwPending;
  if (Store::ready() && Lotw::credentialPresent() && toSend > 0) {
    // Re-prompt for the passphrase; confirming it runs doLotwUpload in the clean boot.
    editTarget = 230; editTitle = "Key password (blank=none)";
    editBuf = ""; screen = SCR_EDIT; lastDrawMs = 0; draw();
  } else {
    lotwStatus = "Nothing to upload"; lastDrawMs = 0; draw();
  }
}

// Parse the LoTW upload response for an accepted-QSO count. The service wording
// has varied; accept a few forms, and fall back to the batch size on a clear
// success indication. Returns 0 if the response looks like a failure.
int App::lotwParseAccepted(const String& resp, int batchN) {
  // LoTW reports the upload result inside an HTML COMMENT marker. The real markers (seen
  // in the server's response) look like:
  //   status:  <!-- .UPL. accepted -->          (the '.' wildcards + a leading space)
  //   message: <!-- .UPLMESSAGE. File queued for processing -->
  // tqsl matches these with the regex <!-- .UPL.\s*([^-]+)\s*-->. An earlier version
  // looked for "<!-- UPL_" with an underscore, which never matches LoTW's real output --
  // so a perfectly accepted upload was reported as a failure. Match the real format, and
  // do NOT just search for the bare word "accepted" anywhere (a login/landing page can
  // contain it and yield a phantom success).
  // Find the status marker "<!-- .UPL." but NOT "<!-- .UPLMESSAGE." (which also starts
  // with ".UPL"). The status marker is ".UPL." immediately followed by whitespace.
  int m = -1;
  for (int i = resp.indexOf("<!-- .UPL."); i >= 0; i = resp.indexOf("<!-- .UPL.", i + 1)) {
    int after = i + 10;                          // index just past "<!-- .UPL."
    if (after < (int)resp.length() &&
        (resp[after] == ' ' || resp[after] == '\t')) { m = i; break; }
  }
  if (m >= 0) {
    int end = resp.indexOf("-->", m);
    String marker = (end > m) ? resp.substring(m, end) : resp.substring(m);
    String lower = marker; lower.toLowerCase();
    if (lower.indexOf("accepted") >= 0) {
      // Pull a QSO count out of the message marker if present, else assume the batch.
      int mm = resp.indexOf("<!-- .UPLMESSAGE.");
      if (mm >= 0) {
        int me = resp.indexOf("-->", mm);
        String msg = (me > mm) ? resp.substring(mm, me) : resp.substring(mm);
        long val = -1; String num;
        for (size_t i = 0; i < msg.length(); ++i) {
          char ch = msg[i];
          if (ch >= '0' && ch <= '9') num += ch;
          else if (num.length()) { val = num.toInt(); break; }
        }
        if (num.length() && val < 0) val = num.toInt();
        if (val > 0) return (int)min((long)batchN, val);
      }
      return batchN;   // accepted, no parseable count
    }
    return 0;          // marker present but not "accepted" -> rejected
  }
  // No UPL marker at all -> not a real LoTW upload result (login/landing/error page,
  // or a transport that didn't reach the processor). Treat as failure, and log a hint.
  Serial.println("[lotw] no <!-- .UPL. ... --> status marker in response -> upload did "
                 "NOT post (see serial dump above)");
  return 0;
}

// Mark up to 'limit' currently-un-uploaded QSOs as uploaded by rewriting the log
// file (the same first-N, in file order, that doLotwUpload collected and sent).
// Returns the number of records flagged.
// Flag up to 'limit' QSOs that don't yet have 'bit' set in their uploaded mask, by
// rewriting the log. bit 1 (mask 0x1) = uploaded to LoTW; bit 2 (mask 0x2) = uploaded
// to Cloudlog. The two are tracked independently so a QSO sent to one service isn't
// assumed sent to the other.
int App::markLogUploaded(int limit, uint8_t bit) {
  if (!Store::fs().exists(FILE_LOG)) return 0;
  File in = Store::fs().open(FILE_LOG, "r");
  if (!in) return 0;
  String tmp = String(FILE_LOG) + ".tmp";
  File out = Store::fs().open(tmp.c_str(), "w");
  if (!out) { in.close(); return 0; }
  int flagged = 0;
  while (in.available()) {
    String l = in.readStringUntil('\n');
    String t = l; t.trim();
    if (!t.length()) continue;
    if (t.startsWith("utc,")) { out.println(t); continue; }
    PendingQso q;
    if (parseQsoCsv(t, q)) {
      if (!(q.uploaded & bit) && flagged < limit) { q.uploaded |= bit; flagged++; }
      writeQsoCsv(out, q);
    }
  }
  in.close(); out.close();
  Store::fs().remove(FILE_LOG);
  Store::fs().rename(tmp.c_str(), FILE_LOG);
  return flagged;
}

// Minimal JSON string-escaper for building request bodies (quotes, backslash,
// control chars, and the newlines that appear in an ADIF payload).
static String jsonEscape(const String& in) {
  String out; out.reserve(in.length() + 16);
  for (size_t i = 0; i < in.length(); ++i) {
    char c = in[i];
    switch (c) {
      case '"':  out += "\\\""; break;
      case '\\': out += "\\\\"; break;
      case '\n': out += "\\n";  break;
      case '\r': out += "\\r";  break;
      case '\t': out += "\\t";  break;
      default:
        if ((uint8_t)c < 0x20) { char b[8]; snprintf(b, sizeof(b), "\\u%04x", c); out += b; }
        else out += c;
    }
  }
  return out;
}

// Append a JSON-escaped copy of `in` to `out` IN PLACE -- no temporary return String.
// Same escaping as jsonEscape() above, but it writes straight into the caller's buffer.
// Used by the Cloudlog body builder so the whole request is assembled in ONE pre-sized
// allocation instead of a cascade of String-operator temporaries: on the no-PSRAM heap,
// that concatenation churn fragments the free-list right before the TLS handshake and
// is what makes the upload connect fail (-1) once the heap has seen any prior activity.
static void jsonEscapeAppend(String& out, const char* in) {
  if (!in) return;
  for (const char* p = in; *p; ++p) {
    char c = *p;
    switch (c) {
      case '"':  out += "\\\""; break;
      case '\\': out += "\\\\"; break;
      case '\n': out += "\\n";  break;
      case '\r': out += "\\r";  break;
      case '\t': out += "\\t";  break;
      default:
        if ((uint8_t)c < 0x20) { char b[8]; snprintf(b, sizeof(b), "\\u%04x", c); out += b; }
        else out += c;
    }
  }
}

// Extract a top-level JSON string/number value by key from a flat response, e.g.
// {"status":"created","imported_count":3}. Returns the raw value (unquoted) or "".
// Good enough for Cloudlog's simple, flat responses; not a general JSON parser.
static String jsonField(const String& json, const char* key) {
  String pat = String("\"") + key + "\"";
  int k = json.indexOf(pat);
  if (k < 0) return "";
  int colon = json.indexOf(':', k + pat.length());
  if (colon < 0) return "";
  int i = colon + 1;
  while (i < (int)json.length() && (json[i] == ' ' || json[i] == '\t')) i++;
  if (i >= (int)json.length()) return "";
  if (json[i] == '"') {                      // string value
    int end = i + 1; String out;
    while (end < (int)json.length() && json[end] != '"') {
      if (json[end] == '\\' && end + 1 < (int)json.length()) { out += json[end+1]; end += 2; }
      else { out += json[end]; end++; }
    }
    return out;
  }
  int end = i;                                // number/bareword value
  while (end < (int)json.length() && json[end] != ',' && json[end] != '}' &&
         json[end] != ' ' && json[end] != '\n' && json[end] != '\r') end++;
  return json.substring(i, end);
}

// ===========================================================================
//  Cloudlog / Wavelog upload (self-hosted online logbook)
//  Uploads QSOs to a user's Cloudlog instance via its JSON QSO API. Because a
//  Cloudlog instance can itself forward QSOs to LoTW/eQSL, this is an alternative
//  to the on-device LoTW upload rather than something to do in addition. Tracked
//  independently of LoTW via bit 0x2 of each QSO's "uploaded" mask.
//  API contract (see docs/design/CLOUDLOG_UPLOAD_SCOPING.md, from the Cloudlog
//  source): POST {url}/index.php/api/qso  with JSON
//    {"key","station_profile_id","type":"adif","string":"<one ADIF record><EOR>"}
//  Success = HTTP 201 with {"status":"created","imported_count":N,...}.
// ===========================================================================

// Count QSOs not yet sent to Cloudlog (bit 0x2 unset) and the total, then open the
// Cloudlog screen.
void App::cloudlogEnter() {
  clBusy = false; clStatus = "";
  clPending = 0; clTotal = 0;
  if (Store::fs().exists(FILE_LOG)) {
    File f = Store::fs().open(FILE_LOG, "r");
    if (f) {
      while (f.available()) {
        String l = f.readStringUntil('\n'); l.trim();
        if (!l.length() || l.startsWith("utc,")) continue;
        PendingQso q;
        if (parseQsoCsv(l, q) && q.call[0]) {
          clTotal++;
          if (!(q.uploaded & 0x2)) clPending++;
        }
      }
      f.close();
    }
  }
  screen = SCR_CLOUDLOG; lastDrawMs = 0;
}

void App::drawCloudlog() {
  header("Cloudlog upload");
  canvas.setTextSize(1);
  canvas.setTextColor(CL_WHITE, CL_BLACK);
  int y = 20;
  bool haveCfg = cfg.clUrl[0] && cfg.clKey[0] && cfg.clStation[0];

  canvas.setCursor(6, y); y += 12;
  canvas.printf("Server: %s", cfg.clUrl[0] ? cfg.clUrl : "(set in Settings)");
  canvas.setCursor(6, y); y += 12;
  canvas.printf("API key: %s   Station: %s",
                cfg.clKey[0] ? "set" : "NO",
                cfg.clStation[0] ? cfg.clStation : "-");
  canvas.setCursor(6, y); y += 14;
  int toSend = clResend ? clTotal : clPending;
  if (clResend) canvas.printf("Re-send ALL QSOs: %d", clTotal);
  else          canvas.printf("Not yet sent: %d", clPending);

  canvas.setTextColor(CL_GREY, CL_BLACK);
  if (clStatus.length()) {
    canvas.setCursor(6, y); y += 12;
    String s = clStatus; if (s.length() > 38) s = s.substring(0, 38);
    canvas.print(s);
  }

  if (clRebootPrompt)    footer("ENT reboot + upload   ` cancel");
  else if (!cfg.ssid[0])      footer("` back   (set WiFi first)");
  else if (!haveCfg)     footer("` back   (set Cloudlog in Settings)");
  else if (toSend)       footer(clResend ? "u upload  a not-sent  ` back"
                                         : "u upload  a resend  ` back");
  else if (clTotal)      footer("a re-send all   ` back");
  else                   footer("` back   (nothing to upload)");
}

void App::keyCloudlog(char c, bool enter, bool back) {
  // If we're asking whether to reboot-and-upload (after a -1 connect), this keypress
  // answers that prompt and nothing else: ENTER confirms the reboot, ` cancels.
  if (clRebootPrompt) {
    if (enter) { clRebootPrompt = false; cloudlogRebootUpload(clResend, clResendSkip); return; }
    if (isBack(c, back)) {
      clRebootPrompt = false;
      clStatus = "Upload cancelled - QSOs still pending";
      lastDrawMs = 0; draw(); return;
    }
    return;   // ignore any other key while the prompt is up
  }
  if (isBack(c, back)) { screen = SCR_LOG; lastDrawMs = 0; return; }
  if (clBusy) return;
  if (c == 'a' && clTotal > 0) { clResend = !clResend; clStatus = ""; lastDrawMs = 0; return; }
  int toSend = clResend ? clTotal : clPending;
  bool haveCfg = cfg.clUrl[0] && cfg.clKey[0] && cfg.clStation[0];
  if (c == 'u' && haveCfg && toSend > 0) {
    clResendSkip = 0;
    int guard = 0;
    do { clMoreBatches = false; doCloudlogUpload(); } while (clMoreBatches && ++guard < 1000);
  }
}

// Build an ADIF batch from the pending (or all, in re-send mode) QSOs, POST it to the
// Cloudlog instance as JSON, and on success flag those QSOs (bit 0x2).
void App::doCloudlogUpload() {
  clBusy = true; lastDrawMs = 0;
  if (!net.connected()) {
    clStatus = "Connecting WiFi..."; draw();
    if (!connectWifiCfg()) { clStatus = "WiFi failed"; clBusy = false; lastDrawMs = 0; draw(); return; }
  }
  clStatus = "Collecting QSOs..."; draw();

  // ONE upload, ONE handshake. The JSON body is written to a temp file on Store::fs()
  // (SD when present, else internal LittleFS -- so this keeps Cloudlog working without
  // an SD card) and STREAMED to the server. This replaced an earlier batching attempt:
  // on this no-PSRAM heap, batching multiplied the TLS handshake count, and each
  // handshake both gambles on the ~32 KB-contiguous knife-edge AND leaves the heap
  // fragmented (largest block ~20 KB) so the NEXT batch's handshake fails -- on-device
  // this gave a reboot-per-batch. Streaming one body keeps it to a single handshake and
  // a constant ~1 KB of RAM regardless of QSO count. (LoTW streams its .tq8 the same way.)
  //
  // Write the body file: {"key":"..","station_profile_id":"..","type":"adif","string":"<escaped ADIF>"}
  // The ADIF is escaped and streamed straight to the file so the whole body is never in
  // RAM at once. No CAP -- the log can be any size.
  int n = 0;
  {
    String tmp = FILE_CLOUDLOG_TMP;
    File out = Store::fs().open(tmp.c_str(), "w");
    if (!out) { clStatus = "Temp file open failed"; clBusy = false; lastDrawMs = 0; draw(); return; }

    // Fixed prefix with the escaped key + station profile id.
    { String pre; pre.reserve(96);
      pre += "{\"key\":\"";        jsonEscapeAppend(pre, cfg.clKey);
      pre += "\",\"station_profile_id\":\""; jsonEscapeAppend(pre, cfg.clStation);
      pre += "\",\"type\":\"adif\",\"string\":\"";
      out.print(pre); }

    if (Store::fs().exists(FILE_LOG)) {
      File f = Store::fs().open(FILE_LOG, "r");
      if (f) {
        int skipRem = clResend ? clResendSkip : 0;   // resend: skip already-sent batches
        while (f.available()) {
          if (n >= CL_BATCH_QSOS) break;   // size-bound the body; remainder goes next batch
          String l = f.readStringUntil('\n'); l.trim();
          if (!l.length() || l.startsWith("utc,")) continue;
          PendingQso q;
          if (!parseQsoCsv(l, q) || !q.call[0]) continue;
          if (!(clResend || !(q.uploaded & 0x2))) continue;
          if (skipRem > 0) { skipRem--; continue; }   // already sent in an earlier batch
          time_t tt = (time_t)q.utc; struct tm* g = gmtime(&tt);
          char d[9] = "", tm6[7] = "";
          if (g) { strftime(d, sizeof(d), "%Y%m%d", g); strftime(tm6, sizeof(tm6), "%H%M%S", g); }
          double dlM = q.dlHz / 1e6, ulM = q.ulHz / 1e6;
          String rec;   // one record at a time -> small, no whole-body String
          adifField(rec, "CALL", q.call);
          if (q.utc) { adifField(rec, "QSO_DATE", String(d)); adifField(rec, "TIME_ON", String(tm6)); }
          adifField(rec, "MODE", q.mode);
          char satnm[7]; lotwSatResolve(q.sat, satnm);
          adifField(rec, "SAT_NAME", satnm);
          adifField(rec, "PROP_MODE", "SAT");
          if (ulM > 0) { adifField(rec, "FREQ", String(ulM, 4)); adifField(rec, "BAND", bandFor(ulM)); }
          if (dlM > 0) { adifField(rec, "FREQ_RX", String(dlM, 4)); adifField(rec, "BAND_RX", bandFor(dlM)); }
          adifField(rec, "RST_SENT", q.rstS);
          adifField(rec, "RST_RCVD", q.rstR);
          adifField(rec, "GRIDSQUARE", q.grid);
          adifField(rec, "MY_GRIDSQUARE", q.myGrid);
          adifField(rec, "STATION_CALLSIGN", q.myCall[0] ? q.myCall : cfg.myCall);
          rec += "<EOR>\n";
          // Stream the escaped record straight into the body file.
          String esc; esc.reserve(rec.length() + rec.length()/8 + 8);
          jsonEscapeAppend(esc, rec.c_str());
          out.print(esc);
          n++;
        }
        f.close();
      }
    }
    out.print("\"}");   // close the JSON string + object
    out.close();
  }

  if (n == 0) {
    Store::fs().remove(FILE_CLOUDLOG_TMP);
    clStatus = "Nothing to upload"; clBusy = false; lastDrawMs = 0; draw(); return;
  }

  clStatus = "Uploading " + String(n) + " QSO(s)..."; draw();
  String url = String(cfg.clUrl) + "/index.php/api/qso";
  String resp;
  bool ok = net.httpsPostJsonFile(url, FILE_CLOUDLOG_TMP, resp);
  Store::fs().remove(FILE_CLOUDLOG_TMP);   // body file no longer needed either way
  Serial.printf("[cloudlog] response (%u bytes): %s\n",
                (unsigned)resp.length(), resp.c_str());

  if (!ok) {
    // Negative code = transport/connect failure -> reboot-to-clean-heap is the cure.
    if (net.lastCode < 0) {
      clRebootPrompt = true;
      clStatus = (net.lastCode == Net::HEAP_ABORT_CODE)
               ? "Low memory after fetches. Reboot to upload? ENT=yes  `=no"
               : "Connect failed. Reboot to upload? ENT=yes  `=no";
      clBusy = false; lastDrawMs = 0; draw(); return;
    }
    String reason = jsonField(resp, "reason");
    clStatus = reason.length() ? ("Failed: " + reason)
                               : ("Upload failed: " + net.lastErr);
    clBusy = false; lastDrawMs = 0; draw(); return;
  }

  // Success: Cloudlog returns {"status":"created","imported_count":N,...}.
  int imported = jsonField(resp, "imported_count").toInt();
  if (jsonField(resp, "status") == "created") {
    if (!clResend) {
      int marked = markLogUploaded(n, 0x2);
      clPending -= marked; if (clPending < 0) clPending = 0;
      clStatus = "Uploaded " + String(n) + ", imported " + String(imported);
      // More un-uploaded QSOs than this size-bounded batch could hold? Continue in a
      // fresh boot (one handshake per session on this no-PSRAM part). Cloudlog needs no
      // passphrase, so the existing one-shot reboot marker is enough. Gate on "any
      // remaining" rather than "marked >= CAP": a batch that flags fewer than CAP (e.g.
      // a QSO already partly flagged) must still continue if work remains.
      int clRemain = countUnuploadedCloudlog();
      Serial.printf("[cloudlog] batch marked=%d (cap=%d), remaining un-uploaded=%d\n",
                    marked, CL_BATCH_QSOS, clRemain);
      if (clRemain > 0) {
        // Continue iteratively (top-level loop re-invokes), NOT recursively -- the same
        // per-batch TLS frame that overflowed the stack on the LoTW path applies here.
        clStatus = "Batch done; " + String(clRemain) + " left...";
        clMoreBatches = true;
        clBusy = false; lastDrawMs = 0; draw();
        return;
      }
    } else {
      clStatus = "Re-sent " + String(n) + ", imported " + String(imported);
      // Advance the resend cursor; continue in a fresh boot if more logged QSOs remain.
      int sentSoFar = clResendSkip + n;
      int remainAfter = clTotal - sentSoFar;   // resend covers ALL logged QSOs
      Serial.printf("[cloudlog] resend batch n=%d (cap=%d), sent=%d/%d, remaining=%d\n",
                    n, CL_BATCH_QSOS, sentSoFar, clTotal, remainAfter);
      if (remainAfter > 0) {
        clResendSkip = sentSoFar;   // advance the resend cursor for the next batch
        clStatus = "Batch done; " + String(remainAfter) + " left...";
        clMoreBatches = true;
        clBusy = false; lastDrawMs = 0; draw();
        return;
      }
      clResend = false; clResendSkip = 0;   // whole resend run complete
    }
  } else {
    String reason = jsonField(resp, "reason");
    clStatus = reason.length() ? ("Rejected: " + reason) : "Server rejected upload";
  }
  clBusy = false; lastDrawMs = 0;
  draw();   // repaint with the final result: SCR_CLOUDLOG is static, so the loop won't
            // auto-refresh it; without this it stays on "Uploading..." until a keypress.
}

// Reboot-then-upload: the in-session POST can hit a connect wall (-1) once a boot has
// already run several TLS fetches (the same pattern the batched transponder cache hits
// -- see doCacheAllTransponders). The reliable cure is a pristine boot. This writes a
// one-shot marker and restarts; resumeCloudlogIfPending() in setup() then performs the
// upload before anything else touches the network, and drops the user back here with
// the result. The marker is cleared the instant it's read, so a failure can't loop.
void App::cloudlogRebootUpload(bool resend, int cursor) {
  File f = Store::fs().open(FILE_CL_RESUME, "w");
  if (f) { f.printf("%d %d\n", resend ? 1 : 0, cursor); f.close(); }  // resend flag + resend cursor
  Serial.println("[cloudlog] reboot-to-upload requested; restarting");
  setStatus("Rebooting to upload...", 2000);
  draw(); delay(1500);
  ESP.restart();
}

// Called near the end of setup(): if the reboot-upload marker is present, this is the
// pristine boot we rebooted for. Clear the marker FIRST (one-shot: never loop, even if
// the upload crashes), bring up WiFi, open the Cloudlog screen, and run the upload now --
// before the GP/AMSAT/weather fetches consume socket/heap headroom.
void App::resumeCloudlogIfPending() {
  if (!Store::fs().exists(FILE_CL_RESUME)) return;
  // Read the marker (resend flag + resend cursor) BEFORE removing it (one-shot).
  int rf = 0, cur = 0;
  { File f = Store::fs().open(FILE_CL_RESUME, "r");
    if (f) { String l = f.readStringUntil('\n'); f.close();
             int sp = l.indexOf(' ');
             if (sp >= 0) { rf = l.substring(0, sp).toInt(); cur = l.substring(sp + 1).toInt(); }
             else rf = l.toInt(); } }
  Store::fs().remove(FILE_CL_RESUME);          // one-shot: consume before doing anything
  Serial.println("[cloudlog] resuming upload in fresh boot");
  cloudlogEnter();                             // counts pending + sets screen = SCR_CLOUDLOG
  screen = SCR_CLOUDLOG; lastDrawMs = 0; draw();
  if (!net.connected() && !connectWifiCfg()) {
    clStatus = "WiFi failed (upload after reboot)"; lastDrawMs = 0; draw(); return;
  }
  clResend = (rf != 0);
  clResendSkip = cur;                          // resend cursor for this continued run
  int toSend = clResend ? (clTotal - cur) : clPending;
  bool haveCfg = cfg.clUrl[0] && cfg.clKey[0] && cfg.clStation[0];
  if (haveCfg && toSend > 0) {
    int guard = 0;
    do { clMoreBatches = false; doCloudlogUpload(); } while (clMoreBatches && ++guard < 1000);
  }
  else { clResendSkip = 0; clStatus = "Nothing to upload"; lastDrawMs = 0; draw(); }
}

void App::drawLogEntry() {
  header(logEditIdx >= 0 ? "Edit QSO" : "Log QSO");
  canvas.setTextSize(1);
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, 18);
  canvas.printf("MyGrid %s  MyCall %s", qso.myGrid[0] ? qso.myGrid : "-",
                qso.myCall[0] ? qso.myCall : "-");

  // The upload-flag rows (LoTW, Cloudlog) only apply to an existing logged QSO, so
  // they are shown when editing (logEditIdx >= 0) and hidden when logging a new one.
  const int LF = (logEditIdx >= 0) ? 13 : 11;
  char dbuf[16], tbuf[16], dlb[16], ulb[16];
  if (qso.utc) { time_t tt = (time_t)qso.utc; struct tm g; gmtime_r(&tt, &g);
                 strftime(dbuf, sizeof(dbuf), "%Y-%m-%d", &g);
                 strftime(tbuf, sizeof(tbuf), "%H:%M:%SZ", &g); }
  else { strcpy(dbuf, "(set)"); strcpy(tbuf, "(set)"); }
  if (qso.dlHz) snprintf(dlb, sizeof(dlb), "%.4f", qso.dlHz / 1e6); else strcpy(dlb, "(set)");
  if (qso.ulHz) snprintf(ulb, sizeof(ulb), "%.4f", qso.ulHz / 1e6); else strcpy(ulb, "(set)");
  const char* labels[13] = { "Date", "Time", "Sat", "DL MHz", "UL MHz",
                             "Call", "Mode", "RST S", "RST R", "Grid", "Notes",
                             "LoTW", "Cloudlog" };
  const char* vals[13]   = { dbuf, tbuf, qso.sat[0] ? qso.sat : "(pick)", dlb, ulb,
                             qso.call, qso.mode, qso.rstS, qso.rstR, qso.grid, qso.notes,
                             (qso.uploaded & 0x1) ? "uploaded (ENT to clear)"
                                                  : "not uploaded (ENT to set)",
                             (qso.uploaded & 0x2) ? "uploaded (ENT to clear)"
                                                  : "not uploaded (ENT to set)" };
  const int VIS = 8;
  int scroll = (logSel >= VIS) ? (logSel - VIS + 1) : 0;
  for (int v = 0; v < VIS && scroll + v < LF; ++v) {
    int i = scroll + v;
    int y = 30 + v*11;
    bool sel = (i == logSel);
    if (sel) { canvas.fillRect(0, y-1, 240, 11, CL_BLUE);
               canvas.setTextColor(CL_WHITE, CL_BLUE); }
    else        canvas.setTextColor(CL_CYAN, CL_BLACK);
    canvas.setCursor(4, y); canvas.printf("%-6s %.27s", labels[i], vals[i]);
  }
  footer(logEditIdx >= 0 ? "ENT edit  s save  x del  ` back"
                         : "ENT edit  s save  ` cancel");
}

void App::keyLogEntry(char c, bool enter, bool back) {
  const int LF = (logEditIdx >= 0) ? 13 : 11;   // +2 upload-flag rows when editing
  if (c != 'x') logDelArm = false;             // any other key disarms delete
  if (isBack(c, back)) { logEditIdx = -1; screen = logReturn; lastDrawMs = 0; return; }
  if (isUp(c))   logSel = (logSel + LF - 1) % LF;
  if (isDown(c)) logSel = (logSel + 1) % LF;
  if (c == 'x' && logEditIdx >= 0) {           // delete this entry (two-press)
    if (!logDelArm) { logDelArm = true; setStatus("Press x again to delete"); return; }
    bool ok = rewriteLog(logFileRow(logEditIdx), nullptr, true);
    setStatus(ok ? "QSO deleted" : "Delete failed");
    logDelArm = false; logEditIdx = -1;
    if (ok) loadLog();
    screen = logReturn; lastDrawMs = 0; return;
  }
  if (c == 's') {
    if (!qso.call[0]) { setStatus("Call required to log"); return; }
    // qso.uploaded is saved as-is: editing any content field already cleared it (so the
    // QSO re-uploads), and the LoTW/Cloudlog rows let the operator override that choice.
    bool ok = (logEditIdx >= 0) ? rewriteLog(logFileRow(logEditIdx), &qso, false)
                                : saveQso();
    setStatus(ok ? (logEditIdx >= 0 ? "QSO updated" : "QSO logged") : "Log write failed");
    if (ok && logReturn == SCR_LOGLIST) loadLog();
    logEditIdx = -1;
    screen = logReturn; lastDrawMs = 0; return;
  }
  if (enter) {
    char b[20];
    if (logEditIdx >= 0 && logSel == 11) {      // LoTW flag: toggle uploaded bit0
      qso.uploaded ^= 0x1;
      setStatus((qso.uploaded & 0x1) ? "Marked uploaded to LoTW"
                                     : "Marked NOT uploaded to LoTW");
      return;
    }
    if (logEditIdx >= 0 && logSel == 12) {      // Cloudlog flag: toggle uploaded bit1
      qso.uploaded ^= 0x2;
      setStatus((qso.uploaded & 0x2) ? "Marked uploaded to Cloudlog"
                                     : "Marked NOT uploaded to Cloudlog");
      return;
    }
    if (logSel == 6) {                          // Mode: toggle SSB<->CW on linear
      if (strcmp(qso.mode, "FM") != 0) {
        strncpy(qso.mode, strcmp(qso.mode, "CW") == 0 ? "SSB" : "CW",
                sizeof(qso.mode) - 1);
        qso.mode[sizeof(qso.mode) - 1] = 0;
        if (logEditIdx >= 0) qso.uploaded = 0;  // mode change re-arms upload
      } else setStatus("FM mode is fixed");
      return;
    }
    if (logSel == 2) {                          // Sat: pick from the satellite list
      logPickSat = true; screen = SCR_SATLIST; lastDrawMs = 0; return;
    }
    switch (logSel) {
      case 0: editTarget = 505; editTitle = "Date YYYY-MM-DD (UTC)";
              if (qso.utc) { time_t tt=(time_t)qso.utc; struct tm g; gmtime_r(&tt,&g);
                             strftime(b,sizeof(b),"%Y-%m-%d",&g); editBuf=b; }
              else editBuf = ""; break;
      case 1: editTarget = 506; editTitle = "Time HH:MM:SS (UTC)";
              if (qso.utc) { time_t tt=(time_t)qso.utc; struct tm g; gmtime_r(&tt,&g);
                             strftime(b,sizeof(b),"%H:%M:%S",&g); editBuf=b; }
              else editBuf = ""; break;
      case 3: editTarget = 507; editTitle = "Downlink MHz";
              if (qso.dlHz) { snprintf(b,sizeof(b),"%.4f",qso.dlHz/1e6); editBuf=b; }
              else editBuf = ""; break;
      case 4: editTarget = 508; editTitle = "Uplink MHz";
              if (qso.ulHz) { snprintf(b,sizeof(b),"%.4f",qso.ulHz/1e6); editBuf=b; }
              else editBuf = ""; break;
      case 5:  editTarget = 500; editTitle = "Callsign";   editBuf = qso.call; break;
      case 7:  editTarget = 501; editTitle = "RST sent";   editBuf = qso.rstS; break;
      case 8:  editTarget = 502; editTitle = "RST rcvd";   editBuf = qso.rstR; break;
      case 9:  editTarget = 503; editTitle = "Their grid"; editBuf = qso.grid; break;
      case 10: editTarget = 504; editTitle = "Notes";      editBuf = qso.notes; break;
    }
    screen = SCR_EDIT;
  }
}

void App::loadLog() {
  logRecN = 0;
  int total = qsoCount();
  logFirstIdx = (total > LOG_VIEW_MAX) ? total - LOG_VIEW_MAX : 0;
  logListSel = 0;
  if (!Store::fs().exists(FILE_LOG)) return;
  File f = Store::fs().open(FILE_LOG, "r");
  if (!f) return;
  int idx = 0;
  while (f.available()) {
    String line = f.readStringUntil('\n');
    while (line.length() && (line[line.length()-1] == '\r' || line[line.length()-1] == '\n'))
      line.remove(line.length() - 1);
    if (!line.length() || line.startsWith("utc,")) continue;
    if (idx >= logFirstIdx && logRecN < LOG_VIEW_MAX)
      if (parseQsoCsv(line, logRecs[logRecN])) { logFileRows[logRecN] = idx; logRecN++; }
    idx++;
  }
  f.close();
  // Show the log in date/time order, NEWEST FIRST. The file is append-only (insertion
  // order), which is usually chronological but not guaranteed once a QSO's time is
  // edited or backdated -- so sort by utc descending rather than just reversing. The
  // parallel logFileRows[] is sorted in lockstep so edit/delete still target the right
  // on-disk line. Simple insertion sort; LOG_VIEW_MAX is small (<=60).
  for (int a = 1; a < logRecN; ++a) {
    PendingQso kq = logRecs[a]; int kr = logFileRows[a];
    int b = a - 1;
    while (b >= 0 && logRecs[b].utc < kq.utc) {     // '<' => descending (newest first)
      logRecs[b+1] = logRecs[b]; logFileRows[b+1] = logFileRows[b]; --b;
    }
    logRecs[b+1] = kq; logFileRows[b+1] = kr;
  }
  logListSel = 0;                                  // default to the newest (now at top)
}

// File row on disk for a logRecs[] index, for rewriteLog() on edit/delete. Records are
// date-sorted in the view, so this is a direct lookup into the parallel array (NOT
// logFirstIdx + i, which only held before the sort).
int App::logFileRow(int recIdx) const {
  if (recIdx < 0 || recIdx >= logRecN) return -1;
  return logFileRows[recIdx];
}

// Edit (rec, del=false) or delete (del=true) one data row by file index, by
// streaming the CSV through a temp file -- no full-RAM load, no data loss.
bool App::rewriteLog(int fileIdx, const PendingQso* rec, bool del) {
  File in = Store::fs().open(FILE_LOG, "r");
  if (!in) return false;
  const char* tmp = "/CardSat/qso_log.tmp";
  File out = Store::fs().open(tmp, "w");
  if (!out) { in.close(); return false; }
  int idx = 0;
  while (in.available()) {
    String line = in.readStringUntil('\n');
    while (line.length() && (line[line.length()-1] == '\r' || line[line.length()-1] == '\n'))
      line.remove(line.length() - 1);
    if (line.startsWith("utc,")) { out.print(line); out.print("\n"); continue; }
    if (!line.length()) continue;
    if (idx == fileIdx) {
      if (!del && rec) writeQsoCsv(out, *rec);       // replace; delete = skip
    } else {
      out.print(line); out.print("\n");
    }
    idx++;
  }
  in.close(); out.close();
  Store::fs().remove(FILE_LOG);
  Store::fs().rename(tmp, FILE_LOG);
  return true;
}

void App::drawLogList() {
  header("QSO Log");
  canvas.setTextSize(1);
  if (logRecN == 0) {
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(6, 44); canvas.print("No QSOs logged yet.");
    footer("` back");
    return;
  }
  const int VIS = 8;
  int top = logListSel - VIS/2;
  if (top > logRecN - VIS) top = logRecN - VIS;
  if (top < 0) top = 0;
  for (int r = 0; r < VIS && top + r < logRecN; ++r) {
    int i = top + r, y = 20 + r*12;
    PendingQso& q = logRecs[i];
    bool sel = (i == logListSel);
    if (sel) { canvas.fillRect(0, y-1, 240, 11, CL_BLUE);
               canvas.setTextColor(CL_WHITE, CL_BLUE); }
    else        canvas.setTextColor(CL_CYAN, CL_BLACK);
    char tb[16];
    if (q.utc) { time_t tt=(time_t)q.utc; struct tm* g=gmtime(&tt);
                 strftime(tb, sizeof(tb), "%m-%d %H:%MZ", g); }
    else strcpy(tb, "--");
    canvas.setCursor(4, y);
    canvas.printf("%s %-9.9s %.8s", tb, q.call[0] ? q.call : "(nocall)", q.sat);
  }
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, 116); canvas.printf("%d/%d", logListSel + 1, logRecN);
  footer("; / . move  ENT edit  ` back");
}

void App::keyLogList(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_LOG; return; }
  if (logRecN == 0) return;
  if (isUp(c))   logListSel = (logListSel + logRecN - 1) % logRecN;
  if (isDown(c)) logListSel = (logListSel + 1) % logRecN;
  if (enter) {
    qso = logRecs[logListSel];
    logEditIdx = logListSel;
    logReturn = SCR_LOGLIST;
    logSel = 0; logDelArm = false;
    screen = SCR_LOGENTRY;
  }
}

void App::footer(const String& t) {
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setTextSize(1);
  canvas.setCursor(2, 127);
  canvas.print(t);
}

// Transient out-of-passband banner. When an operator knob move (FULL/DL) overran
// a passband edge, pbOobUntilMs was armed; flash a red bar on the y=114 status row
// for a moment (the downlink is being pulled back to the edge meanwhile). Returns
// true while it's showing so the live screens can repaint to keep it animating.
bool App::drawOobBanner() {
  if (millis() >= pbOobUntilMs || pbOobDir == 0) return false;
  bool on = ((millis() / 250) & 1);                 // ~2 Hz flash
  canvas.fillRect(0, 114, 240, 11, on ? CL_RED : CL_BLACK);
  if (on) {
    canvas.setTextColor(CL_WHITE, CL_RED);
    canvas.setTextSize(1);
    canvas.setCursor(4, 116);
    canvas.printf("OUT OF PASSBAND (%s edge) - tuning back",
                  pbOobDir < 0 ? "low" : "high");
  }
  return true;
}

