  (void)enter;
  if (isUp(c))   { techScroll--; lastDrawMs = 0; }
  if (isDown(c)) { techScroll++; lastDrawMs = 0; }
  if (isBack(c, back)) { screen = SCR_HELP; lastDrawMs = 0; return; }
