// ===========================================================================
//  Learn: radio + orbital theory for satellites, and how amateur satellites
//  work technically. Deeper companion to the Glossary. 'l' from Help.
//  Scrollable, screen-formatted (<=38 col).
// ===========================================================================
void App::drawLearn() {
  header("Learn");
  static const char* L[] = {
    "ORBITS: WHY THEY WORK",
    " An orbit is just falling and",
    " missing the Earth. Gravity",
    " pulls a satellite down; its",
    " sideways speed carries it past",
    " the horizon as fast as it",
    " falls, so it keeps curving",
    " around instead of hitting the",
    " ground.",
    " Newton + Kepler: the closer the",
    " orbit, the FASTER it must move.",
    " Low birds (~400-800 km) circle",
    " in ~90-100 min; higher orbits",
    " are slower. Geostationary",
    " (35786 km) takes exactly one",
    " day, so it appears fixed in the",
    " sky.",
    "KEPLER'S LAWS (SIMPLIFIED)",
    " 1. Orbits are ellipses with",
    "  Earth at one focus (a circle",
    "  is just e=0).",
    " 2. A line from Earth to the sat",
    "  sweeps equal areas in equal",
    "  time - so the sat moves FASTER",
    "  near perigee (low) and slower",
    "  near apogee (high).",
    " 3. Period^2 is proportional to",
    "  size^3 (a^3). Bigger orbit =",
    "  disproportionately longer",
    "  period.",
    "ORBIT SHAPES FOR HAM SATS",
    " LEO (low Earth orbit): short,",
    "  frequent, fast passes; most",
    "  ham birds live here.",
    " SSO (sun-synchronous): a near-",
    "  polar LEO whose plane drifts",
    "  to keep a constant Sun angle,",
    "  so passes recur near the same",
    "  local time each day.",
    " HEO (highly elliptical): a low",
    "  perigee and very high apogee.",
    "  Near apogee the sat hangs in",
    "  view for hours over a whole",
    "  hemisphere (AO-10/13/40).",
    " GEO (geostationary): fixed over",
    "  one spot; 24/7 access but only",
    "  where it is in view (QO-100).",
    "WHAT PERTURBS AN ORBIT",
    " The Earth is not a point mass",
    " or a perfect sphere. Its",
    " equatorial bulge (the J2 term)",
    " slowly rotates the orbit plane",
    " and the line of apsides.",
    " Designers exploit J2 to make",
    " sun-sync orbits. Atmospheric",
    " drag steadily lowers LEO birds",
    " until they re-enter - which is",
    " why orbital elements go stale",
    " and must be refreshed.",
    "RADIO BASICS",
    " Radio is energy radiated as an",
    " electromagnetic wave. Frequency",
    " (Hz) x wavelength = the speed",
    " of light. Higher frequency =",
    " shorter wavelength = smaller",
    " antennas.",
    " Ham sats mostly use VHF (2 m,",
    " 145 MHz) and UHF (70 cm, 435",
    " MHz), with some on 23 cm, 13 cm",
    " and higher. These punch through",
    " the ionosphere; HF below ~30",
    " MHz usually bounces off it and",
    " does not reach space reliably.",
    "MODES & MODULATION",
    " FM: constant-power, easy, but",
    "  one signal fills the channel.",
    "  Good for simple repeater sats.",
    " SSB: a thin, power-efficient",
    "  voice mode; many fit in one",
    "  passband. Used on linear sats.",
    " CW (Morse): the narrowest and",
    "  most efficient of all - gets",
    "  through when nothing else can.",
    " DIGITAL: packet, FSK, and modern",
    "  data modes for telemetry and",
    "  store-and-forward.",
    "THE LINK BUDGET",
    " Whether you make the contact is",
    " a sum of gains and losses:",
    " TX power + antenna gains - path",
    " loss - feedline/atmos losses =",
    " signal at the far end.",
    " Space is far, so every dB",
    " counts. A small beam's gain and",
    " low feedline loss often matter",
    " more than raw watts. CW/SSB",
    " need far less signal than FM,",
    " which is why weak-signal modes",
    " rule the linear birds.",
    "ANTENNAS & GAIN",
    " Gain is not free power - it",
    " focuses energy in a direction,",
    " like a flashlight reflector. A",
    " Yagi aimed at the sat both",
    " transmits and hears better that",
    " way. That is why you POINT it.",
    " Polarization: the wave's E-field",
    " orientation. LEO sats often use",
    " circular polarization; a linear",
    " hand antenna sees the signal",
    " spin and fade, so twisting the",
    " antenna recovers it.",
    "DOPPLER, PHYSICALLY",
    " A moving source bunches the",
    " waves ahead of it and stretches",
    " them behind - like a passing",
    " siren. Approaching, you hear a",
    " HIGHER frequency; receding, a",
    " LOWER one.",
    " A LEO sat moving ~7 km/s shifts",
    " UHF by several kHz across a",
    " pass. You retune continuously",
    " to track it - exactly what",
    " CardSat computes from the orbit",
    " and applies to your radio.",
    "HOW A TRANSPONDER WORKS",
    " A LINEAR transponder is a",
    " frequency-shifting repeater. It",
    " receives a whole slice of an",
    " uplink band, amplifies it, and",
    " re-transmits it on a downlink",
    " band - usually INVERTED (the",
    " low end of one maps to the high",
    " end of the other). Everyone in",
    " the passband is relayed at once,",
    " so many SSB/CW QSOs coexist.",
    " Key point: there is no channel.",
    " You pick a spot in the passband",
    " and your correspondent finds",
    " your downlink.",
    "HOW AN FM REPEATER SAT WORKS",
    " Like a terrestrial repeater in",
    " orbit: it receives one FM",
    " signal on the uplink and re-",
    " sends it on the downlink, often",
    " gated by a sub-audible CTCSS",
    " tone. Only one QSO at a time,",
    " but simple to work with an HT.",
    "BEACONS & TELEMETRY",
    " Most sats send a BEACON - a",
    " steady signal (CW, BPSK or",
    " packet) carrying telemetry:",
    " voltages, temperatures, status.",
    " It marks the downlink edge for",
    " tuning, confirms the bird is",
    " alive, and lets ground stations",
    " monitor its health.",
    "STORE-AND-FORWARD",
    " Some sats are orbiting mailboxes:",
    " you upload a message on one",
    " pass; the sat carries it and",
    " downloads it to a station",
    " elsewhere on a later pass - data",
    " relay without a live link.",
    "POWER & ATTITUDE",
    " Solar panels charge batteries;",
    " in eclipse the sat runs on",
    " battery (or shuts down, like",
    " AO-7 with dead cells). Many use",
    " passive control - magnets to",
    " align with Earth's field, spin",
    " or gravity-gradient booms - to",
    " keep antennas roughly pointed",
    " without fuel.",
    "SATELLITE CLASSES",
    " CubeSats: 10 cm cube units (1U,",
    "  3U...), cheap rideshares; most",
    "  new ham birds.",
    " Microsats: slightly larger,",
    "  often carrying linear",
    "  transponders.",
    " The ISS: crewed station with",
    "  ham gear (ARISS) - an FM",
    "  repeater, packet, SSTV and",
    "  scheduled school contacts.",
    " GEO payloads: hosted on big",
    "  commercial birds (QO-100).",
    "PUTTING IT TOGETHER",
    " CardSat ties the theory to",
    " practice: it propagates the",
    " orbit (SGP4) to predict where a",
    " bird is, computes the Doppler",
    " from its motion, and tunes your",
    " radio so a contact through a",
    " fast-moving repeater in space",
    " just works.",
    " The physics is over a century",
    " old; the fun is brand new every",
    " pass. 73!",
    "MODULATION: HOW SIGNALS CARRY",
    " Modulation is how you put voice",
    " or data onto a radio carrier.",
    " The mode you pick trades off",
    " bandwidth, power efficiency, and",
    " how well it survives noise and",
    " Doppler.",
    "HF MODES (3-30 MHz)",
    " CW (on/off keyed Morse): the",
    " narrowest, most power-efficient",
    " mode - a few Hz of copy under",
    " the noise. SSB (single sideband,",
    " USB/LSB): voice in ~2.4 kHz, the",
    " HF workhorse. AM: older, wider",
    " (~6 kHz), carrier + two",
    " sidebands. Digital: RTTY (FSK),",
    " PSK31 (phase shift, ~60 Hz),",
    " and FT8/FT4 (weak-signal, decodes",
    " ~20-25 dB below the noise) now",
    " dominate the data segments.",
    "VHF/UHF MODES (50 MHz+)",
    " FM: wide (~12-16 kHz) but capture",
    " effect gives clean full-quieting",
    " audio - the repeater and simplex",
    " standard. SSB/CW: used for weak-",
    " signal work, meteor scatter, and",
    " tropo on the low ends of each",
    " band. Digital voice: D-STAR,",
    " C4FM/Fusion, DMR - voice sampled,",
    " compressed (AMBE/vocoder), then",
    " sent as digital symbols.",
    "SATELLITE MODES",
    " Linear transponders relay a whole",
    " slice of band, so you work them",
    " in SSB or CW (efficient, many",
    " users at once, and you can hear",
    " your own downlink). FM birds use",
    " a single 5 kHz channel - one QSO",
    " at a time, easy with an HT.",
    " Digital birds carry packet (AX.25",
    " AFSK/GMSK) or store-and-forward",
    " data. Mode letters (U/v, V/u...)",
    " name the uplink/downlink bands.",
    "EME (MOONBOUNCE)",
    " The Moon is a weak, noisy, moving",
    " reflector ~2.5 s round trip away.",
    " Path loss is enormous, so EME",
    " lives on the most efficient modes:",
    " CW by ear for big stations, and",
    " JT65 / Q65 (weak-signal digital,",
    " long slow tones with strong error",
    " coding) to pull signals tens of",
    " dB out of the noise. Libration",
    " smears the echo, so narrow, slow,",
    " coded modes win.",
    "SATELLITE TELEMETRY",
    " Telemetry is the beacon a bird",
    " sends about itself: battery",
    " voltage, currents, temperatures,",
    " spin, mode, and computer status.",
    " It rides a separate beacon or is",
    " interleaved with the transponder,",
    " and ground stations decode and",
    " report it - collectively acting",
    " as a distributed health monitor.",
    "HOW IT WORKS",
    " Onboard sensors feed an analog-to-",
    " digital converter; the flight",
    " computer frames the values with",
    " IDs and a checksum, then keys the",
    " beacon transmitter. On the ground",
    " you demodulate, check the frame,",
    " and software converts raw counts",
    " back to volts and degrees using",
    " known calibration curves.",
    "MODES OVER THE YEARS",
    " Early birds (OSCAR 1, 1961) sent",
    " the simplest telemetry possible:",
    " a CW beacon whose keying speed",
    " tracked temperature - copy it by",
    " ear. Next came Morse and then",
    " RTTY telemetry with numeric",
    " channels sent as tones.",
    " The 1980s-90s standardized on",
    " AFSK/FSK packet radio (AX.25,",
    " 1200 bps Bell 202, later 9600 bps",
    " G3RUH GMSK) - the same packet",
    " your TNC decodes on 145.825.",
    " Modern satellites use BPSK/FSK",
    " with strong forward error",
    " correction; many CubeSats send",
    " highly-coded BPSK telemetry that",
    " tools like FoxTelem or SatNOGS",
    " decode, log, and upload to a",
    " shared database automatically.",
    "WHY IT MATTERS",
    " Telemetry is how operators and",
    " control teams know a bird is",
    " healthy, which transponder is on,",
    " and when a battery or eclipse",
    " season is stressing it. Reporting",
    " what you decode genuinely helps",
    " keep the birds flying. 73!",
  };
  const int total = (int)(sizeof(L) / sizeof(L[0]));
  const int rows = 9;
  if (learnScroll > total - rows) learnScroll = total - rows;
  if (learnScroll < 0) learnScroll = 0;
  canvas.setTextSize(1);
  for (int i = 0; i < rows && (learnScroll + i) < total; i++) {
    const char* s = L[learnScroll + i];
    bool hdr = (s[0] != ' ');
    canvas.setTextColor(hdr ? CL_CYAN : CL_WHITE, CL_BLACK);
    canvas.setCursor(4, 20 + i * 12); canvas.print(s);
  }
  footer("; / . scroll   ` back");
}

void App::keyLearn(char c, bool enter, bool back) {
  (void)enter;
  if (isUp(c))   { learnScroll--; lastDrawMs = 0; }
  if (isDown(c)) { learnScroll++; lastDrawMs = 0; }
  if (isBack(c, back)) { screen = SCR_HELP; lastDrawMs = 0; return; }
}

// ===========================================================================
//  Point-here arrow: a big glanceable compass arrow to the satellite's azimuth
//  plus an elevation bar, for hand-aiming a portable antenna. 'a' from Track.
//  Reuses the active sat's live look. Radio/rotator keep running underneath.
// ===========================================================================
void App::drawArrow() {
  SatEntry* s = activeSat();
  header(s ? (String("Point: ") + s->name) : String("Point here"));
  canvas.setTextSize(1);
  if (!s || !timeIsSet()) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 60); canvas.print("No satellite / clock not set.");
    footer("` back");
    return;
  }
  LiveLook L = pred.look(nowUtc());

  // --- Compass rose on the left: arrow points to the satellite azimuth ---
  const int cx = 62, cy = 72, R = 40;
  canvas.drawCircle(cx, cy, R, CL_DGREY);
  canvas.drawCircle(cx, cy, R / 2, CL_DGREY);
  // Cardinal ticks + labels (N up, E right, S down, W left).
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(cx - 3, cy - R - 9);  canvas.print("N");
  canvas.setCursor(cx - 3, cy + R + 2);  canvas.print("S");
  canvas.setCursor(cx + R + 2, cy - 3);  canvas.print("E");
  canvas.setCursor(cx - R - 8, cy - 3);  canvas.print("W");

  // Arrow geometry: screen angle where 0deg az = up (-y), 90deg az = right (+x).
  double az = L.az;
  double th = az * 0.017453292519943295;   // radians
  double sx = sin(th), cy_ = -cos(th);      // unit vector (x right, y up-screen)
  // Tip near the rim, tail near the centre.
  int tipX = cx + (int)lround(sx * (R - 4));
  int tipY = cy + (int)lround(cy_ * (R - 4));
  int tailX = cx - (int)lround(sx * (R - 16));
  int tailY = cy - (int)lround(cy_ * (R - 16));
  // Above the horizon = bright green arrow; below = dim grey (not workable).
  uint16_t aCol = (L.el >= 0.0) ? CL_GREEN : CL_DGREY;
  // Shaft.
  canvas.drawLine(tailX, tailY, tipX, tipY, aCol);
  canvas.drawLine(tailX + 1, tailY, tipX + 1, tipY, aCol);
  // Arrowhead: two short barbs back from the tip.
  double pth = th + 2.5;   // ~143 deg off, gives a neat head
  double qth = th - 2.5;
  int hx1 = tipX + (int)lround(sin(pth) * 10.0);
  int hy1 = tipY + (int)lround(-cos(pth) * 10.0);
  int hx2 = tipX + (int)lround(sin(qth) * 10.0);
  int hy2 = tipY + (int)lround(-cos(qth) * 10.0);
  canvas.fillTriangle(tipX, tipY, hx1, hy1, hx2, hy2, aCol);
  // Centre dot = you.
  canvas.fillCircle(cx, cy, 2, CL_WHITE);

  // --- Elevation bar on the right: 0 at bottom, 90 at top ---
  // (No side "El" label here -- the numeric column to the right has its own El row,
  // and the 90/0 endpoints make the bar self-evident; this avoids crowding the range.)
  const int bx = 150, bTop = 32, bBot = 112, bW = 12;
  canvas.drawRect(bx, bTop, bW, bBot - bTop, CL_DGREY);
  double elc = L.el; if (elc < 0) elc = 0; if (elc > 90) elc = 90;
  int fillH = (int)lround((bBot - bTop) * (elc / 90.0));
  uint16_t eCol = (L.el >= 30.0) ? CL_GREEN : (L.el >= 0.0) ? CL_YELLOW : CL_DGREY;
  if (fillH > 0) canvas.fillRect(bx + 1, bBot - fillH, bW - 2, fillH, eCol);
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(bx - 2, bTop - 10); canvas.print("90");
  canvas.setCursor(bx + 3, bBot + 2);  canvas.print("0");

  // --- Numeric readout on the right (column at x=170, clear of the bar at x<=162) ---
  canvas.setCursor(170, 32);
  canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.print("Az");
  canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(192, 32);
  { char b[8]; snprintf(b, sizeof(b), "%3.0f", L.az); canvas.print(b); }
  canvas.setTextColor(CL_CYAN, CL_BLACK);  canvas.setCursor(170, 44);
  canvas.print(windDirName((int)(L.az + 0.5)));

  canvas.setCursor(170, 60);
  canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.print("El");
  canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(192, 60);
  { char b[8]; snprintf(b, sizeof(b), "%3.0f", L.el); canvas.print(b); }

  canvas.setCursor(170, 76);
  canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.print("Rng");
  canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(170, 88);
  { char b[12]; snprintf(b, sizeof(b), "%.0fkm", L.rangeKm); canvas.print(b); }

  // Up/down state as a compact word in the right column (replaces the old full-width
  // bottom line, which overlapped the footer). Short enough to clear the screen edge.
  canvas.setCursor(170, 106);
  if (L.el >= 0.0) {
    canvas.setTextColor(CL_GREEN, CL_BLACK); canvas.print("UP - aim");
  } else {
    canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.print("below hzn");
  }
  footer("` back  (radio/rotor keep running)");
}

void App::keyArrow(char c, bool enter, bool back) {
  (void)c; (void)enter;
  if (isBack(c, back)) { screen = SCR_TRACK; lastDrawMs = 0; return; }
}

// ===========================================================================
//  "What's overhead now": a synchronous snapshot of every satellite in the GP
//  database that is currently above the horizon, sorted by elevation. A glance-
//  able ambient view reached from the Home menu. Heavy-ish (one look() per sat)
//  but a single pass over the DB, like the GP-age scan on the About screen.
// ===========================================================================
void App::scanOverhead() {
  ovhN = 0; ovhScanned = 0; ovhValid = true;
  if (!timeIsSet()) return;
  pred.setSite(loc.obs());
  time_t now = nowUtc();
  for (int i = 0; i < db.count(); ++i) {
    SatEntry& s = db.at(i);
    ovhScanned++;
    if (!pred.setSat(s)) continue;
    LiveLook L = pred.look(now);
    if (L.el < 0.0) continue;                 // below horizon: skip
    // Insert into the elevation-sorted snapshot (highest first), capped at OVH_MAX.
    // If the list is full and this sat is not higher than the lowest kept, drop it.
    if (ovhN == OVH_MAX && (float)L.el <= ovhEl[OVH_MAX - 1]) continue;
    if (ovhN < OVH_MAX) ovhN++;
    int pos = ovhN - 1;
    while (pos > 0 && ovhEl[pos - 1] < (float)L.el) {
      ovhNorad[pos] = ovhNorad[pos - 1];
      memcpy(ovhName[pos], ovhName[pos - 1], sizeof(ovhName[0]));
      ovhAz[pos] = ovhAz[pos - 1];
      ovhEl[pos] = ovhEl[pos - 1];
      pos--;
    }
    ovhNorad[pos] = s.norad;
    strncpy(ovhName[pos], s.name, sizeof(ovhName[0]) - 1);
    ovhName[pos][sizeof(ovhName[0]) - 1] = 0;
    ovhAz[pos] = (float)L.az;
    ovhEl[pos] = (float)L.el;
  }
  // Restore the propagator to the user's active satellite (we walked the whole DB).
  SatEntry* a = activeSat(); if (a) pred.setSat(*a);
}

void App::drawOverhead() {
  header("Overhead now");
  canvas.setTextSize(1);
  if (!timeIsSet()) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 56); canvas.print("Clock not set (NTP or GPS).");
    footer("` back");
    return;
  }
  if (db.count() == 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 56); canvas.print("No GP data. Run Update.");
    footer("` back");
    return;
  }
  if (!ovhValid) scanOverhead();   // first paint of the visit does the scan

  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, 18); canvas.print("Satellite        El  Az  Dir");

  if (ovhN == 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 44); canvas.print("Nothing above the horizon");
    canvas.setCursor(6, 56); canvas.print("right now. r to rescan.");
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(6, 80); canvas.printf("Scanned %d satellites.", ovhScanned);
    footer("r rescan   ` back");
    return;
  }

  const int ROWS = 9;
  if (ovhScroll > ovhN - ROWS) ovhScroll = ovhN - ROWS;
  if (ovhScroll < 0) ovhScroll = 0;
  for (int r = 0; r < ROWS && (ovhScroll + r) < ovhN; ++r) {
    int i = ovhScroll + r;
    int y = 30 + r * 10;
    // Elevation colour: high = green (easy/overhead), low = yellow (near horizon).
    uint16_t col = (ovhEl[i] >= 30.0f) ? CL_GREEN : CL_YELLOW;
    canvas.setTextColor(col, CL_BLACK);
    canvas.setCursor(4, y);
    canvas.printf("%-15.15s %3.0f %3.0f %-3s",
                  ovhName[i], ovhEl[i], ovhAz[i],
                  windDirName((int)(ovhAz[i] + 0.5f)));
  }
  // Count + scroll indicator.
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, 120);
  canvas.printf("%d up / %d scanned", ovhN, ovhScanned);
  footer("r rescan  ;/. scroll  ` back");
}

void App::keyOverhead(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { ovhValid = false; screen = SCR_HOME; lastDrawMs = 0; return; }
  if (c == 'r') { ovhScroll = 0; scanOverhead(); lastDrawMs = 0; return; }
  if (isUp(c))   { ovhScroll--; lastDrawMs = 0; }
  if (isDown(c)) { ovhScroll++; lastDrawMs = 0; }
}

// ===========================================================================
//  "Zap the Sats" -- a tiny Space-Invaders easter egg. The invaders are
//  satellites; the gun is a ham operator holding an arrow (Yagi) antenna that
//  fires signals upward. Deliberately simple. All state is fixed-size (.bss):
//  no heap, no String, sprites drawn with primitives. Plays in the 240x135
//  canvas like every other screen, animated by a fast redraw branch in loop().
// ===========================================================================

// Play-field geometry.
static const int GAME_TOP    = 18;     // below the header
static const int GAME_BOT    = 128;    // gun baseline
static const int GAME_CELLW  = 34;     // formation cell (px)
static const int GAME_CELLH  = 22;
static const int GAME_INVW   = 22;     // satellite sprite extent
static const int GAME_INVH   = 12;
static const int GAME_GUNW   = 20;

// Draw one satellite sprite at top-left (x,y). Three flavours so the formation
// looks like a mix of birds: 0 = cubesat (body + 2 panels), 1 = drum/AO-style
// (round body + panels), 2 = dish-sat (body + a little dish). Free functions so
// they carry no method overhead; they draw onto the shared canvas passed in.
static void gameDrawSat(M5Canvas& cv, int x, int y, int type) {
  // Solar panels (both sides) -- common to all.
  cv.fillRect(x,        y + 4, 4, 4, CL_BLUE);
  cv.fillRect(x + 18,   y + 4, 4, 4, CL_BLUE);
  cv.drawFastHLine(x - 2, y + 6, 4, CL_DGREY);
  cv.drawFastHLine(x + 20, y + 6, 4, CL_DGREY);
  if (type == 0) {                         // cubesat: yellow body
    cv.fillRect(x + 6, y + 2, 10, 8, CL_YELLOW);
    cv.drawRect(x + 6, y + 2, 10, 8, CL_WHITE);
    cv.drawPixel(x + 11, y, CL_WHITE);     // whip antenna
    cv.drawFastVLine(x + 11, y, 2, CL_WHITE);
  } else if (type == 1) {                   // drum sat: green round body
    cv.fillCircle(x + 11, y + 6, 5, CL_GREEN);
    cv.drawCircle(x + 11, y + 6, 5, CL_WHITE);
    cv.drawPixel(x + 11, y + 6, CL_BLACK);
  } else {                                  // dish sat: cyan body + dish
    cv.fillRect(x + 6, y + 3, 10, 7, CL_CYAN);
    cv.drawRect(x + 6, y + 3, 10, 7, CL_WHITE);
    cv.drawCircle(x + 11, y + 1, 3, CL_WHITE);   // dish
  }
}

// Draw the ham-op gun (head, torso) holding an arrow antenna pointing up. cx is
// the gun centre, base sits on GAME_BOT.
static void gameDrawGun(M5Canvas& cv, int cx) {
  int by = GAME_BOT;
  // Antenna: a vertical boom with a few crossed elements (an arrow/Yagi).
  cv.drawFastVLine(cx, by - 20, 14, CL_WHITE);
  cv.drawFastHLine(cx - 5, by - 18, 11, CL_WHITE);
  cv.drawFastHLine(cx - 4, by - 15, 9,  CL_WHITE);
  cv.drawFastHLine(cx - 3, by - 12, 7,  CL_WHITE);
  // Operator: head + body, holding the boom.
  cv.fillCircle(cx, by - 6, 2, CL_ORANGE);          // head
  cv.drawFastVLine(cx, by - 4, 4, CL_ORANGE);       // torso
  cv.drawLine(cx, by - 3, cx - 3, by, CL_ORANGE);   // legs
  cv.drawLine(cx, by - 3, cx + 3, by, CL_ORANGE);
  cv.drawLine(cx, by - 4, cx, by - 8, CL_ORANGE);   // arm up to the boom
}

void App::gameReset(bool full) {
  if (full) { gScore = 0; gLives = 3; gLevel = 1; }
  else      { gLevel++; }
  gInvAliveN = GAME_INV;
  for (int i = 0; i < GAME_INV; ++i) { gInvAlive[i] = 1; gInvType[i] = (uint8_t)(i % 3); }
  gInvLeft = 6; gInvTop = GAME_TOP + 6; gInvDir = 1;
  for (int i = 0; i < GAME_SHOTS; ++i) gShotY[i] = -1;
  gGunX = 120;
  gStepMs = gFrameMs = millis();
  gState = 1;                                  // playing
}

void App::gameStep() {
  // March the formation: shift sideways; on hitting an edge, drop and reverse.
  // Speed scales with how few invaders remain and with the level (classic feel).
  int liveCols[GAME_COLS]; for (int c = 0; c < GAME_COLS; ++c) liveCols[c] = 0;
  for (int i = 0; i < GAME_INV; ++i) if (gInvAlive[i]) liveCols[i % GAME_COLS] = 1;
  int firstCol = -1, lastCol = -1;
  for (int c = 0; c < GAME_COLS; ++c) if (liveCols[c]) { if (firstCol < 0) firstCol = c; lastCol = c; }
  if (firstCol < 0) return;

  int blockL = gInvLeft + firstCol * GAME_CELLW;
  int blockR = gInvLeft + lastCol * GAME_CELLW + GAME_INVW;
  bool hitEdge = (gInvDir > 0 && blockR >= 236) || (gInvDir < 0 && blockL <= 4);
  if (hitEdge) {
    gInvDir = -gInvDir;
    gInvTop += 8;                              // descend a row
  } else {
    gInvLeft += gInvDir * 4;
  }

  // Did they reach the gun line? That's a life lost (and a reset of the wave pos).
  int blockBottom = gInvTop + (GAME_ROWS - 1) * GAME_CELLH + GAME_INVH;
  if (blockBottom >= GAME_BOT - 8) {
    if (--gLives <= 0) { gState = 3; sfx(200, 300); return; }   // game over
    sfx(400, 150);                              // life lost
    // Reset formation position but keep remaining invaders.
    gInvLeft = 6; gInvTop = GAME_TOP + 6; gInvDir = 1;
  }
}

void App::drawGame() {
  uint32_t ms = millis();
  // Advance shots every frame (~fast), formation on a slower cadence that speeds
  // up as the wave thins out.
  if (gState == 1) {
    // Shots travel up each frame.
    if (ms - gFrameMs >= 40) {
      gFrameMs = ms;
      for (int s = 0; s < GAME_SHOTS; ++s) {
        if (gShotY[s] < 0) continue;
        gShotY[s] -= 6;
        if (gShotY[s] < GAME_TOP) { gShotY[s] = -1; continue; }
        // Collision: which formation cell is the shot in?
        for (int i = 0; i < GAME_INV; ++i) {
          if (!gInvAlive[i]) continue;
          int ix = gInvLeft + (i % GAME_COLS) * GAME_CELLW;
          int iy = gInvTop  + (i / GAME_COLS) * GAME_CELLH;
          if (gShotX[s] >= ix - 2 && gShotX[s] <= ix + GAME_INVW + 2 &&
              gShotY[s] >= iy      && gShotY[s] <= iy + GAME_INVH) {
            gInvAlive[i] = 0; gShotY[s] = -1;
            gScore += 10 * gLevel; gInvAliveN--;
            sfx(900, 10);
            if (gInvAliveN <= 0) { gState = 2; sfx(1800, 120); }   // wave cleared
            break;
          }
        }
      }
    }
    int stepEvery = 220 - gLevel * 20 - (GAME_INV - gInvAliveN) * 8;
    if (stepEvery < 50) stepEvery = 50;
    if (ms - gStepMs >= (uint32_t)stepEvery) { gStepMs = ms; gameStep(); }

    // Optional tilt steering: roll left/right moves the gun a few px per frame.
    float lr;
    if (gameTiltAxis(lr)) {
      gGunX += (int)(lr * 7);
      if (gGunX < 8) gGunX = 8; if (gGunX > 232) gGunX = 232;
    }
  }

  header("Zap the Sats");
  canvas.setTextSize(1);

  // HUD: score and lives on one line under the header.
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, 18);  canvas.printf("Score %d", gScore);
  canvas.setCursor(150, 18); canvas.printf("Lvl %d", gLevel);
  { char lv[8]; int n = gLives < 0 ? 0 : gLives; if (n > 5) n = 5;
    for (int i = 0; i < n; ++i) lv[i] = 'A'; lv[n] = 0;
    canvas.setTextColor(CL_ORANGE, CL_BLACK);
    canvas.setCursor(206, 18); canvas.printf("%s", lv); }   // 'A' glyphs ~ little antennas

  if (gState == 0) {                          // attract screen
    canvas.setTextColor(CL_CYAN, CL_BLACK);
    canvas.setCursor(36, 50); canvas.print("ZAP THE SATS");
    canvas.setTextColor(CL_WHITE, CL_BLACK);
    canvas.setCursor(14, 70); canvas.print("T / U  move    SPACE fire");
    canvas.setCursor(40, 84); canvas.print("ENTER to start");
    gameDrawGun(canvas, 120);
    footer("ENTER start   ` back");
    return;
  }
  if (gState == 3) {                          // game over
    canvas.setTextColor(CL_RED, CL_BLACK);
    canvas.setCursor(48, 54); canvas.print("GAME OVER");
    canvas.setTextColor(CL_WHITE, CL_BLACK);
    canvas.setCursor(54, 72); canvas.printf("Score %d", gScore);
    footer("ENTER retry   ` back");
    return;
  }
  if (gState == 2) {                          // wave cleared
    canvas.setTextColor(CL_GREEN, CL_BLACK);
    canvas.setCursor(28, 60); canvas.print("WAVE CLEARED!");
    footer("ENTER next wave  ` back");
    return;
  }

  // Playing: draw invaders, shots, gun.
  for (int i = 0; i < GAME_INV; ++i) {
    if (!gInvAlive[i]) continue;
    int ix = gInvLeft + (i % GAME_COLS) * GAME_CELLW;
    int iy = gInvTop  + (i / GAME_COLS) * GAME_CELLH;
    gameDrawSat(canvas, ix, iy, gInvType[i]);
  }
  for (int s = 0; s < GAME_SHOTS; ++s) {
    if (gShotY[s] < 0) continue;
    canvas.drawFastVLine(gShotX[s], gShotY[s], 4, CL_YELLOW);
    canvas.drawPixel(gShotX[s], gShotY[s], CL_WHITE);
  }
  gameDrawGun(canvas, gGunX);
  footer("T/U move  SPACE fire  ` back");
}

void App::keyGame(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_ABOUT; lastDrawMs = 0; return; }

  if (gState != 1) {                          // attract / over / wave: ENTER advances
    if (enter) {
      if (gState == 2) gameReset(false);      // next wave keeps score/lives
      else             gameReset(true);       // attract or game-over: fresh game
      lastDrawMs = 0;
    }
    return;
  }

  // Playing. Ergonomic two-hand keys: T = left, U = right (one under each hand;
  // chosen over F/H because 'h' is the global Help key). SPACE = fire. Legacy
  // , . / kept as aliases. Tilt (if enabled + ADV) also steers, per frame in drawGame().
  if (isLeft(c) || c == 't' || c == 'T')  { gGunX -= 8; if (gGunX < 8)   gGunX = 8;   lastDrawMs = 0; return; }
  if (isRight(c) || c == 'u' || c == 'U') { gGunX += 8; if (gGunX > 232) gGunX = 232; lastDrawMs = 0; return; }
  if (c == ' ') {                             // fire: use a free shot slot
    for (int s = 0; s < GAME_SHOTS; ++s) {
      if (gShotY[s] < 0) { gShotX[s] = gGunX; gShotY[s] = GAME_BOT - 22; sfx(1600, 8); break; }
    }
    lastDrawMs = 0; return;
  }
}

// ===========================================================================
//  Shared game helpers + Games menu + five satellite-themed mini-games.
//  Every game keeps ALL state in fixed .bss members (declared in app.h): no
//  heap, no String in the loop, sprites drawn with canvas primitives. Sound is
//  gated on cfg.gameSound; tilt steering on cfg.gameTilt + imuReady (ADV-only,
//  with keyboard fallback everywhere). See docs/design/GAMES_AND_QRZ_GRID_SCOPE.md.
// ===========================================================================

// Gated sound effect: a short speaker tone, only if the user enabled game sound.
// tone() is fire-and-forget (the speaker task plays it), so it does not block the
// ~25 fps game loop.
void App::sfx(uint16_t freq, uint16_t ms) {
  if (!cfg.gameSound) return;
  // Play the tone. tone() lazily allocates the speaker's I2S DMA buffer on first use;
  // that's fine here because game sound and network fetches never overlap (both are
  // modal/user-driven), and the fetch trampoline releases the speaker buffer before any
  // TLS handshake regardless. Stop any prior tone so rapid game effects don't overlap.
  M5Cardputer.Speaker.stop();
  M5Cardputer.Speaker.tone(freq, ms);
}

// Tilt left/right signal in [-1, +1] (negative = roll left). Returns false when
// tilt isn't usable (disabled, or no IMU), so callers fall back to keys. Reuses
// the accel convention from serviceTiltTune(): roll about the long axis moves one
// horizontal component through +/-1 g; a light LPF + dead-zone keeps a hand-held
// device from creeping.
bool App::gameTiltAxis(float& outLR) {
  if (!cfg.gameTilt || !imuReady) return false;
  float ax = 0, ay = 0, az = 0;
  if (!M5.Imu.getAccel(&ax, &ay, &az)) return false;
  static float filt = 0;
  filt += 0.35f * (ax - filt);
  const float DEAD = 0.10f, FULL = 0.55f;
  float mag = fabsf(filt);
  if (mag <= DEAD) { outLR = 0; return true; }
  float norm = (mag - DEAD) / (FULL - DEAD); if (norm > 1) norm = 1;
  // Negate so the on-screen motion follows the physical roll direction (bench
  // testing showed the raw ax sign moves opposite the tilt on this board).
  outLR = (filt < 0 ? norm : -norm);
  return true;
}

// --- Games menu ------------------------------------------------------------
static const char* const GAMES_NAMES[] = {
  "Zap the Sats", "Doppler Lock", "Catch the Pass", "Rotor Runner",
  "Morse Meteors", "Grid Chase"
};
static const int GAMES_N = 6;

void App::drawGamesMenu() {
  header("Games");
  canvas.setTextSize(1);
  for (int i = 0; i < GAMES_N; ++i) {
    int y = 22 + i * 15;
    bool sel = (i == gamesSel);
    if (sel) canvas.fillRect(2, y - 2, 236, 13, CL_SELBG);
    canvas.setTextColor(sel ? CL_BLACK : CL_WHITE, sel ? CL_SELBG : CL_BLACK);
    canvas.setCursor(10, y); canvas.print(GAMES_NAMES[i]);
  }
  footer("UP/DN pick  ENTER play  ` back");
}

void App::keyGamesMenu(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_ABOUT; lastDrawMs = 0; return; }
  if (isUp(c))   { if (--gamesSel < 0) gamesSel = GAMES_N - 1; lastDrawMs = 0; return; }
  if (isDown(c)) { if (++gamesSel >= GAMES_N) gamesSel = 0; lastDrawMs = 0; return; }
  if (enter) {
    switch (gamesSel) {
      case 0: gState = 0; screen = SCR_GAME;     break;   // Zap (its own attract via gState 0)
      case 1: gDopplerReset(); screen = SCR_GDOPPLER; break;
      case 2: gPassReset();    screen = SCR_GPASS;    break;
      case 3: gRotorReset();   screen = SCR_GROTOR;   break;
      case 4: gMorseReset();   screen = SCR_GMORSE;   break;
      case 5: gGridReset();    screen = SCR_GGRID;    break;
    }
    lastDrawMs = 0;
  }
}

// ===========================================================================
//  G1. Doppler Lock -- hold your marker on a frequency that drifts along a
//  Doppler-like S-curve, as if tuning a linear transponder through a pass.
//  Left/right (keys A/L or , /) or tilt nudge the cursor; score accrues while
//  the cursor stays within the "passband" around the target.
// ===========================================================================
void App::gDopplerReset() {
  gScore = 0; gLevel = 1; gLives = 3;
  gdlCursor = 0.5f; gdlVel = 0; gdlPhase = 0; gdlTarget = 0.5f;
  gdlInMs = 0; gdlLastMs = millis();
  gState = 1;
}

void App::drawGDoppler() {
  uint32_t ms = millis();
  if (gState == 1) {
    float dt = (ms - gdlLastMs) / 1000.0f; if (dt > 0.15f) dt = 0.15f; gdlLastMs = ms;
    // Target drifts on a sine (Doppler curve); speed rises with level.
    gdlPhase += dt * (0.5f + gdlLevelRate());
    gdlTarget = 0.5f + 0.42f * sinf(gdlPhase);
    // Cursor: apply tilt or momentum from keys, with light damping.
    float lr;
    if (gameTiltAxis(lr)) gdlVel = lr * 0.9f;
    gdlCursor += gdlVel * dt;
    gdlVel *= 0.90f;                                   // damping so key taps ease off
    if (gdlCursor < 0) { gdlCursor = 0; gdlVel = 0; }
    if (gdlCursor > 1) { gdlCursor = 1; gdlVel = 0; }
    // Scoring: in-band if within the passband half-width (narrows with level).
    float halfBW = 0.09f - gLevel * 0.006f; if (halfBW < 0.035f) halfBW = 0.035f;
    bool inBand = fabsf(gdlCursor - gdlTarget) <= halfBW;
    if (inBand) { gdlInMs += (uint32_t)(dt * 1000); gScore += 1;
                  if ((gScore % 300) == 0 && gLevel < 9) { gLevel++; sfx(1500, 40); } }
    // Level up by time-in-band milestones handled via score above.
  }

  header("Doppler Lock");
  canvas.setTextSize(1);
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, 18); canvas.printf("Score %d", gScore);
  canvas.setCursor(180, 18); canvas.printf("Lvl %d", gLevel);

  if (gState != 1) {
    canvas.setTextColor(CL_CYAN, CL_BLACK);
    canvas.setCursor(30, 44); canvas.print(gState == 0 ? "DOPPLER LOCK" : "TIME'S UP");
    canvas.setTextColor(CL_WHITE, CL_BLACK);
    canvas.setCursor(8, 64);  canvas.print("Keep signal on the drifting");
    canvas.setCursor(8, 76);  canvas.print("bird. A / L or tilt to tune.");
    canvas.setCursor(50, 92); canvas.printf("Score %d", gScore);
    footer("ENTER play   ` back");
    return;
  }

  // The band: a horizontal tuning dial across the screen.
  int x0 = 16, x1 = 224, yb = 78;
  canvas.drawFastHLine(x0, yb, x1 - x0, CL_DGREY);
  // Passband window around the target.
  float halfBW = 0.09f - gLevel * 0.006f; if (halfBW < 0.035f) halfBW = 0.035f;
  int tw0 = x0 + (int)((gdlTarget - halfBW) * (x1 - x0));
  int tw1 = x0 + (int)((gdlTarget + halfBW) * (x1 - x0));
  if (tw0 < x0) tw0 = x0; if (tw1 > x1) tw1 = x1;
  canvas.fillRect(tw0, yb - 12, tw1 - tw0, 24, CL_DGREEN);
  // Target centre (the bird's signal).
  int tx = x0 + (int)(gdlTarget * (x1 - x0));
  canvas.drawFastVLine(tx, yb - 16, 32, CL_GREEN);
  // Cursor (your signal).
  int cx = x0 + (int)(gdlCursor * (x1 - x0));
  bool inBand = fabsf(gdlCursor - gdlTarget) <= halfBW;
  canvas.fillTriangle(cx, yb - 18, cx - 5, yb - 26, cx + 5, yb - 26, inBand ? CL_CYAN : CL_RED);
  canvas.drawFastVLine(cx, yb - 18, 36, inBand ? CL_CYAN : CL_RED);
  // A little "signal meter" when locked.
  canvas.setTextColor(inBand ? CL_GREEN : CL_GREY, CL_BLACK);
  canvas.setCursor(96, 108); canvas.print(inBand ? "* LOCK *" : "  ...  ");
  footer("A / L tune   ` back");
}

// Level-scaled drift rate (rad/s add-on). Kept as a helper so the speed curve is
// in one place.
float App::gdlLevelRate() { return 0.15f * gLevel; }

void App::keyGDoppler(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_GAMES; gamesSel = 1; lastDrawMs = 0; return; }
  if (gState != 1) { if (enter) { gDopplerReset(); lastDrawMs = 0; } return; }
  if (isLeft(c)  || c == 'a' || c == 'A') { gdlVel -= 0.5f; lastDrawMs = 0; return; }
  if (isRight(c) || c == 'l' || c == 'L') { gdlVel += 0.5f; lastDrawMs = 0; return; }
}

// ===========================================================================
//  G2. Catch the Pass -- a satellite arcs across a sky dome; press SPACE while
//  it is above the elevation window (the "workable" part of the pass) to log a
//  QSO. Mistime it and you miss. Windows get tighter as the score climbs.
// ===========================================================================
void App::gPassReset() {
  gScore = 0; gLevel = 1; gpMisses = 0;
  gpT = 0; gpPhase = 0; gpArcMs = millis();
  gState = 1;
}

void App::drawGPass() {
  uint32_t ms = millis();
  if (gState == 1) {
    float dt = (ms - gpArcMs) / 1000.0f; if (dt > 0.15f) dt = 0.15f; gpArcMs = ms;
    // Arc parameter 0..1 across the sky; speed rises with level.
    gpT += dt * (0.18f + 0.03f * gLevel);
    if (gpT >= 1.0f) {                       // sat set without a QSO -> a miss
      gpT = 0; if (++gpMisses >= 5) { gState = 3; sfx(200, 300); }
      else sfx(350, 120);
    }
  }

  header("Catch the Pass");
  canvas.setTextSize(1);
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, 18); canvas.printf("QSOs %d", gScore);
  canvas.setCursor(150, 18); canvas.printf("Miss %d/5", gpMisses);

  if (gState != 1) {
    canvas.setTextColor(CL_CYAN, CL_BLACK);
    canvas.setCursor(28, 44); canvas.print(gState == 0 ? "CATCH THE PASS" : "GAME OVER");
    canvas.setTextColor(CL_WHITE, CL_BLACK);
    canvas.setCursor(8, 64);  canvas.print("Key up (SPACE) as the bird");
    canvas.setCursor(8, 76);  canvas.print("crosses the green window.");
    canvas.setCursor(50, 92); canvas.printf("QSOs %d", gScore);
    footer("ENTER play   ` back");
    return;
  }

  // Sky dome: a half-circle horizon (plotted as points, no drawCircleHelper
  // dependency) with an elevation window band.
  int cx = 120, cy = 120, R = 92;
  for (float a = 0; a <= 3.14159f; a += 0.05f) {
    int px = cx + (int)(R * cosf(a));
    int py = cy - (int)(R * sinf(a));
    canvas.drawPixel(px, py, CL_DGREY);
  }
  canvas.drawFastHLine(cx - R, cy, 2 * R, CL_DGREY);
  // Elevation window: an arc segment near the top (the workable elevation band).
  // Represent the window as a parameter range [w0,w1] along the arc.
  float w0 = 0.42f, w1 = 0.58f;
  float halfW = 0.08f - gLevel * 0.006f; if (halfW < 0.03f) halfW = 0.03f;
  w0 = 0.5f - halfW; w1 = 0.5f + halfW;
  // Draw the window as a thick arc chunk by plotting points.
  for (float t = w0; t <= w1; t += 0.01f) {
    float ang = 3.14159f * (1.0f - t);                    // pi..0 left-to-right
    int px = cx + (int)(R * cosf(ang));
    int py = cy - (int)(R * sinf(ang));
    canvas.fillCircle(px, py, 2, CL_DGREEN);
  }
  // The satellite along the arc.
  float ang = 3.14159f * (1.0f - gpT);
  int sx = cx + (int)(R * cosf(ang));
  int sy = cy - (int)(R * sinf(ang));
  bool inWin = (gpT >= w0 && gpT <= w1);
  gameDrawSat(canvas, sx - 11, sy - 6, 0);
  if (inWin) { canvas.drawCircle(sx, sy, 10, CL_GREEN); }
  // Ground station at the centre baseline.
  gameDrawGun(canvas, cx);
  canvas.setTextColor(inWin ? CL_GREEN : CL_GREY, CL_BLACK);
  canvas.setCursor(86, 30); canvas.print(inWin ? "WORKABLE" : "        ");
  footer("SPACE key up   ` back");
}

void App::keyGPass(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_GAMES; gamesSel = 2; lastDrawMs = 0; return; }
  if (gState != 1) { if (enter) { gPassReset(); lastDrawMs = 0; } return; }
  if (c == ' ') {
    float halfW = 0.08f - gLevel * 0.006f; if (halfW < 0.03f) halfW = 0.03f;
    bool inWin = (gpT >= 0.5f - halfW && gpT <= 0.5f + halfW);
    if (inWin) { gScore++; sfx(1400, 40); if ((gScore % 5) == 0 && gLevel < 9) { gLevel++; sfx(1800, 80); }
                 gpT = 0; }                              // logged -> next bird
    else { if (++gpMisses >= 5) { gState = 3; sfx(200, 300); } else sfx(300, 100); }
    lastDrawMs = 0; return;
  }
}

// ===========================================================================
//  G3. Rotor Runner -- a satellite drifts around the sky; slew your antenna
//  crosshair (tilt pitch+roll, or arrow keys) to keep it centred on the bird.
//  Score accrues while the crosshair is on target. A genuine two-axis IMU game.
// ===========================================================================
void App::gRotorReset() {
  gScore = 0; gLevel = 1; gLives = 3;
  grSatX = 120; grSatY = 74; grCurX = 120; grCurY = 74;
  grSatVX = 22; grSatVY = 14; grOnMs = 0; grLastMs = millis();
  gState = 1;
}

void App::drawGRotor() {
  uint32_t ms = millis();
  const int X0 = 12, X1 = 228, Y0 = 24, Y1 = 124;
  if (gState == 1) {
    float dt = (ms - grLastMs) / 1000.0f; if (dt > 0.15f) dt = 0.15f; grLastMs = ms;
    // Bird wanders, bouncing off the field edges; speed scales with level.
    float sp = 1.0f + 0.15f * gLevel;
    grSatX += grSatVX * dt * sp; grSatY += grSatVY * dt * sp;
    if (grSatX < X0) { grSatX = X0; grSatVX = fabsf(grSatVX); }
    if (grSatX > X1) { grSatX = X1; grSatVX = -fabsf(grSatVX); }
    if (grSatY < Y0) { grSatY = Y0; grSatVY = fabsf(grSatVY); }
    if (grSatY > Y1) { grSatY = Y1; grSatVY = -fabsf(grSatVY); }
    // Occasionally jink so it isn't perfectly predictable.
    if ((esp_random() & 0x3F) == 0) { grSatVX += ((int)(esp_random() % 21) - 10); grSatVY += ((int)(esp_random() % 21) - 10); }
    // Crosshair: tilt (pitch on ay, roll on ax) if available, else keys move it.
    float ax = 0, ay = 0, az = 0;
    if (cfg.gameTilt && imuReady && M5.Imu.getAccel(&ax, &ay, &az)) {
      // Roll (ax) steers X to match physical tilt; pitch (ay) steers Y. Y is
      // NOT negated (bench: inverting both made up/down feel backwards).
      grCurX -= ax * 160 * dt;
      grCurY += ay * 160 * dt;
    }
    if (grCurX < X0) grCurX = X0; if (grCurX > X1) grCurX = X1;
    if (grCurY < Y0) grCurY = Y0; if (grCurY > Y1) grCurY = Y1;
    // On-target test.
    float dx = grCurX - grSatX, dy = grCurY - grSatY;
    float dist = sqrtf(dx * dx + dy * dy);
    bool on = dist < 14;
    if (on) { grOnMs += (uint32_t)(dt * 1000); gScore += 1;
              if ((gScore % 250) == 0 && gLevel < 9) { gLevel++; sfx(1600, 50); } }
  }

  header("Rotor Runner");
  canvas.setTextSize(1);
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, 18); canvas.printf("Score %d", gScore);
  canvas.setCursor(180, 18); canvas.printf("Lvl %d", gLevel);

  if (gState != 1) {
    canvas.setTextColor(CL_CYAN, CL_BLACK);
    canvas.setCursor(34, 44); canvas.print(gState == 0 ? "ROTOR RUNNER" : "DONE");
    canvas.setTextColor(CL_WHITE, CL_BLACK);
    canvas.setCursor(8, 64);  canvas.print("Keep the crosshair on the");
    canvas.setCursor(8, 76);  canvas.print("bird. Tilt or arrow keys.");
    canvas.setCursor(50, 92); canvas.printf("Score %d", gScore);
    footer("ENTER play   ` back");
    return;
  }

  float dx = grCurX - grSatX, dy = grCurY - grSatY;
  bool on = sqrtf(dx * dx + dy * dy) < 14;
  gameDrawSat(canvas, (int)grSatX - 11, (int)grSatY - 6, 1);
  // Crosshair.
  uint8_t cc = on ? CL_GREEN : CL_ORANGE;
  canvas.drawCircle((int)grCurX, (int)grCurY, 12, cc);
  canvas.drawFastHLine((int)grCurX - 16, (int)grCurY, 32, cc);
  canvas.drawFastVLine((int)grCurX, (int)grCurY - 16, 32, cc);
  footer(cfg.gameTilt ? "tilt to track   ` back" : "arrows track   ` back");
}

void App::keyGRotor(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_GAMES; gamesSel = 3; lastDrawMs = 0; return; }
  if (gState != 1) { if (enter) { gRotorReset(); lastDrawMs = 0; } return; }
  // Keyboard fallback / assist (works alongside tilt).
  const float STEP = 10;
  if (isLeft(c)  || c == 'a' || c == 'A') { grCurX -= STEP; lastDrawMs = 0; }
  if (isRight(c) || c == 'l' || c == 'L') { grCurX += STEP; lastDrawMs = 0; }
  if (isUp(c))   { grCurY -= STEP; lastDrawMs = 0; }
  if (isDown(c)) { grCurY += STEP; lastDrawMs = 0; }
}

// ===========================================================================
//  G4. Morse Meteors -- letters fall; clear each by keying its Morse code.
//  Key with two keys: '.' (or ',') = dot, '/' (or SPACE) = dash. The buffer is
//  matched against the lowest letter's code; a correct full code clears it.
//  A small const Morse table lives in flash. Ties into CW satellite operating.
// ===========================================================================
static const char* const MORSE_TBL[26] = {
  ".-","-...","-.-.","-..",".","..-.","--.","....","..",".---",  // A-J
  "-.-",".-..","--","-.","---",".--.","--.-",".-.","...","-",     // K-T
  "..-","...-",".--","-..-","-.--","--.."                         // U-Z
};

void App::gMorseReset() {
  gScore = 0; gLevel = 1; gLives = 3;
  for (int i = 0; i < GMOR_MAX; ++i) { gmLetter[i] = -1; gmY[i] = 0; gmX[i] = 0; }
  gmTypeN = 0; gmType[0] = 0; gmSpawnMs = millis();
  gState = 1;
}

void App::drawGMorse() {
  uint32_t ms = millis();
  if (gState == 1) {
    // Spawn cadence: faster with level. Use a spawn timer rather than dt here.
    static uint32_t lastSpawn = 0;
    uint32_t spawnEvery = 2600 - gLevel * 150; if (spawnEvery < 900) spawnEvery = 900;
    if (ms - lastSpawn > spawnEvery) {
      lastSpawn = ms;
      for (int i = 0; i < GMOR_MAX; ++i) if (gmLetter[i] < 0) {
        gmLetter[i] = (int8_t)(esp_random() % 26);
        gmX[i] = 20 + (int)(esp_random() % 200);
        gmY[i] = 22;
        break;
      }
    }
    // Fall. Speed scales with level.
    float fall = (12.0f + gLevel * 2.0f);                 // px/sec
    static uint32_t lastFall = 0; if (lastFall == 0) lastFall = ms;
    float fdt = (ms - lastFall) / 1000.0f; if (fdt > 0.15f) fdt = 0.15f; lastFall = ms;
    for (int i = 0; i < GMOR_MAX; ++i) {
      if (gmLetter[i] < 0) continue;
      gmY[i] += fall * fdt;
      if (gmY[i] >= 118) {                                // hit the ground -> life lost
        gmLetter[i] = -1; gmTypeN = 0; gmType[0] = 0;
        if (--gLives <= 0) { gState = 3; sfx(200, 300); }
        else sfx(350, 150);
      }
    }
  }

  header("Morse Meteors");
  canvas.setTextSize(1);
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, 18); canvas.printf("Score %d", gScore);
  { char lv[8]; int n = gLives < 0 ? 0 : (gLives > 5 ? 5 : gLives);
    for (int i = 0; i < n; ++i) lv[i] = 'A'; lv[n] = 0;
    canvas.setTextColor(CL_ORANGE, CL_BLACK); canvas.setCursor(206, 18); canvas.print(lv); }

  if (gState != 1) {
    canvas.setTextColor(CL_CYAN, CL_BLACK);
    canvas.setCursor(30, 40); canvas.print(gState == 0 ? "MORSE METEORS" : "GAME OVER");
    canvas.setTextColor(CL_WHITE, CL_BLACK);
    canvas.setCursor(6, 58); canvas.printf("%c = dot   %c = dash",
                     cfg.morseSwap ? 'U' : 'T', cfg.morseSwap ? 'T' : 'U');
    canvas.setCursor(6, 72); canvas.print("Key the lowest letter's code.");
    canvas.setCursor(50, 90); canvas.printf("Score %d", gScore);
    footer("ENTER play   ` back");
    return;
  }

  // Falling letters.
  int lowest = -1; float lowY = -1;
  for (int i = 0; i < GMOR_MAX; ++i) {
    if (gmLetter[i] < 0) continue;
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(gmX[i], (int)gmY[i]);
    canvas.printf("%c", 'A' + gmLetter[i]);
    // Also show that letter's Morse dimly under it.
    canvas.setTextColor(CL_DGREY, CL_BLACK);
    canvas.setCursor(gmX[i] - 6, (int)gmY[i] + 10); canvas.print(MORSE_TBL[gmLetter[i]]);
    if (gmY[i] > lowY) { lowY = gmY[i]; lowest = i; }
  }
  // Ground line + typed buffer.
  canvas.drawFastHLine(0, 120, 240, CL_DGREY);
  canvas.setTextColor(CL_CYAN, CL_BLACK);
  canvas.setCursor(6, 124); canvas.printf("Key: %s", gmType);
  if (lowest >= 0) {
    canvas.setTextColor(CL_GREEN, CL_BLACK);
    canvas.setCursor(150, 124); canvas.printf("-> %c", 'A' + gmLetter[lowest]);
  }
  footer(cfg.morseSwap ? "U dot  T dash   ` back" : "T dot  U dash   ` back");
}

void App::keyGMorse(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_GAMES; gamesSel = 4; lastDrawMs = 0; return; }
  if (gState != 1) { if (enter) { gMorseReset(); lastDrawMs = 0; } return; }
  // T = dot, U = dash by default; cfg.morseSwap flips them for the other convention.
  // (T/U chosen over F/H because 'h' is the global Help key.) Legacy . , (dot) and
  // / SPACE (dash) still work regardless of the swap.
  bool tDot = !cfg.morseSwap;                       // which of T/U is the dot
  bool dot  = (c == '.' || c == ',') || (tDot  ? (c == 't' || c == 'T') : (c == 'u' || c == 'U'));
  bool dash = (c == '/' || c == ' ') || (tDot  ? (c == 'u' || c == 'U') : (c == 't' || c == 'T'));
  if (!dot && !dash) return;
  if (gmTypeN < sizeof(gmType) - 1) { gmType[gmTypeN++] = dot ? '.' : '-'; gmType[gmTypeN] = 0; }
  // Real CW sidetone: same pitch for both, dash is 3x the dot length.
  sfx(700, dot ? 60 : 180);
  // Find the lowest letter and test the buffer against its code.
  int lowest = -1; float lowY = -1;
  for (int i = 0; i < GMOR_MAX; ++i) { if (gmLetter[i] < 0) continue; if (gmY[i] > lowY) { lowY = gmY[i]; lowest = i; } }
  if (lowest < 0) { gmTypeN = 0; gmType[0] = 0; lastDrawMs = 0; return; }
  const char* code = MORSE_TBL[gmLetter[lowest]];
  if (strcmp(gmType, code) == 0) {                        // cleared!
    gmLetter[lowest] = -1; gmTypeN = 0; gmType[0] = 0;
    gScore += 10; sfx(1200, 90);
    if ((gScore % 100) == 0 && gLevel < 9) { gLevel++; sfx(1600, 120); }
  } else if (strncmp(gmType, code, gmTypeN) != 0) {       // wrong prefix -> reset buffer
    gmTypeN = 0; gmType[0] = 0; sfx(300, 60);
  }
  lastDrawMs = 0;
}

// ===========================================================================
//  G5. Grid Chase -- a Maidenhead grid is shown; pick the correct location
//  description... actually pick the correct GRID for a shown lat/lon hint from
//  four options, against a countdown. A grid-square trainer. Not frame-animated;
//  a periodic redraw ticks the timer.
// ===========================================================================
void App::gGridReset() {
  gScore = 0; ggStreak = 0;
  gState = 1;
  ggNewRound();
}

// Build a fresh round: pick a random real-ish grid as the answer, plus 3 distractors.
void App::ggNewRound() {
  // Random lat/lon on land-ish latitudes, convert to a grid via the real routine.
  auto randGrid = [&](char* out) {
    double lat = ((int)(esp_random() % 14000) - 7000) / 100.0;   // -70..+70
    double lon = ((int)(esp_random() % 36000) - 18000) / 100.0;  // -180..+180
    String g = Location::toGrid(lat, lon);
    strncpy(out, g.c_str(), 7); out[7] = 0;
  };
  randGrid(ggGrid);
  ggCorrect = (uint8_t)(esp_random() % 4);
  for (int i = 0; i < 4; ++i) {
    if (i == ggCorrect) { strncpy(ggOpt[i], ggGrid, 7); ggOpt[i][7] = 0; }
    else { char g[8]; do { randGrid(g); } while (strcmp(g, ggGrid) == 0); strncpy(ggOpt[i], g, 7); ggOpt[i][7] = 0; }
  }
  ggSel = 0;
  ggDeadline = millis() + 8000;                           // 8 s to answer
}

void App::drawGGrid() {
  uint32_t ms = millis();
  if (gState == 1 && ms > ggDeadline) {                   // timed out -> streak resets, next
    ggStreak = 0; sfx(300, 150); ggNewRound();
  }

  header("Grid Chase");
  canvas.setTextSize(1);
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, 18); canvas.printf("Score %d", gScore);
  canvas.setCursor(150, 18); canvas.printf("Streak %d", ggStreak);

  if (gState != 1) {
    canvas.setTextColor(CL_CYAN, CL_BLACK);
    canvas.setCursor(48, 44); canvas.print("GRID CHASE");
    canvas.setTextColor(CL_WHITE, CL_BLACK);
    canvas.setCursor(6, 64);  canvas.print("Match the grid to the map dot.");
    canvas.setCursor(50, 82); canvas.printf("Score %d", gScore);
    footer("ENTER play   ` back");
    return;
  }

  // Draw a tiny world rectangle with the target grid's location as a dot.
  int mx = 130, my = 30, mw = 100, mh = 50;
  canvas.drawRect(mx, my, mw, mh, CL_DGREY);
  canvas.drawFastVLine(mx + mw / 2, my, mh, CL_DGREY);    // prime meridian
  canvas.drawFastHLine(mx, my + mh / 2, mw, CL_DGREY);    // equator
  double dlat, dlon;
  if (Location::gridToLatLon(ggGrid, dlat, dlon)) {
    int px = mx + (int)((dlon + 180.0) / 360.0 * mw);
    int py = my + (int)((90.0 - dlat) / 180.0 * mh);
    canvas.fillCircle(px, py, 3, CL_RED);
  }
  // Countdown bar.
  long remain = (long)ggDeadline - (long)ms; if (remain < 0) remain = 0;
  int bw = (int)(remain * 116 / 8000);
  canvas.drawRect(6, 80, 118, 7, CL_DGREY);
  canvas.fillRect(6, 80, bw, 7, remain < 2500 ? CL_RED : CL_DGREEN);

  // Four options. Start higher and keep 9px rows so option 4 clears the footer.
  for (int i = 0; i < 4; ++i) {
    int y = 92 + i * 9;
    bool sel = (i == ggSel);
    if (sel) canvas.fillRect(4, y - 1, 116, 9, CL_SELBG);
    canvas.setTextColor(sel ? CL_BLACK : CL_WHITE, sel ? CL_SELBG : CL_BLACK);
    canvas.setCursor(10, y); canvas.printf("%d. %s", i + 1, ggOpt[i]);
  }
  footer("UP/DN  ENTER pick  ` back");
}

void App::keyGGrid(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_GAMES; gamesSel = 5; lastDrawMs = 0; return; }
  if (gState != 1) { if (enter) { gGridReset(); lastDrawMs = 0; } return; }
  if (isUp(c))   { if (ggSel == 0) ggSel = 3; else ggSel--; lastDrawMs = 0; return; }
  if (isDown(c)) { if (++ggSel > 3) ggSel = 0; lastDrawMs = 0; return; }
  if (c >= '1' && c <= '4') { ggSel = c - '1'; enter = true; }
  if (enter) {
    if (ggSel == ggCorrect) { gScore += 10; ggStreak++; sfx(1600, 60);
                              if (ggStreak % 5 == 0) sfx(2000, 100); }
    else { ggStreak = 0; sfx(300, 150); }
    ggNewRound(); lastDrawMs = 0;
  }
}

// ===========================================================================
//  CAT self-test (Settings -> Radio / CAT -> "Run CAT self-test")
//
//  Exercises every CAT function the active backend exposes and reports a
//  PASS/FAIL/INFO line for each, both on the device screen (SCR_CATTEST) and on
//  the serial monitor at 115200. It is deliberately NON-DESTRUCTIVE:
//    * It never keys the transmitter (PTT is only READ, never set).
//    * It saves the dial state, drives test values, then restores the dial and
//      re-syncs the Doppler send-guards so normal tracking resumes cleanly.
//  Frequency-set "PASS" means the rig accepted the command; where read-back is
//  supported it additionally confirms the value came back within tolerance.
// ===========================================================================

void App::catLog(const String& line) {
  Serial.print("[CAT-TEST] "); Serial.println(line);     // echo to serial monitor
  if (catCount < CATTEST_MAX) catLines[catCount++] = line;
}

void App::catStep(const String& name, bool ok, const String& detail) {
  if (ok) catPass++; else catFail++;
  String l = (ok ? "[PASS] " : "[FAIL] ") + name;
  if (detail.length()) l += ": " + detail;
  catLog(l);
}

void App::runCatTest() {
  catCount = 0; catScroll = 0; catPass = 0; catFail = 0;

  if (!rig || !rig->ready()) {
    catLog("Radio not ready.");
    catLog("Turn CAT on (Track 'r')");
    catLog("or check CAT type/wiring.");
    screen = SCR_CATTEST; lastDrawMs = 0;
    return;
  }

  catLog(String("Rig: ") + rig->name());
  catLog(String("Addr 0x") + String(rig->address(), HEX) +
         "  read=" + (rig->canReadFreq() ? "Y" : "N") +
         " sat=" + (rig->hasSatMode() ? "Y" : "N") +
         " tone=" + (rig->hasTone() ? "Y" : "N"));

  // Save current dial so we can restore it afterwards.
  uint32_t savedRx = lastRxSet, savedUl = lastUlHz;

  // Pick safe in-band test frequencies (2 m downlink, 70 cm uplink). These are
  // RX/standby tunes; we never transmit.
  const uint32_t TEST_DL = 145900000UL;   // 145.900 MHz
  const uint32_t TEST_UL = 435100000UL;   // 435.100 MHz
  const uint32_t TOL     = 50;            // Hz tolerance for read-back compare

  // --- Downlink frequency set (+ read-back verify if supported) ----------
  {
    bool ok = rig->setSubFreq(TEST_DL);
    if (ok && rig->canReadFreq()) {
      uint32_t back = 0;
      if (rig->readSubFreq(back)) {
        uint32_t d = back > TEST_DL ? back - TEST_DL : TEST_DL - back;
        catStep("Downlink set+read", d <= TOL,
                String(back) + " Hz (set " + String(TEST_DL) + ")");
      } else {
        catStep("Downlink set", ok, "set OK, read no-reply");
      }
    } else {
      catStep("Downlink set", ok);
    }
  }

  // --- Uplink frequency set (+ read-back verify if supported) ------------
  {
    bool ok = rig->setMainFreq(TEST_UL);
    if (ok && rig->canReadFreq()) {
      uint32_t back = 0;
      if (rig->readMainFreq(back)) {
        uint32_t d = back > TEST_UL ? back - TEST_UL : TEST_UL - back;
        catStep("Uplink set+read", d <= TOL,
                String(back) + " Hz (set " + String(TEST_UL) + ")");
      } else {
        catStep("Uplink set", ok, "set OK, read no-reply");
      }
    } else {
      catStep("Uplink set", ok);
    }
  }

  // --- Mode set on both legs --------------------------------------------
  catStep("Downlink mode USB", rig->setSubMode(RM_USB));
  catStep("Uplink mode FM",    rig->setMainMode(RM_FM));

  // --- MAIN/SUB band select (Icom: real frames; others: no-op -> INFO) ---
  if (rig->canReadFreq()) {
    rig->selectMainBand();
    rig->selectSubBand();
    catLog("[INFO] Band select sent (MAIN+SUB)");
  }

  // --- Satellite mode toggle (only if the rig has a CAT command) ---------
  if (rig->hasSatMode()) {
    bool on  = rig->enableSatMode(true);
    bool off = rig->enableSatMode(false);   // leave it OFF (CardSat drives bands)
    catStep("Sat mode on/off", on && off);
  } else {
    catLog("[INFO] Sat mode: no CAT cmd");
  }

  // --- PTT / transmit-state read (READ ONLY -- never keys TX) ------------
  {
    bool tx = false;
    if (rig->readPtt(tx)) catStep("PTT read", true, tx ? "TX" : "RX");
    else                  catLog("[INFO] PTT read: not supported");
  }

  // --- CTCSS encoder (only if supported; set a tone then turn it off) -----
  if (rig->hasTone()) {
    bool on  = rig->setCtcss(true, 67.0f);
    bool off = rig->setCtcss(false, 0);     // leave the encoder OFF
    catStep("CTCSS 67.0 on/off", on && off);
  } else {
    catLog("[INFO] CTCSS: not supported");
  }

  // --- Restore the dial and re-sync the Doppler send-guards --------------
  if (savedRx) rig->setSubFreq(savedRx);
  if (savedUl) rig->setMainFreq(savedUl);
  rig->selectSubBand();          // leave access on the downlink for the operator
  lastRxSet = savedRx; lastUlHz = savedUl; uplinkDeferTicks = 0;

  catLog(String("Done: ") + String(catPass) + " pass, " +
         String(catFail) + " fail");

  screen = SCR_CATTEST; lastDrawMs = 0;
}

void App::drawCatTest() {
  header("CAT self-test");
  canvas.setTextSize(1);
  const int rows = 9;
  if (catScroll > catCount - rows) catScroll = catCount - rows;
  if (catScroll < 0) catScroll = 0;
  for (int i = 0; i < rows && (catScroll + i) < catCount; i++) {
    const String& s = catLines[catScroll + i];
    uint16_t col = CL_WHITE;
    if      (s.startsWith("[PASS]")) col = CL_GREEN;
    else if (s.startsWith("[FAIL]")) col = CL_RED;
    else if (s.startsWith("[INFO]")) col = CL_CYAN;
    canvas.setTextColor(col, CL_BLACK);
    canvas.setCursor(4, 20 + i * 12);
    canvas.print(s.substring(0, 38));
  }
  footer("; / . scroll   ` back");
}

void App::keyCatTest(char c, bool enter, bool back) {
  (void)enter;
  if (isUp(c))   { catScroll--; lastDrawMs = 0; }
  if (isDown(c)) { catScroll++; lastDrawMs = 0; }
  if (isBack(c, back)) { setSel = 0; setCat = -1; screen = SCR_SETTINGS; lastDrawMs = 0; return; }
}

// ===========================================================================
//  CAT serial terminal / monitor (SCR_CATMON)
// ===========================================================================
// A diagnostic that shows raw CAT serial traffic (TX and RX, as hex) live on the
// device, for all three wired protocols (CI-V, Yaesu, Kenwood). The operator can
// also type a raw frame in hex and transmit it. It works by registering a trace
// sink that every backend calls on each frame it sends or receives; the sink
// routes through the App singleton (s_self) into a small ring buffer.
//
// WARNING surfaced in the UI and docs: typing raw frames transmits arbitrary
// bytes to the radio. A malformed or wrong-address frame can mis-set the rig.

// Static trampoline matching CatTraceFn; forwards to the live App instance.
void App::catMonTrampoline(const char* dir, const uint8_t* b, size_t n) {
  if (s_self) s_self->catMonPush(dir, b, n);
}

void App::catMonPush(const char* dir, const uint8_t* b, size_t n) {
  bool isTx = (dir && dir[0] == 'T');
  String line;
  for (size_t i = 0; i < n && i < 32; ++i) {
    char h[4]; snprintf(h, sizeof(h), "%02X ", b[i]);
    line += h;
  }
  if (n > 32) line += "...";
  catMonLines[catMonHead] = line;
  catMonIsTx[catMonHead]  = isTx;
  catMonHead = (catMonHead + 1) % CATMON_MAX;
  if (catMonCount < CATMON_MAX) catMonCount++;
  // If the operator is following the tail (scroll 0), stay there; otherwise hold
  // their scroll position by advancing it as the ring rolls.
  if (catMonScroll > 0 && catMonScroll < CATMON_MAX) catMonScroll++;
}

void App::enterCatMon() {
  catMonCount = 0; catMonHead = 0; catMonScroll = 0;
  catMonActive = true;
  catMonLastPollMs = 0;                     // poll immediately on first service tick
  catTraceSink = &App::catMonTrampoline;   // start capturing
  screen = SCR_CATMON; lastDrawMs = 0;
}

void App::drawCatMon() {
  header("CAT serial monitor");
  canvas.setTextSize(1);
  const int rows = 8;
  // Oldest-to-newest index of the ring. tail = most recent line.
  int total = catMonCount;
  int firstShown = total - rows - catMonScroll;   // scroll 0 => show newest rows
  if (firstShown < 0) firstShown = 0;
  for (int i = 0; i < rows; ++i) {
    int idx = firstShown + i;
    if (idx >= total) break;
    // Map logical index (0 = oldest) to ring slot.
    int slot = (catMonHead - total + idx + CATMON_MAX * 2) % CATMON_MAX;
    bool tx = catMonIsTx[slot];
    canvas.setTextColor(tx ? CL_CYAN : CL_GREEN, CL_BLACK);
    canvas.setCursor(2, 20 + i * 12);
    canvas.printf("%s %s", tx ? "T" : "R", catMonLines[slot].substring(0, 36).c_str());
  }
  if (total == 0) {
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(2, 20);
    canvas.print("(no traffic yet)");
    canvas.setCursor(2, 32);
    canvas.print(catMonPoll ? "polling rig... check CAT wiring/baud"
                            : "poll off: 'p' to poll, 's' to send");
  }
  footer(catMonPoll ? "s send  p poll:on  ;/. scroll  ` back"
                    : "s send  p poll:off  ;/. scroll  ` back");
}

void App::keyCatMon(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) {
    catTraceSink = nullptr;            // release the sink so there's no overhead
    catMonActive = false;
    setSel = 0; setCat = -1; screen = SCR_SETTINGS; lastDrawMs = 0; return;
  }
  if (c == 's') {                       // type a raw hex frame to transmit
    editTarget = 250; editTitle = "Send hex (e.g. FE FE 4C E0 03 FD)";
    editBuf = ""; screen = SCR_EDIT; lastDrawMs = 0; return;
  }
  if (c == 'p') { catMonPoll = !catMonPoll; lastDrawMs = 0; return; }   // toggle heartbeat poll
  if (isUp(c))   { if (catMonScroll < catMonCount) catMonScroll++; lastDrawMs = 0; }
  if (isDown(c)) { if (catMonScroll > 0) catMonScroll--; lastDrawMs = 0; }
}

// Parse a string of hex byte tokens ("FE FE 4C E0 03 FD", spaces optional) and
// transmit the bytes verbatim on the current CAT port via the backend's raw write.
void App::catMonSendHex(const String& hex) {
  uint8_t buf[48]; size_t n = 0; int hi = -1;
  auto nib = [](char ch)->int {
    if (ch >= '0' && ch <= '9') return ch - '0';
    if (ch >= 'A' && ch <= 'F') return ch - 'A' + 10;
    if (ch >= 'a' && ch <= 'f') return ch - 'a' + 10;
    return -1;
  };
  for (size_t i = 0; i < hex.length() && n < sizeof(buf); ++i) {
    int v = nib(hex[i]);
    if (v < 0) {                        // separator: flush a pending nibble
      if (hi >= 0) { buf[n++] = (uint8_t)hi; hi = -1; }
      continue;
    }
    if (hi < 0) hi = v;                 // first nibble of a byte
    else { buf[n++] = (uint8_t)((hi << 4) | v); hi = -1; }   // second completes it
  }
  if (hi >= 0 && n < sizeof(buf)) buf[n++] = (uint8_t)hi;    // trailing nibble
  if (!n) { setStatus("No hex bytes parsed"); return; }
  if (!rig || !rig->sendRaw(buf, n)) { setStatus("Send failed (no CAT port)"); return; }
  setStatus(String("Sent ") + n + " byte(s)");
}

// ===========================================================================
//  Charge / Sleep screen (Launcher-style low-power mode)
// ===========================================================================
// Replicates the spirit of bmorcelli/Launcher's charging mode: the operator
// parks CardSat on the charger, the backlight blanks, and almost nothing runs.
// A keypress wakes the screen briefly to show battery status; ESC/back exits to
// the home menu. This is a *cooperative* idle (not deep sleep) so a keypress
// wakes it instantly and a long session's heap can be coalesced (see below) --
// deep sleep is already offered separately by the AOS sleep path.

// More accurate battery % than the raw fuel-gauge level. The Cardputer's PMIC
// level can be a coarse linear map; deriving % from the cell voltage against a
// LiPo discharge curve tracks reality better, especially in the flat 3.6-3.9 V
// region. Voltage is clamped to a single 3.0-4.2 V cell. Falls back to the raw
// level if voltage is unavailable.
int App::batteryPercent() {
  int mv = M5Cardputer.Power.getBatteryVoltage();   // mV, single cell
  if (mv <= 0) {                                     // no voltage -> raw gauge
    int lvl = M5Cardputer.Power.getBatteryLevel();
    return (lvl < 0) ? -1 : (lvl > 100 ? 100 : lvl);
  }
  // Piecewise LiPo curve (open-circuit-ish), monotonic, 3.30 V=0% .. 4.20 V=100%.
  static const struct { int mv; int pct; } C[] = {
    {4200,100},{4150,95},{4110,90},{4080,85},{4020,80},{3980,75},{3950,70},
    {3910,65},{3870,60},{3850,55},{3840,50},{3820,45},{3800,40},{3790,35},
    {3770,30},{3750,25},{3730,20},{3710,15},{3690,10},{3610,5},{3300,0}
  };
  const int N = (int)(sizeof(C) / sizeof(C[0]));
  if (mv >= C[0].mv)     return 100;
  if (mv <= C[N-1].mv)   return 0;
  for (int i = 0; i < N - 1; ++i) {
    if (mv <= C[i].mv && mv > C[i+1].mv) {           // linear-interp this segment
      int dmv = C[i].mv - C[i+1].mv, dpc = C[i].pct - C[i+1].pct;
      return C[i+1].pct + (int)((long)(mv - C[i+1].mv) * dpc / (dmv ? dmv : 1));
    }
  }
  return -1;
}

// On-demand heap de-fragmentation. Over a long session, repeated TLS handshakes
// (HTTPS) can fragment the heap on the no-PSRAM ESP32-S3 until the largest free
// block is too small for a new TLS context, even though total free heap looks
// fine -- TLS then starts failing. Dropping the WiFi/TLS stack and reconnecting
// frees and coalesces those transient allocations. net.hardResetWifi() already
// does the disconnect(true)+reconnect+pool-flush dance; we just call it here and
// report the before/after largest contiguous block.
// Enter charge mode: stop the radio/rotator output (no tracking while parked),
// blank the backlight, and mark the screen asleep. We deliberately do NOT enter
// deep sleep so any key wakes instantly and WiFi can stay up for a heap reset.
void App::enterChargeMode() {
  radioOut = false; rotOut = false;                  // no tracking while charging
  chargeWoke = false; chargeWokeMs = 0;
  M5Cardputer.Display.setBrightness(0);
  screenAsleep = true;
  // Minimal-power park: this screen only needs to wake on a keypress and show the
  // charge state, so shut down the big consumers. The WiFi radio is the largest
  // draw -- turn it fully off (not just disconnect) -- and drop the CPU clock right
  // down. A keypress still wakes instantly (the keyboard is polled by
  // M5Cardputer.update(), which is unaffected). Both are restored on exit.
  WiFi.disconnect(true);                             // drop association + power down the PHY
  WiFi.mode(WIFI_OFF);
  setCpuFrequencyMhz(80);                            // 240 -> 80 MHz (~3x less core power)
  lastDrawMs = 0;
}

void App::drawCharge() {
  // When asleep, keep the panel dark and cheap: clear to black, no backlight.
  if (screenAsleep && !chargeWoke) {
    canvas.fillSprite(CL_BLACK);
    canvas.pushSprite(0, 0);
    return;
  }
  // Woken (or first entry): show battery status, then auto-blank after ~5 s.
  canvas.fillSprite(CL_BLACK);
  bool charging = M5Cardputer.Power.isCharging();
  int  pct = batteryPercent();
  int  mv  = M5Cardputer.Power.getBatteryVoltage();

  canvas.setTextColor(CL_CYAN, CL_BLACK);
  canvas.setTextSize(1);
  canvas.setCursor(6, 6); canvas.print("Charge / Sleep");

  // Big battery glyph centered.
  const int bx = 70, by = 40, bw = 100, bh = 44;
  canvas.drawRect(bx, by, bw, bh, CL_WHITE);
  canvas.fillRect(bx + bw, by + 14, 5, bh - 28, CL_WHITE);   // terminal nub
  int fill = (pct < 0) ? 0 : (pct * (bw - 4)) / 100;
  uint16_t col = charging ? CL_GREEN : (pct > 50 ? CL_GREEN : (pct > 20 ? CL_YELLOW : CL_RED));
  if (fill > 0) canvas.fillRect(bx + 2, by + 2, fill, bh - 4, col);

  canvas.setTextColor(CL_WHITE, CL_BLACK);
  canvas.setTextSize(2);
  String p = (pct < 0) ? String("--") : String(pct);
  canvas.setCursor(120 - (int)(p.length() + 1) * 6, by + bh / 2 - 7);
  canvas.print(p); canvas.print("%");

  canvas.setTextSize(1);
  canvas.setTextColor(charging ? CL_GREEN : CL_GREY, CL_BLACK);
  canvas.setCursor(6, 96);
  canvas.print(charging ? "Charging" : "On battery");
  if (mv > 0) { canvas.setTextColor(CL_GREY, CL_BLACK);
                canvas.setCursor(150, 96); canvas.printf("%d.%02d V", mv/1000, (mv%1000)/10); }

  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(6, 112); canvas.print("ENT redraw");
  canvas.setCursor(6, 122); canvas.print("ESC exit to menu");
  canvas.pushSprite(0, 0);
}

void App::keyCharge(char c, bool enter, bool back) {
  // ESC/back always exits to the home menu and restores the backlight.
  if (isBack(c, back)) {
    setCpuFrequencyMhz(240);                         // restore full clock
    connectWifiCfg();                                // bring WiFi back up (was powered off)
    M5Cardputer.Display.setBrightness(cfg.bright);
    screenAsleep = false; chargeWoke = false;
    homeSel = 17; screen = SCR_HOME; lastDrawMs = 0;
    return;
  }
  // Any other key wakes the screen to show status for a few seconds.
  M5Cardputer.Display.setBrightness(cfg.bright);
  chargeWoke = true; chargeWokeMs = millis();
  lastDrawMs = 0;
}

// ===========================================================================
//  Orbital analysis screen (off Satellites). Multi-page: Info / Live geometry /
//  Next pass / forward Ground track / Doppler curve. Heavy per-orbit analysis
//  (ascending node, next pass, eclipse, optical visibility) is computed once in
//  buildOrbit(); the live pages (0-2) re-render with a single fresh look().
// ===========================================================================
// --- rudimentary orbital-decay estimate (exponential-atmosphere drag) -------
static double expAtmosphere(double hkm) {
  static const double B[][3] = {
    {100,5.297e-7,5.877},{110,9.661e-8,7.263},{120,2.438e-8,9.473},
    {130,8.484e-9,12.636},{140,3.845e-9,16.149},{150,2.070e-9,22.523},
    {180,5.464e-10,29.740},{200,2.789e-10,37.105},{250,7.248e-11,45.546},
    {300,2.418e-11,53.628},{350,9.518e-12,53.298},{400,3.725e-12,58.515},
    {450,1.585e-12,60.828},{500,6.967e-13,63.822},{600,1.454e-13,71.835},
    {700,3.614e-14,88.667},{800,1.170e-14,124.64},{900,5.245e-15,181.05},
    {1000,3.019e-15,268.00}
  };
  const int N = (int)(sizeof(B) / sizeof(B[0]));
  if (hkm >= 1100) return 0.0;            // above the table -> treat as drag-free
  if (hkm < 100)  hkm = 100;
  int i = 0; for (; i < N - 1; ++i) if (hkm < B[i + 1][0]) break;
  return B[i][1] * exp(-(hkm - B[i][0]) / B[i][2]);
}

// Density scale factors for the assumed solar-activity level. Thermospheric
// density at LEO altitudes varies ~an order of magnitude over the solar cycle;
// these bracket the static table (tuned to roughly cycle-mean conditions).
static double solarDensityScale(uint8_t act) {
  switch (act) {
    case SOLAR_LOW:  return 0.35;   // solar minimum
    case SOLAR_HIGH: return 3.0;    // solar maximum
    default:         return 1.0;    // cycle mean
  }
}

// Days to reentry from B* + exponential atmosphere, using a King-Hele style
// decay that lets the orbit circularize: drag is strongest at perigee, so the
// apogee comes down faster than the perigee while the perigee altitude is what
// governs the drag. We track perigee/apogee radii (rp, ra) separately and apply
// the per-orbit energy loss preferentially to apogee until the orbit is nearly
// circular, then bring both down together. Cd*A/m = 12.741621 * B* (m^2/kg).
// densScale brackets solar activity. Order-of-magnitude only: no attitude, lift,
// or short-term space weather. Returns -1 = rising/no data, 1e9 = effectively
// stable, otherwise estimated days to a ~120 km perigee.
static double estimateDecayDays(const SatEntry& s, double densScale) {
  if (s.bstar <= 0 || s.meanMotion <= 0 || densScale <= 0) return -1;
  const double MU = 3.986004418e14, RE = 6.378137e6, TP = 6.283185307179686;
  // Cd*A/m from B*: the textbook SGP4 conversion (12.741621*B*) leaves LEO
  // lifetimes ~3x too long against observed reentries (an un-reboosted ISS at
  // ~420 km comes down in ~1-2 yr, not ~10). Calibrating the per-rev decay
  // against ISS-class, ~400 km and ~550 km objects at mean solar activity puts
  // the multiplier near 38 (about 3x the textbook value -- consistent with a
  // reference-density normalization slip). Still order-of-magnitude: B* itself
  // is frequently a fitted fudge term, so treat the result as a coarse cue.
  double CdAm = 38.0 * s.bstar;                            // m^2/kg (calibrated)
  double nn = s.meanMotion * TP / 86400.0;                 // rad/s
  double a  = pow(MU / (nn * nn), 1.0 / 3.0);              // m
  double e  = s.ecc; if (e < 0) e = 0; if (e > 0.95) e = 0.95;
  double rp = a * (1.0 - e);                               // perigee radius (m)
  double ra = a * (1.0 + e);                               // apogee radius (m)
  double tDays = 0;
  for (int it = 0; it < 200000; ++it) {
    double hp = rp - RE;                                    // perigee altitude (m)
    if (hp < 120e3) return tDays;                           // reentry
    double rho = expAtmosphere(hp / 1000.0) * densScale;    // density at perigee
    if (rho <= 0) return 1e9;                               // above atmosphere table
    a = 0.5 * (rp + ra);
    double T = TP * sqrt(a * a * a / MU);                   // orbital period (s)
    // Energy-equivalent SMA decay rate, evaluated with perigee density (drag
    // acts mainly near perigee). dadt < 0.
    double dadt = -2.0 * TP * CdAm * rho * a * a / T;       // m/s
    if (dadt >= 0) return 1e9;
    // Adaptive step: shrink near the end so the fast final plunge isn't overshot.
    double margin = hp - 120e3;
    double dt = -(margin * 0.25 + 1000.0) / dadt;           // ~quarter of remaining drop
    double capDays = (hp < 200e3) ? 0.25 : (hp < 350e3 ? 5.0 : 30.0);
    if (dt > capDays * 86400.0) dt = capDays * 86400.0;
    if (dt < 1.0) dt = 1.0;
    double da = dadt * dt;                                  // total SMA decrement (<0)
    // King-Hele: while eccentric, drag at perigee removes energy mainly from
    // apogee. Pull apogee down at ~ (ra/rp) the rate of perigee so the orbit
    // circularizes; once nearly circular, both fall together.
    double ecur = (ra - rp) / (ra + rp);
    if (ecur > 1e-3) {
      double ratio = ra / rp;                               // > 1
      double dra = 2.0 * da * ratio / (1.0 + ratio);        // apogee share
      double drp = 2.0 * da / (1.0 + ratio);                // perigee share (smaller)
      ra += dra; rp += drp;
      if (ra < rp) ra = rp;                                 // clamp at circular
    } else {
      ra += da; rp += da;                                   // circular: uniform
    }
    tDays += dt / 86400.0;
    if (tDays > 36500.0) return 1e9;                        // > 100 yr
  }
  return tDays;
}

static String fmtDecay(double days) {
  if (days < 0)       return "n/a";
  if (days >= 36500)  return "stable";
  if (days < 1)       return "<1 d";
  if (days < 100)     return "~" + String((long)lround(days)) + "d";
  if (days < 730)     return "~" + String((long)lround(days / 30.0)) + "mo";
  return "~" + String(days / 365.0, 1) + "yr";
}

// Terse form (no "~") for the range bracket display.
static String fmtDecayShort(double days) {
  if (days < 0)       return "n/a";
  if (days >= 36500)  return "stable";
  if (days < 1)       return "<1d";
  if (days < 100)     return String((long)lround(days)) + "d";
  if (days < 730)     return String((long)lround(days / 30.0)) + "mo";
  return String(days / 365.0, 1) + "yr";
}

static const char* solarActLabel(uint8_t a) {
  return a == SOLAR_LOW ? "min" : (a == SOLAR_HIGH ? "max"
       : a == SOLAR_AUTO ? "auto" : "mean");
}

// Perigee altitude (km) from the mean elements -- the drag-critical number.
static double perigeeAltKm(const SatEntry& s) {
  if (s.meanMotion <= 0) return -1;
  const double MU = 3.986004418e14, RE = 6.378137e6, TP = 6.283185307179686;
  double nn = s.meanMotion * TP / 86400.0;          // rad/s
  double a  = pow(MU / (nn * nn), 1.0 / 3.0);        // m
  double rp = a * (1.0 - s.ecc);                     // perigee radius (m)
  return (rp - RE) / 1000.0;                          // km
}

// True for crewed / regularly-reboosted space stations, whose orbits are
// actively maintained -- a decay estimate is meaningless for them, so they must
// never raise a decay flag. Matched by NORAD id (robust vs. name variants):
// ISS (ZARYA) 25544, CSS/Tiangong (TIANHE) 48274. Docked vehicles co-orbit but
// carry their own ids; the stations themselves are what matters here.
static bool isSpaceStation(const SatEntry& s) {
  switch (s.norad) {
    case 25544:   // ISS (ZARYA)
    case 48274:   // CSS (TIANHE) / Tiangong
      return true;
    default:
      return false;
  }
}

// At-a-glance decay classification for the list flag and watch view.
// 0 = none/stable, 1 = watch, 2 = soon, 3 = imminent. Driven by the King-Hele
// time-to-decay estimate and gated so NO flag appears unless the satellite is
// within one year of decay; a low perigee only escalates the urgency *within*
// that window, it does not raise a flag on its own. Reboosted space stations
// are excluded entirely.
uint8_t App::decayLevelFor(const SatEntry& s) {
  if (isSpaceStation(s)) return 0;                  // reboosted -> never flag
  double days = estimateDecayDays(s, decayDensityScale());
  // Need a valid, finite estimate inside the one-year window to flag at all.
  if (days < 0 || days >= 365) return 0;
  double hp = perigeeAltKm(s);
  uint8_t lvl;
  if (days < 30)       lvl = 3;                     // imminent
  else if (days < 90)  lvl = 2;                     // soon
  else                 lvl = 1;                     // watch (90..365 days)
  // A very low perigee escalates urgency within the flagged window.
  if (hp >= 0) {
    if (hp < 200)      lvl = 3;
    else if (hp < 300 && lvl < 2) lvl = 2;
  }
  return lvl;
}


void App::buildOrbit(bool quiet) {
  orbHasPass = false; orbEcl = false; orbVisible = false; orbSunPct = 0;
  orbAscT = 0; orbAscLon = 0; orbEclT0 = 0; orbEclT1 = 0;
  orbDecayDays = -1; orbDecayLo = -1; orbDecayHi = -1;
  SatEntry* s = activeSat();
  if (!s || !timeIsSet() || s->meanMotion <= 0) return;
  if (!quiet) { setStatus("Analyzing orbit..."); draw(); }
  pred.setSite(loc.obs()); pred.setSat(*s);
  time_t now = nowUtc();
  double periodSec = 86400.0 / s->meanMotion;

  // Apogee/perigee for the Info page: sample the geocentric altitude (the same value
  // the live readout shows) across one full orbit and take the extremes. Doing it this
  // way -- rather than the mean-element a(1+/-e)-RE -- guarantees the displayed Altitude
  // always lies within [perigee, apogee]. SGP4's osculating altitude oscillates a few km
  // around the mean orbit (short-period J2), so a mean-element apogee can read just below
  // the live altitude near apogee, which looked like a bug. Seed with the mean-element
  // values so there's always something sane even before the loop runs.
  {
    const double MU_ = 398600.4418, RE_ = 6378.137;
    double nrad = s->meanMotion * 6.283185307179586 / 86400.0;
    double a_ = (nrad > 0) ? pow(MU_ / (nrad * nrad), 1.0 / 3.0) : 0;
    orbApoKm  = a_ * (1.0 + s->ecc) - RE_;
    orbPeriKm = a_ * (1.0 - s->ecc) - RE_;
    double hi = -1e9, lo = 1e9;
    // ~120 samples over one period catches the extremes to a fraction of a km; a small
    // pad absorbs the residual granularity so the live altitude (sampled at an arbitrary
    // instant between grid points) can never read just outside [perigee, apogee].
    long step = (long)(periodSec / 120.0); if (step < 2) step = 2;
    for (long dt = 0; dt <= (long)periodSec + step; dt += step) {
      LiveLook L = pred.look(now + dt);
      double h = geocentricAltKm(L.subLat, L.satAltKm);
      if (h > hi) hi = h;
      if (h < lo) lo = h;
    }
    if (hi > -1e8) orbApoKm = hi + 1.0;            // +1 km pad (see note above)
    if (lo <  1e8) orbPeriKm = lo - 1.0;           // -1 km pad
  }

  // Next ascending node: step up to one period, find a subLat - -> + crossing,
  // then bisect to refine the time and read its sub-longitude.
  double prevLat = pred.look(now).subLat; time_t prevT = now;
  for (long dt = 30; dt <= (long)periodSec + 60; dt += 30) {
    LiveLook L = pred.look(now + dt);
    if (prevLat < 0 && L.subLat >= 0) {
      time_t a = prevT, b = now + dt;
      for (int k = 0; k < 14; ++k) {
        time_t m = a + (b - a) / 2;
        if (pred.look(m).subLat < 0) a = m; else b = m;
      }
      orbAscT = b; orbAscLon = pred.look(b).subLon; break;
    }
    prevLat = L.subLat; prevT = now + dt;
  }

  // Next pass + eclipse timing + optical-visibility flag.
  PassPredict pp[1];
  int np = pred.predictPasses(now, cfg.minPassEl, pp, 1);
  if (np > 0) {
    orbPass = pp[0]; orbHasPass = true;
    int total = 0, sun = 0; bool prevSun = true;
    for (time_t t = orbPass.aos; t <= orbPass.los; t += 15) {
      LiveLook L = pred.look(t);
      total++; if (L.sunlit) sun++; else orbEcl = true;
      if (t > orbPass.aos) {
        if (prevSun && !L.sunlit && orbEclT0 == 0) orbEclT0 = t;                 // entered shadow
        if (!prevSun && L.sunlit && orbEclT1 == 0 && orbEclT0 != 0) orbEclT1 = t; // left shadow
      }
      prevSun = L.sunlit;
      if (L.sunlit && L.el > 0 && L.sunEl < -6.0) orbVisible = true;             // sunlit sat, dark sky
    }
    orbSunPct = total ? (100.0f * sun / total) : 0;
  }
  orbDecayDays = estimateDecayDays(*s, decayDensityScale());
  orbDecayLo   = estimateDecayDays(*s, solarDensityScale(SOLAR_LOW));   // longest life
  orbDecayHi   = estimateDecayDays(*s, solarDensityScale(SOLAR_HIGH));  // shortest life

  // Pass outlook over the next ORB_OUTLOOK_DAYS days: count passes, find the best
  // (highest) one, the longest, how many clear 30 deg, and the mean spacing.
  // Use ONE predictPasses call over the whole window (the SGP4 nextpass cursor
  // advances correctly through consecutive passes) -- the same pattern buildVis
  // uses. Repeated single-pass re-inits mis-behave for high orbits like AO-7.
  orbOutlookN = 0; orbOutlookHi = 0; orbBestEl = 0; orbBestT = 0; orbBestDur = 0;
  orbLongestMin = 0; orbAvgGapH = 0;
  {
    time_t winEnd = now + (time_t)ORB_OUTLOOK_DAYS * 86400;
    // Reuse the 10-day overview buffer (only live while that screen is open; it
    // is rebuilt on entry there, so borrowing it here is safe).
    int n = pred.predictPasses(now, cfg.minPassEl, visPasses, VIS_PASS_MAX, winEnd);
    orbOutlookN = n;
    for (int i = 0; i < n; ++i) {
      const PassPredict& p = visPasses[i];
      int dur = (int)(p.los - p.aos);
      if (p.maxEl > orbBestEl) { orbBestEl = p.maxEl; orbBestT = p.aos; orbBestDur = dur; }
      if (dur / 60.0f > orbLongestMin) orbLongestMin = dur / 60.0f;
      if (p.maxEl >= 30.0f) orbOutlookHi++;
    }
    if (n > 1)
      orbAvgGapH = (float)(visPasses[n - 1].aos - visPasses[0].aos) / (n - 1) / 3600.0f;
  }
  if (!quiet) setStatus("");
}

void App::drawOrbit() {
  SatEntry* s = activeSat();
  static const char* PG[] = { "Info", "Live", "Pass", "Track", "Doppler", "Nodal",
                              "Sun/B", "Outlook", "OrbPos", "Phys" };
  { String h = (s ? String(s->name) : String("Orbit")) + " " + PG[orbitPage] +
               " " + String(orbitPage + 1) + "/10";
    header(h); }
  canvas.setTextSize(1);
  if (!s) { canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 56);
            canvas.print("No satellite."); footer("` back"); return; }

  const double MU = 398600.4418, RE = 6378.137, TWO_PI_ = 6.283185307179586;
  const double C_KM = 299792.458;
  double mm = s->meanMotion;                         // rev/day
  double periodMin = (mm > 0) ? 1440.0 / mm : 0;
  double n = mm * TWO_PI_ / 86400.0;                 // rad/s
  double a = (n > 0) ? pow(MU / (n * n), 1.0 / 3.0) : 0;   // semi-major axis, km
  double apo = a * (1 + s->ecc) - RE, peri = a * (1 - s->ecc) - RE;
  time_t now = timeIsSet() ? nowUtc() : 0;

  int y = 18; const int LH = 9;
  auto row = [&](const char* k, const String& v) {
    canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.setCursor(2, y);  canvas.print(k);
    canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(98, y); canvas.print(v);
    y += LH;
  };

  if (orbitPage == 0) {                              // ---------- Satellite info ----------
    double geoAlt = 0;          // geodetic height above the ellipsoid (for footprint)
    double altNow = 0;          // geocentric altitude (for the readout, vs apo/peri)
    if (now) {
      pred.setSat(*s);
      LiveLook lk = pred.look(now);
      geoAlt = lk.satAltKm;
      altNow = geocentricAltKm(lk.subLat, lk.satAltKm);
    }
    // Footprint circle diameter (km) = 2*Re*acos(Re/(Re+h)). This is the widest
    // surface span both able to see the bird at once -> longest possible QSO. Uses
    // the geodetic height (true height above ground), which is what governs who can
    // actually see the satellite.
    auto fpDia = [&](double h) -> double {
      return (h > 0) ? 2.0 * RE * acos(RE / (RE + h)) : 0.0;
    };
    double ageD = now ? (now - s->epochUnix) / 86400.0 : 0;
    long revNow = (long)s->revAtEpoch +
                  (now ? (long)floor((now - s->epochUnix) / (periodMin * 60.0)) : 0);
    row("NORAD",        String(s->norad));
    row("Altitude",     String(altNow, 0) + " km");
    row("Footprint",    String(fpDia(geoAlt), 0) + " km dia");
    row("Period",       String(periodMin, 1) + " min");
    row("Apo/Peri",     String(orbApoKm, 0) + "/" + String(orbPeriKm, 0) + " km");
    row("Fp apo/peri",  String(fpDia(apo), 0) + "/" + String(fpDia(peri), 0) + " km");
    row("Incl/Ecc",     String(s->incl, 2) + " / " + String(s->ecc, 5));
    row("SMA (a)",      String(a, 0) + " km");
    row("B* / decay",   String(s->bstar, 6) + " " + fmtDecay(orbDecayDays));
    if (orbDecayDays >= 0 && orbDecayDays < 36500)        // show the solar bracket
      row("Decay rng",  fmtDecayShort(orbDecayHi) + "-" + fmtDecayShort(orbDecayLo) +
                        " (" + solarActLabel(cfg.solarAct) + ")");
    row("Age/Rev",      String(ageD, 2) + "d / " + String(revNow));
    if (orbAscT) {
      struct tm tmv; gmtime_r(&orbAscT, &tmv);
      char b[28]; snprintf(b, sizeof(b), "%.1f%c %02d:%02dZ", fabs(orbAscLon),
                           orbAscLon < 0 ? 'W' : 'E', tmv.tm_hour, tmv.tm_min);
      row("Asc node", String(b));
    } else row("Asc node", "--");
    footer(",// page  r refresh  ` bk");
    return;
  }

  if (orbitPage == 1) {                              // ---------- Live geometry ----------
    if (!now) { canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 56);
                canvas.print("Clock not set."); footer(",// page  ` bk"); return; }
    pred.setSat(*s); LiveLook L = pred.look(now);
    row("Az / El",    String(L.az, 1) + " / " + String(L.el, 1));
    row("Range",      String(L.rangeKm, 0) + " km");
    row("Range rate", String(L.rangeRate, 3) + " km/s");
    row("Dop 145.8",  String((long)lround(-L.rangeRate / C_KM * 145800000.0)) + " Hz");
    row("Dop 435.0",  String((long)lround(-L.rangeRate / C_KM * 435000000.0)) + " Hz");
    row("Sub pt",     String(L.subLat, 2) + "," + String(L.subLon, 2));
    double maNow = fmod(s->ma + 360.0 * mm * (now - s->epochUnix) / 86400.0, 360.0);
    if (maNow < 0) maNow += 360.0;
    int phase = ((int)lround(maNow * 256.0 / 360.0)) & 255;
    row("MA / phase", String(maNow, 0) + " / " + String(phase));
    canvas.setTextColor(L.sunlit ? CL_YELLOW : CL_CYAN, CL_BLACK);
    canvas.setCursor(2, y); canvas.print(L.sunlit ? "SUNLIT" : "ECLIPSE");
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.printf("  sun el %.0f  ecl dep %+.1f", L.sunEl, pred.eclipseDepthDeg(now));
    footer(",// page  ` bk");
    return;
  }

  if (orbitPage == 2) {                              // ---------- Next pass ----------
    if (!orbHasPass) { canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 56);
      canvas.print("No upcoming pass."); footer(",// page  r refresh  ` bk"); return; }
    auto hms = [](long sec) -> String { if (sec < 0) sec = 0; char b[12];
      snprintf(b, sizeof(b), "%ld:%02ld", sec / 60, sec % 60); return String(b); };
    row("AOS in",   hms((long)(orbPass.aos - now)));
    row("Duration", hms((long)(orbPass.los - orbPass.aos)));
    row("Max el",   String(orbPass.maxEl, 1) + " deg");
    row("AOS az",   String(orbPass.azAos, 0) + " deg");
    row("LOS az",   String(orbPass.azLos, 0) + " deg");
    row("Sunlit",   String(orbSunPct, 0) + " %");
    if (orbEcl && orbEclT0) {
      String e = "+" + hms((long)(orbEclT0 - orbPass.aos));
      if (orbEclT1) e += " to +" + hms((long)(orbEclT1 - orbPass.aos));
      row("Ecl (pass)", e);
      // deepest point in Earth's shadow during the pass (PREDICT-style depth)
      double dMax = -90.0;
      for (time_t t = orbPass.aos; t <= orbPass.los; t += 15) {
        double d = pred.eclipseDepthDeg(t); if (d > dMax) dMax = d;
      }
      if (dMax > 0) row("Ecl depth", String(dMax, 1) + " deg peak");
    } else row("Ecl (pass)", orbEcl ? "yes" : "none");
    if (now) {                                       // slant range + 1-way path delay
      pred.setSite(loc.obs()); pred.setSat(*s);
      double rA = pred.look(orbPass.aos).rangeKm, rT = pred.look(orbPass.tca).rangeKm,
             rL = pred.look(orbPass.los).rangeKm;
      row("Rng A/T/L", String(rA, 0) + "/" + String(rT, 0) + "/" + String(rL, 0));
      row("Delay TCA", String(rT / 299.792458, 1) + " ms 1-way");
    }
    canvas.setTextColor(orbVisible ? CL_YELLOW : CL_GREY, CL_BLACK);
    canvas.setCursor(2, y); canvas.print(orbVisible ? "Optically VISIBLE pass"
                                                    : "Not optically visible");
    footer(",// page  r refresh  ` bk");
    return;
  }

  if (orbitPage == 3) {                              // ---------- Forward ground track ----------
    const int MX = 0, MY = 16, MW = 240, MH = 92;
    canvas.fillRect(MX, MY, MW, MH, CL_BLACK);
    { int px = 0, py = 0, plo = 0; bool pen = false;       // coastline
      for (int i = 0; i + 1 < COAST_N; i += 2) {
        int lo = COAST[i], la = COAST[i + 1];
        if (lo == 999) { pen = false; continue; }
        int x = MX + (lo + 180) * MW / 360, yy = MY + (90 - la) * MH / 180;
        if (pen && abs(lo - plo) < 180) canvas.drawLine(px, py, x, yy, CL_DGREEN);
        px = x; py = yy; plo = lo; pen = true; } }
    canvas.drawFastHLine(MX, MY + MH / 2, MW, CL_MGREY);     // equator
    if (now) {
      pred.setSat(*s);
      double periodSec = 86400.0 / mm; const int N = 80;
      int pxo = 0, pyo = 0; double plon = 0; bool pen = false;
      for (int i = 0; i <= N; ++i) {
        LiveLook L = pred.look(now + (time_t)(periodSec * 2 * i / N));
        double lon = L.subLon; while (lon < -180) lon += 360; while (lon > 180) lon -= 360;
        int x = MX + (int)lround((lon + 180.0) / 360.0 * MW);
        int yy = MY + (int)lround((90.0 - L.subLat) / 180.0 * MH);
        if (pen && fabs(lon - plon) < 180) canvas.drawLine(pxo, pyo, x, yy, CL_CYAN);
        pxo = x; pyo = yy; plon = lon; pen = true;
      }
      LiveLook L0 = pred.look(now);
      double lon0 = L0.subLon; while (lon0 < -180) lon0 += 360; while (lon0 > 180) lon0 -= 360;
      int cx = MX + (int)lround((lon0 + 180.0) / 360.0 * MW);
      int cy = MY + (int)lround((90.0 - L0.subLat) / 180.0 * MH);
      canvas.fillCircle(cx, cy, 2, CL_YELLOW);
    }
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(2, MY + MH + 2); canvas.print("ground track: next 2 orbits");
    footer(",// page  ` bk");
    return;
  }

  if (orbitPage == 6) {                              // ---------- Sun / beta angle ----------
    const double D2R = 0.017453292519943295;
    double beta = now ? pred.betaAngleDeg(now, s->incl, s->raan) : 0.0;
    // beta* (analytic full-sun threshold) is shown as context, but the actual
    // full-sun/eclipse verdict and fraction come from sampling one full orbit
    // with the SAME geometric shadow test the illumination screen uses -- so the
    // two screens never disagree near the threshold.
    double hMean = a - RE;                                  // km (a, RE in km here)
    double betaStar = (hMean > 0) ? acos(RE / (RE + hMean)) / D2R : 0.0;
    double periodMin2 = (mm > 0) ? 1440.0 / mm : 0.0;
    double fEcl = 0.0; bool fullSun = true;
    if (now && periodMin2 > 0) {
      time_t period = (time_t)(periodMin2 * 60.0 + 0.5);
      int N = 180, ecl = 0;                                 // sample the orbit at ~N points
      for (int k = 0; k < N; ++k) {
        time_t t = now + (time_t)((double)period * k / N);
        if (!pred.sunlitAt(t)) ecl++;
      }
      fEcl = (double)ecl / N;
      fullSun = (ecl == 0);
    }
    row("Beta now",   String(beta, 1) + " deg");
    row("Sunlight",   fullSun ? "full-sun orbit" : "eclipsed each rev");
    row("Beta*",      "+/-" + String(betaStar, 1) + " deg (full-sun)");
    if (!fullSun) {
      row("Eclipse",  String(fEcl * 100.0, 0) + "% /orbit");
      row("Ecl time", String(fEcl * periodMin2, 1) + " min/orbit");
    } else {
      row("Eclipse",  "none (continuous sun)");
    }
    // Scan ahead to the next full-sun window edge (beta crossing +/-beta*).
    if (now) {
      time_t found = 0; bool wantFull = !fullSun;
      for (long d = 1; d <= 180; ++d) {
        double b = pred.betaAngleDeg(now + (time_t)d * 86400, s->incl, s->raan);
        if ((fabs(b) >= betaStar) == wantFull) { found = now + (time_t)d * 86400; break; }
      }
      if (found) {
        struct tm tmv; gmtime_r(&found, &tmv);
        char b[20]; snprintf(b, sizeof(b), "%02d/%02d", tmv.tm_mon + 1, tmv.tm_mday);
        long dd = (long)((found - now) / 86400);
        row(wantFull ? "-> full sun" : "-> eclipses",
            String(b) + " (" + String(dd) + "d)");
      } else {
        row(wantFull ? "-> full sun" : "-> eclipses", ">180d");
      }
    }
    footer(",// page  r refresh  ` bk");
    return;
  }

  if (orbitPage == 7) {                              // ---------- Pass outlook ----------
    if (!now) { canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 56);
                canvas.print("Clock not set."); footer(",// page  r refresh  ` bk"); return; }
    canvas.setTextColor(CL_CYAN, CL_BLACK); canvas.setCursor(2, y);
    canvas.printf("Next %d days", ORB_OUTLOOK_DAYS); y += LH;
    if (orbOutlookN == 0) {
      canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(2, y);
      canvas.print("No passes above mask.");
      footer(",// page  r refresh  ` bk"); return;
    }
    auto hms = [](long sec) -> String { if (sec < 0) sec = 0; char b[12];
      snprintf(b, sizeof(b), "%ld:%02ld", sec / 60, sec % 60); return String(b); };
    row("Passes",   String(orbOutlookN) + " (" + String(orbOutlookHi) + " >30 deg)");
    row("Longest",  String(orbLongestMin, 1) + " min");
    row("Avg gap",  String(orbAvgGapH, 1) + " h");
    // Best pass: when, how high, how long, and its sunlit state.
    if (orbBestT) {
      struct tm tmv; gmtime_r(&orbBestT, &tmv);
      char d[16]; snprintf(d, sizeof(d), "%02d/%02d %02d:%02dZ",
                           tmv.tm_mon + 1, tmv.tm_mday, tmv.tm_hour, tmv.tm_min);
      row("Best el",  String(orbBestEl, 0) + " deg");
      row("Best at",  String(d));
      row("Best in",  hms((long)(orbBestT - now)));
      row("Best dur", hms((long)orbBestDur));
    }
    footer(",// page  r refresh  ` bk");
    return;
  }

  if (orbitPage == 8) {                              // ---------- Orbit position ----------
    if (!now) { canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 56);
                canvas.print("Clock not set."); footer(",// page  ` bk"); return; }
    const double D2R = 0.017453292519943295, TWO_PI2 = 6.283185307179586;
    double periodS = (mm > 0) ? 86400.0 / mm : 0.0;
    // Mean anomaly now (deg) advanced from epoch.
    double maNow = fmod(s->ma + 360.0 * mm * (now - s->epochUnix) / 86400.0, 360.0);
    if (maNow < 0) maNow += 360.0;
    // Time to perigee (MA = 0/360) and apogee (MA = 180), via mean motion.
    double toPeri = (360.0 - maNow) / 360.0 * periodS;     // s until next MA=0
    double toApo  = fmod((180.0 - maNow + 360.0), 360.0) / 360.0 * periodS;
    // Argument of latitude u = argp + true anomaly (approx with MA for small e is
    // poor; use a 3-term equation-of-centre expansion for the true anomaly).
    double M = maNow * D2R, e = s->ecc;
    double nu = M + (2*e - 0.25*e*e*e) * sin(M)
                  + 1.25*e*e * sin(2*M)
                  + (13.0/12.0)*e*e*e * sin(3*M);           // true anomaly (rad)
    double u = fmod(s->argp + nu / D2R, 360.0); if (u < 0) u += 360.0;
    long revNow = (long)s->revAtEpoch +
                  (long)floor((now - s->epochUnix) / periodS);
    auto hms = [](long sec) -> String { if (sec < 0) sec = 0; char b[12];
      snprintf(b, sizeof(b), "%ld:%02ld", sec / 60, sec % 60); return String(b); };
    row("Mean anom", String(maNow, 1) + " deg");
    row("True anom", String(nu / D2R, 1) + " deg");
    row("Arg lat",   String(u, 1) + " deg");
    row("To perigee",hms((long)toPeri));
    row("To apogee", hms((long)toApo));
    row("Arg peri",  String(s->argp, 1) + " deg");
    row("RAAN",      String(s->raan, 1) + " deg");
    row("Rev now",   String(revNow));
    row("Epoch age", String((now - s->epochUnix) / 86400.0, 2) + " d");
    footer(",// page  ` bk");
    return;
  }

  if (orbitPage == 5) {                              // ---------- Orbit dynamics (J2) ----------
    const double D2R = 0.017453292519943295;
    const double J2 = 0.00108262998905, DPD = 57.29577951308232 * 86400.0;  // rad/s -> deg/day
    double ci = cos(s->incl * D2R);
    double pp = a * (1.0 - s->ecc * s->ecc);
    double ReP2 = (pp > 0) ? (RE / pp) * (RE / pp) : 0.0;
    double Odot = -1.5 * n * J2 * ReP2 * ci * DPD;             // node regression, deg/day
    double Wdot = 0.75 * n * J2 * ReP2 * (5 * ci * ci - 1) * DPD;  // apsidal, deg/day
    row("Revs/day",    String(mm, 4));
    row("Node drift",  String(Odot, 3) + " /day");
    row("Perig drift", String(Wdot, 3) + " /day");
    row("Sun-sync",    (fabs(Odot - 0.98565) < 0.05) ? "yes" : "no");
    if (now) {                                                // local time of ascending node
      double d = ((double)now - 946728000.0) / 86400.0;       // days since J2000
      double Ls = 280.460 + 0.9856474 * d;
      double g  = (357.528 + 0.9856003 * d) * D2R;
      double lam = (Ls + 1.915 * sin(g) + 0.020 * sin(2 * g)) * D2R;
      double eps = 23.439 * D2R;
      double ra = atan2(cos(eps) * sin(lam), cos(lam)) / D2R;  // Sun RA, deg
      double lt = fmod((s->raan - ra) / 15.0 + 12.0 + 48.0, 24.0);
      int hh = (int)lt, mi = (int)((lt - hh) * 60.0 + 0.5);
      if (mi >= 60) { mi -= 60; hh = (hh + 1) % 24; }
      char b[8]; snprintf(b, sizeof(b), "%02d:%02d", hh, mi);
      row("LTAN", String(b));
    } else row("LTAN", "--");
    { double best = 1e9; int bP = 0, bQ = 0;                  // repeat ground track
      for (int P = 1; P <= 30; ++P) { int Q = (int)lround(mm * P);
        double err = fabs(mm - (double)Q / (double)P);
        if (err < best) { best = err; bP = P; bQ = Q; } }
      if (bP && best < 0.015) row("Repeat trk", String(bQ) + " rev/" + String(bP) + "d");
      else                    row("Repeat trk", "none <30d");
    }
    { double rApo = a * (1.0 + s->ecc);                       // longest pass (overhead, apogee)
      double lamA = (rApo > RE) ? acos(RE / rApo) : 0.0;
      double wApo = sqrt(MU * pp) / (rApo * rApo);            // rad/s at apogee
      double tmax = (wApo > 0) ? 2.0 * lamA / wApo / 60.0 : 0.0;
      row("Max pass",  String(tmax, 1) + " min");
    }
    footer(",// page  r refresh  ` bk");
    return;
  }

  if (orbitPage == 9) {                              // ---------- Physical / identity ----------
    const double D2R = 0.017453292519943295;
    // Instantaneous orbital speed via vis-viva: v = sqrt(mu*(2/r - 1/a)). The
    // geocentric radius r is from the current true anomaly (r = a(1-e^2)/(1+e*cos v)),
    // advanced from the epoch mean anomaly -- so the speed is live and correctly higher
    // near perigee, lower near apogee.
    double e = s->ecc;
    double maNow = fmod(s->ma + 360.0 * mm * (now ? (now - s->epochUnix) : 0) / 86400.0, 360.0);
    if (maNow < 0) maNow += 360.0;
    double M = maNow * D2R;
    double nu = M + (2*e - 0.25*e*e*e) * sin(M) + 1.25*e*e * sin(2*M)
                  + (13.0/12.0)*e*e*e * sin(3*M);       // true anomaly (rad)
    double pOrb = a * (1.0 - e * e);
    double r = (1.0 + e * cos(nu) != 0) ? pOrb / (1.0 + e * cos(nu)) : a;
    double vNow = (a > 0 && r > 0) ? sqrt(MU * (2.0 / r - 1.0 / a)) : 0.0;
    double vApo = (a > 0) ? sqrt(MU * (2.0 / (a * (1 + e)) - 1.0 / a)) : 0.0;
    double vPer = (a > 0) ? sqrt(MU * (2.0 / (a * (1 - e)) - 1.0 / a)) : 0.0;
    row("Velocity",  (now ? String(vNow, 3) : String("--")) + " km/s");
    row("V apo/peri", String(vApo, 2) + " / " + String(vPer, 2) + " km/s");
    row("Elset", "#" + String(s->elsetNum));

    // Launch year + satellite age from the COSPAR International Designator
    // "YYYY-NNNP" (the catalog stores the 4-digit-year form). The first four chars
    // are the launch year; chars 5-7 (after the dash) are the launch number of that
    // year. Age is now - Jan 1 of the launch year (year-granular; the designator has
    // no launch day). Falls back to "--" if the field isn't the expected form.
    int lyear = 0, lnum = 0;
    if (s->intlDes[0] && strlen(s->intlDes) >= 5 && s->intlDes[4] == '-'
        && isdigit((unsigned char)s->intlDes[0]) && isdigit((unsigned char)s->intlDes[1])
        && isdigit((unsigned char)s->intlDes[2]) && isdigit((unsigned char)s->intlDes[3])) {
      lyear = (s->intlDes[0]-'0')*1000 + (s->intlDes[1]-'0')*100
            + (s->intlDes[2]-'0')*10 + (s->intlDes[3]-'0');
      lnum = atoi(s->intlDes + 5);
    }
    if (lyear >= 1957) {
      row("Launched", String(lyear) + (lnum ? (" (#" + String(lnum) + ")") : String("")));
      if (now) {
        struct tm ly; memset(&ly, 0, sizeof(ly));
        ly.tm_year = lyear - 1900; ly.tm_mday = 1;    // Jan 1 of the launch year
        double ageY = (now - mktime(&ly)) / 31557600.0;   // Julian years
        row("In orbit", String(ageY, 1) + " yr");
      }
      row("Cospar", String(s->intlDes));
      // Launch siblings: other cataloged objects sharing the COSPAR YYYY-NNN
      // prefix (same launch). AO-7 rode up with three companions, for example.
      // Show the count, then the names themselves wrapped across lines (that is
      // the useful part -- *which* birds shared the ride, not just how many).
      int sibs = 0;
      String sibList;
      for (int i2 = 0; i2 < db.count(); ++i2) {
        const SatEntry& t2 = db.at(i2);
        if (&t2 != s && t2.intlDes[0] && strncmp(t2.intlDes, s->intlDes, 8) == 0) {
          sibs++;
          if (sibList.length()) sibList += ", ";
          sibList += t2.name;
        }
      }
      row("Launch sibs", sibs ? String(sibs) + " in catalog" : String("none in catalog"));
      // Wrap the name list under the count, ~38 chars/line, stopping before the
      // footer (y >= 112) so a big launch batch can never overrun it.
      if (sibs) {
        y += 4;                                      // small gap so the names read as a distinct block
        const int WRAP = 38;
        int pos = 0, L = sibList.length();
        while (pos < L && y <= 110) {
          int take = L - pos;
          if (take > WRAP) {                         // break at the last comma that fits
            take = WRAP;
            int br = sibList.lastIndexOf(',', pos + WRAP);
            if (br > pos) take = br - pos + 1;        // include the comma
          }
          String seg = sibList.substring(pos, pos + take);
          seg.trim();
          canvas.setTextColor(CL_CYAN, CL_BLACK);
          canvas.setCursor(10, y); canvas.print(seg);
          y += LH; pos += take;
        }
        if (pos < L) {                               // ran out of room: show it was clipped
          canvas.setTextColor(CL_GREY, CL_BLACK);
          canvas.setCursor(10, y); canvas.print("...");
        }
      }
    } else {
      row("Launched", "--");
      if (s->intlDes[0]) row("Cospar", String(s->intlDes));
    }
    footer(",// page  ` bk");
    return;
  }

  // orbitPage == 4                                  // ---------- Doppler curve ----------
  {
    const int PX = 30, PY = 20, PW = 204, PH = 90;
    canvas.drawRect(PX - 1, PY - 1, PW + 2, PH + 2, CL_MGREY);
    if (!orbHasPass) { canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 56);
      canvas.print("No upcoming pass."); footer(",// page  ` bk"); return; }
    pred.setSat(*s);
    static float buf[PW > 0 ? PW : 1];
    double dur = (double)(orbPass.los - orbPass.aos);
    double fbHz = cfg.beaconMHz * 1e6;
    float mn = 1e9f, mx = -1e9f; double maxRR = 0;
    for (int i = 0; i < PW; ++i) {
      double t = (double)orbPass.aos + dur * i / (PW - 1);
      double rr = pred.rangeRateAt(t); if (fabs(rr) > maxRR) maxRR = fabs(rr);
      float dop = (float)(-rr / C_KM * fbHz);                          // Hz @ beacon freq
      buf[i] = dop; if (dop < mn) mn = dop; if (dop > mx) mx = dop;
    }
    if (mx <= mn) mx = mn + 1;
    int zy = PY + (int)((mx - 0.0f) / (mx - mn) * (PH - 1));
    if (zy >= PY && zy < PY + PH) canvas.drawFastHLine(PX, zy, PW, CL_DGREY);   // 0 Hz line
    int ppx = 0, ppy = 0;
    for (int i = 0; i < PW; ++i) {
      int x = PX + i, yv = PY + (int)((mx - buf[i]) / (mx - mn) * (PH - 1));
      if (i) canvas.drawLine(ppx, ppy, x, yv, CL_GREEN);
      ppx = x; ppy = yv;
    }
    float peak = (fabs(mx) > fabs(mn) ? fabs(mx) : fabs(mn)) / 1000.0f;
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(2, PY - 2);        canvas.printf("%+.0f", mx);
    canvas.setCursor(2, PY + PH - 6);   canvas.printf("%+.0f", mn);
    canvas.setCursor(2, PY + PH + 2);   canvas.printf("@%g MHz  pk %.1f kHz  RR %.2f",
                                                      cfg.beaconMHz, peak, maxRR);
    footer(",// page  f freq  ` bk");
    return;
  }
}

void App::keyOrbit(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { screen = SCR_SATLIST; lastDrawMs = 0; return; }
  if (isRight(c)) { if (++orbitPage > 9) orbitPage = 0; lastDrawMs = 0; return; }
  if (isLeft(c))  { if (--orbitPage < 0) orbitPage = 9; lastDrawMs = 0; return; }
  if (c == 'r')   { buildOrbit(); lastDrawMs = 0; return; }
  if (c == 'f' && orbitPage == 4) {                   // edit Doppler-page beacon freq
    editTarget = 210; editTitle = "Beacon freq (MHz)";
    editBuf = String(cfg.beaconMHz, 3); screen = SCR_EDIT; lastDrawMs = 0; return;
  }
}

// ===========================================================================
//  EQX table (off Satellites): equatorial crossing times + longitudes for use
//  with an OSCARLOCATOR plotting board. Each EQX is an ascending-node crossing
//  (sub-satellite latitude going south -> north). Times are UTC; longitudes are
//  printed West-positive (W = +), the convention printed on Oscarlocator dials.
//  Covers a rolling 3-day window from now, computed on-device from the selected
//  sat's GP elements (no network needed). Modeled on AO-7_OSCARLOCATOR (N8HM).
// ===========================================================================
void App::buildEqx() {
  eqxN = 0; eqxScroll = 0;
  SatEntry* s = activeSat();
  if (!s || !timeIsSet() || s->meanMotion <= 0) return;
  setStatus(eqxDescending ? "Computing crossings (desc)..." : "Computing EQX table...");
  draw();
  pred.setSite(loc.obs()); pred.setSat(*s);

  const time_t now    = nowUtc();
  const time_t window = (time_t)(3 * 86400);         // 3 days
  const time_t end    = now + window;
  // Coarse step a fraction of the period so we never skip a node; each node type
  // recurs once per orbit. 30 s is plenty for LEO/HEO amateur sats.
  const long   step   = 30;

  double prevLat = pred.look(now).subLat;
  time_t prevT   = now;
  for (time_t t = now + step; t <= end && eqxN < EQX_MAX; t += step) {
    LiveLook L = pred.look(t);
    // Ascending node: lat crosses 0 going - -> + (northbound).
    // Descending node: lat crosses 0 going + -> - (southbound).
    bool cross = eqxDescending ? (prevLat >= 0 && L.subLat < 0)
                               : (prevLat < 0 && L.subLat >= 0);
    if (cross) {
      time_t a = prevT, b = t;                       // bracket, then bisect
      for (int k = 0; k < 18; ++k) {
        time_t m = a + (b - a) / 2;
        double lm = pred.look(m).subLat;
        // keep [a,b] straddling the crossing for whichever direction we want
        bool firstHalf = eqxDescending ? (lm >= 0) : (lm < 0);
        if (firstHalf) a = m; else b = m;
      }
      double lonE = pred.look(b).subLon;             // East-positive, -180..180
      double lonW = -lonE; while (lonW < 0) lonW += 360.0; while (lonW >= 360.0) lonW -= 360.0;
      if (lonW < 0.05 || lonW > 359.95) lonW = 0.0;  // avoid "-0.0 W" at the meridian
      eqxT[eqxN]    = b;
      eqxLonW[eqxN] = (float)lonW;
      eqxN++;
    }
    prevLat = L.subLat; prevT = t;
  }
  setStatus(eqxN ? "" : "No crossings found");
}

void App::drawEqx() {
  SatEntry* s = activeSat();
  header(s ? (String(s->name) + (eqxDescending ? " DEQX" : " EQX"))
           : String("EQX table"));
  canvas.setTextSize(1);
  if (!s) { canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 56);
            canvas.print("No satellite."); footer("` back"); return; }
  if (!timeIsSet()) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 52);
    canvas.print("Clock not set.");
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(6, 66);
    canvas.print("Set UTC (GPS or Location).");
    footer("` back"); return;
  }
  if (eqxN == 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 52);
    canvas.print(eqxDescending ? "No descending crossings." : "No ascending crossings.");
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(6, 66);
    canvas.print("r recompute   ` back");
    footer("` back"); return;
  }
  // Column header
  canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(4, 17);
  canvas.print(eqxDescending ? "Date  Desc UTC    Long (W+)"
                             : "Date    EQX UTC    Long (W+)");
  const int LH = 9, ROWS = 10;                       // 10 data rows under the head
  if (eqxScroll > eqxN - 1) eqxScroll = 0;
  int y = 28;
  int lastMday = -1;
  for (int e = eqxScroll; e < eqxN && e < eqxScroll + ROWS; ++e) {
    struct tm g; gmtime_r(&eqxT[e], &g);
    char date[8] = "      ";
    if (g.tm_mday != lastMday) { snprintf(date, sizeof(date), "%02d/%02d", g.tm_mon + 1, g.tm_mday);
                                 lastMday = g.tm_mday; }
    char line[40];
    snprintf(line, sizeof(line), "%-6s %02d:%02d:%02d   %5.1f W",
             date, g.tm_hour, g.tm_min, g.tm_sec, eqxLonW[e]);
    canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(4, y);
    canvas.print(line);
    y += LH;
  }
  // scrollbar hints + position
  canvas.setTextColor(CL_GREY, CL_BLACK);
  if (eqxScroll > 0)              { canvas.setCursor(232, 28);  canvas.print("^"); }
  if (eqxScroll + ROWS < eqxN)    { canvas.setCursor(232, 112); canvas.print("v"); }
  int last = eqxScroll + ROWS; if (last > eqxN) last = eqxN;
  { char c[28]; snprintf(c, sizeof(c), "%d-%d/%d", eqxScroll + 1, last, eqxN);
    footer(String("`bk ;/. scr d ") + (eqxDescending ? "asc" : "desc") + " r recalc " + c); }
}

void App::keyEqx(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { screen = SCR_SATLIST; lastDrawMs = 0; return; }
  const int ROWS = 10;
  if (isDown(c)) { if (eqxScroll + ROWS < eqxN) eqxScroll += ROWS; lastDrawMs = 0; return; }
  if (isUp(c))   { eqxScroll -= ROWS; if (eqxScroll < 0) eqxScroll = 0; lastDrawMs = 0; return; }
  if (c == 'd')  { eqxDescending = !eqxDescending; buildEqx(); lastDrawMs = 0; return; }
  if (c == 'r')  { buildEqx(); lastDrawMs = 0; return; }
}

// ===========================================================================
//  Simulation screen (off Satellites): freeze a UTC time and scrub it to see
//  where the selected satellite will be. A frozen snapshot (not live).
// ===========================================================================
static const long  SIM_STEP[]  = { 60, 600, 3600, 21600, 86400 };
static const char* SIM_STEPL[] = { "1 min", "10 min", "1 hr", "6 hr", "1 day" };

void App::drawSim() {
  SatEntry* s = activeSat();
  header(s ? (String(s->name) + (simMap ? " sim map" : " sim")) : String("Simulation"));
  canvas.setTextSize(1);
  if (!s) { canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 56);
            canvas.print("No satellite."); footer("` back"); return; }
  if (!timeIsSet()) { canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 56);
            canvas.print("Clock not set (NTP/GPS)."); footer("` back"); return; }
  if (simTime == 0) simTime = nowUtc();

  struct tm tmv; gmtime_r(&simTime, &tmv);
  char ts[28]; snprintf(ts, sizeof(ts), "%04d-%02d-%02d %02d:%02d:%02dZ",
                        tmv.tm_year + 1900, tmv.tm_mon + 1, tmv.tm_mday,
                        tmv.tm_hour, tmv.tm_min, tmv.tm_sec);

  pred.setSite(loc.obs()); pred.setSat(*s);
  LiveLook L = pred.look(simTime);

  if (simMap) {
    // ---- World-map view: sub-point + footprint at the simulated instant. ----
    const int MX = 0, MY = 16, MW = 240, MH = 92;      // map rect (y 16..108)
    const uint16_t GRID = CL_MGREY;
    canvas.fillRect(MX, MY, MW, MH, CL_BLACK);
    { int px = 0, py = 0, plo = 0; bool pen = false;
      for (int i = 0; i + 1 < COAST_N; i += 2) {
        int lo = COAST[i], la = COAST[i + 1];
        if (lo == 999) { pen = false; continue; }
        int x = MX + (int)lround((lo + 180.0) / 360.0 * MW);
        int y = MY + (int)lround((90.0 - la) / 180.0 * MH);
        if (pen && abs(lo - plo) < 180) canvas.drawLine(px, py, x, y, CL_DGREEN);
        px = x; py = y; plo = lo; pen = true;
      }
    }
    for (int lon = -180; lon <= 180; lon += 30) {
      int x = MX + (lon + 180) * MW / 360; if (x > MX + MW - 1) x = MX + MW - 1;
      canvas.drawLine(x, MY, x, MY + MH - 1, lon == 0 ? CL_DGREEN : GRID);
    }
    for (int lat = -60; lat <= 60; lat += 30) {
      int y = MY + (90 - lat) * MH / 180;
      canvas.drawLine(MX, y, MX + MW - 1, y, lat == 0 ? CL_DGREEN : GRID);
    }
    canvas.drawRect(MX, MY, MW, MH, GRID);

    Observer o = loc.obs();
    if (o.valid) {
      int qx = MX + (int)lround((o.lon + 180.0) / 360.0 * MW);
      int qy = MY + (int)lround((90.0  - o.lat) / 180.0 * MH);
      canvas.drawLine(qx - 3, qy, qx + 3, qy, CL_WHITE);
      canvas.drawLine(qx, qy - 3, qx, qy + 3, CL_WHITE);
    }

    double lon = L.subLon; while (lon < -180) lon += 360; while (lon > 180) lon -= 360;
    double lat = L.subLat; if (lat > 90) lat = 90; if (lat < -90) lat = -90;
    int x = MX + (int)lround((lon + 180.0) / 360.0 * MW);
    int y = MY + (int)lround((90.0 - lat) / 180.0 * MH);
    uint16_t col = L.sunlit ? CL_YELLOW : CL_CYAN;
    if (L.satAltKm > 1.0) {                            // ground footprint outline
      const double D2R = 0.0174532925199433, R2D = 57.2957795130823, RE = 6371.0;
      double beta = acos(RE / (RE + L.satAltKm));
      double la1 = lat * D2R, lo1 = lon * D2R, sb = sin(beta), cb = cos(beta);
      double s1 = sin(la1), c1 = cos(la1);
      int pfx = 0, pfy = 0; double pflon = 0; bool have = false;
      for (int a = 0; a <= 360; a += 15) {
        double az = a * D2R;
        double la2 = asin(s1 * cb + c1 * sb * cos(az));
        double lo2 = lo1 + atan2(sin(az) * sb * c1, cb - s1 * sin(la2));
        double lo2d = lo2 * R2D; while (lo2d < -180) lo2d += 360; while (lo2d > 180) lo2d -= 360;
        int fx = MX + (int)lround((lo2d + 180.0) / 360.0 * MW);
        int fy = MY + (int)lround((90.0 - la2 * R2D) / 180.0 * MH);
        if (have && fabs(lo2d - pflon) < 180.0) canvas.drawLine(pfx, pfy, fx, fy, col);
        pfx = fx; pfy = fy; pflon = lo2d; have = true;
      }
    }
    canvas.fillCircle(x, y, 2, col);
    canvas.drawCircle(x, y, 3, CL_BLACK);
    SatEntry* a = activeSat(); if (a) pred.setSat(*a);  // restore propagator

    // Time + step strip below the map.
    canvas.setTextColor(CL_CYAN, CL_BLACK); canvas.setCursor(2, MY + MH + 1); canvas.print(ts);
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(2, MY + MH + 11);
    canvas.printf("El %.0f  step %s  %s", L.el, SIM_STEPL[simStepIdx],
                  L.el > 0 ? "VIS" : "---");
    footer("m data  ,// time  ;/. step  ` bk");
    return;
  }

  int y = 18; const int LH = 11;
  auto row = [&](const char* k, const String& v) {
    canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.setCursor(2, y);  canvas.print(k);
    canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(86, y); canvas.print(v);
    y += LH;
  };
  canvas.setTextColor(CL_CYAN, CL_BLACK); canvas.setCursor(2, y); canvas.print(ts); y += LH;

  long d = (long)(simTime - nowUtc()); long ad = d < 0 ? -d : d;
  char ds[28]; snprintf(ds, sizeof(ds), "%c%ldd %02ldh %02ldm", d < 0 ? '-' : '+',
                        ad / 86400, (ad % 86400) / 3600, (ad % 3600) / 60);
  row("Offset", ds);
  row("Step",   SIM_STEPL[simStepIdx]);

  row("Az / El",  String(L.az, 1) + " / " + String(L.el, 1));
  row("Range",    String(L.rangeKm, 0) + " km");
  row("Sub pt",   String(L.subLat, 2) + "," + String(L.subLon, 2));
  row("Altitude", String(L.satAltKm, 0) + " km");
  canvas.setTextColor(L.el > 0 ? CL_GREEN : CL_GREY, CL_BLACK);
  canvas.setCursor(2, y); canvas.print(L.el > 0 ? "ABOVE horizon" : "below horizon");
  canvas.setTextColor(L.sunlit ? CL_YELLOW : CL_CYAN, CL_BLACK);
  canvas.printf("  %s", L.sunlit ? "sunlit" : "eclipse");
  footer("m map  ,// time  ;/. step  x now  ` bk");
}

void App::keySim(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { screen = SCR_SATLIST; lastDrawMs = 0; return; }
  if (c == 'm')   { simMap = !simMap; lastDrawMs = 0; return; }
  if (simTime == 0 && timeIsSet()) simTime = nowUtc();
  if (isRight(c)) { simTime += SIM_STEP[simStepIdx]; lastDrawMs = 0; return; }
  if (isLeft(c))  { simTime -= SIM_STEP[simStepIdx]; lastDrawMs = 0; return; }
  if (isDown(c))  { if (++simStepIdx > 4) simStepIdx = 4; lastDrawMs = 0; return; }
  if (isUp(c))    { if (--simStepIdx < 0) simStepIdx = 0; lastDrawMs = 0; return; }
  if (c == 'x')   { if (timeIsSet()) simTime = nowUtc(); lastDrawMs = 0; return; }
}

// ===========================================================================
//  Sun / Moon tracking screen (off the main menu). Live az/el for both; pick
//  one (;/.) and engage the rotator on it (o); parks on exit. Pointing runs in
//  the loop (smOut) at ~1 Hz, like tracking a pass.
// ===========================================================================
void App::drawSunMoon() {
  header("Sun / Moon");
  canvas.setTextSize(1);
  Observer o = loc.obs();
  if (!o.valid || !timeIsSet()) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 56);
    canvas.print(!o.valid ? "Set your location first." : "Clock not set (NTP/GPS).");
    footer("` back"); return;
  }
  time_t now = nowUtc();
  double azv[2], elv[2];
  skyObjAzEl(now, o.lat, o.lon, false, azv[0], elv[0]);   // Sun
  skyObjAzEl(now, o.lat, o.lon, true,  azv[1], elv[1]);   // Moon
  static const char* nm[2] = { "SUN", "MOON" };
  const uint16_t SUNCOL = CL_YELLOW, MOONCOL = CL_CYAN;
  const uint16_t bodyCol[2] = { SUNCOL, MOONCOL };

  if (smGraphic) {
    // ---- Graphical sky dome: zenith at centre, N up, elevation = radius. ----
    // Bodies below the horizon are shown faintly just outside the rim so their
    // azimuth is still readable. The selected body gets a ring, not a fill bar.
    const int cx = 62, cy = 68, R = 42;
    drawPolarGrid(cx, cy, R);
    auto domeXY = [&](double az, double el, int& x, int& y) {
      double e = el; if (e > 90) e = 90; if (e < -6) e = -6;
      double rr = (e >= 0) ? R * (90.0 - e) / 90.0 : R + 4;   // below: just outside rim
      double a  = az * (M_PI / 180.0);
      x = cx + (int)lround(rr * sin(a));
      y = cy - (int)lround(rr * cos(a));
    };
    for (int i = 0; i < 2; ++i) {
      int x, y; domeXY(azv[i], elv[i], x, y);
      bool up = elv[i] > 0;
      uint16_t col = up ? bodyCol[i] : CL_GREY;
      if (i == 0) {                                  // Sun: filled disc + rays
        canvas.fillCircle(x, y, 5, col);
        if (up) for (int a = 0; a < 360; a += 45) {
          double ar = a * (M_PI / 180.0);
          canvas.drawLine(x + (int)lround(7*sin(ar)), y - (int)lround(7*cos(ar)),
                          x + (int)lround(9*sin(ar)), y - (int)lround(9*cos(ar)), col);
        }
      } else {                                       // Moon: disc with a bite (crescent)
        canvas.fillCircle(x, y, 5, col);
        canvas.fillCircle(x + 2, y - 1, 4, CL_BLACK);
      }
      if (smSel == i) canvas.drawCircle(x, y, 9, CL_GREEN);   // selection ring
    }

    // ---- Compact data panel on the right. ----
    int px = 124;
    for (int i = 0; i < 2; ++i) {
      int y = 22 + i * 40;
      bool sel = (smSel == i);
      canvas.setTextSize(2);
      canvas.setTextColor(sel ? CL_GREEN : bodyCol[i], CL_BLACK);
      canvas.setCursor(px, y); canvas.print(nm[i]);
      canvas.setTextSize(1);
      canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.setCursor(px, y + 18);  canvas.print("Az");
      canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(px + 18, y + 18); canvas.printf("%.1f", azv[i]);
      canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.setCursor(px + 64, y + 18); canvas.print("El");
      canvas.setTextColor(elv[i] > 0 ? CL_WHITE : CL_GREY, CL_BLACK);
      canvas.setCursor(px + 82, y + 18); canvas.printf("%.1f", elv[i]);
      canvas.setTextColor(elv[i] > 0 ? CL_GREEN : CL_GREY, CL_BLACK);
      canvas.setCursor(px, y + 28); canvas.print(elv[i] > 0 ? "above horizon" : "below horizon");
    }
  } else {
    // ---- Data-list view (compact, no full-width highlight bar). ----
    for (int i = 0; i < 2; ++i) {
      int y = 24 + i * 36;
      bool sel = (smSel == i);
      if (sel) { canvas.drawRect(2, y - 4, 236, 32, CL_GREEN); }   // outline, not fill
      canvas.setTextColor(sel ? CL_GREEN : bodyCol[i], CL_BLACK);
      canvas.setTextSize(2); canvas.setCursor(8, y); canvas.print(nm[i]); canvas.setTextSize(1);
      canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.setCursor(96, y);      canvas.print("Az");
      canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(114, y);     canvas.printf("%.1f", azv[i]);
      canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.setCursor(96, y + 13); canvas.print("El");
      canvas.setTextColor(elv[i] > 0 ? CL_WHITE : CL_GREY, CL_BLACK);
      canvas.setCursor(114, y + 13); canvas.printf("%.1f", elv[i]);
      canvas.setTextColor(elv[i] > 0 ? CL_GREEN : CL_GREY, CL_BLACK);
      canvas.setCursor(186, y + 6); canvas.print(elv[i] > 0 ? "up" : "down");
    }
  }

  bool rok = rot && rot->ready();
  canvas.setTextColor(smOut ? CL_GREEN : (rok ? CL_GREY : CL_ORANGE), CL_BLACK);
  canvas.setCursor(8, 116);
  const char* rs = !smOut ? (rok ? "off" : "n/c")
                  : (elv[smSel] <= 0 ? (smSel ? "MOON set (parked)" : "SUN set (parked)")
                                     : (smSel ? "tracking MOON" : "tracking SUN"));
  canvas.printf("Rotator: %s", rs);
  footer(";/. pick g o rot s sky t x stop  ` bk");
}

void App::keySunMoon(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) {
    if (smOut && rot) rotPoint((float)cfg.rotParkAz, (float)cfg.rotParkEl);   // park on exit
    smOut = false; screen = SCR_HOME; lastDrawMs = 0; return;
  }
  if (isUp(c) || isDown(c)) { smSel ^= 1; lastAzCmd = lastElCmd = -999.0f; lastDrawMs = 0; return; }
  if (c == 'g') { smGraphic = !smGraphic; lastDrawMs = 0; return; }
  if (c == 'o') {
    if (!rot || !rot->ready()) { setStatus("Rotator not ready"); return; }
    smOut = !smOut; lastAzCmd = lastElCmd = -999.0f;
    if (smOut) { rotOut = false; emeRotOut = false; gcRotOut = false;  // Sun/Moon takes the rotator
                 setStatus(smSel ? "Tracking Moon" : "Tracking Sun"); }
    else { rotPoint((float)cfg.rotParkAz, (float)cfg.rotParkEl); setStatus("Rotator OFF (parked)"); }
    lastDrawMs = 0; return;
  }
  if (c == 'x') { if (rot) rot->stop(); smOut = false; lastDrawMs = 0; return; }
  if (c == 's') { skySel = 0; screen = SCR_SKYMAP; lastDrawMs = 0; return; }  // sky plot
  if (c == 't') { screen = SCR_TRANSIT; transitStartJob(); lastDrawMs = 0; return; }  // Sun/Moon transits
  if (c == 'e') { emeMutShown = false; screen = SCR_EME; lastDrawMs = 0; return; }     // EME / moonbounce
}

// ---- EME (moonbounce) screen ---------------------------------------------------------
// Live lunar Doppler for the ham bands, topocentric range + range-rate, path degradation
// vs perigee, and a coarse sky-noise flag from the Moon's galactic latitude. Reachable
// from the Sun/Moon screen with 'e'. A sub-view ('m') finds the mutual-Moon window against
// a DX grid (when the Moon is above the horizon for both stations).

// Fill the mutual-Moon window list: scan forward and record spans where the Moon is up
// (el > 0) for BOTH our QTH and the DX grid -- the EME common window.
void App::emeComputeMutual(const String& grid) {
  emeMutN = 0; emeMutSel = 0; emeMutScroll = 0;
  Observer o = loc.obs();
  double dlat, dlon;
  if (!Location::gridToLatLon(grid, dlat, dlon)) { setStatus("Bad grid"); return; }
  if (!o.valid || !timeIsSet()) { setStatus("Need QTH + clock"); return; }
  time_t now = nowUtc();
  const int STEP = 300;                 // 5-min scan step over the next 14 days
  const time_t END = now + (time_t)14 * 86400;
  bool inWin = false; time_t winStart = 0;
  auto bothUp = [&](time_t t)->bool {
    double az1, el1, az2, el2;
    skyObjAzEl(t, o.lat, o.lon, true, az1, el1);
    skyObjAzEl(t, dlat, dlon, true, az2, el2);
    return el1 > 0 && el2 > 0;
  };
  for (time_t t = now; t < END && emeMutN < EME_MUT_MAX; t += STEP) {
    bool up = bothUp(t);
    if (up && !inWin) { inWin = true; winStart = t; }
    else if (!up && inWin) {
      inWin = false;
      emeMut[emeMutN].aos = winStart; emeMut[emeMutN].los = t; emeMutN++;
    }
  }
  if (inWin && emeMutN < EME_MUT_MAX) { emeMut[emeMutN].aos = winStart; emeMut[emeMutN].los = END; emeMutN++; }
  strncpy(emeMutGrid, grid.c_str(), sizeof(emeMutGrid) - 1); emeMutGrid[sizeof(emeMutGrid) - 1] = 0;
  if (emeMutN == 0) setStatus("No common Moon window in 14 d");
}

void App::drawEme() {
  header("EME / Moonbounce");
  canvas.setTextSize(1);
  Observer o = loc.obs();
  if (!o.valid || !timeIsSet()) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 44); canvas.print(!o.valid ? "Set your location first." : "Clock not set (NTP/GPS).");
    footer("` back");
    return;
  }
  time_t now = nowUtc();

  if (emeMutShown) {                     // ---- mutual-Moon window sub-view ----
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(4, 20); canvas.printf("Common Moon window vs %s", emeMutGrid);
    if (emeMutN == 0) {
      canvas.setTextColor(CL_YELLOW, CL_BLACK);
      canvas.setCursor(6, 40); canvas.print("No common window in 14 days.");
      footer("g grid  ` back");
      return;
    }
    const int rows = 8;
    if (emeMutSel < emeMutScroll) emeMutScroll = emeMutSel;
    if (emeMutSel >= emeMutScroll + rows) emeMutScroll = emeMutSel - rows + 1;
    for (int r = 0; r < rows && (emeMutScroll + r) < emeMutN; ++r) {
      int vi = emeMutScroll + r; int y = 32 + r * 11;
      bool sel = (vi == emeMutSel);
      if (sel) canvas.fillRect(0, y - 1, 240, 11, CL_SELBG);
      canvas.setTextColor(sel ? CL_BLACK : CL_WHITE, sel ? CL_SELBG : CL_BLACK);
      time_t a = emeMut[vi].aos, l = emeMut[vi].los;
      long durMin = (long)(l - a) / 60;
      struct tm tmv; gmtime_r(&a, &tmv);
      canvas.setCursor(4, y);
      canvas.printf("%02d-%02d %02d:%02dZ  %ldh%02ldm", tmv.tm_mon + 1, tmv.tm_mday,
                    tmv.tm_hour, tmv.tm_min, durMin / 60, durMin % 60);
    }
    footer("g grid  ` back");
    return;
  }

  // ---- main EME data view ----
  double az, el; skyObjAzEl(now, o.lat, o.lon, true, az, el);
  double rangeKm, rrMs; moonTopoRangeRate(now, o.lat, o.lon, rangeKm, rrMs);
  double galLat = moonGalacticLatDeg(now);
  // Sun proximity: within ~10 deg of the Moon the Sun sits in the beam and its
  // noise buries weak echoes. Angular separation from the two az/el vectors.
  const double D2R_ = 0.017453292519943295;
  double saz, sel_; skyObjAzEl(now, o.lat, o.lon, false, saz, sel_);
  double sunSep = acos(sin(el * D2R_) * sin(sel_ * D2R_)
                     + cos(el * D2R_) * cos(sel_ * D2R_) * cos((az - saz) * D2R_)) / D2R_;

  // Moon az/el + up/down
  canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(4, 20); canvas.print("Moon");
  canvas.setTextColor(el > 0 ? CL_GREEN : CL_ORANGE, CL_BLACK);
  canvas.setCursor(40, 20); canvas.printf("Az %.1f  El %.1f  %s", az, el, el > 0 ? "UP" : "down");
  if (el > 0 && sunSep < 10.0) {
    canvas.setTextColor(CL_RED, CL_BLACK); canvas.setCursor(186, 20);
    canvas.printf("SUN %.0fdeg", sunSep);
  }

  // Range + range-rate
  canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(4, 32); canvas.print("Range");
  canvas.setTextColor(CL_WHITE, CL_BLACK);
  canvas.setCursor(46, 32); canvas.printf("%.0f km   rate %+.0f m/s", rangeKm, rrMs);

  // Path degradation vs perigee (40*log10(r/rp)); note near perigee/apogee.
  const double RP = 356500.0, RA = 406700.0;
  double degdB = 40.0 * log10(rangeKm / RP);
  const char* pa = (rangeKm < RP + 8000) ? " (near perigee)"
                 : (rangeKm > RA - 8000) ? " (near apogee)" : "";
  canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(4, 44); canvas.print("Degrad");
  canvas.setTextColor(degdB < 1.0 ? CL_GREEN : (degdB < 1.8 ? CL_YELLOW : CL_ORANGE), CL_BLACK);
  canvas.setCursor(46, 44); canvas.printf("%.2f dB%s", degdB, pa);

  // Sky-noise flag from |galactic latitude|.
  double b = fabs(galLat);
  const char* sky = (b < 10) ? "HOT (galactic plane)" : (b < 25) ? "warm" : "cold sky";
  uint16_t skyc = (b < 10) ? CL_RED : (b < 25) ? CL_YELLOW : CL_GREEN;
  canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(4, 56); canvas.print("Sky");
  canvas.setTextColor(skyc, CL_BLACK); canvas.setCursor(46, 56); canvas.printf("%s (b %+.0f)", sky, galLat);

  // Per-band lunar Doppler (round trip): shift = -2*f*rr/c. Rows are pitched to keep
  // all five bands (through the 10 GHz row) clear of the footer at y=127.
  canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(4, 70); canvas.print("Self-echo Doppler:");
  struct { const char* n; double mhz; } bands[] = {
    {"50", 50.0}, {"144", 144.0}, {"432", 432.0}, {"1296", 1296.0}, {"10G", 10368.0}
  };
  const double C = 299792458.0;
  for (int i = 0; i < 5; ++i) {
    int y = 80 + i * 9;
    double dop = -2.0 * bands[i].mhz * 1e6 * rrMs / C;
    canvas.setTextColor(CL_CYAN, CL_BLACK); canvas.setCursor(8, y); canvas.printf("%-5s MHz", bands[i].n);
    canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(88, y);
    if (fabs(dop) >= 1000) canvas.printf("%+.2f kHz", dop / 1000.0);
    else                   canvas.printf("%+.0f Hz", dop);
  }

  footer(emeRotOut ? "o STOP rot  m mutual  p plan  ` back" : "o point Moon  m mutual  p plan  ` back");
}

void App::keyEme(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) {
    if (emeMutShown) { emeMutShown = false; lastDrawMs = 0; return; }   // sub-view -> main
    if (emeRotOut && rot) rotPoint((float)cfg.rotParkAz, (float)cfg.rotParkEl);
    emeRotOut = false; screen = SCR_SUNMOON; lastDrawMs = 0; return;
  }
  if (emeMutShown) {
    if (isUp(c)   && emeMutSel > 0)            { emeMutSel--; lastDrawMs = 0; return; }
    if (isDown(c) && emeMutSel < emeMutN - 1)  { emeMutSel++; lastDrawMs = 0; return; }
    if (c == 'g') { editTarget = 360; editTitle = "DX grid (EME)"; editBuf = emeMutGrid; screen = SCR_EDIT; return; }
    return;
  }
  if (c == 'p') {                        // 30-day EME planning view
    time_t now2 = timeIsSet() ? nowUtc() : 0;
    if (!now2) { setStatus("Clock not set"); return; }
    emePlanT0 = now2 - (now2 % 86400) + 12 * 3600;   // 12:00 UTC today, then daily
    const double D2Rp = 0.017453292519943295;
    for (int d = 0; d < 30; ++d) {
      time_t tt = emePlanT0 + (time_t)d * 86400;
      double x, y, z; moonGeoEqKm(tt, x, y, z);
      double r = sqrt(x * x + y * y + z * z);
      emePlanDec[d] = (float)(atan2(z, sqrt(x * x + y * y)) / D2Rp);
      emePlanDeg[d] = (float)(40.0 * log10(r / 356500.0));
    }
    emePlanN = 30; emePlanScroll = 0;
    screen = SCR_EMEPLAN; lastDrawMs = 0; return;
  }
  if (c == 'o') {                        // point the rotator at the Moon (el included)
    if (!rot || !rot->ready()) { setStatus("Rotator not ready"); return; }
    emeRotOut = !emeRotOut;
    if (emeRotOut) { rotOut = false; smOut = false; gcRotOut = false; setStatus("Pointing at Moon"); }
    else { rotPoint((float)cfg.rotParkAz, (float)cfg.rotParkEl); setStatus("Rotator OFF (parked)"); }
    lastDrawMs = 0; return;
  }
  if (c == 'x') { if (rot) rot->stop(); emeRotOut = false; lastDrawMs = 0; return; }
  if (c == 'm') {                        // mutual-Moon window vs a DX grid
    if (emeMutGrid[0]) { emeComputeMutual(String(emeMutGrid)); emeMutShown = true; lastDrawMs = 0; }
    else { editTarget = 360; editTitle = "DX grid (EME)"; editBuf = ""; screen = SCR_EDIT; }
    return;
  }
}

// ---- Grid distance/bearing calculator (SCR_GRIDCALC) ---------------------------------
// A main-menu tool: enter a Maidenhead grid, get great-circle distance + beam heading
// from your QTH, and optionally point the rotator at that bearing (terrestrial: el 0).

void App::gcCompute() {
  gcHaveResult = false;
  Observer o = loc.obs();
  if (!o.valid) { setStatus("Set your location first"); return; }
  double dlat, dlon;
  if (!gcGrid[0] || !Location::gridToLatLon(String(gcGrid), dlat, dlon)) { setStatus("Bad grid"); return; }
  greatCircle(o.lat, o.lon, dlat, dlon, gcDistKm, gcBearing);
  gcHaveResult = true;
}

void App::drawGridCalc() {
  header("Grid dist / bearing");
  canvas.setTextSize(1);
  Observer o = loc.obs();
  if (!o.valid) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 44); canvas.print("Set your location first.");
    footer("` back");
    return;
  }
  canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(4, 22); canvas.print("Your QTH");
  canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(64, 22);
  { String mg = Location::toGrid(o.lat, o.lon); canvas.print(mg); }
  canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(4, 36); canvas.print("Target");
  canvas.setTextColor(CL_CYAN, CL_BLACK); canvas.setCursor(64, 36);
  canvas.print(gcGrid[0] ? gcGrid : "(none - press g)");

  if (gcHaveResult) {
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(4, 58); canvas.print("Distance");
    canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(72, 58);
    canvas.printf("%.0f km  (%.0f mi)", gcDistKm, gcDistKm * 0.621371);
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(4, 72); canvas.print("Heading");
    canvas.setTextColor(CL_GREEN, CL_BLACK); canvas.setCursor(72, 72);
    canvas.printf("%.0f deg", gcBearing);
    // long-path
    double lp = gcBearing + 180.0; if (lp >= 360) lp -= 360;
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(4, 86); canvas.print("Long path");
    canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(72, 86);
    canvas.printf("%.0f deg  (%.0f km)", lp, 40075.0 - gcDistKm);
    if (gcRotOut) { canvas.setTextColor(CL_GREEN, CL_BLACK); canvas.setCursor(4, 104);
                    canvas.printf("Rotator -> %.0f deg", gcBearing); }
  } else {
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(6, 62);
    canvas.print("Press g to enter a grid,");
    canvas.setCursor(6, 74); canvas.print("or q to look up a callsign.");
  }
  footer(gcRotOut ? "g grid q qrz o STOP rot `bk" : "g grid q qrz o point rot `bk");
}

void App::keyGridCalc(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) {
    if (gcRotOut && rot) rotPoint((float)cfg.rotParkAz, (float)cfg.rotParkEl);
    gcRotOut = false; screen = SCR_HOME; lastDrawMs = 0; return;
  }
  if (c == 'g') { editTarget = 350; editTitle = "Target grid"; editBuf = gcGrid; screen = SCR_EDIT; return; }
  if (c == 'q') { editTarget = 351; editTitle = "Callsign"; editBuf = ""; screen = SCR_EDIT; return; }
  if (c == 'o') {                        // point rotator at the bearing (terrestrial: el 0)
    if (!gcHaveResult) { setStatus("Compute a bearing first"); return; }
    if (!rot || !rot->ready()) { setStatus("Rotator not ready"); return; }
    gcRotOut = !gcRotOut;
    if (gcRotOut) { rotOut = false; smOut = false; emeRotOut = false;
                    float a = (float)gcBearing + cfg.rotAzOff; while (a >= 360) a -= 360; while (a < 0) a += 360;
                    rotPoint(a, 0.0f); setStatus("Rotator pointed at grid"); }
    else { rotPoint((float)cfg.rotParkAz, (float)cfg.rotParkEl); setStatus("Rotator OFF (parked)"); }
    lastDrawMs = 0; return;
  }
  if (c == 'x') { if (rot) rot->stop(); gcRotOut = false; lastDrawMs = 0; return; }
}

// ---- QRZ-to-grid lookup (SCR_QRZGRID) ------------------------------------------------
// A separate QRZ-lookup screen that only resolves a callsign to its grid and seeds the
// grid calculator. Kept independent of the main SCR_QRZ screen, which is untouched. Reuses
// the existing qrzLookup() session/fetch (which sets the qrzGrid member).

void App::qrzGridLookup() {
  if (!net.connected()) { qgStatus = "No WiFi - connect in Settings"; qgHave = false; return; }
  if (strlen(cfg.qrzUser) == 0 || strlen(cfg.qrzPass) == 0) {
    qgStatus = "Set QRZ login in Settings"; qgHave = false; return;
  }
  String err;
  if (qrzLookup(String(qgCall), err)) {
    qgGrid = qrzGrid; qgName = qrzName;              // qrzName/qrzGrid set by qrzLookup()
    if (qgGrid.length() >= 4) { qgHave = true; qgStatus = ""; }
    else { qgHave = false; qgStatus = "No grid for that call"; }
  } else {
    qgHave = false; qgStatus = err.length() ? err : "Lookup failed";
  }
}

void App::drawQrzGrid() {
  header("QRZ -> grid");
  canvas.setTextSize(1);
  canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(4, 24); canvas.print("Callsign");
  canvas.setTextColor(CL_CYAN, CL_BLACK); canvas.setCursor(72, 24);
  canvas.print(qgCall[0] ? qgCall : "(press c)");
  if (qgHave) {
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(4, 44); canvas.print("Name");
    canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(72, 44); canvas.print(qgName.substring(0, 26));
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(4, 58); canvas.print("Grid");
    canvas.setTextColor(CL_GREEN, CL_BLACK); canvas.setCursor(72, 58); canvas.print(qgGrid);
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(6, 80);
    canvas.print("ENTER: use this grid in the");
    canvas.setCursor(6, 92); canvas.print("distance/bearing calculator.");
    footer("ENTER use grid  c call  ` back");
  } else {
    canvas.setTextColor(qgStatus.startsWith("No ") || qgStatus.length() ? CL_YELLOW : CL_GREY, CL_BLACK);
    canvas.setCursor(6, 56); canvas.print(qgStatus.length() ? qgStatus : "Press c to enter a callsign.");
    footer("c call  ` back");
  }
}

void App::keyQrzGrid(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_GRIDCALC; lastDrawMs = 0; return; }
  if (c == 'c') { editTarget = 351; editTitle = "Callsign"; editBuf = qgCall; screen = SCR_EDIT; return; }
  if (enter && qgHave) {                  // seed the grid calculator with this grid
    strncpy(gcGrid, qgGrid.c_str(), sizeof(gcGrid) - 1); gcGrid[sizeof(gcGrid) - 1] = 0;
    gcCompute(); screen = SCR_GRIDCALC; lastDrawMs = 0; return;
  }
}

