void App::drawBandPlan() {
  header("Band plan / frequencies");
  canvas.setTextSize(1);
  const int N = (int)(sizeof(BANDPLAN) / sizeof(BANDPLAN[0]));
  const int rows = 10;
  if (bpScroll < 0) bpScroll = 0;
  if (bpScroll > N - rows) bpScroll = (N > rows) ? N - rows : 0;
  for (int r = 0; r < rows && (bpScroll + r) < N; ++r) {
    int i = bpScroll + r, y = 20 + r * 11;
    const char* s = BANDPLAN[i];
    if (s[0] == '#') {                    // section header
      canvas.setTextColor(CL_ORANGE, CL_BLACK);
      canvas.setCursor(4, y); canvas.print(s + 1);
    } else {
      // "band|range|notes" -> band (cyan) + range (white); notes shown when the
      // band field is short enough to leave room.
      const char* p1 = strchr(s, '|');
      const char* p2 = p1 ? strchr(p1 + 1, '|') : nullptr;
      char band[22] = {0}, range[40] = {0};
      if (p1) { int n = (int)(p1 - s); if (n > 21) n = 21; memcpy(band, s, n); }
      if (p1 && p2) { int n = (int)(p2 - p1 - 1); if (n > 39) n = 39; memcpy(range, p1 + 1, n); }
      else if (p1)  { strncpy(range, p1 + 1, 39); }
      bool indent = (band[0] == ' ');
      canvas.setTextColor(indent ? CL_GREY : CL_CYAN, CL_BLACK);
      canvas.setCursor(indent ? 8 : 4, y); canvas.print(band);
      canvas.setTextColor(CL_WHITE, CL_BLACK);
      canvas.setCursor(96, y); canvas.print(range);
    }
  }
  // scroll arrows
  canvas.setTextColor(CL_GREY, CL_BLACK);
  if (bpScroll > 0)          { canvas.setCursor(232, 20);  canvas.print("^"); }
  if (bpScroll + rows < N)   { canvas.setCursor(232, 119); canvas.print("v"); }
  footer("; / . scroll  ` back");
}

void App::keyBandPlan(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { screen = SCR_HELP; lastDrawMs = 0; return; }
  const int N = (int)(sizeof(BANDPLAN) / sizeof(BANDPLAN[0]));
  if (isUp(c))   { bpScroll--; lastDrawMs = 0; }
  if (isDown(c)) { bpScroll++; lastDrawMs = 0; }
  if (c == '{')  { bpScroll -= 10; lastDrawMs = 0; }
  if (c == '}')  { bpScroll += 10; lastDrawMs = 0; }
  if (bpScroll < 0) bpScroll = 0;
  if (bpScroll > N - 1) bpScroll = N - 1;
}

// ===========================================================================
//  Celestial sky plot (SCR_SKYMAP): planets and strong radio sources on a sky
//  dome (zenith centre, N up, elevation = radius), reached with `s` from the
//  Sun/Moon screen. Useful for antenna pointing (Sun/Moon/planet) and as a
//  reference for the strongest cosmic radio sources crossing the sky.
// ===========================================================================

// Equatorial (RA/Dec, degrees, J2000-ish) -> horizontal (az/el) for the observer
// at time t. The same conversion used inside skyObjAzEl, factored out so fixed
// catalogue sources and computed planet positions can share it.
static void raDecToAzEl(time_t t, double latDeg, double lonDeg,
                        double raDeg, double decDeg, double& az, double& el) {
  const double D2R = 0.017453292519943295, R2D = 57.29577951308232,
               TWO_PI_ = 6.283185307179586;
  double d = ((double)t - 946728000.0) / 86400.0;
  double gmst = fmod(280.46061837 + 360.98564736629 * d, 360.0);
  if (gmst < 0) gmst += 360.0;
  double ra = raDeg * D2R, dec = decDeg * D2R, latR = latDeg * D2R;
  double lst = (gmst + lonDeg) * D2R, ha = lst - ra;
  double sinAlt = sin(latR) * sin(dec) + cos(latR) * cos(dec) * cos(ha);
  double alt = asin(sinAlt);
  double cosA = (sin(dec) - sin(latR) * sinAlt) / (cos(latR) * cos(alt));
  if (cosA > 1) cosA = 1; if (cosA < -1) cosA = -1;
  double A = acos(cosA);
  if (sin(ha) > 0) A = TWO_PI_ - A;
  az = A * R2D; el = alt * R2D;
}

// Low-precision heliocentric -> geocentric RA/Dec for the classical planets,
// using Schlyter's elements (good to ~1-2 arcmin, far finer than a 112 px dome).
static void planetRaDec(int p, time_t t, double& raDeg, double& decDeg) {
  const double D2R = 0.017453292519943295, R2D = 57.29577951308232;
  double d = ((double)t - 946728000.0) / 86400.0;          // days since J2000
  double ecl = (23.4393 - 3.563e-7 * d) * D2R;
  // Orbital elements: N, i, w, a, e, M (deg / AU), linear in d (Schlyter).
  // p: 0 Mercury 1 Venus 2 Mars 3 Jupiter 4 Saturn.
  struct El { double N0,Nr,i0,ir,w0,wr,a0,ar,e0,er,M0,Mr; };
  static const El E[5] = {
    { 48.3313,3.24587e-5, 7.0047,5.00e-8, 29.1241,1.01444e-5, 0.387098,0,      0.205635,5.59e-10, 168.6562,4.0923344368},
    { 76.6799,2.46590e-5, 3.3946,2.75e-8, 54.8910,1.38374e-5, 0.723330,0,      0.006773,-1.302e-9,48.0052,1.6021302244},
    { 49.5574,2.11081e-5, 1.8497,-1.78e-8,286.5016,2.92961e-5,1.523688,0,      0.093405,2.516e-9, 18.6021,0.5240207766},
    {100.4542,2.76854e-5, 1.3030,-1.557e-7,273.8777,1.64505e-5,5.20256,0,      0.048498,4.469e-9, 19.8950,0.0830853001},
    {113.6634,2.38980e-5, 2.4886,-1.081e-7,339.3939,2.97661e-5,9.55475,0,      0.055546,-9.499e-9,316.9670,0.0334442282},
  };
  const El& e = E[p];
  auto rad = [&](double deg){ return deg * D2R; };
  double N = rad(e.N0 + e.Nr * d), i = rad(e.i0 + e.ir * d), w = rad(e.w0 + e.wr * d);
  double a = e.a0, ecc = e.e0 + e.er * d, M = rad(e.M0 + e.Mr * d);
  M = fmod(M, 2 * M_PI); if (M < 0) M += 2 * M_PI;
  double Ea = M + ecc * sin(M) * (1 + ecc * cos(M));
  for (int k = 0; k < 5; ++k) Ea -= (Ea - ecc * sin(Ea) - M) / (1 - ecc * cos(Ea));
  double xv = a * (cos(Ea) - ecc), yv = a * sqrt(1 - ecc * ecc) * sin(Ea);
  double v = atan2(yv, xv), r = sqrt(xv * xv + yv * yv);
  double xh = r * (cos(N) * cos(v + w) - sin(N) * sin(v + w) * cos(i));
  double yh = r * (sin(N) * cos(v + w) + cos(N) * sin(v + w) * cos(i));
  double zh = r * (sin(v + w) * sin(i));
  // Sun's geocentric position (Earth heliocentric, negated).
  double Ms = rad(356.0470 + 0.9856002585 * d), ws = rad(282.9404 + 4.70935e-5 * d);
  double es = 0.016709 - 1.151e-9 * d;
  double Es = Ms + es * sin(Ms) * (1 + es * cos(Ms));
  double xvs = cos(Es) - es, yvs = sqrt(1 - es * es) * sin(Es);
  double lonsun = atan2(yvs, xvs) + ws, rs = sqrt(xvs * xvs + yvs * yvs);
  double xs = rs * cos(lonsun), ys = rs * sin(lonsun);
  // Geocentric ecliptic -> equatorial.
  double xg = xh + xs, yg = yh + ys, zg = zh;
  double xe = xg;
  double ye = yg * cos(ecl) - zg * sin(ecl);
  double ze = yg * sin(ecl) + zg * cos(ecl);
  raDeg = atan2(ye, xe) * R2D; if (raDeg < 0) raDeg += 360.0;
  decDeg = atan2(ze, sqrt(xe * xe + ye * ye)) * R2D;
}

// Catalogue of strong cosmic radio sources (fixed J2000 RA/Dec, degrees) plus a
// couple of bright orientation stars. Names kept short for the 240 px display.
struct SkySrc { const char* name; double ra, dec; bool rf; };
static const SkySrc SKY_RF[] = {
  { "CasA",  350.85,  58.81, true },   // brightest galactic radio source
  { "CygA",  299.87,  40.73, true },   // radio galaxy
  { "SgrA",  266.42, -29.01, true },   // galactic centre
  { "TauA",   83.63,  22.01, true },   // Crab nebula / pulsar
  { "VirA",  187.71,  12.39, true },   // M87
  { "Sun",     0.0,    0.0,  true },   // placeholder (computed live)
  { "Polaris",37.95,  89.26, false },  // orientation
  { "Vega",  279.23,  38.78, false },
  { "Antares",247.35,-26.43, false },
};
static const int SKY_RF_N = sizeof(SKY_RF) / sizeof(SKY_RF[0]);
static const char* PLANET_NAME[5] = { "Mercury", "Venus", "Mars", "Jupiter", "Saturn" };

void App::drawSkyMap() {
  header("Sky sources");
  canvas.setTextSize(1);
  Observer o = loc.obs();
  if (!o.valid || !timeIsSet()) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 56);
    canvas.print(!o.valid ? "Set your location first." : "Clock not set (NTP/GPS).");
    footer("` back"); return;
  }
  time_t now = nowUtc();

  // Build the combined object list: 5 planets, then the catalogue sources.
  const int NP = 5, NTOT = NP + SKY_RF_N;
  double az[32], el[32]; const char* nm[32]; bool isRf[32];
  for (int p = 0; p < NP; ++p) {
    double ra, dec; planetRaDec(p, now, ra, dec);
    raDecToAzEl(now, o.lat, o.lon, ra, dec, az[p], el[p]);
    nm[p] = PLANET_NAME[p]; isRf[p] = false;
  }
  for (int i = 0; i < SKY_RF_N; ++i) {
    int k = NP + i;
    if (i == 5) {  // "Sun" entry: compute live
      skyObjAzEl(now, o.lat, o.lon, false, az[k], el[k]);
    } else {
      raDecToAzEl(now, o.lat, o.lon, SKY_RF[i].ra, SKY_RF[i].dec, az[k], el[k]);
    }
    nm[k] = SKY_RF[i].name; isRf[k] = SKY_RF[i].rf;
  }
  if (skySel < 0) skySel = NTOT - 1;
  if (skySel >= NTOT) skySel = 0;

  // Sky dome: zenith centre, N up, elevation = radius (same as Sun/Moon graphic).
  const int cx = 62, cy = 70, R = 50;
  drawPolarGrid(cx, cy, R);
  auto domeXY = [&](double a, double e, int& x, int& y) {
    double ee = e; if (ee > 90) ee = 90; if (ee < -6) ee = -6;
    double rr = (ee >= 0) ? R * (90.0 - ee) / 90.0 : R + 4;
    double ar = a * (M_PI / 180.0);
    x = cx + (int)lround(rr * sin(ar));
    y = cy - (int)lround(rr * cos(ar));
  };
  for (int k = 0; k < NTOT; ++k) {
    int x, y; domeXY(az[k], el[k], x, y);
    bool up = el[k] > 0;
    uint16_t col = isRf[k] ? (up ? CL_ORANGE : CL_DGREY)
                           : (up ? CL_CYAN   : CL_DGREY);
    if (isRf[k]) {                       // RF source: small cross
      canvas.drawLine(x - 2, y, x + 2, y, col);
      canvas.drawLine(x, y - 2, x, y + 2, col);
    } else {                             // planet: filled dot
      canvas.fillCircle(x, y, 2, col);
    }
    if (k == skySel) canvas.drawCircle(x, y, 5, CL_GREEN);
  }

  // Right-hand readout for the selected object.
  int px = 122;
  canvas.setTextSize(2);
  canvas.setTextColor(isRf[skySel] ? CL_ORANGE : CL_CYAN, CL_BLACK);
  canvas.setCursor(px, 20); canvas.printf("%.10s", nm[skySel]);
  canvas.setTextSize(1);
  canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.setCursor(px, 44); canvas.print("Az");
  canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(px + 18, 44); canvas.printf("%.1f%c", az[skySel], 248);
  canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.setCursor(px, 56); canvas.print("El");
  canvas.setTextColor(el[skySel] > 0 ? CL_WHITE : CL_GREY, CL_BLACK);
  canvas.setCursor(px + 18, 56); canvas.printf("%.1f%c", el[skySel], 248);
  canvas.setTextColor(el[skySel] > 0 ? CL_GREEN : CL_GREY, CL_BLACK);
  canvas.setCursor(px, 70); canvas.print(el[skySel] > 0 ? "above horizon" : "below horizon");
  canvas.setTextColor(isRf[skySel] ? CL_ORANGE : CL_CYAN, CL_BLACK);
  canvas.setCursor(px, 86); canvas.print(isRf[skySel] ? "radio source" : "planet");
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(px, 104); canvas.printf("%d/%d", skySel + 1, NTOT);

  footer(";/. select  ` back");
}

void App::keySkyMap(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { screen = SCR_SUNMOON; lastDrawMs = 0; return; }
  const int NTOT = 5 + SKY_RF_N;
  if (isUp(c) || isLeft(c))    { skySel = (skySel + NTOT - 1) % NTOT; lastDrawMs = 0; }
  if (isDown(c) || isRight(c)) { skySel = (skySel + 1) % NTOT;        lastDrawMs = 0; }
}

// ===========================================================================
//  Live GPS position (SCR_GPSPOS): latitude/longitude in degrees-minutes-seconds
//  to full precision, plus ground speed, course, altitude and grid square.
//  Reached with `p` from the Location screen.
// ===========================================================================

// Format a signed decimal degree as D M' S.sss" with a hemisphere letter.
static String fmtDMS(double deg, bool isLat) {
  char hemi = isLat ? (deg >= 0 ? 'N' : 'S') : (deg >= 0 ? 'E' : 'W');
  double a = fabs(deg);
  int d = (int)a;
  double mfull = (a - d) * 60.0;
  int m = (int)mfull;
  double s = (mfull - m) * 60.0;        // seconds, keep 3 decimals (~0.03 m)
  char buf[40];
  snprintf(buf, sizeof(buf), "%d%c%02d' %06.3f\" %c", d, 248, m, s, hemi);
  return String(buf);
}

void App::drawGpsPos() {
  header("GPS position");
  canvas.setTextSize(1);
  bool fix = loc.gpsHasFix();
  const Observer& o = loc.obs();

  if (!fix && !o.valid) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 50); canvas.print("No GPS fix yet.");
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(6, 64); canvas.print("Needs a GPS module + sky view.");
    footer("` back"); return;
  }

  // Status line: fix source + satellite count + HDOP.
  canvas.setTextColor(fix ? CL_GREEN : CL_ORANGE, CL_BLACK);
  canvas.setCursor(2, 18);
  if (fix) canvas.printf("FIX  %d sats  HDOP %.1f", loc.gpsSats(), loc.gpsHdop());
  else     canvas.print("No live fix (last known)");

  // Latitude / longitude in DMS.
  canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.setCursor(2, 34); canvas.print("Lat");
  canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(24, 34); canvas.print(fmtDMS(o.lat, true).c_str());
  canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.setCursor(2, 46); canvas.print("Lon");
  canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(24, 46); canvas.print(fmtDMS(o.lon, false).c_str());

  // Decimal degrees (full precision) underneath, for copy/reference.
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(24, 58); canvas.printf("%.6f, %.6f", o.lat, o.lon);

  // Altitude + grid.
  canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.setCursor(2, 72); canvas.print("Alt");
  canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(24, 72); canvas.printf("%.1f m", o.altM);
  canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.setCursor(120, 72); canvas.print("Grid");
  canvas.setTextColor(CL_CYAN, CL_BLACK);  canvas.setCursor(148, 72); canvas.print(Location::toGrid(o.lat, o.lon).c_str());

  // Speed + course (only meaningful with a live fix).
  double spd = loc.gpsSpeedKmh(), crs = loc.gpsCourseDeg();
  canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.setCursor(2, 88);  canvas.print("Spd");
  canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(24, 88);
  canvas.printf("%.1f km/h  %.1f kn", spd, spd * 0.539957);
  canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.setCursor(2, 100); canvas.print("Crs");
  canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(24, 100);
  static const char* CARD[8] = { "N","NE","E","SE","S","SW","W","NW" };
  canvas.printf("%.0f%c %s", crs, 248, CARD[((int)((crs + 22.5) / 45.0)) & 7]);

  footer("` back");
}

void App::keyGpsPos(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { screen = SCR_LOCATION; lastDrawMs = 0; return; }
}

// ===========================================================================
//  Sat-to-sat visibility finder (SCR_SATSAT): the windows over the next few days
//  when the selected satellite AND a second satellite (chosen from favourites)
//  are BOTH above the horizon at your location at the same time — e.g. for
//  cross-satellite relay experiments or back-to-back working. Reached with `2`
//  from the Satellites screen.
// ===========================================================================

// Begin (or restart) the incremental sat-to-sat search. Allocates the elevation
// tracks and sets phase 1; the actual sampling/scan runs a chunk per loop() tick
// in satsatJobTick(), so the device never blocks long enough to stall.
void App::satsatStartJob() {
  satsatAbortJob();                  // free any previous run first
  satsatN = 0; satsatComputed = false;
  SatEntry* a = activeSat();
  if (!a || !timeIsSet() || favN == 0) { satsatComputed = true; return; }
  if (satsatOther < 0) satsatOther = 0;
  if (satsatOther >= favN) satsatOther = favN - 1;
  int bIdx = db.indexOfNorad(favs[satsatOther]);
  if (bIdx < 0) { satsatComputed = true; return; }
  if (db.at(bIdx).norad == a->norad) { satsatComputed = true; return; }  // same bird

  satsatElA = (int8_t*)malloc(SATSAT_NS);
  satsatElB = (int8_t*)malloc(SATSAT_NS);
  if (!satsatElA || !satsatElB) { satsatAbortJob(); satsatComputed = true; return; }

  satsatT0 = nowUtc();
  satsatJobPhase = 1; satsatJobI = 0; satsatJobPct = 0;
  // Prime the predictor for sat A; the tick samples from here.
  pred.setSite(loc.obs()); pred.setSat(*a);
}

// Free the job buffers and return to idle. Safe to call anytime.
void App::satsatAbortJob() {
  if (satsatElA) { free(satsatElA); satsatElA = nullptr; }
  if (satsatElB) { free(satsatElB); satsatElB = nullptr; }
  satsatJobPhase = 0; satsatJobI = 0;
}

// Advance the incremental search by one chunk. Called every loop() tick while a
// job is active. Sampling is split into bounded chunks so a single tick stays
// well under the watchdog window; the scan phase is cheap and finishes in one go.
void App::satsatJobTick() {
  if (satsatJobPhase == 0) return;
  if (!satsatElA || !satsatElB) { satsatAbortJob(); satsatComputed = true; return; }

  const int STEP  = 60;                         // seconds between samples
  const int CHUNK = 240;                        // samples processed per tick

  if (satsatJobPhase == 1) {                    // sampling satellite A
    int end = satsatJobI + CHUNK; if (end > SATSAT_NS) end = SATSAT_NS;
    for (int i = satsatJobI; i < end; ++i) {
      double az, el; pred.azelAt(satsatT0 + (time_t)i * STEP, az, el);
      satsatElA[i] = (int8_t)constrain((int)lround(el), -90, 90);
    }
    satsatJobI = end;
    satsatJobPct = (satsatJobI * 50) / SATSAT_NS;        // 0..50%
    if (satsatJobI >= SATSAT_NS) {
      // Switch to sat B: re-point the predictor, restart the index.
      int bIdx = db.indexOfNorad(favs[satsatOther]);
      if (bIdx < 0) { satsatAbortJob(); satsatComputed = true; satsatN = 0; return; }
      SatEntry b = db.at(bIdx);
      pred.setSat(b);
      satsatJobPhase = 2; satsatJobI = 0;
    }
    return;
  }

  if (satsatJobPhase == 2) {                    // sampling satellite B
    int end = satsatJobI + CHUNK; if (end > SATSAT_NS) end = SATSAT_NS;
    for (int i = satsatJobI; i < end; ++i) {
      double az, el; pred.azelAt(satsatT0 + (time_t)i * STEP, az, el);
      satsatElB[i] = (int8_t)constrain((int)lround(el), -90, 90);
    }
    satsatJobI = end;
    satsatJobPct = 50 + (satsatJobI * 50) / SATSAT_NS;   // 50..100%
    if (satsatJobI >= SATSAT_NS) { satsatJobPhase = 3; satsatJobI = 0; }
    return;
  }

  if (satsatJobPhase == 3) {                    // scan the two tracks for overlaps
    satsatN = 0;
    bool inWin = false; time_t wStart = 0; float maxA = 0, maxB = 0;
    for (int i = 0; i < SATSAT_NS; ++i) {
      bool both = (satsatElA[i] > 0 && satsatElB[i] > 0);
      time_t t = satsatT0 + (time_t)i * STEP;
      if (both && !inWin) { inWin = true; wStart = t; maxA = satsatElA[i]; maxB = satsatElB[i]; }
      else if (both) { if (satsatElA[i] > maxA) maxA = satsatElA[i]; if (satsatElB[i] > maxB) maxB = satsatElB[i]; }
      else if (!both && inWin) {
        inWin = false;
        if (satsatN < SATSAT_MAX) {
          satsatWin[satsatN].start = wStart; satsatWin[satsatN].end = t;
          satsatWin[satsatN].maxElA = maxA;  satsatWin[satsatN].maxElB = maxB; satsatN++;
        } else break;
      }
    }
    if (inWin && satsatN < SATSAT_MAX) {
      satsatWin[satsatN].start = wStart;
      satsatWin[satsatN].end = satsatT0 + (time_t)(SATSAT_NS - 1) * STEP;
      satsatWin[satsatN].maxElA = maxA; satsatWin[satsatN].maxElB = maxB; satsatN++;
    }
    // Done: free buffers, restore the predictor to the primary sat for the UI.
    satsatAbortJob();
    satsatComputed = true; satsatJobPct = 100; satsatSel = 0;
    SatEntry* a = activeSat();
    if (a) { pred.setSite(loc.obs()); pred.setSat(*a); }
    // Completion sets satsatComputed, which also stops the periodic redraw that
    // was painting the progress bar -- so draw the results now rather than
    // waiting for a keypress. (Setting lastDrawMs=0 alone wouldn't repaint.)
    lastDrawMs = 0;
    if (screen == SCR_SATSAT) draw();
    return;
  }
}

// ---- Sun/Moon transit finder --------------------------------------------
// Angular separation (deg) between two topocentric az/el directions.
float App::angSepDeg(double az1, double el1, double az2, double el2) {
  const double D2R = 0.017453292519943295;
  double a1 = az1 * D2R, e1 = el1 * D2R, a2 = az2 * D2R, e2 = el2 * D2R;
  double cosd = sin(e1) * sin(e2) + cos(e1) * cos(e2) * cos(a1 - a2);
  if (cosd > 1.0) cosd = 1.0; if (cosd < -1.0) cosd = -1.0;
  return (float)(acos(cosd) * 57.29577951308232);
}

void App::transitStartJob() {
  transitN = 0; transitSel = 0; transitJobPct = 0;
  transitHist[0] = transitHist[1] = 0;
  if (!timeIsSet()) { transitJobPhase = 0; return; }
  SatEntry* s = activeSat();
  if (!s) { transitJobPhase = 0; return; }
  pred.setSite(loc.obs()); pred.setSat(*s);
  transitT0 = nowUtc();
  transitJobOff = 0;
  transitJobPhase = 1;
}

void App::transitJobTick() {
  if (transitJobPhase != 1) return;
  Observer o = loc.obs();
  const long CHUNK_S = 4000;                    // seconds of window scanned per tick
  long end = transitJobOff + CHUNK_S;
  if (end > TRANSIT_WIN_S) end = TRANSIT_WIN_S;
  // For each body (Sun, Moon) we track a running minimum of separation; when the
  // separation starts increasing again after dipping under the threshold, we have a
  // local minimum (closest approach) -- record it (refining at 1 s would need state
  // across ticks, so the 2 s coarse step is the reported precision; good to ~deg).
  for (long off = transitJobOff; off < end; off += TRANSIT_STEP_S) {
    time_t t = transitT0 + off;
    double sAz, sEl; pred.azelAt(t, sAz, sEl);
    if (sEl < 0) {                                // sat below horizon: reset both histories
      transitHist[0] = transitHist[1] = 0;
      continue;
    }
    for (uint8_t body = 0; body < 2; ++body) {
      double bAz, bEl; skyObjAzEl(t, o.lat, o.lon, body == 1, bAz, bEl);
      if (bEl < 0) { transitHist[body] = 0; continue; }     // body below horizon
      float sep = angSepDeg(sAz, sEl, bAz, bEl);
      // A confirmed local minimum: two steps ago > one step ago < now (V shape),
      // with the trough under the threshold. transitSep1 is the trough (one step
      // ago); record it. Per-body history so Sun/Moon don't clobber each other.
      if (transitHist[body] >= 2 &&
          transitSep1[body] < transitSep2[body] &&
          transitSep1[body] < sep &&
          transitSep1[body] < transitMaxThreshDeg) {
        if (transitN < TRANSIT_MAX) {
          TransitHit& h = transitHits[transitN++];
          h.t = t - TRANSIT_STEP_S;             // the trough step
          h.sepDeg = transitSep1[body];
          h.bodyEl = (float)bEl;
          h.body = body;
          h.central = (transitSep1[body] < (body == 1 ? 0.26f : 0.27f));  // ~disc radius
        }
      }
      // shift history: sep2 <- sep1 <- sep
      transitSep2[body] = transitSep1[body];
      transitSep1[body] = sep;
      if (transitHist[body] < 2) transitHist[body]++;
    }
  }
  transitJobOff = end;
  transitJobPct = (int)((transitJobOff * 100) / TRANSIT_WIN_S);
  if (transitJobOff >= TRANSIT_WIN_S || transitN >= TRANSIT_MAX) {
    transitJobPhase = 0; transitJobPct = 100;
    SatEntry* a = activeSat();
    if (a) { pred.setSite(loc.obs()); pred.setSat(*a); }
    // Completion clears transitJobPhase, which also stops the periodic redraw
    // that was painting the progress bar -- so draw the results now rather than
    // waiting for a keypress. (Setting lastDrawMs=0 alone wouldn't repaint.)
    lastDrawMs = 0;
    if (screen == SCR_TRANSIT) draw();
  }
}

void App::drawTransit() {
  SatEntry* s = activeSat();
  header(s ? String(s->name) + " transits" : String("Transits"));
  canvas.setTextSize(1);
  if (!s) { footer("` back"); return; }
  if (!timeIsSet()) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 44); canvas.print("Clock not set (NTP or GPS).");
    footer("` back"); return;
  }
  if (transitJobPhase == 1) {                   // scanning: progress bar
    canvas.setTextColor(CL_WHITE, CL_BLACK);
    canvas.setCursor(6, 40); canvas.print("Scanning next 48 h...");
    int x0 = 6, x1 = 234, y = 56;
    canvas.drawRect(x0, y, x1 - x0, 10, CL_GREY);
    canvas.fillRect(x0 + 1, y + 1, (int)((x1 - x0 - 2) * transitJobPct / 100), 8, CL_CYAN);
    canvas.setCursor(6, 72); canvas.printf("%d%%  hits: %d", transitJobPct, transitN);
    footer("` back");
    return;
  }
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, 18); canvas.print("Body  When     Sep    El   Type");
  if (transitN == 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 44); canvas.print("No Sun/Moon transits or close");
    canvas.setCursor(6, 56); canvas.print("approaches in the next 48 h.");
    footer("r rescan  ` back");
    return;
  }
  time_t now = nowUtc();
  int shown = 0;
  for (int i = 0; i < transitN && shown < 8; ++i, ++shown) {
    TransitHit& h = transitHits[i];
    int y = 28 + shown * 10;
    if (i == transitSel) { canvas.fillRect(0, y - 1, 240, 10, CL_SELBG);
                           canvas.setTextColor(CL_BLACK, CL_SELBG); }
    else canvas.setTextColor(h.central ? CL_YELLOW : CL_WHITE, CL_BLACK);
    String when = fmtCountdown((long)(h.t - now));
    canvas.setCursor(4, y);
    canvas.printf("%-4s %-7s %4.1f%c %3.0f  %s",
                  h.body == 1 ? "Moon" : "Sun",
                  when.c_str(), h.sepDeg, 0xF8 /* deg */, h.bodyEl,
                  h.central ? "TRANSIT" : "near");
    // Cloud cover at transit time: a solar transit is a photo op only under a
    // clear sky, and the 48 h cloud window matches the transit search window.
    int cld = cloudAtUnix(h.t);
    if (cld >= 0) {
      uint16_t bg = (i == transitSel) ? CL_SELBG : CL_BLACK;
      uint16_t fg = (i == transitSel) ? CL_BLACK
                  : (cld < 30 ? CL_GREEN : (cld < 70 ? CL_WHITE : CL_ORANGE));
      canvas.setTextColor(fg, bg);
      canvas.setCursor(210, y); canvas.printf("%3d%%", cld);
    }
  }
  footer("r rescan  ` back  (Sun: use a filter!)");
}

void App::keyTransit(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { transitJobPhase = 0; screen = SCR_SUNMOON; lastDrawMs = 0; return; }
  if (c == 'r') { transitStartJob(); lastDrawMs = 0; return; }
  if (isUp(c))   { if (transitSel > 0) transitSel--; lastDrawMs = 0; }
  if (isDown(c)) { if (transitSel < transitN - 1) transitSel++; lastDrawMs = 0; }
}

void App::drawSatSat() {
  SatEntry* a = activeSat();
  header(a ? (String(a->name) + " + sat") : String("Sat-to-sat"));
  canvas.setTextSize(1);
  if (!a) { footer("` back"); return; }
  if (favN == 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 50); canvas.print("No favorites. Star sats");
    canvas.setCursor(6, 62); canvas.print("with 'f' to pick a 2nd.");
    footer("` back"); return;
  }
  // Picking state: let the operator choose the 2nd satellite WITHOUT running the
  // (multi-day) search on every cycle. n/p change the pick instantly; ENTER or 'r'
  // starts the calculation. This avoids waiting through a full search just to scroll
  // past a satellite that isn't the one they want.
  if (satsatPicking) {
    int bIdx = db.indexOfNorad(favs[satsatOther]);
    const char* bName = (bIdx >= 0) ? db.at(bIdx).name : "?";
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(2, 28);
    canvas.print("2nd satellite:");
    canvas.setTextColor(CL_CYAN, CL_BLACK); canvas.setCursor(2, 42);
    canvas.printf("%.24s", bName);
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(2, 58);
    canvas.printf("(%d of %d favorites)", satsatOther + 1, favN);
    canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(2, 78);
    canvas.print("ENTER to find windows");
    footer("n/p pick  ENTER find  `bk");
    return;
  }

  // While the incremental search runs, show a live progress bar. The actual
  // sampling happens a chunk per loop() tick in satsatJobTick(), so this screen
  // stays responsive (the back key still works) and always finishes.
  if (satsatJobPhase != 0 || !satsatComputed) {
    int bIdx = db.indexOfNorad(favs[satsatOther]);
    const char* bName = (bIdx >= 0) ? db.at(bIdx).name : "?";
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 46); canvas.print("Calculating windows...");
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(6, 58); canvas.printf("vs %.20s", bName);
    // progress bar
    int pct = satsatJobPct; if (pct < 0) pct = 0; if (pct > 100) pct = 100;
    const int bx = 6, by = 74, bw = 228, bh = 10;
    canvas.drawRect(bx, by, bw, bh, CL_GREY);
    canvas.fillRect(bx + 1, by + 1, (bw - 2) * pct / 100, bh - 2, CL_GREEN);
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(bx, by + 14); canvas.printf("%d%%  (searching 3 days)", pct);
    footer("` back");
    lastDrawMs = 0;              // keep redrawing so the bar advances
    return;
  }

  // Which 2nd sat.
  int bIdx = db.indexOfNorad(favs[satsatOther]);
  const char* bName = (bIdx >= 0) ? db.at(bIdx).name : "?";
  canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(2, 18);
  canvas.print("2nd:");
  canvas.setTextColor(CL_CYAN, CL_BLACK); canvas.setCursor(28, 18);
  canvas.printf("%.16s", bName);
  canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(2, 28);
  canvas.print("Both up @ your QTH:");

  if (satsatN == 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 60); canvas.print("No overlap in 5 days.");
    footer("n/p pick  r recompute  `bk"); return;
  }

  // Column header + rows.
  canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(2, 40);
  canvas.print("Start UTC    Dur   elA elB");
  const int VIS = 7;
  int scroll = (satsatSel >= VIS) ? (satsatSel - VIS + 1) : 0;
  for (int v = 0; v < VIS && (scroll + v) < satsatN; ++v) {
    int i = scroll + v;
    SatSatWin& w = satsatWin[i];
    long secs = (long)(w.end - w.start);
    int y = 50 + v * 10;
    bool sel = (i == satsatSel);
    // Selected row: a solid SELBG bar with black text in every column (matching
    // the memo/mutual/log lists). Drawing the per-column colours with a CL_BLACK
    // text background used to punch black cells through the highlight, which made
    // the selected row look striped and hard to read.
    uint16_t bg = sel ? CL_SELBG : CL_BLACK;
    if (sel) canvas.fillRect(0, y - 1, 240, 10, CL_SELBG);
    canvas.setTextColor(sel ? CL_BLACK : CL_WHITE, bg); canvas.setCursor(2, y);
    canvas.print(fmtMDHM(w.start).c_str());
    canvas.setTextColor(sel ? CL_BLACK : CL_GREY, bg);  canvas.setCursor(96, y);
    canvas.printf("%ld:%02ld", secs / 60, secs % 60);
    canvas.setTextColor(sel ? CL_BLACK : CL_GREEN, bg); canvas.setCursor(150, y);
    canvas.printf("%.0f", w.maxElA);
    canvas.setTextColor(sel ? CL_BLACK : CL_CYAN, bg);  canvas.setCursor(180, y);
    canvas.printf("%.0f", w.maxElB);
  }

  footer("n/p pick  r recompute  `bk");
}

void App::keySatSat(char c, bool enter, bool back) {
  if (isBack(c, back)) { satsatAbortJob(); buildSatView(); screen = SCR_SATLIST; lastDrawMs = 0; return; }
  if (favN == 0) return;
  // n / p just change WHICH 2nd satellite is selected -- no calculation yet, so
  // cycling through favorites is instant. The search only runs on ENTER or 'r'.
  if (c == 'n') {
    satsatOther = (satsatOther + 1) % favN;
    satsatPicking = true; satsatComputed = false; satsatN = 0; lastDrawMs = 0; return;
  }
  if (c == 'p') {
    satsatOther = (satsatOther - 1 + favN) % favN;
    satsatPicking = true; satsatComputed = false; satsatN = 0; lastDrawMs = 0; return;
  }
  if (c == 'r' || enter) {                     // run (or re-run) the search for the pick
    satsatPicking = false; satsatStartJob(); lastDrawMs = 0; return;
  }
  if (isUp(c))   { if (satsatSel > 0) satsatSel--; lastDrawMs = 0; }
  if (isDown(c)) { if (satsatSel < satsatN - 1) satsatSel++; lastDrawMs = 0; }
}

// ===========================================================================
//  LoRa text messaging (SCR_MESSAGES)
//
//  Broadcast group chat between CardSats sharing a frequency/SF/BW. The wire
//  frame is deliberately tiny and fixed-layout so there is no heap churn:
//      [0]    magic   0xC5
//      [1]    version 0x01
//      [2..15] from callsign, space-padded, 14 bytes
//      [16..] message text, up to 48 bytes (not null-terminated on air)
//  Anything that doesn't start 0xC5 0x01 is ignored (other LoRa users on band).
//  History is a fixed ring of MSG_MAX entries; nothing here allocates.
// ===========================================================================

static const uint8_t LORA_MSG_MAGIC = 0xC5;
static const uint8_t LORA_MSG_VER   = 0x01;

// --- Great-circle distance + initial bearing between two lat/lon points ------
// Distance in km (haversine), bearing in degrees from true north (0..360).
// Used by the LoRa position-exchange compass. Small and self-contained; no
// dependency on the SGP4 predictor (this is ground-to-ground, not orbital).
static void greatCircle(double lat1, double lon1, double lat2, double lon2,
                        double& distKm, double& bearingDeg) {
  const double D2R = 0.017453292519943295, RE = 6371.0088;  // mean Earth radius km
  double p1 = lat1 * D2R, p2 = lat2 * D2R;
  double dp = (lat2 - lat1) * D2R, dl = (lon2 - lon1) * D2R;
  double a = sin(dp / 2) * sin(dp / 2) + cos(p1) * cos(p2) * sin(dl / 2) * sin(dl / 2);
  distKm = 2.0 * RE * atan2(sqrt(a), sqrt(1.0 - a));
  double y = sin(dl) * cos(p2);
  double x = cos(p1) * sin(p2) - sin(p1) * cos(p2) * cos(dl);
  double b = atan2(y, x) / D2R;
  bearingDeg = fmod(b + 360.0, 360.0);
}

// --- Decode actionable tokens out of a received message's text ---------------
// The LoRa frame is unchanged (see below); we simply scan the free-text payload
// for three human-readable sigils an operator (or a send trigger) may include:
//   @lat,lon                 -> a position       (compass / distance+bearing)
//   #SAT                     -> a satellite name (opens sat detail)
//   !SAT YYYY-MM-DD HH:MM    -> a sked proposal  (pre-fills the sked editor)
// A single message may carry any combination. Parsing is deterministic on the
// sigils, so ordinary words/numbers/frequencies never false-trigger.
// (struct MsgDecode is declared in app.h -- see the note there re: the Arduino build.)

// Copy a token (up to dstMax-1 chars) from src until a delimiter; returns chars copied.
static int copyToken(const char* src, char* dst, int dstMax, const char* delims) {
  int n = 0;
  while (src[n] && !strchr(delims, src[n]) && n < dstMax - 1) { dst[n] = src[n]; n++; }
  dst[n] = 0;
  return n;
}

// Parse a "NAME[/NORAD]" satellite reference from the front of `src`, where NAME may
// itself contain spaces AND slashes (real catalog names do: "ISS (ZARYA)",
// "CSS/Tiangong (TIANHE)"). The NORAD, when present, is the LAST slash-delimited field
// and is all digits; everything before that last slash is the name. If there is no
// trailing "/<digits>" field, the whole reference is the name and norad is 0.
//
// `stopAtSpace` controls where the reference ends:
//   * #SAT messages are just "#NAME/NORAD" with nothing after, so the reference runs to
//     end-of-string or the next sigil (stopAtSpace = false) -- this is what lets a spaced
//     name survive.
//   * !SAT messages are "!NAME/NORAD <date> <time>", so the name scan stops at the first
//     space (stopAtSpace = true); a "/<digits>" NORAD field, if present before that space,
//     is still split off.
// Returns the number of chars consumed from `src` (so a caller can resume parsing after).
static int parseSatRef(const char* src, char* nameOut, int nameMax,
                       uint32_t& noradOut, bool stopAtSpace) {
  noradOut = 0;
  // Special case for !SAT (stopAtSpace): a name may contain spaces, which normally collide
  // with the space that separates the name from the date. But if the reference carries a
  // "/<digits>" NORAD field, that field unambiguously marks the end of the name -- so scan
  // for "/<digits>" bounded by a following space (or end) FIRST, and if found, take the
  // name as everything before that slash and resume parsing after the NORAD.
  if (stopAtSpace) {
    // Scan the whole reference for a "/<digits>" field bounded by a following space or end.
    // Spaces *within* the name come before that field, so we do NOT stop at the first space
    // here -- but we stop the scan at a date-like token ("NNNN-") so a bare, space-separated
    // name ("SO-50 2026-07-04 ...") isn't mis-scanned into the date.
    for (int i = 0; src[i]; ++i) {
      char c = src[i];
      if (c == '@' || c == '#' || c == '!' || c == '\t') break;
      // A YYYY- date token (4 digits + dash) marks the start of the date field: stop.
      if (c >= '0' && c <= '9' && src[i+1] >= '0' && src[i+1] <= '9' &&
          src[i+2] >= '0' && src[i+2] <= '9' && src[i+3] >= '0' && src[i+3] <= '9' &&
          src[i+4] == '-') break;
      if (c == '/') {
        int j = i + 1;
        while (src[j] >= '0' && src[j] <= '9') j++;
        if (j > i + 1 && (src[j] == ' ' || src[j] == 0)) {   // "/<digits>" then space/end
          noradOut = (uint32_t)strtoul(src + i + 1, nullptr, 10);
          int n = 0;
          for (int k = 0; k < i && n < nameMax - 1; ++k) nameOut[n++] = src[k];
          nameOut[n] = 0;
          while (n > 0 && nameOut[n - 1] == ' ') nameOut[--n] = 0;
          return j;   // consumed up to end of the NORAD field
        }
      }
    }
  }
  // Determine the extent of the whole reference token.
  int end = 0;
  while (src[end]) {
    char c = src[end];
    if (c == '\t') break;
    if (c == '@' || c == '#' || c == '!') break;           // another sigil ends it
    if (stopAtSpace && c == ' ') break;                    // space ends the !SAT name field
    end++;
  }
  // Look for a trailing "/<digits>" within [0, end): the LAST slash whose tail (up to end)
  // is all digits is the NORAD.
  int nameEnd = end;
  for (int i = end - 1; i >= 0; --i) {
    if (src[i] == '/') {
      bool allDigits = (i + 1 < end);
      for (int j = i + 1; j < end && allDigits; ++j)
        if (src[j] < '0' || src[j] > '9') allDigits = false;
      if (allDigits) { noradOut = (uint32_t)strtoul(src + i + 1, nullptr, 10); nameEnd = i; }
      break;   // only consider the last slash
    }
  }
  int n = 0;
  for (int i = 0; i < nameEnd && n < nameMax - 1; ++i) nameOut[n++] = src[i];
  nameOut[n] = 0;
  // Trim trailing spaces from the name (harmless for #SAT, tidy for both).
  while (n > 0 && nameOut[n - 1] == ' ') nameOut[--n] = 0;
  return end;
}

static MsgDecode decodeMsg(const char* text) {
  MsgDecode d;
  if (!text) return d;

  // @lat,lon  -- signed decimals separated by a comma.
  const char* at = strchr(text, '@');
  if (at) {
    char* endp = nullptr;
    double la = strtod(at + 1, &endp);
    if (endp && *endp == ',') {
      char* endp2 = nullptr;
      double lo = strtod(endp + 1, &endp2);
      if (endp2 != endp + 1 && la >= -90.0 && la <= 90.0 && lo >= -180.0 && lo <= 180.0) {
        d.hasPos = true; d.lat = la; d.lon = lo;
      }
    }
  }

  // #NAME/NORAD  -- satellite token up to a space (or end). The optional "/NORAD" suffix
  // (a catalog number) is split off into d.norad so the receiver can resolve by the
  // invariant NORAD id regardless of the display name in the message.
  const char* hash = strchr(text, '#');
  if (hash && hash[1] && hash[1] != ' ') {
    // Name may contain spaces/slashes; the trailing "/<digits>" (if any) is the NORAD.
    parseSatRef(hash + 1, d.sat, sizeof(d.sat), d.norad, /*stopAtSpace=*/false);
    if (d.sat[0]) d.hasSat = true;
  }

  // !NAME/NORAD YYYY-MM-DD HH:MM  -- sked proposal: sat (opt. /NORAD), then date, then time.
  const char* bang = strchr(text, '!');
  if (bang && bang[1] && bang[1] != ' ') {
    const char* p = bang + 1;
    // The sked name field ends at the first space (the date follows); a "/<digits>" NORAD
    // before that space is still captured.
    int sn = parseSatRef(p, d.skedSat, sizeof(d.skedSat), d.skedNorad, /*stopAtSpace=*/true);
    p += sn; while (*p == ' ') p++;
    // date YYYY-MM-DD (exactly 10 chars, digits + dashes)
    if (strlen(p) >= 10 && p[4] == '-' && p[7] == '-') {
      memcpy(d.skedDate, p, 10); d.skedDate[10] = 0;
      p += 10; while (*p == ' ') p++;
      // time HH:MM (5 chars)
      if (strlen(p) >= 5 && p[2] == ':') {
        memcpy(d.skedTime, p, 5); d.skedTime[5] = 0;
        if (d.skedSat[0]) d.hasSked = true;
      }
    }
  }
  return d;
}

static const int     LORA_FROM_LEN  = 14;
static const int     LORA_TEXT_MAX  = 48;

void App::msgPush(const char* from, const char* text, bool mine, int rssi, int snr) {
  LoraMsg& m = msgRing[msgHead];
  strncpy(m.from, from ? from : "", sizeof(m.from) - 1); m.from[sizeof(m.from)-1] = 0;
  strncpy(m.text, text ? text : "", sizeof(m.text) - 1); m.text[sizeof(m.text)-1] = 0;
  m.mine = mine;
  m.rssi = (int16_t)rssi;
  m.snr  = (int8_t)snr;
  m.tMs  = millis();
  msgHead = (msgHead + 1) % MSG_MAX;
  if (msgCount < MSG_MAX) msgCount++;
  msgScroll = 0;                    // jump to newest on any new message
}

void App::loraStart() {
  int8_t tx = cfg.loraTxDbm; if (tx > 22) tx = 22; if (tx < 0) tx = 0;
  loraStarted = lora.begin(cfg.loraFreqKHz, cfg.loraSf, cfg.loraBwHz, tx);
}

void App::loraPoll() {
  if (!lora.ready()) return;
  uint8_t buf[64]; size_t n = 0; float rssi = 0, snr = 0;
  if (!lora.poll(buf, sizeof(buf), n, rssi, snr)) return;
  if (n < 2 || buf[0] != LORA_MSG_MAGIC || buf[1] != LORA_MSG_VER) return;  // not ours

  char from[LORA_FROM_LEN + 1]; char text[LORA_TEXT_MAX + 1];
  size_t fEnd = 2 + LORA_FROM_LEN;
  size_t fLen = (n >= fEnd) ? LORA_FROM_LEN : (n > 2 ? n - 2 : 0);
  memcpy(from, buf + 2, fLen); from[fLen] = 0;
  for (int i = (int)strlen(from) - 1; i >= 0 && from[i] == ' '; --i) from[i] = 0; // trim pad
  size_t tLen = (n > fEnd) ? (n - fEnd) : 0;
  if (tLen > LORA_TEXT_MAX) tLen = LORA_TEXT_MAX;
  memcpy(text, buf + fEnd, tLen); text[tLen] = 0;

  msgPush(from[0] ? from : "?", text, false, (int)lroundf(rssi), (int)lroundf(snr));

  // If this message reports a position, record the sender in the station roster (keyed by
  // callsign; the grid is derived locally from lat/lon). Then, if automatic position
  // reporting is enabled, consider replying with our own position -- the loop-guards inside
  // maybeAutoReplyPosition (global rate limit + per-station cooldown) keep two auto-reply
  // units from ping-ponging. This runs only for genuinely received frames (loraPoll never
  // sees our own echoes), so an auto-reply cannot trigger our own auto-reply.
  {
    MsgDecode d = decodeMsg(text);
    if (d.hasPos && from[0]) {
      rosterUpsert(from, d.lat, d.lon, (int)lroundf(rssi), (int)lroundf(snr));
      maybeAutoReplyPosition(from);
    }
  }

  // Notify: track unread for the header badge, and (unless on the Messages screen
  // already, or in charge/sleep mode) raise a brief cross-screen banner and an
  // opt-in beep. cfg.msgNotify: 0=off, 1=banner, 2=banner+beep.
  if (screen == SCR_MESSAGES || screen == SCR_LORAROSTER) {
    lastDrawMs = 0; draw();                          // visible already: refresh now
  } else {
    if (msgUnread < 0xFFFF) msgUnread++;
    strncpy(msgLastFrom, from[0] ? from : "?", sizeof(msgLastFrom) - 1);
    msgLastFrom[sizeof(msgLastFrom) - 1] = 0;
    if (cfg.msgNotify >= 1 && screen != SCR_CHARGE) {
      setStatus(String("Msg from ") + msgLastFrom, 3000);
      if (cfg.msgNotify >= 2) beep(1568, 60);       // opt-in chirp (G6)
    }
  }
}

void App::loraSendCurrent(const char* text) {
  if (!lora.ready()) { setStatus("LoRa radio not ready"); return; }
  uint8_t frame[2 + LORA_FROM_LEN + LORA_TEXT_MAX];
  frame[0] = LORA_MSG_MAGIC; frame[1] = LORA_MSG_VER;
  // from callsign, space-padded to fixed width
  char call[LORA_FROM_LEN + 1];
  strncpy(call, cfg.myCall[0] ? cfg.myCall : "NOCALL", LORA_FROM_LEN); call[LORA_FROM_LEN] = 0;
  for (int i = 0; i < LORA_FROM_LEN; ++i)
    frame[2 + i] = (i < (int)strlen(call)) ? (uint8_t)call[i] : (uint8_t)' ';
  // text (clamped)
  int tLen = (int)strlen(text); if (tLen > LORA_TEXT_MAX) tLen = LORA_TEXT_MAX;
  memcpy(frame + 2 + LORA_FROM_LEN, text, tLen);
  size_t total = 2 + LORA_FROM_LEN + tLen;

  bool ok = lora.sendRaw(frame, total);
  char shown[LORA_TEXT_MAX + 1];
  strncpy(shown, text, LORA_TEXT_MAX); shown[LORA_TEXT_MAX] = 0;
  msgPush("", shown, true, 0, 0);            // echo my own message into history
  setStatus(ok ? "Sent" : "TX failed");
}

// North-up bearing plot to a decoded peer position (SCR_LORACOMPASS). This is a
// BEARING display, not a live magnetometer compass: the Cardputer ADV has no
// magnetometer, so the rose is fixed with true North at the top and the peer is
// drawn at its great-circle bearing. The operator reads the bearing in degrees and
// orients using their own means. Distance + message age are shown so a stale
// position (the peer may have moved) is obvious.
void App::drawLoraCompass() {
  header("Peer bearing");
  const Observer& o = loc.obs();
  if (!o.valid) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 60); canvas.print("No local position.");
    canvas.setCursor(6, 74); canvas.print("Set location or get a GPS fix.");
    footer("` back");
    return;
  }
  double distKm, brg;
  greatCircle(o.lat, o.lon, lcLat, lcLon, distKm, brg);

  // Compass rose: fixed, North up. cx/cy centre, R radius.
  const int cx = 70, cy = 78, R = 42;
  canvas.drawCircle(cx, cy, R, CL_DGREY);
  canvas.drawCircle(cx, cy, 2, CL_GREY);
  // Cardinal ticks + labels (N up, E right, S down, W left).
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(cx - 3, cy - R - 9); canvas.print("N");
  canvas.setCursor(cx + R + 3, cy - 3);  canvas.print("E");
  canvas.setCursor(cx - 3, cy + R + 2);  canvas.print("S");
  canvas.setCursor(cx - R - 8, cy - 3);  canvas.print("W");

  // Peer marker: screen angle where 0deg = up (North), increasing clockwise.
  const double D2R = 0.017453292519943295;
  double a = brg * D2R;
  int px = cx + (int)lroundf((float)(sin(a) * (R - 4)));
  int py = cy - (int)lroundf((float)(cos(a) * (R - 4)));
  canvas.drawLine(cx, cy, px, py, CL_ORANGE);
  canvas.fillCircle(px, py, 3, CL_ORANGE);

  // Text column (right of the rose).
  int rx = 128;
  canvas.setTextColor(CL_WHITE, CL_BLACK);
  canvas.setCursor(rx, 34); canvas.printf("%s", lcFrom[0] ? lcFrom : "peer");
  canvas.setTextColor(CL_CYAN, CL_BLACK);
  canvas.setCursor(rx, 50); canvas.printf("Brg %03d", (int)lroundf((float)brg));
  canvas.setTextColor(CL_WHITE, CL_BLACK);
  if (distKm < 10.0)      { canvas.setCursor(rx, 64); canvas.printf("%.2f km", distKm); }
  else if (distKm < 1000) { canvas.setCursor(rx, 64); canvas.printf("%.1f km", distKm); }
  else                    { canvas.setCursor(rx, 64); canvas.printf("%.0f km", distKm); }
  // Message age (staleness cue).
  uint32_t ageMs = millis() - lcMsgMs;
  uint32_t ageMin = ageMs / 60000;
  canvas.setTextColor(ageMin >= 10 ? CL_ORANGE : CL_GREY, CL_BLACK);
  canvas.setCursor(rx, 80);
  if (ageMin < 1)        canvas.print("just now");
  else if (ageMin < 60)  canvas.printf("%lum ago", (unsigned long)ageMin);
  else                   canvas.printf("%luh ago", (unsigned long)(ageMin / 60));
  canvas.setTextColor(CL_CYAN, CL_BLACK);
  canvas.setCursor(rx, 92); canvas.printf("%s", Location::toGrid(lcLat, lcLon).c_str());
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(rx, 104); canvas.printf("@%.3f", lcLat);
  canvas.setCursor(rx, 114); canvas.printf(" %.3f", lcLon);

  footer("` back");
}
void App::keyLoraCompass(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { screen = SCR_MESSAGES; lastDrawMs = 0; }
}

// Detail for a satellite named in a received #NAME/NORAD message (SCR_LORASAT). Resolves
// by NORAD first (name-agnostic), falling back to the name, and if found shows identity +
// the next pass computed for the current observer. If the sat isn't in the DB, says so
// (the receiver may not have that bird cached).
void App::drawLoraSat() {
  header("Sat (from msg)");
  int si = dbResolveSat(db, lsSat, lsNorad);
  if (si < 0) {
    canvas.setTextColor(CL_WHITE, CL_BLACK);
    canvas.setCursor(6, 46);
    if (lsNorad) canvas.printf("'%s' (NORAD %lu)", lsSat, (unsigned long)lsNorad);
    else         canvas.printf("'%s'", lsSat);
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 64); canvas.print("Not in your satellite list.");
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(6, 78); canvas.print("Update GP, then try again.");
    footer("` back");
    return;
  }
  SatEntry& s = db.at(si);
  canvas.setTextColor(CL_CYAN, CL_BLACK);
  canvas.setCursor(6, 34); canvas.printf("%s", s.name);
  // If the sender's display name differs from ours (resolved via NORAD), show theirs too.
  if (lsSat[0] && strcasecmp(lsSat, s.name) != 0) {
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(6, 20); canvas.printf("sent as: %s", lsSat);
  }
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(6, 48); canvas.printf("NORAD %lu", (unsigned long)s.norad);
  if (s.intlDes[0]) { canvas.setCursor(120, 48); canvas.printf("%s", s.intlDes); }

  // Next pass for the current observer.
  const Observer& o = loc.obs();
  canvas.setTextColor(CL_WHITE, CL_BLACK);
  if (!o.valid || !timeIsSet()) {
    canvas.setCursor(6, 68); canvas.print("Next pass: need location + time");
  } else {
    pred.setSite(o);
    if (!pred.setSat(s)) {
      canvas.setCursor(6, 68); canvas.print("Orbit data unavailable.");
    } else {
      PassPredict pp;
      if (pred.predictPasses(nowUtc(), cfg.minPassEl, &pp, 1) >= 1) {
        char buf[32]; struct tm g;
        time_t aos = pp.aos; gmtime_r(&aos, &g);
        strftime(buf, sizeof(buf), "%m-%d %H:%M", &g);
        canvas.setCursor(6, 68); canvas.printf("Next AOS %s UTC", buf);
        canvas.setCursor(6, 82); canvas.printf("Max el %.0f  dur %ldm",
                                               pp.maxEl, (long)((pp.los - pp.aos) / 60));
      } else {
        canvas.setCursor(6, 68); canvas.print("No pass in the search window.");
      }
    }
  }
  footer("s select as active   ` back");
}
void App::keyLoraSat(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { screen = SCR_MESSAGES; lastDrawMs = 0; return; }
  if (c == 's') {                          // adopt this sat as the active selection
    int si = dbResolveSat(db, lsSat, lsNorad);
    if (si >= 0) { satSel = si; setStatus(String("Active: ") + db.at(si).name, 2000); }
  }
}

// ---- Station roster (who's on the LoRa channel, and where) --------------------------

// Broadcast our own @lat,lon. This is both the "p" key on Messages and the presence ping;
// the text is exactly the existing @lat,lon format so any receiver's decodeMsg() picks it
// up and adds us to their roster. No new frame type.
void App::sendMyPosition() {
  const Observer& o = loc.obs();
  if (!o.valid) { setStatus("No position (set location/GPS)", 2500); return; }
  char msg[MSG_TEXT_MAX + 1];
  snprintf(msg, sizeof(msg), "@%.4f,%.4f", o.lat, o.lon);
  loraSendCurrent(msg);
}

int App::rosterIndexByCall(const char* call) {
  if (!call || !call[0]) return -1;
  for (int i = 0; i < rosterCount; ++i)
    if (strcasecmp(rosterList[i].call, call) == 0) return i;
  return -1;
}

// Record (or update) a station we heard reporting a position. Keyed by callsign: an
// existing station's position/signal/time are refreshed; a new one is appended, evicting
// the oldest-heard entry when the array is full. autoRepliedMs is preserved across updates
// so the per-station auto-reply cooldown survives repeated position reports.
void App::rosterUpsert(const char* call, double lat, double lon, int rssi, int snr) {
  if (!call || !call[0]) return;
  int i = rosterIndexByCall(call);
  if (i < 0) {
    if (rosterCount < ROSTER_MAX) {
      i = rosterCount++;
    } else {
      // Evict the least-recently-heard entry.
      int oldest = 0;
      for (int k = 1; k < rosterCount; ++k)
        if (rosterList[k].heardMs < rosterList[oldest].heardMs) oldest = k;
      i = oldest;
    }
    memset(&rosterList[i], 0, sizeof(RosterEntry));
    strncpy(rosterList[i].call, call, sizeof(rosterList[i].call) - 1);
    rosterList[i].call[sizeof(rosterList[i].call) - 1] = 0;
  }
  rosterList[i].lat = lat; rosterList[i].lon = lon;
  rosterList[i].rssi = (int16_t)rssi; rosterList[i].snr = (int8_t)snr;
  rosterList[i].heardMs = millis();
}

// Auto-reply with our own position when someone else reports theirs -- but only if the
// setting is on AND both loop-guards pass:
//   * global rate limit: at most one auto-reply every AUTO_REPLY_MIN_GAP_MS, so a busy
//     channel can't turn into a reply storm; and
//   * per-station cooldown: don't auto-reply to the same station more than once every
//     AUTO_REPLY_PER_STA_MS, so two auto-reply units can't ping-pong endlessly.
// A short randomized delay before sending avoids everyone answering in the same instant
// (which would collide on the shared channel).
void App::maybeAutoReplyPosition(const char* toCall) {
  if (!cfg.autoPosReply) return;
  const Observer& o = loc.obs();
  if (!o.valid) return;                         // nothing to report
  if (!toCall || !toCall[0]) return;

  const uint32_t AUTO_REPLY_MIN_GAP_MS = 30000;    // >= 30 s between any two auto-replies
  const uint32_t AUTO_REPLY_PER_STA_MS = 300000;   // >= 5 min per individual station
  uint32_t now = millis();

  if (lastAutoReplyMs != 0 && (now - lastAutoReplyMs) < AUTO_REPLY_MIN_GAP_MS) return;
  int i = rosterIndexByCall(toCall);
  if (i >= 0 && rosterList[i].autoRepliedMs != 0 &&
      (now - rosterList[i].autoRepliedMs) < AUTO_REPLY_PER_STA_MS) return;

  // Randomized settle (120-600 ms) so simultaneous listeners don't all key up together.
  delay(120 + (int)(esp_random() % 480));
  sendMyPosition();
  lastAutoReplyMs = millis();
  if (i >= 0) rosterList[i].autoRepliedMs = lastAutoReplyMs;
}

// Roster screen: every station heard reporting a position, newest first, with grid,
// distance + bearing from us (when we have our own fix), signal, and age. ENTER opens the
// bearing compass to the selected station.
void App::drawLoraRoster() {
  header("Stations heard");
  if (rosterCount == 0) {
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(6, 58); canvas.print("No stations heard yet.");
    canvas.setCursor(6, 72); canvas.print("Positions appear here when a");
    canvas.setCursor(6, 82); canvas.print("CardSat sends @lat,lon (p key).");
    footer("p ping   ` back");
    return;
  }
  // Draw newest-heard first. Build an index order by heardMs descending.
  int order[ROSTER_MAX];
  for (int i = 0; i < rosterCount; ++i) order[i] = i;
  for (int a = 0; a < rosterCount - 1; ++a)
    for (int b = a + 1; b < rosterCount; ++b)
      if (rosterList[order[b]].heardMs > rosterList[order[a]].heardMs) {
        int t = order[a]; order[a] = order[b]; order[b] = t;
      }
  if (rosterSel < 0) rosterSel = 0;
  if (rosterSel >= rosterCount) rosterSel = rosterCount - 1;

  const Observer& o = loc.obs();
  const int rowY0 = 20, rowH = 22, ROWS = 5;
  int shown = rosterCount < ROWS ? rosterCount : ROWS;
  // Keep the selection visible (simple top window).
  int top = 0;
  if (rosterSel >= ROWS) top = rosterSel - ROWS + 1;
  for (int r = 0; r < shown; ++r) {
    int oi = top + r; if (oi >= rosterCount) break;
    RosterEntry& e = rosterList[order[oi]];
    int y = rowY0 + r * rowH;
    bool sel = (oi == rosterSel);
    if (sel) canvas.fillRect(0, y - 1, 240, rowH, CL_DGREY);
    uint8_t bg = sel ? CL_DGREY : CL_BLACK;
    // Line 1: callsign + grid + age.
    canvas.setTextColor(CL_GREEN, bg);
    canvas.setCursor(2, y); canvas.printf("%s", e.call);
    canvas.setTextColor(CL_CYAN, bg);
    canvas.setCursor(92, y); canvas.printf("%s", Location::toGrid(e.lat, e.lon).c_str());
    uint32_t ageMin = (millis() - e.heardMs) / 60000;
    canvas.setTextColor(ageMin >= 10 ? CL_ORANGE : CL_GREY, bg);
    canvas.setCursor(176, y);
    if (ageMin < 1)       canvas.print("now");
    else if (ageMin < 60) canvas.printf("%lum", (unsigned long)ageMin);
    else                  canvas.printf("%luh", (unsigned long)(ageMin / 60));
    // Line 2: distance + bearing (if we have a fix) and signal.
    canvas.setTextColor(CL_WHITE, bg);
    canvas.setCursor(2, y + 10);
    if (o.valid) {
      double distKm, brg;
      greatCircle(o.lat, o.lon, e.lat, e.lon, distKm, brg);
      if (distKm < 10.0)      canvas.printf("%.1fkm %03d", distKm, (int)lroundf((float)brg));
      else if (distKm < 1000) canvas.printf("%.0fkm %03d", distKm, (int)lroundf((float)brg));
      else                    canvas.printf("%.0fkm %03d", distKm, (int)lroundf((float)brg));
    } else {
      canvas.printf("@%.3f,%.3f", e.lat, e.lon);
    }
    canvas.setTextColor(CL_GREY, bg);
    canvas.setCursor(140, y + 10); canvas.printf("%ddBm", (int)e.rssi);
  }
  footer(";/. sel  ENT compass  p ping  ` bk");
}

void App::keyLoraRoster(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_MESSAGES; lastDrawMs = 0; return; }
  if (rosterCount == 0) {
    if (c == 'p') { sendMyPosition(); }
    return;
  }
  if (c == ';') { if (rosterSel > 0) rosterSel--; lastDrawMs = 0; return; }        // up
  if (c == '.') { if (rosterSel < rosterCount - 1) rosterSel++; lastDrawMs = 0; return; } // down
  if (c == 'p') { sendMyPosition(); return; }
  if (enter) {
    // Open the bearing compass to the selected station.
    int order[ROSTER_MAX];
    for (int i = 0; i < rosterCount; ++i) order[i] = i;
    for (int a = 0; a < rosterCount - 1; ++a)
      for (int b = a + 1; b < rosterCount; ++b)
        if (rosterList[order[b]].heardMs > rosterList[order[a]].heardMs) {
          int t = order[a]; order[a] = order[b]; order[b] = t;
        }
    RosterEntry& e = rosterList[order[rosterSel]];
    lcLat = e.lat; lcLon = e.lon; lcMsgMs = e.heardMs;
    strncpy(lcFrom, e.call, sizeof(lcFrom) - 1); lcFrom[sizeof(lcFrom) - 1] = 0;
    screen = SCR_LORACOMPASS; lastDrawMs = 0;
  }
}

// ---- AMSAT status screen ------------------------------------------------------------

// Build the display list: every catalog sat that has an AMSAT report (amsatStatus != 0),
// sorted by status precedence (Heard > Telemetry > Not heard) then most-recent report
// first. Capped at AMSTAT_MAX rows.
void App::buildAmsatStatusView() {
  amStatN = 0;
  for (int i = 0; i < db.count() && amStatN < AMSTAT_MAX; ++i)
    if (db.at(i).amsatStatus != 0) amStatIdx[amStatN++] = i;
  // Insertion sort (small N): higher amsatPrio first; tie -> newer amsatHeardEpoch first.
  auto prio = [](uint8_t s){ return s == 1 ? 3 : s == 3 ? 2 : s == 2 ? 1 : 0; };
  for (int a = 1; a < amStatN; ++a) {
    int key = amStatIdx[a]; int b = a - 1;
    while (b >= 0) {
      SatEntry& sb = db.at(amStatIdx[b]); SatEntry& sk = db.at(key);
      bool after = (prio(sb.amsatStatus) > prio(sk.amsatStatus)) ||
                   (prio(sb.amsatStatus) == prio(sk.amsatStatus) &&
                    sb.amsatHeardEpoch >= sk.amsatHeardEpoch);
      if (after) break;
      amStatIdx[b + 1] = amStatIdx[b]; b--;
    }
    amStatIdx[b + 1] = key;
  }
  if (amStatSel >= amStatN) amStatSel = amStatN > 0 ? amStatN - 1 : 0;
  if (amStatScroll > amStatSel) amStatScroll = amStatSel;
}

void App::drawAmsatStatus() {
  header(String("AMSAT status \xB7 ") + (int)cfg.amsatWindowH + "h");
  canvas.setTextSize(1);
  if (amStatN == 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 42); canvas.print("No AMSAT reports in window.");
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(6, 56); canvas.print("Run Update to fetch status,");
    canvas.setCursor(6, 68); canvas.print("or widen the window in Settings.");
    footer("u update   ` back");
    return;
  }
  // Column header.
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, 20);  canvas.print("SATELLITE");
  canvas.setCursor(120, 20); canvas.print("STATUS");
  canvas.setCursor(196, 20); canvas.print("AGO");
  const int rows = 9;
  if (amStatSel < amStatScroll) amStatScroll = amStatSel;
  if (amStatSel >= amStatScroll + rows) amStatScroll = amStatSel - rows + 1;
  for (int r = 0; r < rows && (amStatScroll + r) < amStatN; ++r) {
    int vi = amStatScroll + r; SatEntry& s = db.at(amStatIdx[vi]);
    int y = 32 + r * 10;
    bool sel = (vi == amStatSel);
    if (sel) { canvas.fillRect(0, y - 1, 240, 10, CL_SELBG); }
    uint16_t base = sel ? CL_BLACK : CL_WHITE;
    canvas.setTextColor(base, sel ? CL_SELBG : CL_BLACK);
    canvas.setCursor(4, y); canvas.printf("%-19.19s", s.name);
    // Status word in its color (or black when the row is selected, for contrast).
    canvas.setTextColor(sel ? CL_BLACK : amsatColor(s.amsatStatus), sel ? CL_SELBG : CL_BLACK);
    canvas.setCursor(120, y); canvas.printf("%-10s", amsatWord(s.amsatStatus));
    // Recency + report count.
    canvas.setTextColor(base, sel ? CL_SELBG : CL_BLACK);
    String ago = amsatHeardAgo(s.amsatHeardEpoch);
    canvas.setCursor(196, y); canvas.printf("%-4s", ago.length() ? ago.c_str() : "-");
    if (s.amsatReports) { canvas.setCursor(224, y); canvas.printf("%d", (int)s.amsatReports); }
  }
  footer("g who-heard  p report  u update  ` back");
}

void App::keyAmsatStatus(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_HOME; lastDrawMs = 0; return; }
  if (amStatN == 0) {
    if (c == 'u') {
      if (net.connected()) { fetchAmsatStatus(); buildAmsatStatusView(); setStatus("AMSAT status updated", 1500); }
      else setStatus("No WiFi - connect in Settings", 2000);
      lastDrawMs = 0;
    }
    return;
  }
  if (isUp(c)   && amStatSel > 0)            { amStatSel--; lastDrawMs = 0; return; }
  if (isDown(c) && amStatSel < amStatN - 1)  { amStatSel++; lastDrawMs = 0; return; }
  if (c == '{') { amStatSel = max(0, amStatSel - 9); lastDrawMs = 0; return; }
  if (c == '}') { amStatSel = min(amStatN - 1, amStatSel + 9); lastDrawMs = 0; return; }
  if (c == 'p' && amStatN > 0) {              // post a status report (full picker)
    int idx = amStatIdx[amStatSel];
    bool amb = false;
    (void)amsPickNameFor(idx, amb);           // fills pickName/pickN (any count)
    pickSatIdx = idx; pickNameSel = 0; pickSel = 0; pickStat = 0;
    pickReturn = SCR_AMSATSTAT; screen = SCR_AMSRPICK; lastDrawMs = 0; return;
  }
  if (c == 'g' && amStatN > 0) {              // per-report detail (callsigns + grids)
    SatEntry& gs = db.at(amStatIdx[amStatSel]);
    if (!gs.amsatName[0]) { setStatus("No AMSAT name match"); return; }
    fetchAmsatReports(gs.amsatName);
    screen = SCR_AMSRPT; amsRptScroll = 0; lastDrawMs = 0; return;
  }
  if (c == 'u') {
    if (net.connected()) { fetchAmsatStatus(); buildAmsatStatusView(); setStatus("AMSAT status updated", 1500); }
    else setStatus("No WiFi - connect in Settings", 2000);
    lastDrawMs = 0; return;
  }
  if (enter) {                                // adopt the selected sat as active + track
    int idx = amStatIdx[amStatSel];
    satSel = idx; ensureTransponders(db.at(idx));
    setStatus(String("Active: ") + db.at(idx).name, 1500);
    screen = SCR_TRACK; lastDrawMs = 0;
  }
}

// ===========================================================================
//  AMSAT per-report detail (SCR_AMSRPT), 'g' from the AMSAT status screen.
//  Fetches the selected satellite's individual reports (reports.php) on demand
//  and lists callsign / grid / age / status, headed by a distinct-grid count --
//  "7 reports from 5 grids" is a footprint-activity read the summary can't give.
//  The payload is small (limit=24, ~4 KB); it is streamed to the shared temp
//  file, read back, scanned, and the file deleted -- the same heap-safe pattern
//  as the other fetches on this no-PSRAM part.
// ===========================================================================

// "YYYY-MM-DDTHH:MM:SSZ" (UTC, per the API) -> unix. 0 on parse failure.
// Same days_from_civil math as the GP and weather parsers.
static time_t isoZToUnix(const char* iso) {
  int Y, Mo, D, H, Mi, Se;
  if (!iso || sscanf(iso, "%d-%d-%dT%d:%d:%d", &Y, &Mo, &D, &H, &Mi, &Se) != 6) return 0;
  int y2 = Y - (Mo <= 2); int era = (y2 >= 0 ? y2 : y2 - 399) / 400;
  unsigned yoe = (unsigned)(y2 - era * 400);
  unsigned doy = (153u * (unsigned)(Mo + (Mo > 2 ? -3 : 9)) + 2) / 5 + (unsigned)D - 1;
  unsigned doe = yoe * 365 + yoe / 4 - yoe / 100 + doy;
  long days = (long)era * 146097 + (long)doe - 719468;
  return (time_t)days * 86400 + (long)H * 3600 + (long)Mi * 60 + Se;
}

void App::fetchAmsatReports(const char* apiName) {
  amsRptN = 0; amsRptGrids = 0;
  strncpy(amsRptFor, apiName, sizeof(amsRptFor) - 1); amsRptFor[sizeof(amsRptFor) - 1] = 0;
  if (!net.connected() && !connectWifiCfg()) { setStatus("WiFi failed (check SSID/pass)"); return; }
  String nm;                                       // percent-encode the API name
  for (const char* p = apiName; *p; ++p) {         // ([ ] / space _ etc. all appear)
    char ch = *p;
    if ((ch >= 'A' && ch <= 'Z') || (ch >= 'a' && ch <= 'z') ||
        (ch >= '0' && ch <= '9') || ch == '-' || ch == '.' || ch == '_' || ch == '~') nm += ch;
    else { char eb[4]; snprintf(eb, sizeof(eb), "%%%02X", (unsigned char)ch); nm += eb; }
  }
  String url = String(AMSAT_REPORTS_URL) + nm
             + "&hours=" + String((int)cfg.amsatWindowH) + "&limit=24";
  setStatus("AMSAT reports..."); draw();
  if (!net.httpsGetToFileRetry(url, FILE_DL_TMP, 60000, nullptr, 2)) {
    setStatus("Report fetch failed"); return;
  }
  status = "";                       // clear the "AMSAT reports..." banner before the list
  File f = Store::fs().open(FILE_DL_TMP, "r");
  if (!f) return;
  String bd; bd.reserve(f.size() + 8);
  while (f.available()) bd += (char)f.read();
  f.close(); Store::fs().remove(FILE_DL_TMP);

  int da = bd.indexOf("\"data\"");
  int as2 = (da >= 0) ? bd.indexOf('[', da) : -1;
  int pos = as2;
  // Walk flat {..} records. The array ends when the first non-space character after
  // a record's closing brace is ']'. We must NOT stop on the first ']' in the buffer,
  // because every mode-tagged name ("AO-91_[FM]") contains one inside a string.
  while (amsRptN < 24 && pos >= 0) {
    int ob = bd.indexOf('{', pos); if (ob < 0) break;
    int cb2 = bd.indexOf('}', ob); if (cb2 < 0) break;
    String one = bd.substring(ob, cb2 + 1);
    auto fld = [&](const char* k) -> String {
      int i2 = one.indexOf(String("\"") + k + "\"");
      if (i2 < 0) return String();
      int c1 = one.indexOf(':', i2); int q1 = one.indexOf('"', c1); int q2 = one.indexOf('"', q1 + 1);
      if (q1 < 0 || q2 < 0) return String();
      return one.substring(q1 + 1, q2);
    };
    String cs = fld("callsign"), gr = fld("grid_square"), rp = fld("report"), ra = fld("reported_time");
    if (cs.length()) {
      AmsRpt& r = amsRpt[amsRptN];
      strncpy(r.call, cs.c_str(), sizeof(r.call) - 1); r.call[sizeof(r.call) - 1] = 0;
      strncpy(r.grid, gr.c_str(), sizeof(r.grid) - 1); r.grid[sizeof(r.grid) - 1] = 0;
      r.st = rp.startsWith("Heard") ? 1 : rp.startsWith("Not") ? 2
           : rp.startsWith("Tele")  ? 3 : rp.startsWith("Crew") ? 4 : 0;
      r.t = isoZToUnix(ra.c_str());
      amsRptN++;
    }
    pos = cb2 + 1;
    int nb = bd.indexOf('{', pos), nbk = bd.indexOf(']', pos);   // next record vs array end
    if (nbk >= 0 && (nb < 0 || nbk < nb)) break;                 // ']' comes first -> done
  }
  // Distinct grids (full-string compare over <= 24 entries; blanks don't count).
  for (int i2 = 0; i2 < amsRptN; ++i2) {
    if (!amsRpt[i2].grid[0]) continue;
    bool seen = false;
    for (int j2 = 0; j2 < i2; ++j2)
      if (strcmp(amsRpt[j2].grid, amsRpt[i2].grid) == 0) { seen = true; break; }
    if (!seen) amsRptGrids++;
  }
}

void App::drawAmsRpt() {
  header(String(amsRptFor) + " reports");
  canvas.setTextSize(1);
  if (amsRptN == 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 50); canvas.print("No reports in the window");
    canvas.setCursor(6, 62); canvas.printf("(%d h) or fetch failed.", (int)cfg.amsatWindowH);
    footer("r refetch  ` back");
    return;
  }
  canvas.setTextColor(CL_CYAN, CL_BLACK); canvas.setCursor(4, 18);
  canvas.printf("%d reports, %d grids, last %d h", amsRptN, amsRptGrids, (int)cfg.amsatWindowH);
  canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(4, 29);
  canvas.print("CALL       GRID    AGE  STATUS");
  const int rows = 8;
  if (amsRptScroll > amsRptN - rows) amsRptScroll = amsRptN - rows;
  if (amsRptScroll < 0) amsRptScroll = 0;
  time_t nowU = timeIsSet() ? nowUtc() : 0;
  for (int vi = 0; vi < rows && amsRptScroll + vi < amsRptN; ++vi) {
    AmsRpt& r = amsRpt[amsRptScroll + vi];
    int y = 40 + vi * 10;
    String age = "--";
    if (nowU && r.t) {
      long m = (long)(nowU - r.t) / 60;
      age = (m < 60) ? String(m) + "m" : (m < 2880 ? String(m / 60) + "h" : String(m / 1440) + "d");
    }
    const char* w = r.st == 1 ? "Heard" : r.st == 2 ? "Not heard"
                  : r.st == 3 ? "Telemetry" : r.st == 4 ? "Crew" : "?";
    uint16_t fc = r.st == 1 ? CL_GREEN : r.st == 3 ? CL_CYAN
                : r.st == 4 ? CL_GREEN : r.st == 2 ? CL_ORANGE : CL_WHITE;
    canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(4, y);
    canvas.printf("%-10.10s %-6.6s %4s ", r.call, r.grid[0] ? r.grid : "--", age.c_str());
    canvas.setTextColor(fc, CL_BLACK); canvas.print(w);
  }
  footer(";/. scroll  r refetch  ` back");
}

void App::keyAmsRpt(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { screen = SCR_AMSATSTAT; lastDrawMs = 0; return; }
  if (isUp(c))   { if (--amsRptScroll < 0) amsRptScroll = 0; lastDrawMs = 0; return; }
  if (isDown(c)) { ++amsRptScroll; lastDrawMs = 0; return; }
  if (c == '{')  { amsRptScroll -= 8; if (amsRptScroll < 0) amsRptScroll = 0; lastDrawMs = 0; return; }
  if (c == '}')  { amsRptScroll += 8; lastDrawMs = 0; return; }
  if (c == 'r' && amsRptFor[0]) { fetchAmsatReports(amsRptFor); lastDrawMs = 0; return; }
}

// ===========================================================================
//  AMSAT status reporting (POST reports.php). The catalog map makes it
//  mode-aware: AO-7 is two API entries (AO-7_[U/v], AO-7_[V/a]) and the report
//  should land on the one matching the transponder actually being worked.
// ===========================================================================
static const char* AMS_STATUSES[4] = { "Heard", "Telemetry Only", "Not Heard", "Crew Active" };

// IARU-style band letter for a frequency, matching the tags the AMSAT catalog
// uses in mode pairs like [U/v] (uppercase uplink / lowercase downlink).
static char amsBandLetter(double mhz) {
  if (mhz >= 21.0   && mhz < 21.5)   return 'H';
  if (mhz >= 24.0   && mhz < 30.0)   return 'A';
  if (mhz >= 144.0  && mhz < 148.0)  return 'V';
  if (mhz >= 420.0  && mhz < 460.0)  return 'U';
  if (mhz >= 1240.0 && mhz < 1300.0) return 'L';
  if (mhz >= 2300.0 && mhz < 2460.0) return 'S';
  if (mhz >= 5600.0 && mhz < 5860.0) return 'C';
  if (mhz >= 10000.0 && mhz < 10500.0) return 'X';
  if (mhz >= 24000.0 && mhz < 24300.0) return 'K';
  return 0;
}

// Does the [tag] of an API name fit the given transponder? Pair tags ("U/v")
// match on band letters; FM / TLM / Digi match on the transponder's character.
// SSTV / DATV / Crew / Music / SSDV and other event tags never auto-match --
// those are deliberate reports and go through the picker.
static bool amsTagFits(const char* apiName, const Transponder& tx) {
  const char* lb = strrchr(apiName, '[');
  if (!lb) return true;                              // untagged (IO-117): fits
  char tag[16]; int L = 0;
  for (const char* p = lb + 1; *p && *p != ']' && L < 15; ++p) tag[L++] = *p;
  tag[L] = 0;
  bool beacon = (tx.uplink == 0 && tx.downlink != 0);
  if (L == 3 && tag[1] == '/') {                     // band pair "U/v"
    char up = toupper(tag[0]), dn = toupper(tag[2]);
    if (beacon) return false;
    return up == amsBandLetter(tx.uplink / 1e6) && dn == amsBandLetter(tx.downlink / 1e6);
  }
  if (strcasecmp(tag, "FM") == 0)
    return !beacon && strstr(tx.mode, "FM") != nullptr;
  if (strcasecmp(tag, "TLM") == 0 || strcasecmp(tag, "BCN") == 0)
    return beacon;
  { char tu[16]; int q = 0;                          // uppercase copy (no strcasestr dep)
    for (const char* p = tag; *p && q < 15; ++p) tu[q++] = (char)toupper((unsigned char)*p);
    tu[q] = 0;
    if (strstr(tu, "DIGI"))
      return strstr(tx.mode, "DATA") || strstr(tx.mode, "PKT") ||
             strstr(tx.mode, "APRS") || strstr(tx.mode, "DIGI");
  }
  return false;
}

// Choose the API name for a satellite from its mapped names, using the active
// transponder to disambiguate multi-mode birds. Returns null when the sat has
// no mapped name at all; sets 'ambiguous' when a human should pick.
const char* App::amsPickNameFor(int satIdx, bool& ambiguous) {
  ambiguous = false;
  pickN = db.amsNamesFor(satIdx, pickName, 6);
  if (pickN == 0) {
    SatEntry& s2 = db.at(satIdx);
    if (s2.amsatName[0]) { pickName[0] = s2.amsatName; pickN = 1; return pickName[0]; }
    return nullptr;
  }
  if (pickN == 1) return pickName[0];
  if (activeSat() == &db.at(satIdx) && activeTxCount > 0) {
    int fit = -1, fits = 0;
    for (int i = 0; i < pickN; ++i)
      if (amsTagFits(pickName[i], activeTx[curTx])) { fit = i; fits++; }
    if (fits == 1) return pickName[fit];
  }
  ambiguous = true;
  return nullptr;
}

bool App::postAmsatReport(const char* apiName, const char* status) {
  if (!cfg.myCall[0]) { setStatus("Set your callsign first (Settings)"); return false; }
  if (!timeIsSet())   { setStatus("Clock not set (NTP/GPS)"); return false; }
  if (!net.connected() && !connectWifiCfg()) { setStatus("WiFi failed (check SSID/pass)"); return false; }
  time_t nowU = nowUtc(); struct tm tmv; gmtime_r(&nowU, &tmv);
  char ts[24];
  snprintf(ts, sizeof(ts), "%04d-%02d-%02dT%02d:%02d:%02dZ",
           tmv.tm_year + 1900, tmv.tm_mon + 1, tmv.tm_mday,
           tmv.tm_hour, tmv.tm_min, tmv.tm_sec);
  const Observer& o = loc.obs();
  String grid = (o.lat != 0.0 || o.lon != 0.0) ? loc.toGrid(o.lat, o.lon) : String("");
  String bodyS = String("{\"name\":\"") + apiName + "\",\"report\":\"" + status +
                 "\",\"callsign\":\"" + cfg.myCall + "\"" +
                 (grid.length() ? String(",\"grid_square\":\"") + grid + "\"" : String("")) +
                 ",\"reported_at\":\"" + ts + "\"}";
  setStatus(String("Reporting ") + apiName + "..."); draw();
  String resp;
  bool ok = net.httpsPostJson(AMSAT_REPORT_POST, bodyS, resp);
  if (ok) {
    setStatus(String(status) + " reported: " + apiName, 3000);
  } else {
    String why = net.lastErr.length() ? net.lastErr : resp.substring(0, 40);
    setStatus(String("Report failed: ") + why, 4000);
  }
  return ok;
}

// ---------------------------------------------------------------------------
//  Report picker (SCR_AMSRPICK): the deliberate path. Two rows -- the API name
//  (mode) and the status value -- ,/. cycles the highlighted row, ENTER sends.
//  Reached from the AMSAT status screen ('p'), or from Track when the one-key
//  path cannot resolve the mode by itself.
// ---------------------------------------------------------------------------
void App::drawAmsRpick() {
  header("Report satellite status");
  canvas.setTextSize(1);
  if (pickN == 0 || pickSatIdx < 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 50); canvas.print("No AMSAT catalog name for");
    canvas.setCursor(6, 62); canvas.print("this satellite.");
    footer("` back");
    return;
  }
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, 22); canvas.printf("Sat: %.28s", db.at(pickSatIdx).name);
  auto row2 = [&](int r, const char* k, const String& v) {
    int y = 44 + r * 16;
    bool sel = (pickSel == r);
    if (sel) canvas.fillRect(0, y - 3, 240, 14, CL_SELBG);
    canvas.setTextColor(sel ? CL_BLACK : CL_GREY, sel ? CL_SELBG : CL_BLACK);
    canvas.setCursor(4, y); canvas.print(k);
    canvas.setTextColor(sel ? CL_BLACK : CL_WHITE, sel ? CL_SELBG : CL_BLACK);
    canvas.setCursor(70, y); canvas.print(v);
  };
  String nm = String(pickName[pickNameSel]);
  if (pickN > 1) nm += " (" + String(pickNameSel + 1) + "/" + String(pickN) + ")";
  row2(0, "As", nm);
  row2(1, "Status", AMS_STATUSES[pickStat]);
  canvas.setTextColor(CL_MGREY, CL_BLACK);
  canvas.setCursor(4, 96); canvas.print("Public report to amsat.org as");
  canvas.setCursor(4, 106); canvas.printf("%s. Same hour+period replaces.", cfg.myCall[0] ? cfg.myCall : "(no call!)");
  footer(",// change  ;/. row  ENTER send  ` back");
}

void App::keyAmsRpick(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = pickReturn; lastDrawMs = 0; return; }
  if (pickN == 0) return;
  if (isUp(c) || isDown(c)) { pickSel ^= 1; lastDrawMs = 0; return; }
  if (isLeft(c) || isRight(c)) {
    int d = isRight(c) ? 1 : -1;
    if (pickSel == 0) pickNameSel = (pickNameSel + pickN + d) % pickN;
    else              pickStat    = (pickStat + 4 + d) % 4;
    lastDrawMs = 0; return;
  }
  if (enter) {
    if (postAmsatReport(pickName[pickNameSel], AMS_STATUSES[pickStat]))
      { screen = pickReturn; lastDrawMs = 0; }
    return;
  }
}

// ===========================================================================
//  TOOLS HUB (SCR_TOOLS, reached with 't' from About). A set of offline
//  ham-radio bench tools: an infix scientific calculator and several
//  live-recalc forms. All math is local -- no network needed.
// ===========================================================================

// Tool ids for the live-recalc form engine.
enum { TOOL_COAX = 0, TOOL_DIPOLE, TOOL_VERTICAL, TOOL_YAGI, TOOL_QUAD,
       TOOL_RFCONV, TOOL_SWR, TOOL_FSPL, TOOL_UNITS, TOOL_RFEXP, TOOL_BATT,
       TOOL_DEBRIS, TOOL_XAREA, TOOL__N };

static const char* const TOOLS_NAMES[] = {
  "Scientific calculator",
  "Programmer calc (hex/bin)",
  "Char lookup (ASCII/RTTY)",
  "DXCC entity lookup",
  "CQ zones (WAZ)",
  "ITU zones",
  "Link budget",
  "Coax loss / power",
  "Dipole length",
  "Vertical / ground plane",
  "Yagi elements",
  "Quad (full-wave loop)",
  "RF units (dBm/W/V)",
  "SWR / return loss",
  "Free-space path loss",
  "Unit converter",
  "RF exposure (MPE)",
  "Battery runtime",
  "Orbit lifetime (debris)",
  "Cross-section area",
};
static const int TOOLS_N = (int)(sizeof(TOOLS_NAMES) / sizeof(TOOLS_NAMES[0]));

void App::drawTools() {
  header("Tools");
  canvas.setTextSize(1);
  const int LH = 9, VIS = 11;                    // 11 rows fit (y 20..110); list scrolls beyond
  if (toolsSel < toolsScroll) toolsScroll = toolsSel;
  if (toolsSel >= toolsScroll + VIS) toolsScroll = toolsSel - VIS + 1;
  for (int r = 0; r < VIS; ++r) {
    int i = toolsScroll + r;
    if (i >= TOOLS_N) break;
    int y = 20 + r * LH;
    bool sel = (i == toolsSel);
    if (sel) canvas.fillRect(2, y - 2, 236, 9, CL_SELBG);
    canvas.setTextColor(sel ? CL_BLACK : CL_WHITE, sel ? CL_SELBG : CL_BLACK);
    canvas.setCursor(8, y); canvas.print(TOOLS_NAMES[i]);
  }
  if (toolsScroll > 0)                 { canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(230, 20);  canvas.print("^"); }
  if (toolsScroll + VIS < TOOLS_N)     { canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(230, 110); canvas.print("v"); }
  footer(";/. pick  ENTER open  ` back");
}

void App::keyTools(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_ABOUT; lastDrawMs = 0; return; }
  if (isUp(c))   { if (--toolsSel < 0) toolsSel = TOOLS_N - 1; lastDrawMs = 0; return; }
  if (isDown(c)) { if (++toolsSel >= TOOLS_N) toolsSel = 0; lastDrawMs = 0; return; }
  if (enter) {
    if (toolsSel == 0) {                       // scientific calculator
      calcBuf = ""; calcResult = ""; calcErr = false;
      screen = SCR_CALC;
    } else if (toolsSel == 1) {                // programmer's calculator
      screen = SCR_PCALC;
    } else if (toolsSel == 2) {                // character / raw-value lookup
      screen = SCR_CHARLK;
    } else if (toolsSel == 3) {                // DXCC entity lookup
      dxQuery = ""; dxRunFilter(); screen = SCR_DXLK;
    } else if (toolsSel == 4) {                // CQ (WAZ) zone reference
      cqzSel = 0; cqzScroll = 0; screen = SCR_CQZ;
    } else if (toolsSel == 5) {                // ITU zone reference
      ituSel = 0; ituScroll = 0; screen = SCR_ITUZ;
    } else if (toolsSel == 6) {                // link budget calculator
      lbInit(); screen = SCR_LINKB;
    } else {                                   // one of the live-recalc forms
      toolFormInit(toolsSel - 7);              // form ids are toolsSel-7 (seven tools precede)
      screen = SCR_TOOLFORM;
    }
    lastDrawMs = 0;
  }
}

// ---------------------------------------------------------------------------
//  Infix scientific calculator. Recursive-descent parser over a C string:
//    expr   := term (('+'|'-') term)*
//    term   := power (('*'|'/') power)*
//    power  := unary ('^' power)?           (right-assoc)
//    unary  := ('-'|'+') unary | atom
//    atom   := number | 'pi' | 'e' | 'Ans' | func '(' expr ')' | '(' expr ')'
//  Trig is in DEGREES (what a ham wants for beam headings). On any parse error
//  ok=false. This is a leaf computation -- no allocations beyond the input.
// ---------------------------------------------------------------------------
namespace {
  struct CalcP {
    const char* p; bool ok; double ans;
    void ws() { while (*p == ' ') ++p; }
    bool word(const char* w) {                 // match a keyword, case-sensitive
      const char* q = p; while (*w && *q == *w) { ++q; ++w; }
      if (*w) return false;
      if ((*q >= 'a' && *q <= 'z') || (*q >= 'A' && *q <= 'Z')) return false; // longer ident
      p = q; return true;
    }
    double expr() {
      double v = term();
      for (;;) { ws();
        if (*p == '+') { ++p; v += term(); }
        else if (*p == '-') { ++p; v -= term(); }
        else break;
      }
      return v;
    }
    double term() {
      double v = power();
      for (;;) { ws();
        if (*p == '*') { ++p; v *= power(); }
        else if (*p == '/') { ++p; double d = power(); if (d == 0) ok = false; else v /= d; }
        else break;
      }
      return v;
    }
    double power() {
      double v = unary(); ws();
      if (*p == '^') { ++p; v = pow(v, power()); }
      return v;
    }
    double unary() { ws();
      if (*p == '-') { ++p; return -unary(); }
      if (*p == '+') { ++p; return unary(); }
      return atom();
    }
    double callFn(double (*f)(double), double scale) {  // scale for deg->rad on trig
      ws(); if (*p != '(') { ok = false; return 0; }
      ++p; double a = expr(); ws();
      if (*p == ')') ++p; else ok = false;
      return f(a * scale);
    }
    double atom() { ws();
      const double D2R = 0.017453292519943295, R2D = 57.29577951308232;
      if (*p == '(') { ++p; double v = expr(); ws(); if (*p == ')') ++p; else ok = false; return v; }
      if (word("pi"))  return 3.14159265358979323846;
      if (word("e"))   return 2.71828182845904523536;
      if (word("Ans")) return ans;
      if (word("sin"))  return callFn(::sin,  D2R);
      if (word("cos"))  return callFn(::cos,  D2R);
      if (word("tan"))  return callFn(::tan,  D2R);
      if (word("asin")) { double r = callFn(::asin, 1.0); return r * R2D; }
      if (word("acos")) { double r = callFn(::acos, 1.0); return r * R2D; }
      if (word("atan")) { double r = callFn(::atan, 1.0); return r * R2D; }
      if (word("sqrt")) return callFn(::sqrt, 1.0);
      if (word("ln"))   return callFn(::log,  1.0);
      if (word("log"))  return callFn(::log10, 1.0);
      if (word("exp"))  return callFn(::exp,  1.0);
      if (word("abs"))  return callFn(::fabs, 1.0);
      // number
      char* endp = nullptr; double v = strtod(p, &endp);
      if (endp == p) { ok = false; return 0; }
      p = endp; return v;
    }
  };
}

double App::calcEval(const char* s, bool& ok) {
  CalcP c; c.p = s; c.ok = true; c.ans = calcAns;
  double v = c.expr(); c.ws();
  if (*c.p != 0) c.ok = false;                 // trailing junk
  if (!isfinite(v)) c.ok = false;
  ok = c.ok; return v;
}

void App::drawCalc() {
  header("Calculator");
  canvas.setTextSize(1);
  // Scrolling tape: the last entries and their results, bottom-anchored above the
  // entry line. ;/. scroll back through history; new input snaps back to newest.
  const int TAPE_Y0 = 22, TAPE_ROWS = 6, LH = 9;
  int total = calcTapeN;
  int newestShown = total - calcScroll;                      // exclusive upper index
  int first = newestShown - TAPE_ROWS; if (first < 0) first = 0;
  int y = TAPE_Y0 + (TAPE_ROWS - (newestShown - first)) * LH; // bottom-anchor
  for (int i = first; i < newestShown; ++i) {
    const String& ln = calcTape[i % CALC_TAPE];
    canvas.setTextColor(ln.startsWith("=") ? CL_CYAN : CL_GREY, CL_BLACK);
    canvas.setCursor(6, y); canvas.print(ln.length() > 38 ? ln.substring(0, 38) : ln);
    y += LH;
  }
  if (calcScroll > 0) { canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(230, TAPE_Y0); canvas.print("^"); }
  canvas.drawFastHLine(4, 74, 232, CL_MGREY);
  // Entry line
  canvas.setTextColor(CL_WHITE, CL_BLACK);
  canvas.setCursor(4, 79);
  String shown = String("> ") + calcBuf + "_";
  if (shown.length() > 40) shown = shown.substring(shown.length() - 40);
  canvas.print(shown);
  canvas.drawFastHLine(4, 90, 232, CL_MGREY);
  // Function hints, kept just above the footer
  canvas.setTextColor(CL_MGREY, CL_BLACK);
  canvas.setCursor(4, 96);  canvas.print("fns: sin cos tan asin acos atan (deg)");
  canvas.setCursor(4, 106); canvas.print("     sqrt ln log exp abs ^ pi e Ans");
  footer("type  ENTER =  [ ] scroll  ` back");
}

void App::keyCalc(char c, bool enter, bool back) {
  // Only the backtick exits. The DEL key is delivered via the 'back' flag (ks.del),
  // so it must be treated as backspace here -- NOT routed through isBack(), which
  // would exit. (This mirrors keyEdit's handling of text entry.)
  if (c == '`') { screen = SCR_TOOLS; lastDrawMs = 0; return; }
  // Tape scroll uses [ ] -- the arrow keys ; and . are expression characters
  // ('.' is the decimal point), so they must reach the entry buffer.
  if (c == '[') { if (calcScroll < calcTapeN - 1) calcScroll++; lastDrawMs = 0; return; }
  if (c == ']') { if (calcScroll > 0) calcScroll--;             lastDrawMs = 0; return; }
  auto tapePush = [&](const String& ln) {
    calcTape[calcTapeN % CALC_TAPE] = ln;
    if (calcTapeN < CALC_TAPE) calcTapeN++;
    else {                                        // ring full: shift window (simple rotate)
      for (int i = 0; i < CALC_TAPE - 1; ++i) calcTape[i] = calcTape[i + 1];
      calcTape[CALC_TAPE - 1] = ln;
    }
  };
  if (enter) {
    if (calcBuf.length()) {
      bool ok; double v = calcEval(calcBuf.c_str(), ok);
      tapePush(calcBuf);
      if (ok) { calcAns = v;
                char b[24]; dtostrf(v, 0, 6, b);
                String r(b); while (r.indexOf('.') >= 0 && (r.endsWith("0") || r.endsWith("."))) r.remove(r.length() - 1);
                tapePush(String("= ") + r); }
      else      tapePush("= error");
      calcBuf = ""; calcScroll = 0;               // traditional: clear entry, snap to newest
    }
    lastDrawMs = 0; return;
  }
  if (back || c == 8 || c == 127) {             // DEL (delivered via 'back') only edits
    if (calcBuf.length()) calcBuf.remove(calcBuf.length() - 1);
    lastDrawMs = 0; return;
  }
  if (c >= 32 && c < 127) { calcBuf += c; calcScroll = 0; lastDrawMs = 0; }
}

// ---------------------------------------------------------------------------
//  Programmer's calculator (SCR_PCALC). A 64-bit accumulator shown at once in
//  hex / dec / bin / oct, with a selectable display width (8/16/32/64) that
//  masks the value. Digit keys enter in the current base; the operation keys
//  apply +-*/ and the bitwise AND OR XOR and shifts via a classic pending-op
//  model (like a four-function calculator). 'n' = bitwise NOT, 'm' = negate.
// ---------------------------------------------------------------------------
namespace {
  uint64_t pcMask(int width) {
    return (width >= 64) ? ~0ULL : ((1ULL << width) - 1ULL);
  }
  // Format 'v' in the given base into 'out', grouped for readability. Binary and
  // hex are zero-padded to the display width; dec/oct are plain.
  String pcFmt(uint64_t v, int base, int width) {
    v &= pcMask(width);
    if (base == 10) { char b[24]; snprintf(b, sizeof(b), "%llu", (unsigned long long)v); return String(b); }
    if (base == 8)  { char b[24]; snprintf(b, sizeof(b), "%llo", (unsigned long long)v); return String(b); }
    const char* dig = "0123456789ABCDEF";
    if (base == 16) {
      int nyb = width / 4; String s;
      for (int i = nyb - 1; i >= 0; --i) { s += dig[(v >> (i * 4)) & 0xF]; if (i && i % 4 == 0) s += ' '; }
      return s;
    }
    // binary: group in nibbles
    String s;
    for (int i = width - 1; i >= 0; --i) { s += char('0' + ((v >> i) & 1)); if (i && i % 4 == 0) s += ' '; }
    return s;
  }
  // Digit value for a char in a given base, or -1 if not a valid digit there.
  int pcDigit(char c, int base) {
    int d = -1;
    if (c >= '0' && c <= '9') d = c - '0';
    else if (c >= 'a' && c <= 'f') d = c - 'a' + 10;
    else if (c >= 'A' && c <= 'F') d = c - 'A' + 10;
    return (d >= 0 && d < base) ? d : -1;
  }
}

void App::drawPCalc() {
  header("Programmer calc");
  canvas.setTextSize(1);
  uint64_t v = pcalcVal & pcMask(pcalcWidth);
  // The four bases, stacked. The active entry base is highlighted.
  struct { const char* tag; int base; } rows[] = { {"HEX", 16}, {"DEC", 10}, {"BIN", 2}, {"OCT", 8} };
  int y = 22;
  for (int i = 0; i < 4; ++i) {
    bool act = (rows[i].base == pcalcBase);
    canvas.setTextColor(act ? CL_CYAN : CL_GREY, CL_BLACK);
    canvas.setCursor(4, y); canvas.print(rows[i].tag);
    canvas.setTextColor(act ? CL_WHITE : CL_GREY, CL_BLACK);
    String s = pcFmt(v, rows[i].base, pcalcWidth);
    if (rows[i].base == 2 && s.length() > 34) {          // binary can be wide: show two lines for 64-bit
      canvas.setCursor(34, y); canvas.print(s.substring(0, s.length() / 2));
      y += 9; canvas.setCursor(34, y); canvas.print(s.substring(s.length() / 2));
    } else {
      canvas.setCursor(34, y); canvas.print(s);
    }
    y += 10;
  }
  y += 2;
  canvas.drawFastHLine(4, y - 2, 232, CL_MGREY);
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, y);
  canvas.printf("base %d  width %d  %s", pcalcBase, pcalcWidth, pcalcPend ? "op:" : "");
  if (pcalcPend) { canvas.setTextColor(CL_ORANGE, CL_BLACK); canvas.setCursor(150, y);
                   char op[2] = { pcalcPend, 0 }; canvas.print(op); }
  y += 11;
  canvas.setTextColor(CL_MGREY, CL_BLACK);
  canvas.setCursor(4, y);      canvas.print(";/. base  w:width  & | ^  n:NOT m:neg");
  canvas.setCursor(4, y + 9);  canvas.print("<:<<  >:>>  + - * /  = ENTER  x:clr");
  footer("digits + ops  ;/. base  ` back");
}

void App::keyPCalc(char c, bool enter, bool back) {
  if (c == '`') { screen = SCR_TOOLS; lastDrawMs = 0; return; }   // only backtick exits
  uint64_t mask = pcMask(pcalcWidth);

  auto applyPending = [&]() {                    // fold acc <op> val -> val
    if (!pcalcPend) return;
    uint64_t a = pcalcAcc, b = pcalcVal;
    uint64_t r = b;
    switch (pcalcPend) {
      case '&': r = a & b; break;
      case '|': r = a | b; break;
      case '^': r = a ^ b; break;
      case '+': r = a + b; break;
      case '-': r = a - b; break;
      case '*': r = a * b; break;
      case '/': r = b ? (a / b) : 0; break;
      case '<': r = a << (b & 63); break;
      case '>': r = a >> (b & 63); break;
    }
    pcalcVal = r & mask; pcalcPend = 0;
  };
  auto setOp = [&](char op) {
    applyPending();                              // chain: fold any prior op first
    pcalcAcc = pcalcVal; pcalcPend = op; pcalcFresh = true;
  };

  // Base: up/down arrows move the highlighted base row (hex -> dec -> bin -> oct).
  // 'b' and 'C' can't be used -- they are hex digits. 'x' clears (not a hex digit).
  static const int PC_BASES[4] = { 16, 10, 2, 8 };   // row order on screen
  if (isUp(c) || isDown(c)) {
    int cur = 0; for (int i = 0; i < 4; ++i) if (PC_BASES[i] == pcalcBase) cur = i;
    cur = (cur + (isDown(c) ? 1 : 3)) % 4;
    pcalcBase = PC_BASES[cur]; lastDrawMs = 0; return;
  }
  if (c == 'w') { pcalcWidth = (pcalcWidth == 8) ? 16 : (pcalcWidth == 16) ? 32 : (pcalcWidth == 32) ? 64 : 8;
                  pcalcVal &= pcMask(pcalcWidth); lastDrawMs = 0; return; }
  if (c == 'x') { pcalcVal = 0; pcalcAcc = 0; pcalcPend = 0; pcalcFresh = true; lastDrawMs = 0; return; }

  // unary ops
  if (c == 'n') { pcalcVal = (~pcalcVal) & mask; pcalcFresh = true; lastDrawMs = 0; return; }  // NOT
  if (c == 'm') { pcalcVal = ((uint64_t)(-(int64_t)pcalcVal)) & mask; pcalcFresh = true; lastDrawMs = 0; return; } // negate

  // binary ops (pending)
  if (c == '&' || c == '|' || c == '^' || c == '+' || c == '-' || c == '*' || c == '/') { setOp(c); lastDrawMs = 0; return; }
  if (c == '<') { setOp('<'); lastDrawMs = 0; return; }
  if (c == '>') { setOp('>'); lastDrawMs = 0; return; }

  if (enter || c == '=') { applyPending(); pcalcFresh = true; lastDrawMs = 0; return; }

  if (back || c == 8 || c == 127) {              // DEL (via 'back'): drop the low digit
    pcalcVal /= (uint64_t)pcalcBase; pcalcVal &= mask; lastDrawMs = 0; return;
  }

  // digit entry in the current base
  int d = pcDigit(c, pcalcBase);
  if (d >= 0) {
    if (pcalcFresh) { pcalcVal = 0; pcalcFresh = false; }
    pcalcVal = (pcalcVal * (uint64_t)pcalcBase + (uint64_t)d) & mask;
    lastDrawMs = 0;
  }
}

// ---------------------------------------------------------------------------
//  Character / raw-value lookup (SCR_CHARLK). Enter a byte in hex, dec, bin or
//  oct and see everything it represents at once: the ASCII character (control
//  codes by name), its Morse pattern, the Baudot/ITA2 (US-TTY) letters- and
//  figures-shift meaning for 5-bit values, and the BCD reading (CI-V frequency
//  bytes are BCD). ;/. browse +-1, ,// cycle the entry base, digits type in
//  the current base, a non-hex letter (g-z) looks that character up directly.
// ---------------------------------------------------------------------------
namespace {
  const char* const ASCII_NAME[33] = {
    "NUL","SOH","STX","ETX","EOT","ENQ","ACK","BEL","BS","TAB","LF","VT","FF",
    "CR","SO","SI","DLE","DC1","DC2","DC3","DC4","NAK","SYN","ETB","CAN","EM",
    "SUB","ESC","FS","GS","RS","US","SP" };
  // ITA2 / US-TTY, 5-bit codes 0..31: letters shift and figures shift.
  const char* const ITA2_LTRS[32] = {
    "NUL","E","LF","A","SP","S","I","U","CR","D","R","J","N","F","C","K",
    "T","Z","L","W","H","Y","P","Q","O","B","G","FIGS","M","X","V","LTRS" };
  const char* const ITA2_FIGS[32] = {
    "NUL","3","LF","-","SP","BEL","8","7","CR","$","4","'",",","!",":","(",
    "5","\"",")","2","#","6","0","1","9","?","&","FIGS",".","/",";","LTRS" };
  // Morse for digits (letters come from the game's MORSE_TBL).
  const char* const MORSE_DIG[10] = {
    "-----",".----","..---","...--","....-",".....","-....","--...","---..","----." };

  String clkBaseFmt(uint8_t v, int base) {
    char b[12];
    if (base == 10)      snprintf(b, sizeof(b), "%u", v);
    else if (base == 8)  snprintf(b, sizeof(b), "%o", v);
    else if (base == 16) snprintf(b, sizeof(b), "%02X", v);
    else { int k = 0; for (int i = 7; i >= 0; --i) b[k++] = char('0' + ((v >> i) & 1)); b[k] = 0; }
    return String(b);
  }
}

void App::drawCharLk() {
  header("Char lookup");
  canvas.setTextSize(1);
  uint8_t v = clkVal;
  // The value in all four bases; the active entry base is highlighted.
  struct { const char* tag; int base; } B[4] = { {"HEX",16},{"DEC",10},{"BIN",2},{"OCT",8} };
  int x = 4;
  for (int i = 0; i < 4; ++i) {
    bool act = (B[i].base == clkBase);
    canvas.setTextColor(act ? CL_CYAN : CL_GREY, CL_BLACK);
    canvas.setCursor(x, 20); canvas.print(B[i].tag);
    canvas.setTextColor(act ? CL_WHITE : CL_GREY, CL_BLACK);
    String s = clkBaseFmt(v, B[i].base);
    canvas.setCursor(x, 30); canvas.print(s);
    x += (i == 1) ? 66 : 52;                       // extra room after DEC for BIN's 8 digits
  }
  canvas.drawFastHLine(4, 42, 232, CL_MGREY);
  // The character itself, large, plus its ASCII name.
  canvas.setTextSize(2);
  canvas.setTextColor(CL_CYAN, CL_BLACK);
  canvas.setCursor(8, 50);
  if (v > 32 && v < 127)      { char cs[2] = { (char)v, 0 }; canvas.print(cs); }
  else if (v == 32)             canvas.print("_");
  else                          canvas.print("*");
  canvas.setTextSize(1);
  canvas.setTextColor(CL_WHITE, CL_BLACK);
  canvas.setCursor(40, 54);
  if (v <= 32)       canvas.printf("ASCII %s (control)", ASCII_NAME[v]);
  else if (v < 127)  canvas.printf("ASCII '%c'", (char)v);
  else if (v == 127) canvas.print("ASCII DEL (control)");
  else               canvas.print("extended (no ASCII)");
  int y = 72;
  auto row = [&](const char* k, const String& val, uint16_t col) {
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(6, y); canvas.print(k);
    canvas.setTextColor(col, CL_BLACK);     canvas.setCursor(70, y); canvas.print(val);
    y += 10;
  };
  // Morse (letters from the game's table, digits from ours).
  String mo = "--";
  if (v >= 'A' && v <= 'Z')      mo = MORSE_TBL[v - 'A'];
  else if (v >= 'a' && v <= 'z') mo = MORSE_TBL[v - 'a'];
  else if (v >= '0' && v <= '9') mo = MORSE_DIG[v - '0'];
  row("Morse", mo, CL_WHITE);
  // Baudot / ITA2 (5-bit values only).
  if (v < 32) row("Baudot", String(ITA2_LTRS[v]) + " / " + ITA2_FIGS[v] + "  (LTRS/FIGS, US-TTY)", CL_WHITE);
  else        row("Baudot", "-- (5-bit: 0-31)", CL_GREY);
  // BCD reading (both nibbles must be decimal digits).
  int hi = (v >> 4) & 0xF, lo = v & 0xF;
  row("BCD", (hi <= 9 && lo <= 9) ? String(hi) + String(lo) : String("-- (nibble > 9)"),
      (hi <= 9 && lo <= 9) ? CL_CYAN : CL_GREY);
  canvas.setTextColor(CL_MGREY, CL_BLACK);
  canvas.setCursor(4, y + 2); canvas.print("g-z: look a character up directly");
  footer(";/. +-1  ,// base  digits enter  ` back");
}

void App::keyCharLk(char c, bool enter, bool back) {
  (void)enter;
  if (c == '`') { screen = SCR_TOOLS; lastDrawMs = 0; return; }   // only backtick exits
  if (isUp(c))   { clkVal--; clkFresh = true; lastDrawMs = 0; return; }   // browse
  if (isDown(c)) { clkVal++; clkFresh = true; lastDrawMs = 0; return; }
  if (c == ',' || c == '/') {                    // cycle entry base
    static const int ORDER[4] = { 16, 10, 2, 8 };
    int cur = 0; for (int i = 0; i < 4; ++i) if (ORDER[i] == clkBase) cur = i;
    clkBase = ORDER[(cur + (c == '/' ? 1 : 3)) % 4];
    lastDrawMs = 0; return;
  }
  if (back) {                                     // DEL: drop the low digit (edit-only)
    clkVal = (uint8_t)(clkVal / clkBase); lastDrawMs = 0; return;
  }
  if (c == 'x') { clkVal = 0; clkFresh = true; lastDrawMs = 0; return; }
  // digit in the current base?
  int d = -1;
  if (c >= '0' && c <= '9') d = c - '0';
  else if (clkBase == 16 && c >= 'a' && c <= 'f') d = c - 'a' + 10;
  else if (clkBase == 16 && c >= 'A' && c <= 'F') d = c - 'A' + 10;
  if (d >= 0 && d < clkBase) {
    if (clkFresh) { clkVal = 0; clkFresh = false; }
    clkVal = (uint8_t)((clkVal * clkBase + d) & 0xFF);
    lastDrawMs = 0; return;
  }
  // any other letter: direct character lookup (the typed character itself)
  if ((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z')) {
    clkVal = (uint8_t)c; clkFresh = true; lastDrawMs = 0; return;
  }
}

// ---------------------------------------------------------------------------
//  DXCC entity lookup (SCR_DXLK search + SCR_DXLKD detail). Type a prefix, a
//  partial name, or an entity code; matches list live. ENTER opens a detail
//  card. Data is the embedded DXCC_LK[] table (dxcc_lookup.h), generated from
//  the ARRL DXCC list, so it works entirely offline.
// ---------------------------------------------------------------------------

// Case-insensitive "does hay contain needle" (needle already upper-cased).
static bool dxContainsCI(const char* hay, const char* needleUpper) {
  if (!*needleUpper) return true;
  for (const char* h = hay; *h; ++h) {
    const char* a = h; const char* b = needleUpper;
    while (*a && *b) {
      char ca = *a; if (ca >= 'a' && ca <= 'z') ca -= 32;
      if (ca != *b) break;
      ++a; ++b;
    }
    if (!*b) return true;
  }
  return false;
}

// Does any comma/space-separated prefix token in 'field' start with 'needleUpper'?
static bool dxPrefixStarts(const char* field, const char* needleUpper) {
  if (!*needleUpper) return false;
  const char* p = field;
  while (*p) {
    while (*p == ',' || *p == ' ') ++p;          // token start
    const char* b = needleUpper; const char* a = p;
    bool ok = true;
    while (*b) {
      char ca = *a; if (ca >= 'a' && ca <= 'z') ca -= 32;
      if (ca != *b) { ok = false; break; }
      ++a; ++b;
    }
    if (ok) return true;
    while (*p && *p != ',' && *p != ' ') ++p;     // skip to next token
  }
  return false;
}

void App::dxRunFilter() {
  dxMatchN = 0; dxSel = 0; dxScroll = 0;
  const int CAP = (int)(sizeof(dxMatch) / sizeof(dxMatch[0]));
  // Upper-case copy of the query for case-insensitive matching.
  char q[24]; int qi = 0;
  for (int i = 0; i < (int)dxQuery.length() && qi < 23; ++i) {
    char c = dxQuery[i]; if (c >= 'a' && c <= 'z') c -= 32; q[qi++] = c;
  }
  q[qi] = 0;
  bool numeric = (qi > 0);
  for (int i = 0; i < qi; ++i) if (q[i] < '0' || q[i] > '9') { numeric = false; break; }
  for (int i = 0; i < DXCC_LK_N && dxMatchN < CAP; ++i) {
    const DxccLk& e = DXCC_LK[i];
    bool hit = false;
    if (qi == 0) hit = true;
    else if (numeric) {
      hit = (atoi(q) == e.code);                  // numeric code match (001 == 1 == 1)
    } else {
      hit = dxPrefixStarts(e.prefix, q) || dxContainsCI(e.name, q);
    }
    if (hit) dxMatch[dxMatchN++] = i;
  }
}

void App::drawDxLk() {
  header("DXCC lookup");
  canvas.setTextSize(1);
  // Query line
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, 20); canvas.print("Prefix / name / code:");
  canvas.setTextColor(CL_WHITE, CL_BLACK);
  canvas.setCursor(4, 31); canvas.print("> "); canvas.print(dxQuery); canvas.print("_");
  canvas.drawFastHLine(4, 42, 232, CL_MGREY);
  // Match list
  const int LH = 10, VIS = 7, Y0 = 46;
  if (dxSel < dxScroll) dxScroll = dxSel;
  if (dxSel >= dxScroll + VIS) dxScroll = dxSel - VIS + 1;
  if (dxMatchN == 0) {
    canvas.setTextColor(CL_MGREY, CL_BLACK);
    canvas.setCursor(8, Y0 + 4); canvas.print(dxQuery.length() ? "no match" : "type to search 402 entities");
  }
  for (int r = 0; r < VIS; ++r) {
    int m = dxScroll + r; if (m >= dxMatchN) break;
    const DxccLk& e = DXCC_LK[dxMatch[m]];
    int y = Y0 + r * LH; bool sel = (m == dxSel);
    if (sel) canvas.fillRect(2, y - 1, 236, 10, CL_SELBG);
    canvas.setTextColor(sel ? CL_BLACK : (e.deleted ? CL_MGREY : CL_WHITE), sel ? CL_SELBG : CL_BLACK);
    char line[44];
    snprintf(line, sizeof(line), "%-11.11s %3d %.20s", e.prefix[0] ? e.prefix : "-", e.code, e.name);
    canvas.setCursor(6, y); canvas.print(line);
  }
  if (dxScroll > 0)                { canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(230, Y0);            canvas.print("^"); }
  if (dxScroll + VIS < dxMatchN)   { canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(230, Y0 + 6 * LH);  canvas.print("v"); }
  char ft[42];
  snprintf(ft, sizeof(ft), "%d match  ENTER open  ;/. pick  ` back", dxMatchN);
  footer(ft);
}

void App::keyDxLk(char c, bool enter, bool back) {
  if (c == '`') { screen = SCR_TOOLS; lastDrawMs = 0; return; }
  if (isUp(c))   { if (dxSel > 0) dxSel--; lastDrawMs = 0; return; }
  if (isDown(c)) { if (dxSel < dxMatchN - 1) dxSel++; lastDrawMs = 0; return; }
  if (enter) {
    if (dxMatchN > 0) { dxDetail = dxMatch[dxSel]; screen = SCR_DXLKD; lastDrawMs = 0; }
    return;
  }
  if (back) {                                    // DEL edits the query
    if (dxQuery.length()) { dxQuery.remove(dxQuery.length() - 1); dxRunFilter(); }
    lastDrawMs = 0; return;
  }
  // printable query characters (letters, digits, punctuation used in prefixes)
  if (c > 32 && c < 127) { if (dxQuery.length() < 20) { dxQuery += c; dxRunFilter(); } lastDrawMs = 0; }
}

void App::drawDxLkDetail() {
  const DxccLk& e = DXCC_LK[dxDetail];
  header("DXCC entity");
  canvas.setTextSize(1);
  int y = 20;
  auto field = [&](const char* k, const String& v, uint16_t col) {
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(6, y);  canvas.print(k);
    canvas.setTextColor(col, CL_BLACK);     canvas.setCursor(78, y); canvas.print(v);
    y += 11;
  };
  // name, wrapped to two lines if needed
  canvas.setTextColor(CL_CYAN, CL_BLACK);
  String nm = e.name;
  canvas.setCursor(6, y);
  canvas.print(nm.length() > 38 ? nm.substring(0, 38) : nm);
  y += 10;
  if (nm.length() > 38) { canvas.setCursor(6, y); canvas.print(nm.substring(38)); y += 10; }
  y += 2;
  field("Code", String(e.code), CL_WHITE);
  field("Prefix", e.prefix[0] ? String(e.prefix) : String("(see notes)"), CL_WHITE);
  field("Continent", e.cont, CL_WHITE);
  field("ITU zone", e.itu, CL_WHITE);
  field("CQ zone", e.cq, CL_WHITE);
  String flags;
  if (e.deleted)    flags += "DELETED  ";
  if (e.thirdParty) flags += "3rd-party OK";
  if (flags.length()) field("Status", flags, e.deleted ? CL_ORANGE : CL_GREEN);
  // footnotes
  if (e.note1 >= 0 && e.note1 < DXCC_NOTES_N) {
    canvas.setTextColor(CL_MGREY, CL_BLACK);
    String n1 = DXCC_NOTES[e.note1];
    canvas.setCursor(6, y); canvas.print("note: "); 
    canvas.print(n1.length() > 33 ? n1.substring(0, 33) : n1); y += 9;
    if (n1.length() > 33) { canvas.setCursor(6, y); canvas.print("  "); canvas.print(n1.substring(33, 71)); y += 9; }
  }
  if (e.note2 >= 0 && e.note2 < DXCC_NOTES_N && y < 116) {
    canvas.setTextColor(CL_MGREY, CL_BLACK);
    String n2 = DXCC_NOTES[e.note2];
    canvas.setCursor(6, y); canvas.print("note: ");
    canvas.print(n2.length() > 33 ? n2.substring(0, 33) : n2); y += 9;
  }
  footer("z CQ-def  i ITU-def  ` back");
}

void App::keyDxLkDetail(char c, bool enter, bool back) {
  (void)enter;
  if (c == '`' || back) { screen = SCR_DXLK; lastDrawMs = 0; return; }
  if (c == 'z') {                               // jump to this entity's CQ zone definition
    int zn = atoi(DXCC_LK[dxDetail].cq);        // leading number of the CQ field (e.g. "03-05" -> 3)
    if (zn >= 1 && zn <= 40) { openCqZone(zn, SCR_DXLKD); lastDrawMs = 0; }
    return;
  }
  if (c == 'i') {                               // jump to this entity's ITU zone definition
    int zn = atoi(DXCC_LK[dxDetail].itu);       // leading number of the ITU field
    if (zn >= 1 && zn <= 90) { openItuZone(zn, SCR_DXLKD); lastDrawMs = 0; }
    return;
  }
}

// ---------------------------------------------------------------------------
//  CQ (WAZ) zone reference (SCR_CQZ list + SCR_CQZD detail). All 40 zones with
//  their names; the detail view shows the full prefix/region text, scrolled if
//  it runs long. Reachable from the Tools hub, and jumped-to from a DXCC
//  entity's CQ zone (cqzReturn remembers where to go back to). Data is the
//  embedded CQ_ZONES[] table (cqzones.h), generated from the CQ WAZ list.
// ---------------------------------------------------------------------------

// Open the detail card for a given zone number (1..40); 'ret' is the screen to
// return to. Used by the list and by the DXCC detail card's jump.
void App::openCqZone(int zoneNum, int ret) {
  int idx = 0;
  for (int i = 0; i < CQ_ZONES_N; ++i) if (CQ_ZONES[i].n == zoneNum) { idx = i; break; }
  cqzDetail = idx; cqzDScroll = 0; cqzReturn = ret; screen = SCR_CQZD;
}

void App::drawCqz() {
  header("CQ zones (WAZ)");
  canvas.setTextSize(1);
  const int LH = 13, VIS = 8, Y0 = 20;
  if (cqzSel < cqzScroll) cqzScroll = cqzSel;
  if (cqzSel >= cqzScroll + VIS) cqzScroll = cqzSel - VIS + 1;
  for (int r = 0; r < VIS; ++r) {
    int i = cqzScroll + r; if (i >= CQ_ZONES_N) break;
    int y = Y0 + r * LH; bool sel = (i == cqzSel);
    if (sel) canvas.fillRect(2, y - 1, 236, 13, CL_SELBG);
    canvas.setTextColor(sel ? CL_BLACK : CL_CYAN, sel ? CL_SELBG : CL_BLACK);
    char num[6]; snprintf(num, sizeof(num), "%2d", CQ_ZONES[i].n);
    canvas.setCursor(6, y + 3); canvas.print(num);
    canvas.setTextColor(sel ? CL_BLACK : CL_WHITE, sel ? CL_SELBG : CL_BLACK);
    String nm = CQ_ZONES[i].name;
    canvas.setCursor(30, y + 3); canvas.print(nm.length() > 34 ? nm.substring(0, 34) : nm);
  }
  if (cqzScroll > 0)                { canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(230, Y0);           canvas.print("^"); }
  if (cqzScroll + VIS < CQ_ZONES_N) { canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(230, Y0 + 7 * LH); canvas.print("v"); }
  footer("ENTER detail  ;/. pick  ` back");
}

void App::keyCqz(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_TOOLS; lastDrawMs = 0; return; }
  if (isUp(c))   { if (cqzSel > 0) cqzSel--; lastDrawMs = 0; return; }
  if (isDown(c)) { if (cqzSel < CQ_ZONES_N - 1) cqzSel++; lastDrawMs = 0; return; }
  if (enter) { openCqZone(CQ_ZONES[cqzSel].n, SCR_CQZ); lastDrawMs = 0; return; }
}

void App::drawCqzDetail() {
  const CqZone& z = CQ_ZONES[cqzDetail];
  char h[24]; snprintf(h, sizeof(h), "CQ zone %d", z.n);
  header(h);
  canvas.setTextSize(1);
  // Zone name (wrapped to two lines if needed).
  canvas.setTextColor(CL_CYAN, CL_BLACK);
  String nm = z.name; int y = 20;
  canvas.setCursor(6, y); canvas.print(nm.length() > 38 ? nm.substring(0, 38) : nm); y += 10;
  if (nm.length() > 38) { canvas.setCursor(6, y); canvas.print(nm.substring(38)); y += 10; }
  canvas.drawFastHLine(4, y + 1, 232, CL_MGREY); y += 6;
  // Detail text, word-wrapped to ~39 chars/line, scrollable with ;/.
  String d = z.detail;
  const int WRAP = 39, LINES = 7;
  int line = 0, shown = 0, pos = 0, L = d.length();
  while (pos < L && shown < LINES) {
    int end = pos + WRAP;
    if (end >= L) end = L;
    else { int sp = end; while (sp > pos && d[sp] != ' ') sp--; if (sp > pos) end = sp; }
    if (line >= cqzDScroll) {
      canvas.setTextColor(CL_WHITE, CL_BLACK);
      canvas.setCursor(6, y); canvas.print(d.substring(pos, end)); y += 10; shown++;
    }
    line++; pos = end; while (pos < L && d[pos] == ' ') pos++;
  }
  bool more = (pos < L);
  if (cqzDScroll > 0) { canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(230, 32); canvas.print("^"); }
  if (more)           { canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(230, 108); canvas.print("v"); }
  footer(more || cqzDScroll ? ";/. scroll  ` back" : "` back");
}

void App::keyCqzDetail(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { screen = (cqzReturn == SCR_DXLKD) ? SCR_DXLKD : SCR_CQZ; lastDrawMs = 0; return; }
  if (isUp(c))   { if (cqzDScroll > 0) cqzDScroll--; lastDrawMs = 0; return; }
  if (isDown(c)) { cqzDScroll++; lastDrawMs = 0; return; }   // draw clamps by simply showing fewer lines
}

// ---------------------------------------------------------------------------
//  ITU zone reference (SCR_ITUZ list + SCR_ITUZD detail). ITU zones have no
//  descriptive names, just a number and a prefix/region definition, and the
//  numbering is not contiguous (this list is 1-75, 78, 90). Reachable from the
//  Tools hub and jumped-to from a DXCC entity's ITU zone. Data is the embedded
//  ITU_ZONES[] table (ituzones.h), generated from the RSGB ITU zones list.
// ---------------------------------------------------------------------------

void App::openItuZone(int zoneNum, int ret) {
  int idx = -1;
  for (int i = 0; i < ITU_ZONES_N; ++i) if (ITU_ZONES[i].n == zoneNum) { idx = i; break; }
  if (idx < 0) return;                           // not a listed zone -- no jump
  ituDetail = idx; ituDScroll = 0; ituReturn = ret; screen = SCR_ITUZD;
}

void App::drawItuz() {
  header("ITU zones");
  canvas.setTextSize(1);
  const int LH = 11, VIS = 9, Y0 = 20;
  if (ituSel < ituScroll) ituScroll = ituSel;
  if (ituSel >= ituScroll + VIS) ituScroll = ituSel - VIS + 1;
  for (int r = 0; r < VIS; ++r) {
    int i = ituScroll + r; if (i >= ITU_ZONES_N) break;
    int y = Y0 + r * LH; bool sel = (i == ituSel);
    if (sel) canvas.fillRect(2, y - 1, 236, 11, CL_SELBG);
    canvas.setTextColor(sel ? CL_BLACK : CL_CYAN, sel ? CL_SELBG : CL_BLACK);
    char num[6]; snprintf(num, sizeof(num), "%2d", ITU_ZONES[i].n);
    canvas.setCursor(6, y + 2); canvas.print(num);
    canvas.setTextColor(sel ? CL_BLACK : CL_WHITE, sel ? CL_SELBG : CL_BLACK);
    String d = ITU_ZONES[i].detail;
    canvas.setCursor(30, y + 2); canvas.print(d.length() > 34 ? d.substring(0, 34) : d);
  }
  if (ituScroll > 0)                 { canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(230, Y0);           canvas.print("^"); }
  if (ituScroll + VIS < ITU_ZONES_N) { canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(230, Y0 + 8 * LH); canvas.print("v"); }
  footer("ENTER detail  ;/. pick  ` back");
}

void App::keyItuz(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_TOOLS; lastDrawMs = 0; return; }
  if (isUp(c))   { if (ituSel > 0) ituSel--; lastDrawMs = 0; return; }
  if (isDown(c)) { if (ituSel < ITU_ZONES_N - 1) ituSel++; lastDrawMs = 0; return; }
  if (enter) { openItuZone(ITU_ZONES[ituSel].n, SCR_ITUZ); lastDrawMs = 0; return; }
}

void App::drawItuzDetail() {
  const ItuZone& z = ITU_ZONES[ituDetail];
  char h[24]; snprintf(h, sizeof(h), "ITU zone %d", z.n);
  header(h);
  canvas.setTextSize(1);
  int y = 22;
  String d = z.detail;
  const int WRAP = 39, LINES = 9;
  int line = 0, shown = 0, pos = 0, L = d.length();
  while (pos < L && shown < LINES) {
    int end = pos + WRAP;
    if (end >= L) end = L;
    else { int sp = end; while (sp > pos && d[sp] != ' ') sp--; if (sp > pos) end = sp; }
    if (line >= ituDScroll) {
      canvas.setTextColor(CL_WHITE, CL_BLACK);
      canvas.setCursor(6, y); canvas.print(d.substring(pos, end)); y += 10; shown++;
    }
    line++; pos = end; while (pos < L && d[pos] == ' ') pos++;
  }
  bool more = (pos < L);
  if (ituDScroll > 0) { canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(230, 22);  canvas.print("^"); }
  if (more)           { canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(230, 108); canvas.print("v"); }
  footer(more || ituDScroll ? ";/. scroll  ` back" : "` back");
}

void App::keyItuzDetail(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { screen = (ituReturn == SCR_DXLKD) ? SCR_DXLKD : SCR_ITUZ; lastDrawMs = 0; return; }
  if (isUp(c))   { if (ituDScroll > 0) ituDScroll--; lastDrawMs = 0; return; }
  if (isDown(c)) { ituDScroll++; lastDrawMs = 0; return; }
}

// ---------------------------------------------------------------------------
//  Link budget calculator (SCR_LINKB). Computes the full chain:
//    EIRP = Ptx(dBm) - TX line loss + TX antenna gain
//    Prx  = EIRP - FSPL - extra losses + RX antenna gain - RX line loss
//    N    = -174 dBm/Hz + 10*log10(BW) + NF        (kTB at 290 K + noise figure)
//    SNR  = Prx - N ; margin = SNR - required SNR for the mode
//  Twelve inputs scroll in a window; the key outputs stay pinned below and
//  recompute live. Row 0 is a mode preset that sets bandwidth + required SNR
//  as a pair (both stay editable afterwards). An S-meter estimate uses the
//  IARU convention: S9 = -93 dBm above 30 MHz (-73 dBm below), 6 dB per S-unit.
// ---------------------------------------------------------------------------
namespace {
  struct LbMode { const char* name; double bwHz; double reqSnr; };
  // Required SNR is defined IN the listed bandwidth. Sensible planning figures:
  // ear-copy CW in a 500 Hz filter, comfortable SSB, FM threshold-plus, packet
  // through an FM channel, and the WSJT modes' decode thresholds referenced to
  // their conventional 2.5 kHz passband.
  const LbMode LB_MODES[] = {
    { "CW (500Hz)",   500.0,    6.0 },
    { "SSB",          2400.0,  10.0 },
    { "FM voice",     15000.0, 12.0 },
    { "AFSK 1k2",     15000.0, 13.0 },
    { "GMSK 9k6",     20000.0, 13.0 },
    { "FT8",          2500.0, -20.0 },
    { "JT65/Q65",     2500.0, -24.0 },
    { "Custom",       0.0,      0.0 },   // leaves BW / req-SNR untouched
  };
  const int LB_MODES_N = (int)(sizeof(LB_MODES) / sizeof(LB_MODES[0]));
  const char* const LB_LABEL[12] = {
    "Mode", "Freq MHz", "Dist km", "TX pwr W", "TX line dB", "TX ant dBi",
    "Extra loss", "RX ant dBi", "RX line dB", "RX NF dB", "BW Hz", "Req SNR dB" };
}

void App::lbInit() {
  lbSel = 1; lbScroll = 0; lbEditing = false; lbEditBuf = "";
  lbVal[0] = 0;                 // (unused -- mode row shows LB_MODES[lbMode].name)
  lbVal[1] = 435.0;             // freq MHz
  lbVal[2] = 1000.0;            // distance km (typical LEO slant range)
  lbVal[3] = 25.0;              // TX power W
  lbVal[4] = 1.5;               // TX line loss dB
  lbVal[5] = 12.0;              // TX antenna gain dBi
  lbVal[6] = 2.0;               // extra losses dB (polarization + pointing + atm)
  lbVal[7] = 0.0;               // RX antenna gain dBi
  lbVal[8] = 0.0;               // RX line loss dB
  lbVal[9] = 3.0;               // RX noise figure dB
  lbMode = 1;                   // SSB
  lbVal[10] = LB_MODES[lbMode].bwHz;
  lbVal[11] = LB_MODES[lbMode].reqSnr;
}

void App::drawLinkB() {
  header("Link budget");
  canvas.setTextSize(1);
  // --- input window: 5 rows over the 12 ---
  const int VIS = 5, LH = 11, Y0 = 20;
  if (lbSel < lbScroll) lbScroll = lbSel;
  if (lbSel >= lbScroll + VIS) lbScroll = lbSel - VIS + 1;
  for (int r = 0; r < VIS; ++r) {
    int i = lbScroll + r; if (i >= LB_NF) break;
    int y = Y0 + r * LH; bool sel = (i == lbSel);
    if (sel) canvas.fillRect(2, y - 2, 236, 11, CL_SELBG);
    canvas.setTextColor(sel ? CL_BLACK : CL_GREY, sel ? CL_SELBG : CL_BLACK);
    canvas.setCursor(6, y); canvas.print(LB_LABEL[i]);
    canvas.setTextColor(sel ? CL_BLACK : CL_WHITE, sel ? CL_SELBG : CL_BLACK);
    String vs;
    if (i == 0)                        vs = LB_MODES[lbMode].name;
    else if (sel && lbEditing)         vs = lbEditBuf + "_";
    else {
      char b[20]; dtostrf(lbVal[i], 0, (i == 10) ? 0 : 1, b);   // BW as integer Hz
      String r2(b); while (r2.indexOf('.') >= 0 && (r2.endsWith("0") || r2.endsWith("."))) r2.remove(r2.length() - 1);
      vs = r2;
    }
    canvas.setCursor(130, y); canvas.print(vs);
  }
  if (lbScroll > 0)             { canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(230, Y0);            canvas.print("^"); }
  if (lbScroll + VIS < LB_NF)   { canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(230, Y0 + 4 * LH);  canvas.print("v"); }
  canvas.drawFastHLine(4, 77, 232, CL_MGREY);
  // --- live outputs, pinned ---
  double ptxDbm = 10.0 * log10(lbVal[3] * 1000.0);
  double eirp = ptxDbm - lbVal[4] + lbVal[5];
  double fspl = 32.44 + 20.0 * log10(lbVal[2]) + 20.0 * log10(lbVal[1]);
  double prx  = eirp - fspl - lbVal[6] + lbVal[7] - lbVal[8];
  double nflr = -174.0 + 10.0 * log10(lbVal[10] > 0 ? lbVal[10] : 1) + lbVal[9];
  double snr  = prx - nflr;
  double marg = snr - lbVal[11];
  // S-meter estimate (IARU): S9 = -93 dBm >=30 MHz, -73 below; 6 dB per S-unit.
  double s9 = (lbVal[1] >= 30.0) ? -93.0 : -73.0;
  String smet;
  if (prx >= s9) { char b[12]; snprintf(b, sizeof(b), "S9+%.0f", prx - s9); smet = b; }
  else { int s = (int)lround(9.0 + (prx - s9) / 6.0); if (s < 0) s = 0; smet = "S" + String(s); }
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(6, 82);  canvas.printf("EIRP %.1f dBm   FSPL %.1f dB", eirp, fspl);
  canvas.setCursor(6, 92);  canvas.printf("RX %.1f dBm   N %.1f dBm", prx, nflr);
  canvas.setTextColor(CL_WHITE, CL_BLACK);
  canvas.setCursor(6, 102); canvas.printf("SNR %.1f dB   ~%s", snr, smet.c_str());
  uint16_t mc = (marg >= 6.0) ? CL_GREEN : (marg >= 0.0) ? CL_ORANGE : CL_RED;
  canvas.setTextColor(mc, CL_BLACK);
  canvas.setCursor(6, 112); canvas.printf("MARGIN %+.1f dB %s", marg,
      (marg >= 6) ? "(solid)" : (marg >= 0) ? "(thin)" : "(no copy)");
  if (lbSel == 0) footer(",// mode  ;/. field  ` back");
  else            footer("type value  ;/. field  ` back");
}

void App::keyLinkB(char c, bool enter, bool back) {
  if (c == '`') { screen = SCR_TOOLS; lastDrawMs = 0; return; }   // only backtick exits
  auto commit = [&]() {
    if (lbEditing) { lbVal[lbSel] = lbEditBuf.toFloat(); lbEditing = false; lbEditBuf = ""; }
  };
  if (isUp(c))   { commit(); if (--lbSel < 0) lbSel = LB_NF - 1; lastDrawMs = 0; return; }
  if (isDown(c)) { commit(); if (++lbSel >= LB_NF) lbSel = 0;    lastDrawMs = 0; return; }
  if (lbSel == 0) {                              // mode preset row
    if (c == ',' || c == '/') {
      lbMode = (lbMode + (c == '/' ? 1 : LB_MODES_N - 1)) % LB_MODES_N;
      if (LB_MODES[lbMode].bwHz > 0) {           // Custom leaves the fields alone
        lbVal[10] = LB_MODES[lbMode].bwHz;
        lbVal[11] = LB_MODES[lbMode].reqSnr;
      }
      lastDrawMs = 0;
    }
    return;
  }
  if (back || c == 8 || c == 127) {              // DEL: edit-only backspace
    if (lbEditing && lbEditBuf.length()) lbEditBuf.remove(lbEditBuf.length() - 1);
    lastDrawMs = 0; return;
  }
  if ((c >= '0' && c <= '9') || c == '.' || c == '-') {
    if (!lbEditing) { lbEditing = true; lbEditBuf = ""; }
    lbEditBuf += c; lastDrawMs = 0; return;
  }
  if (enter) { commit(); lastDrawMs = 0; return; }
}







// ---------------------------------------------------------------------------
//  Live-recalc form engine. toolFormInit() sets up the fields for a tool; the
//  draw routine computes and shows the outputs every frame from tfVal[]; keys
//  move between fields and edit values in place (numeric) or cycle choices
//  (pick-list fields, e.g. the coax type).
// ---------------------------------------------------------------------------

// Coax cable table: name + k where matched loss(dB/100ft) = k * sqrt(f_MHz).
namespace {
  struct Coax { const char* name; double k; };
  const Coax COAX_TBL[] = {
    { "RG-58",    0.3724 }, { "RG-8X",    0.2483 }, { "RG-213",   0.1655 },
    { "LMR-240",  0.2400 }, { "LMR-400",  0.1241 }, { "LMR-600",  0.0828 },
    { "RG-174",   0.6621 }, { "Hardline1/2", 0.0703 },
  };
  const int COAX_N = (int)(sizeof(COAX_TBL) / sizeof(COAX_TBL[0]));

  // Standard CubeSat form factors: name + nominal body dimensions X,Y,Z in cm.
  // "Custom" leaves the dimension fields alone so any satellite can be entered.
  struct XsecPreset { const char* name; double x, y, z; };
  const XsecPreset XSEC_PRESET[] = {
    { "1U",     10, 10, 10 }, { "2U",     10, 10, 20 }, { "3U",   10, 10, 30 },
    { "6U",     10, 20, 30 }, { "12U",    20, 20, 30 }, { "16U",  20, 20, 40 },
    { "0.5U",   10, 10, 5  }, { "Custom", 0,  0,  0  },
  };
  const int XSEC_PRESET_N = (int)(sizeof(XSEC_PRESET) / sizeof(XSEC_PRESET[0]));

  // FCC OET-65 Maximum Permissible Exposure limits (mW/cm^2) by frequency (MHz).
  double mpeUncontrolled(double f) {         // general population / uncontrolled
    if (f < 1.34) return 100.0;
    if (f < 30)   return 180.0 / (f * f);
    if (f < 300)  return 0.2;
    if (f < 1500) return f / 1500.0;
    return 1.0;
  }
  double mpeControlled(double f) {           // occupational / controlled
    if (f < 3.0)  return 100.0;
    if (f < 30)   return 900.0 / (f * f);
    if (f < 300)  return 1.0;
    if (f < 1500) return f / 300.0;
    return 5.0;
  }
  // OET-65 far-field compliance-distance estimate (cm):
  //   S = P_mW*G/(4*pi*d^2)  ->  d = sqrt(P_mW*G/(4*pi*S))
  double mpeDistCm(double P_w, double G_dbi, double duty, double S_limit) {
    if (S_limit <= 0) return 0;
    double P_mw = P_w * 1000.0 * (duty / 100.0);
    double G = pow(10.0, G_dbi / 10.0);
    return sqrt(P_mw * G / (4.0 * 3.14159265358979323846 * S_limit));
  }

  // Vallado exponential-atmosphere model: base altitude (km), nominal density
  // (kg/m^3) at that base, and scale height (km). Used for a rough orbital-
  // lifetime (debris) estimate. "Nominal" ~ mean solar activity; real lifetime
  // swings several-fold over the solar cycle, so this is an order-of-magnitude
  // planning figure, NOT a compliance determination (use NASA DAS for that).
  struct AtmBand { double h0, rho0, H; };
  const AtmBand ATM[] = {
    {150, 2.070e-9, 22.523}, {180, 5.464e-10, 29.740}, {200, 2.789e-10, 37.105},
    {250, 7.248e-11, 45.546}, {300, 2.418e-11, 53.628}, {350, 9.518e-12, 53.298},
    {400, 3.725e-12, 58.515}, {450, 1.585e-12, 60.828}, {500, 6.967e-13, 63.822},
    {600, 1.454e-13, 71.835}, {700, 3.614e-14, 88.667}, {800, 1.170e-14, 124.64},
    {900, 5.245e-15, 181.05}, {1000, 3.019e-15, 268.00},
  };
  const int ATM_N = (int)(sizeof(ATM) / sizeof(ATM[0]));
  const AtmBand& atmBand(double h_km) {
    int idx = 0;
    for (int i = 0; i < ATM_N; ++i) { if (h_km >= ATM[i].h0) idx = i; else break; }
    return ATM[idx];
  }
  double atmDensity(double h_km) {
    const AtmBand& b = atmBand(h_km);
    return b.rho0 * exp(-(h_km - b.h0) / b.H);
  }
  // Orbital lifetime (years) for a near-circular orbit decaying via drag, by
  // summing the time to descend through each 2 km slice from the start altitude
  // down to ~150 km. da/dt = -B*rho*sqrt(mu*a); B = Cd*A/m.
  double orbitLifetimeYr(double h_km, double mass, double area, double cd) {
    const double MU = 3.986004418e14, RE = 6378137.0;
    double B = cd * area / mass;
    if (B <= 0 || h_km <= 150.0) return 0;
    double t = 0, h = h_km;
    while (h > 150.0) {
      double h_lo = h - 2.0; if (h_lo < 150.0) h_lo = 150.0;
      double r_mid = RE + ((h + h_lo) / 2.0) * 1000.0;
      double H = atmBand(h).H * 1000.0;
      double dt = (1.0 / (B * sqrt(MU * r_mid))) * H * (1.0 / atmDensity(h) - 1.0 / atmDensity(h_lo));
      if (dt > 0) t += dt;
      h = h_lo;
    }
    return t / (365.25 * 86400.0);
  }
}

const char* App::tfChoiceLabel(int field, int idx) {
  if (toolId == TOOL_COAX && field == 0) {
    if (idx >= 0 && idx < COAX_N) return COAX_TBL[idx].name;
  }
  if (toolId == TOOL_XAREA && field == 0) {
    if (idx >= 0 && idx < XSEC_PRESET_N) return XSEC_PRESET[idx].name;
  }
  return "?";
}

void App::toolFormInit(int id) {
  toolId = id; tfSel = 0; tfEditing = false; tfEditBuf = ""; tfOutScroll = 0;
  for (int i = 0; i < TF_MAXF; ++i) { tfChoice[i] = -1; tfChoiceN[i] = 0; tfUnit[i][0] = 0; }
  auto FLD = [&](int i, const char* lab, const char* unit, double v) {
    strncpy(tfLabel[i], lab, sizeof(tfLabel[i]) - 1); tfLabel[i][sizeof(tfLabel[i]) - 1] = 0;
    strncpy(tfUnit[i], unit, sizeof(tfUnit[i]) - 1);   tfUnit[i][sizeof(tfUnit[i]) - 1] = 0;
    tfVal[i] = v;
  };
  switch (id) {
    case TOOL_COAX:
      tfN = 4;
      FLD(0, "Cable", "", 4);            tfChoice[0] = 4; tfChoiceN[0] = COAX_N;  // default LMR-400
      FLD(1, "Freq", "MHz", 146.0);
      FLD(2, "Length", "ft", 50.0);
      FLD(3, "SWR at load", ":1", 1.5);
      break;
    case TOOL_DIPOLE:
      tfN = 1; FLD(0, "Freq", "MHz", 14.2); break;
    case TOOL_VERTICAL:
      tfN = 1; FLD(0, "Freq", "MHz", 146.0); break;
    case TOOL_YAGI:
      tfN = 2; FLD(0, "Freq", "MHz", 144.2); FLD(1, "Elements", "", 3); break;
    case TOOL_QUAD:
      tfN = 2; FLD(0, "Freq", "MHz", 50.1);  FLD(1, "Elements", "", 2); break;
    case TOOL_RFCONV:
      tfN = 1; FLD(0, "Power", "W", 100.0); break;
    case TOOL_SWR:
      tfN = 1; FLD(0, "SWR", ":1", 2.0); break;
    case TOOL_FSPL:
      tfN = 2; FLD(0, "Distance", "km", 1000.0); FLD(1, "Freq", "MHz", 145.0); break;
    case TOOL_UNITS:
      tfN = 1; FLD(0, "Value", "", 100.0); break;
    case TOOL_RFEXP:
      tfN = 4; FLD(0, "Freq", "MHz", 146.0); FLD(1, "Power", "W", 100.0);
      FLD(2, "Duty", "%", 100.0); FLD(3, "Ant gain", "dBi", 2.15); break;
    case TOOL_BATT:
      tfN = 5; FLD(0, "Capacity", "Ah", 20.0); FLD(1, "RX draw", "A", 0.5);
      FLD(2, "TX draw", "A", 8.0); FLD(3, "TX duty", "%", 30.0);
      FLD(4, "Usable", "%", 80.0); break;
    case TOOL_DEBRIS:
      tfN = 4; FLD(0, "Altitude", "km", 550.0); FLD(1, "Mass", "kg", 4.0);
      FLD(2, "Area", "m2", 0.03); FLD(3, "Drag Cd", "", 2.2); break;
    case TOOL_XAREA:
      tfN = 5;
      FLD(0, "Form factor", "", 2); tfChoice[0] = 2; tfChoiceN[0] = XSEC_PRESET_N; // default 3U
      FLD(1, "Body X", "cm", 10.0); FLD(2, "Body Y", "cm", 10.0);
      FLD(3, "Body Z", "cm", 30.0); FLD(4, "Panel area", "m2", 0.0); break;
  }
}

// Render one output line helper is inline in drawToolForm via a local lambda.
void App::drawToolForm() {
  header(TOOLS_NAMES[toolId + 7]);           // +7: calc, pcalc, char-lookup, DXCC, CQ, ITU, link-budget precede
  canvas.setTextSize(1);
  int y = 20; const int LH = 11;
  // --- input fields ---
  for (int i = 0; i < tfN; ++i) {
    bool sel = (i == tfSel);
    if (sel) canvas.fillRect(2, y - 2, 236, 11, CL_SELBG);
    canvas.setTextColor(sel ? CL_BLACK : CL_GREY, sel ? CL_SELBG : CL_BLACK);
    canvas.setCursor(6, y); canvas.print(tfLabel[i]);
    canvas.setTextColor(sel ? CL_BLACK : CL_WHITE, sel ? CL_SELBG : CL_BLACK);
    String vs;
    if (tfChoice[i] >= 0)            vs = tfChoiceLabel(i, tfChoice[i]);
    else if (sel && tfEditing)       vs = tfEditBuf + "_";
    else {
      char b[20]; dtostrf(tfVal[i], 0, 3, b);
      String r(b); while (r.indexOf('.') >= 0 && (r.endsWith("0") || r.endsWith("."))) r.remove(r.length() - 1);
      vs = r;
    }
    canvas.setCursor(120, y); canvas.print(vs);
    if (tfUnit[i][0]) { canvas.setCursor(120 + (int)vs.length() * 6 + 4, y); canvas.print(tfUnit[i]); }
    y += LH;
  }
  y += 3;
  canvas.drawFastHLine(4, y - 2, 232, CL_MGREY);
  // --- computed outputs (per tool) ---
  // Output lines honor tfOutScroll (skip the first N) and clip above the footer;
  // "more" arrows show when the list extends past either edge.
  int skip = tfOutScroll; bool moreBelow = false; int outTop = y;
  auto out = [&](const String& k, const String& v, uint16_t col) {
    if (skip > 0) { --skip; return; }
    if (y > 112) { moreBelow = true; return; }
    canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.setCursor(6, y);   canvas.print(k);
    canvas.setTextColor(col, CL_BLACK);      canvas.setCursor(120, y); canvas.print(v);
    y += 10;
  };
  auto ftin = [](double ft) -> String {       // pretty length: ft + in
    long inch = lroundl(ft * 12.0);
    return String(inch / 12) + "ft " + String(inch % 12) + "in";
  };
  const double C_FTMHZ = 983.571;              // speed of light, ft*MHz (for reference)
  switch (toolId) {
    case TOOL_COAX: {
      double k = COAX_TBL[tfChoice[0] >= 0 ? tfChoice[0] : 0].k;
      double f = tfVal[1], len = tfVal[2], swr = tfVal[3];
      double ml = k * sqrt(f) * len / 100.0;   // matched loss, dB
      double g = (swr > 1) ? (swr - 1) / (swr + 1) : 0.0;
      double a = pow(10.0, ml / 10.0);
      double num = a * a - g * g, den = a * (1 - g * g);
      double tot = (den > 0 && num > 0) ? 10.0 * log10(num / den) : ml;
      out("Matched loss", String(ml, 2) + " dB", CL_WHITE);
      out("Loss at SWR", String(tot, 2) + " dB", swr > 2 ? CL_ORANGE : CL_WHITE);
      out("Power out %", String(pow(10.0, -tot / 10.0) * 100.0, 1) + " %", CL_CYAN);
      out("100W in ->", String(100.0 * pow(10.0, -tot / 10.0), 1) + " W", CL_CYAN);
      break;
    }
    case TOOL_DIPOLE: {
      double f = tfVal[0]; double L = 468.0 / f;      // ft, half-wave with end effect
      out("Total length", ftin(L), CL_CYAN);
      out("Each leg", ftin(L / 2), CL_WHITE);
      out("Metric", String(L * 0.3048, 3) + " m", CL_WHITE);
      break;
    }
    case TOOL_VERTICAL: {
      double f = tfVal[0]; double L = 234.0 / f;       // quarter wave
      out("1/4-wave", ftin(L), CL_CYAN);
      out("Radials (4)", ftin(L * 1.02), CL_WHITE);    // slightly longer
      out("Metric", String(L * 0.3048, 3) + " m", CL_WHITE);
      break;
    }
    case TOOL_YAGI: {
      double f = tfVal[0]; double dr = 468.0 / f;      // driven ~ dipole
      int n = (int)lround(tfVal[1]); if (n < 2) n = 2; if (n > 12) n = 12;
      out("Driven elem", ftin(dr), CL_CYAN);
      out("Reflector", ftin(dr * 1.05), CL_WHITE);     // ~5% longer
      // Directors: ~5% shorter than driven, each subsequent ~1% shorter again.
      // Starting dimensions -- real lengths depend on boom and element diameter.
      for (int d2 = 1; d2 <= n - 2; ++d2)
        out(String("Director ") + d2, ftin(dr * (0.95 - 0.01 * (d2 - 1))), CL_WHITE);
      out("Spacing 0.2wl", ftin(0.2 * C_FTMHZ / f), CL_GREY);
      break;
    }
    case TOOL_QUAD: {
      double f = tfVal[0]; double loop = 1005.0 / f;   // full-wave loop, ft
      int n = (int)lround(tfVal[1]); if (n < 2) n = 2; if (n > 8) n = 8;
      out("Driven loop", ftin(loop), CL_CYAN);
      out("  each side", ftin(loop / 4), CL_WHITE);
      out("Refl loop", ftin(1030.0 / f), CL_WHITE);    // ~2.5% larger
      for (int d2 = 1; d2 <= n - 2; ++d2)
        out(String("Dir ") + d2 + " loop", ftin(975.0 / f), CL_WHITE);  // ~3% smaller
      break;
    }
    case TOOL_RFCONV: {
      double w = tfVal[0]; if (w <= 0) w = 1e-6;
      double dbm = 10.0 * log10(w) + 30.0;
      double vrms = sqrt(w * 50.0);                    // into 50 ohm
      out("dBm", String(dbm, 2) + " dBm", CL_CYAN);
      out("dBW", String(dbm - 30.0, 2) + " dBW", CL_WHITE);
      out("Vrms @50ohm", String(vrms, 2) + " V", CL_WHITE);
      out("Vpp @50ohm", String(vrms * 2.828, 2) + " V", CL_GREY);
      break;
    }
    case TOOL_SWR: {
      double s = tfVal[0]; if (s < 1) s = 1;
      double g = (s - 1) / (s + 1);
      double rl = (g > 0) ? -20.0 * log10(g) : 99.0;
      double refl = g * g * 100.0;
      out("Return loss", String(rl, 2) + " dB", CL_WHITE);
      out("Refl coeff", String(g, 4), CL_WHITE);
      out("Power refl", String(refl, 1) + " %", refl > 11 ? CL_ORANGE : CL_CYAN);
      out("Mismatch", String(-10.0 * log10(1 - g * g), 3) + " dB", CL_GREY);
      break;
    }
    case TOOL_FSPL: {
      double d = tfVal[0], f = tfVal[1];
      if (d > 0 && f > 0) {
        double fspl = 20.0 * log10(d) + 20.0 * log10(f) + 32.44;
        out("Path loss", String(fspl, 1) + " dB", CL_CYAN);
        out("At 1W EIRP", String(-fspl + 30.0, 1) + " dBm", CL_WHITE);
      }
      break;
    }
    case TOOL_UNITS: {
      double v = tfVal[0];
      out("ft -> m", String(v * 0.3048, 3), CL_WHITE);
      out("m -> ft", String(v / 0.3048, 3), CL_WHITE);
      out("C -> F", String(v * 9.0 / 5.0 + 32.0, 2), CL_CYAN);
      out("F -> C", String((v - 32.0) * 5.0 / 9.0, 2), CL_CYAN);
      out("mi -> km", String(v * 1.609344, 3), CL_GREY);
      break;
    }
    case TOOL_RFEXP: {
      // FCC RF-exposure MPE limits and estimated compliance distances. This is a
      // far-field estimate (OET-65); it is guidance, not a substitute for a full
      // station evaluation. Distances shown in meters; ground reflections can
      // increase real exposure (worst case ~2x distance).
      double f = tfVal[0], p = tfVal[1], duty = tfVal[2], g = tfVal[3];
      double mu = mpeUncontrolled(f), mc = mpeControlled(f);
      double du = mpeDistCm(p, g, duty, mu) / 100.0;
      double dc = mpeDistCm(p, g, duty, mc) / 100.0;
      out("Unctrl MPE", String(mu, 3) + " mW/cm2", CL_GREY);
      out("  distance", String(du, 2) + " m", CL_CYAN);
      out("Ctrl MPE", String(mc, 3) + " mW/cm2", CL_GREY);
      out("  distance", String(dc, 2) + " m", CL_WHITE);
      out("Avg power", String(p * duty / 100.0, 1) + " W", CL_GREY);
      out("+reflect x2", String(du * 2.0, 2) + " m unc", CL_ORANGE);
      break;
    }
    case TOOL_BATT: {
      // Battery runtime from an average current draw (RX/TX weighted by duty),
      // limited to the usable fraction of capacity.
      double cap = tfVal[0], rx = tfVal[1], tx = tfVal[2], duty = tfVal[3], use = tfVal[4];
      double avg = rx * (1.0 - duty / 100.0) + tx * (duty / 100.0);
      double rt = (avg > 0) ? (cap * (use / 100.0) / avg) : 0.0;
      int hh = (int)rt, mm = (int)((rt - hh) * 60.0 + 0.5);
      if (mm == 60) { hh++; mm = 0; }
      out("Avg current", String(avg, 2) + " A", CL_WHITE);
      out("Usable cap", String(cap * use / 100.0, 1) + " Ah", CL_GREY);
      out("Runtime", String(rt, 2) + " h", CL_CYAN);
      out("  = ", String(hh) + "h " + String(mm) + "m", CL_CYAN);
      out("Energy", String(avg * rt, 1) + " Ah used", CL_GREY);
      break;
    }
    case TOOL_DEBRIS: {
      // Rough orbital-lifetime / debris-mitigation estimate. NOT a compliance
      // tool -- NASA DAS is authoritative; this is an order-of-magnitude figure.
      double alt = tfVal[0], mass = tfVal[1], area = tfVal[2], cd = tfVal[3];
      double bc = (cd * area > 0) ? mass / (cd * area) : 0;
      double yr = orbitLifetimeYr(alt, mass, area, cd);
      out("Ballistic", String(bc, 1) + " kg/m2", CL_GREY);
      if (yr < 1.0)   out("Lifetime", String(yr * 365.25, 0) + " days", CL_CYAN);
      else            out("Lifetime", String(yr, 1) + " years", CL_CYAN);
      out("25-yr rule", yr <= 25.0 ? "OK" : "EXCEEDS", yr <= 25.0 ? CL_GREEN : CL_RED);
      out("5-yr (new)", yr <= 5.0 ? "OK" : "EXCEEDS", yr <= 5.0 ? CL_GREEN : CL_ORANGE);
      out("nominal Sun", "+-several x", CL_MGREY);
      out("est only", "use NASA DAS", CL_MGREY);
      break;
    }
    case TOOL_XAREA: {
      // Cross-sectional (projected) area of a rectangular body, plus optional
      // deployable panel area. Body dims are cm; areas shown in m^2.
      //   face products: ab, bc, ca (m^2)
      //   end-on (min) and broadside (max) faces
      //   max projected at any angle = sqrt(ab^2+bc^2+ca^2)  (Cauchy-Schwarz)
      //   tumbling average = (ab+bc+ca)/2                    (Cauchy's theorem)
      //   a flat panel of area P tumbling-averages to P/2 (two-sided plate)
      double a = tfVal[1] / 100.0, b = tfVal[2] / 100.0, c = tfVal[3] / 100.0;
      double panel = tfVal[4];                    // already m^2
      double ab = a * b, bc = b * c, ca = c * a;
      double minf = ab; if (bc < minf) minf = bc; if (ca < minf) minf = ca;
      double maxf = ab; if (bc > maxf) maxf = bc; if (ca > maxf) maxf = ca;
      double maxproj = sqrt(ab * ab + bc * bc + ca * ca);
      double tumble = (ab + bc + ca) / 2.0;
      out("End-on min", String(minf, 4) + " m2", CL_WHITE);
      out("Broadside", String(maxf + panel, 4) + " m2", CL_WHITE);
      out("Max any ang", String(maxproj + panel, 4) + " m2", CL_GREY);
      out("Tumbling avg", String(tumble + panel / 2.0, 4) + " m2", CL_CYAN);
      if (panel > 0) out("  (panels)", "+" + String(panel, 3) + " bc/2 tum", CL_MGREY);
      out("-> debris Area", String(tumble + panel / 2.0, 4), CL_ORANGE);
      break;
    }
  }
  if (tfOutScroll > 0)  { canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(230, outTop); canvas.print("^"); }
  if (moreBelow)        { canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(230, 108);    canvas.print("v"); }
  if (!moreBelow && skip > 0 && tfOutScroll > 0) tfOutScroll -= skip;   // over-scrolled: pull back
  if (tfChoice[tfSel] >= 0) footer(",// change  ;/. field  ` back");
  else if (toolId == TOOL_YAGI || toolId == TOOL_QUAD ||
           toolId == TOOL_RFEXP || toolId == TOOL_BATT || toolId == TOOL_DEBRIS ||
           toolId == TOOL_XAREA)
                            footer("type val  ;/. field  ,// scroll  ` back");
  else                      footer("type value  ;/. field  ` back");
}

void App::keyToolForm(char c, bool enter, bool back) {
  if (c == '`') { screen = SCR_TOOLS; lastDrawMs = 0; return; }   // only backtick exits
  // (DEL arrives via 'back' and is handled below as backspace on the edit buffer.)
  // field navigation
  if (!tfEditing && (isUp(c)))   { if (--tfSel < 0) tfSel = tfN - 1; lastDrawMs = 0; return; }
  if (!tfEditing && (isDown(c))) { if (++tfSel >= tfN) tfSel = 0;    lastDrawMs = 0; return; }
  // pick-list field: ,// cycles choices; on numeric forms ,// scrolls the output list
  if (tfChoice[tfSel] >= 0) {
    if (c == ',' || c == '/') {
      int d = (c == '/') ? 1 : -1;
      tfChoice[tfSel] = (tfChoice[tfSel] + tfChoiceN[tfSel] + d) % tfChoiceN[tfSel];
      // Satellite cross-section: selecting a CubeSat preset fills the body
      // dimensions (X/Y/Z), which then stay editable. "Custom" leaves them alone.
      if (toolId == TOOL_XAREA && tfSel == 0) {
        const XsecPreset& p = XSEC_PRESET[tfChoice[0]];
        if (p.x > 0) { tfVal[1] = p.x; tfVal[2] = p.y; tfVal[3] = p.z; }
      }
      lastDrawMs = 0;
    }
    return;
  }
  if (c == '/') { tfOutScroll++;                      lastDrawMs = 0; return; }
  if (c == ',') { if (tfOutScroll > 0) tfOutScroll--; lastDrawMs = 0; return; }
  // numeric field: type digits to edit in place; ENTER or field-move commits
  if (back || c == 8 || c == 127) {            // DEL (via 'back'): backspace the edit buffer
    if (tfEditing && tfEditBuf.length()) tfEditBuf.remove(tfEditBuf.length() - 1);
    lastDrawMs = 0; return;                     // never exits -- backtick is the way out
  }
  if ((c >= '0' && c <= '9') || c == '.' || c == '-') {
    if (!tfEditing) { tfEditing = true; tfEditBuf = ""; }
    tfEditBuf += c; lastDrawMs = 0; return;
  }
  if (enter) {
    if (tfEditing) { tfVal[tfSel] = tfEditBuf.toFloat(); tfEditing = false; tfEditBuf = ""; }
    lastDrawMs = 0; return;
  }
}





// Start a sked-proposal send: capture the current satellite, then prompt for a date
// and (on completion) a time, composing "!SAT date time" and transmitting. Reuses the
// SCR_EDIT text-entry system with two chained targets (702 date -> 703 time).
void App::beginSkedSend() {
  SatEntry* a = activeSat();
  if (!a) { setStatus("No satellite selected", 2000); return; }
  strncpy(ssSat, a->name, sizeof(ssSat) - 1); ssSat[sizeof(ssSat) - 1] = 0;
  ssNorad = a->norad;                          // carry the NORAD through the prompts
  ssDate[0] = 0;
  // Prefill the date field with today (UTC) as a convenient starting point.
  editBuf = "";
  if (timeIsSet()) {
    time_t now = nowUtc(); struct tm g; gmtime_r(&now, &g);
    char d[11]; strftime(d, sizeof(d), "%Y-%m-%d", &g); editBuf = d;
  }
  editTarget = 704; editTitle = "Sked date (YYYY-MM-DD)"; screen = SCR_EDIT;
}

// ENTER on a message row: decode its text and open the matching screen. Priority
// when a message carries more than one sigil: sked > position > satellite (a sked
// proposal is the most time-sensitive and actionable).
void App::openDecodedAction(int orderIdx) {
  if (orderIdx < 0 || orderIdx >= msgCount) return;
  int idx = (msgHead - msgCount + orderIdx + MSG_MAX * 2) % MSG_MAX;
  const LoraMsg& m = msgRing[idx];
  MsgDecode d = decodeMsg(m.text);

  if (d.hasSked) {
    // Pre-fill a sked draft from the proposal and drop into the sked editor. Resolve the
    // satellite by NORAD first (name-agnostic) and store THIS station's name for it, so a
    // proposal that used a different display name still lands on the right bird. Fall back
    // to the name from the message when we can't resolve the NORAD locally.
    beginSkedEntry(-1);                    // fresh draft (sets defaults + own call)
    int si = dbResolveSat(db, d.skedSat, d.skedNorad);
    const char* localName = (si >= 0) ? db.at(si).name : d.skedSat;
    strncpy(skedDraft.sat,  localName,  sizeof(skedDraft.sat)  - 1);
    skedDraft.sat[sizeof(skedDraft.sat) - 1] = 0;
    strncpy(skedDraft.date, d.skedDate, sizeof(skedDraft.date) - 1);
    skedDraft.date[sizeof(skedDraft.date) - 1] = 0;
    // start time HH:MM -> HH:MM:00
    snprintf(skedDraft.start, sizeof(skedDraft.start), "%s:00", d.skedTime);
    if (m.from[0]) {
      strncpy(skedDraft.call, m.from, sizeof(skedDraft.call) - 1);
      skedDraft.call[sizeof(skedDraft.call) - 1] = 0;
    }
    setStatus(si >= 0 ? "Sked from message - review & save"
                      : "Sked: sat not in your list - review", 2500);
    return;                                // beginSkedEntry already set screen
  }
  if (d.hasPos) {
    lcLat = d.lat; lcLon = d.lon; lcMsgMs = m.tMs;
    strncpy(lcFrom, m.from[0] ? m.from : "peer", sizeof(lcFrom) - 1);
    lcFrom[sizeof(lcFrom) - 1] = 0;
    screen = SCR_LORACOMPASS; lastDrawMs = 0;
    return;
  }
  if (d.hasSat) {
    strncpy(lsSat, d.sat, sizeof(lsSat) - 1); lsSat[sizeof(lsSat) - 1] = 0;
    lsNorad = d.norad;                     // carry the NORAD for name-agnostic resolution
    screen = SCR_LORASAT; lastDrawMs = 0;
    return;
  }
  setStatus("No @position / #sat / !sked here", 2000);
}

void App::drawMessages() {
  header("Messages");
  msgUnread = 0;            // viewing the list clears the unread badge
  canvas.setTextSize(1);

  if (!cfg.loraEnable) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 44); canvas.print("LoRa messaging is off.");
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(6, 58); canvas.print("Enable it in Settings,");
    canvas.setCursor(6, 70); canvas.print("then set your callsign.");
    footer("` back");
    return;
  }
  if (!loraStarted || !lora.ready()) {
    canvas.setTextColor(CL_ORANGE, CL_BLACK);
    canvas.setCursor(6, 44); canvas.print("Radio not ready.");
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(6, 58); canvas.print("Needs the Cap LoRa + a");
    canvas.setCursor(6, 70); canvas.print("RadioLib build (see docs).");
    footer("r retry   ` back");
    return;
  }

  // Status line: freq / SF / BW + my call.
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(2, 19);
  canvas.printf("%.3fMHz SF%d %ldk  %s",
                cfg.loraFreqKHz / 1000.0, cfg.loraSf, (long)(cfg.loraBwHz / 1000),
                cfg.myCall[0] ? cfg.myCall : "NOCALL");
  canvas.drawLine(0, 28, 240, 28, CL_DGREY);

  // Message list: newest at the bottom, scrollable with ;/. (msgScroll counts
  // back from newest). Each message is one or two rows -- a message whose text
  // doesn't fit on the first line (after the "who:" prefix) wraps the remainder
  // onto a second, full-width line rather than being truncated.
  const int ROWS = 8, rowY0 = 31, rowH = 10;   // ROWS must match the drawable height below
                                               // (rowY0 + ROWS*rowH <= yMax); if they disagree,
                                               // the window includes rows the render loop clips
                                               // and messages vanish as you scroll.
  const int LINE_CH = 39;                       // chars per line at size-1 font (240px)
  // Build a display order: oldest..newest indices.
  int order[MSG_MAX]; int on = 0;
  for (int i = 0; i < msgCount; ++i) {
    int idx = (msgHead - msgCount + i + MSG_MAX * 2) % MSG_MAX;
    order[on++] = idx;
  }
  if (on == 0) {
    // No messages yet -- still expose the send keys (they compose from your own
    // position / selected satellite, so they work with an empty list).
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(6, 60); canvas.print("No messages yet.");
    canvas.setCursor(6, 74); canvas.print("p=pos  s=sat  k=sked  n=write");
#if CARDSAT_HAS_LORARX
    footer("p/s/k send  o who  m RX  ` bk");
#else
    footer("p/s/k send  n write  o who  ` bk");
#endif
    return;
  }
  // Row count for a message: 1, or 2 if the text overflows the first line.
  auto rowsFor = [&](const LoraMsg& m) -> int {
    int prefixCh = (m.mine ? 1 : 0) + (int)strlen(m.mine ? "me" : m.from) + 1; // ">"/"" + name + ":"
    int firstMax = LINE_CH - prefixCh - 1;       // -1 for the leading space
    if (firstMax < 1) firstMax = 1;
    return ((int)strlen(m.text) > firstMax) ? 2 : 1;
  };
  // Bottom item shown is (newest - msgScroll). Walk BACKWARD from there summing
  // row heights until the available ROWS are filled; that gives the topmost
  // message to draw. Variable-height rows mean we anchor on the bottom and derive
  // the top (so wrapped messages don't make the window shrink as you scroll).
  int maxScroll = on - 1;                         // can scroll until oldest is the bottom item
  if (msgScroll > maxScroll) msgScroll = maxScroll;
  if (msgScroll < 0) msgScroll = 0;
  int bottom = (on - 1) - msgScroll;              // index in order[] of the bottom message
  if (bottom < 0) bottom = 0;
  int top = bottom, used = 0;
  for (int r = bottom; r >= 0; --r) {
    int h = rowsFor(msgRing[order[r]]);
    if (used + h > ROWS) break;                   // next message wouldn't fully fit
    used += h; top = r;
  }
  // Bottom-anchor the list (chat style): the newest visible message always sits on the
  // last drawable line, just above the hint; any empty space appears at the TOP. We start
  // drawing at yMax minus the exact height the visible messages occupy (`used` rows). When
  // the window is full this equals rowY0 (whole area used); when only a few messages exist
  // it starts lower, so the newest never floats up into the middle of the screen.
  const int yMax = rowY0 + ROWS * rowH;         // == 111; below this: hint (112), footer (127)
  int y = yMax - used * rowH;                    // top of the first (oldest visible) row
  if (y < rowY0) y = rowY0;                       // clamp (shouldn't trigger: used <= ROWS)
  for (int r = top; r <= bottom && y < yMax; ++r) {
    LoraMsg& m = msgRing[order[r]];
    bool selected = (r == bottom);                // bottom-anchored row is the selection
    const char* who = m.mine ? "me" : m.from;
    int prefixCh = (m.mine ? 1 : 0) + (int)strlen(who) + 1;
    int firstMax = LINE_CH - prefixCh - 1;        // text chars that fit on line 1
    if (firstMax < 1) firstMax = 1;
    int len = (int)strlen(m.text);
    int rowLines = (len > firstMax) ? 2 : 1;
    // Highlight the selected message with a subtle background bar spanning its lines,
    // so scrolling moves a visible cursor rather than blanking anything.
    if (selected) canvas.fillRect(0, y - 1, 240, rowH * rowLines, CL_DGREY);
    uint8_t nameCol = m.mine ? CL_CYAN : CL_GREEN;
    uint8_t textCol = CL_WHITE;
    // Line 1: "who:" prefix + the first slice of text.
    canvas.setTextColor(nameCol, selected ? CL_DGREY : CL_BLACK);
    canvas.setCursor(2, y);
    canvas.printf("%s%s:", m.mine ? ">" : "", who);
    canvas.setTextColor(textCol, selected ? CL_DGREY : CL_BLACK);
    canvas.printf(" %.*s", firstMax, m.text);
    y += rowH;
    // Line 2 (only if the text overflowed line 1): the remainder, full width,
    // indented two chars so it reads as a continuation of the message above.
    if (len > firstMax && y < yMax) {
      int contMax = LINE_CH - 2;                  // continuation line width (2-char indent)
      canvas.setTextColor(textCol, selected ? CL_DGREY : CL_BLACK);
      canvas.setCursor(2, y);
      canvas.printf("  %.*s", contMax, m.text + firstMax);
      y += rowH;
    }
  }

  // Decoded-action hint for the SELECTED (bottom-anchored) message: if its text
  // carries an @position / #sat / !sked sigil, show what ENTER will open. Placed at
  // y=112, above the footer (y=127) and below the message area (yMax=108) so nothing
  // overlaps.
  int selIdx = (msgCount > 0) ? (msgCount - 1 - msgScroll) : -1;
  if (selIdx >= 0) {
    int ri = (msgHead - msgCount + selIdx + MSG_MAX * 2) % MSG_MAX;
    MsgDecode d = decodeMsg(msgRing[ri].text);
    if (d.hasSked || d.hasPos || d.hasSat) {
      canvas.setTextColor(CL_YELLOW, CL_BLACK);
      canvas.setCursor(2, 112);
      if (d.hasSked)      canvas.printf("ENT: sked %s %s %s", d.skedSat, d.skedDate, d.skedTime);
      else if (d.hasPos)  canvas.printf("ENT: bearing to @%.3f,%.3f", d.lat, d.lon);
      else                canvas.printf("ENT: satellite %s", d.sat);
    }
  }

#if CARDSAT_HAS_LORARX
  footer("p/s/k  ENT open  o who  m RX  ` bk");
#else
  footer("p/s/k  ENT open  o who  ` back");
#endif
}

void App::keyMessages(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_HOME; lastDrawMs = 0; return; }
  if (!cfg.loraEnable) return;
  if ((!loraStarted || !lora.ready())) {
    if (c == 'r') { loraStart(); lastDrawMs = 0; }
    return;
  }
#if CARDSAT_HAS_LORARX
  // 'm' opens the general LoRa RX / hex Monitor (radio is up here). It takes over
  // the shared radio; receive-only, no satellite infrastructure.
  if (c == 'm') {
    if (lorarx.enter(this)) { screen = SCR_LORARX; lastDrawMs = 0; }
    return;
  }
#endif
  if (c == 'n') {                          // compose a new message (reuse SCR_EDIT)
    editTarget = 700; editTitle = "Message"; editBuf = ""; screen = SCR_EDIT; return;
  }
  // Send triggers -- compose a sigil message for the CURRENT satellite / my position
  // and transmit via the normal path (the frame format is unchanged; these just build
  // recognizable text that a receiver's decodeMsg() picks up).
  if (c == 'p') {                          // @lat,lon  -- my position (also a presence ping)
    sendMyPosition();
    lastDrawMs = 0; return;
  }
  if (c == 'o') {                          // open the station roster (who's on / where)
    rosterSel = 0; screen = SCR_LORAROSTER; lastDrawMs = 0; return;
  }
  if (c == 's') {                          // #NAME/NORAD  -- current satellite
    SatEntry* a = activeSat();
    if (!a) { setStatus("No satellite selected", 2000); return; }
    char msg[MSG_TEXT_MAX + 1];
    // Include the NORAD catalog number after the name so the far end can resolve the
    // satellite even if its database uses a different display name (e.g. RS95S vs
    // QMR-KWT2). The name stays first so it remains human-readable and older receivers
    // still see it. Omit "/0" if the NORAD is unknown.
    if (a->norad) snprintf(msg, sizeof(msg), "#%s/%lu", a->name, (unsigned long)a->norad);
    else          snprintf(msg, sizeof(msg), "#%s", a->name);
    loraSendCurrent(msg); lastDrawMs = 0; return;
  }
  if (c == 'k') {                          // !SAT date time  -- sked proposal (prompts)
    SatEntry* a = activeSat();
    if (!a) { setStatus("No satellite selected", 2000); return; }
    beginSkedSend();                       // dedicated date -> time prompt, then auto-send
    return;
  }
  // ENTER acts on the SELECTED message (the bottom-anchored one; scroll to choose):
  // decode its @position / #sat / !sked and open the matching screen.
  if (enter) {
    int sel = (msgCount > 0) ? (msgCount - 1 - msgScroll) : -1;
    if (sel >= 0) openDecodedAction(sel);
    return;
  }
  // Scroll counts back from the newest; you can scroll until the oldest message
  // is the bottom item. (Row heights vary with wrapping, so the render derives
  // the visible window from this bottom anchor.) The bottom message is "selected".
  int maxScroll = (msgCount > 0) ? msgCount - 1 : 0;
  if (isUp(c))   { if (msgScroll < maxScroll) msgScroll++; lastDrawMs = 0; }
  if (isDown(c)) { if (msgScroll > 0) msgScroll--; lastDrawMs = 0; }
}

// ===========================================================================
//  Space weather summary (off Home). Shows the solar 10.7 cm flux and the
//  planetary Kp index fetched from NOAA SWPC (with GP updates), plus a plain
//  reading of what they mean for HF and satellite operation. r = refresh.
// ===========================================================================
void App::drawSpaceWx() {
  header("Space Wx");
  canvas.setTextSize(1);
  int y = 20; const int LH = 11;
  auto row = [&](const char* k, const String& v, uint16_t col) {
    canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.setCursor(6, y);  canvas.print(k);
    canvas.setTextColor(col, CL_BLACK);      canvas.setCursor(104, y); canvas.print(v);
    y += LH;
  };
  if (spaceF107 <= 0 && spaceKp < 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 56);
    canvas.print("No data yet.");
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(6, 70);
    canvas.print("Update GP or press r (WiFi).");
    footer("r refresh  ` back");
    return;
  }
  // --- Solar 10.7 cm flux ---
  if (spaceF107 > 0) {
    const char* sLbl; uint16_t sCol;
    if      (spaceF107 < 90)  { sLbl = "low";       sCol = CL_GREY; }
    else if (spaceF107 < 120) { sLbl = "moderate";  sCol = CL_WHITE; }
    else if (spaceF107 < 160) { sLbl = "good";      sCol = CL_GREEN; }
    else                      { sLbl = "very high"; sCol = CL_YELLOW; }
    row("Solar flux", String(spaceF107, 0) + " sfu", sCol);
    row("  (F10.7)", String(sLbl), sCol);
  } else {
    row("Solar flux", "--", CL_GREY);
  }
  // --- Planetary Kp (geomagnetic) ---
  if (spaceKp >= 0) {
    const char* kLbl; uint16_t kCol;
    if      (spaceKp < 4) { kLbl = "quiet";        kCol = CL_GREEN; }
    else if (spaceKp < 5) { kLbl = "unsettled";    kCol = CL_WHITE; }
    else if (spaceKp < 6) { kLbl = "minor storm";  kCol = CL_YELLOW; }
    else if (spaceKp < 7) { kLbl = "mod. storm";   kCol = CL_YELLOW; }
    else                  { kLbl = "major storm";  kCol = CL_RED; }
    row("Kp index", String(spaceKp, 1) + "  " + kLbl, kCol);
  } else {
    row("Kp index", "--", CL_GREY);
  }
  // --- Running A index (daily-equivalent geomagnetic amplitude), if available ---
  if (spaceA >= 0) {
    const char* aLbl; uint16_t aCol;
    if      (spaceA < 8)  { aLbl = "quiet";     aCol = CL_GREEN; }
    else if (spaceA < 16) { aLbl = "unsettled"; aCol = CL_WHITE; }
    else if (spaceA < 30) { aLbl = "active";    aCol = CL_YELLOW; }
    else                  { aLbl = "storm";     aCol = CL_RED; }
    row("A index", String(spaceA, 0) + "  " + aLbl, aCol);
  }
  // --- Aurora likelihood (from Kp): a quick space-weather context line ---
  if (spaceKp >= 0) {
    const char* auLbl; uint16_t auCol;
    if      (spaceKp < 4) { auLbl = "unlikely";       auCol = CL_GREY; }
    else if (spaceKp < 5) { auLbl = "possible high lat"; auCol = CL_WHITE; }
    else if (spaceKp < 7) { auLbl = "likely high lat"; auCol = CL_YELLOW; }
    else                  { auLbl = "likely mid lat";  auCol = CL_RED; }
    row("Aurora", String(auLbl), auCol);
  }
  y += 3;
  // --- Plain-language operating note ---
  canvas.setTextColor(CL_CYAN, CL_BLACK); canvas.setCursor(6, y); y += LH;
  canvas.print("Operating outlook:");
  canvas.setTextColor(CL_WHITE, CL_BLACK);
  const char* note;
  if (spaceKp >= 5)
    note = "Geomag storm: aurora & VHF\nflutter likely; HF paths\ndisturbed at high lat.";
  else if (spaceF107 >= 120 && spaceKp >= 0 && spaceKp < 4)
    note = "Strong sun, quiet field:\ngood HF & stable sat passes.";
  else if (spaceF107 > 0 && spaceF107 < 90)
    note = "Weak sun: lower HF MUF;\nsat passes unaffected.";
  else
    note = "Settled conditions; normal\nHF and satellite operation.";
  { int ly = y; const char* p = note;
    while (*p) { const char* nl = strchr(p, '\n'); int len = nl ? (int)(nl - p) : (int)strlen(p);
      String line(""); for (int i = 0; i < len; ++i) line += p[i];
      canvas.setCursor(6, ly); canvas.print(line); ly += 10;
      if (!nl) break; p = nl + 1; }
  }
  // freshness
  if (spaceWxEpoch) {
    long ageH = (long)((nowUtc() - spaceWxEpoch) / 3600);
    canvas.setTextColor(CL_GREY, CL_BLACK);
    String age = (ageH < 1) ? String("<1h old")
               : (ageH < 48) ? (String(ageH) + "h old")
               : (String(ageH / 24) + "d old");
    canvas.setCursor(240 - 2 - (int)age.length() * 6, 116); canvas.print(age);
  }
  footer("p propagation  r refresh  ` back");
}

void App::keySpaceWx(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { screen = SCR_HOME; lastDrawMs = 0; return; }
  if (c == 'r') { spaceWxEnter(); return; }   // same show-cache + fetch + result flow
  if (c == 'p') { screen = SCR_PROP; lastDrawMs = 0; return; }   // HF/6m propagation guidance
}

// ===========================================================================
//  HF / 6m propagation guidance (SCR_PROP), reached with 'p' from Space Wx.
//  Translates the F10.7 solar flux and Kp index (already fetched for Space Wx)
//  into rule-of-thumb band-opening, geomagnetic, aurora, and D-layer absorption
//  guidance. These are CLIMATOLOGICAL heuristics, not a real-time propagation
//  model -- the screen says so -- but they turn two raw indices into the kind of
//  "what's likely open" read an HF/6m/VHF operator wants. No new data source.
// ===========================================================================
void App::drawProp() {
  header("HF / 6m propagation");
  canvas.setTextSize(1);
  float sfi = spaceF107, kp = spaceKp;
  if (sfi <= 0 && kp < 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK);
    canvas.setCursor(6, 44); canvas.print("No space-wx data yet.");
    canvas.setTextColor(CL_GREY, CL_BLACK);
    canvas.setCursor(6, 58); canvas.print("Update GP or fetch on the");
    canvas.setCursor(6, 70); canvas.print("Space Wx screen (WiFi).");
    footer("` back");
    return;
  }
  int y = 20; const int LH = 9;
  auto row = [&](const char* k, const String& v, uint16_t vc) {
    canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.setCursor(2, y);  canvas.print(k);
    canvas.setTextColor(vc, CL_BLACK);       canvas.setCursor(78, y); canvas.print(v);
    y += LH;
  };

  // The two indices, up top, with a delta vs the previous sample when one exists
  // (e.g. "142 sfu +5" = rising flux). Deltas below 1 sfu / 0.3 Kp are noise-hidden.
  String fx = (sfi > 0 ? String(sfi, 0) + " sfu" : String("--"));
  if (sfi > 0 && spacePrevEpoch > 0 && spacePrevF107 > 0) {
    int d = (int)lround(sfi - spacePrevF107);
    if (d >= 1 || d <= -1) fx += " " + String(d >= 0 ? "+" : "") + String(d);
  }
  row("Solar flux", fx,
      sfi >= 120 ? CL_GREEN : (sfi >= 90 ? CL_WHITE : (sfi >= 70 ? CL_YELLOW : CL_ORANGE)));
  String kx = (kp >= 0 ? String(kp, 1) : String("--"));
  if (kp >= 0 && spacePrevEpoch > 0 && spacePrevKp >= 0) {
    float d = kp - spacePrevKp;
    if (d >= 0.3f || d <= -0.3f) kx += " " + String(d >= 0 ? "+" : "") + String(d, 1);
  }
  row("Kp index", kx,
      kp < 0 ? CL_GREY : (kp < 4 ? CL_GREEN : (kp < 5 ? CL_WHITE : (kp < 7 ? CL_YELLOW : CL_RED))));

  // HF band summary from solar flux (higher flux -> higher MUF -> high bands open).
  if (sfi > 0) {
    const char* hf; uint16_t hc;
    if      (sfi >= 150) { hf = "10/12/15m wide open (day)"; hc = CL_GREEN; }
    else if (sfi >= 120) { hf = "10/15m likely open (day)";  hc = CL_GREEN; }
    else if (sfi >= 90)  { hf = "15/17/20m workable";        hc = CL_WHITE; }
    else if (sfi >= 70)  { hf = "20/40m mainstay";           hc = CL_YELLOW; }
    else                 { hf = "40/80m only, highs weak";   hc = CL_ORANGE; }
    row("HF bands", hf, hc);
    // Per-band daytime openings (rough MUF tendency).
    auto st = [](float f, float openT, float margT) {
      return (f >= openT) ? "open" : (f >= margT ? "marg" : "shut"); };
    row("10/15/20m", String(st(sfi,120,100)) + " / " + st(sfi,100,85) + " / " + st(sfi,75,60),
        CL_WHITE);
  }

  // Geomagnetic effect on HF from Kp.
  if (kp >= 0) {
    const char* g; uint16_t gc;
    if      (kp >= 7) { g = "severe storm, HF badly hit"; gc = CL_RED; }
    else if (kp >= 5) { g = "storm, HF degraded";         gc = CL_ORANGE; }
    else if (kp >= 4) { g = "unsettled, some fading";     gc = CL_YELLOW; }
    else              { g = "quiet, stable HF";           gc = CL_GREEN; }
    row("Geomag", g, gc);
    // Aurora / VHF -- the 6m/2m and EME crowd.
    const char* au; uint16_t ac;
    if      (kp >= 6) { au = "likely: 6m/2m, beam N"; ac = CL_GREEN; }
    else if (kp >= 5) { au = "possible, watch 6m";    ac = CL_YELLOW; }
    else              { au = "unlikely";              ac = CL_GREY; }
    row("Aurora VHF", au, ac);
    // Daytime D-layer absorption on the low bands (worse with disturbed field).
    row("Absorption", String(kp >= 5 ? "high" : (kp >= 4 ? "moderate" : "low")) + " (LF/80/40 day)",
        kp >= 5 ? CL_ORANGE : (kp >= 4 ? CL_YELLOW : CL_GREEN));
  }

  // Honest disclaimer: these are heuristics + a reminder that 6m Es is seasonal.
  canvas.setTextColor(CL_MGREY, CL_BLACK);
  canvas.setCursor(2, 116); canvas.print("rule-of-thumb; 6m Es is seasonal");
  footer("r refresh  ` back");
}

void App::keyProp(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { screen = SCR_SPACEWX; lastDrawMs = 0; return; }
  if (c == 'r') {                          // refetch the indices without leaving this screen
    if (!net.connected() && !connectWifiCfg()) { setStatus("WiFi failed (check SSID/pass)"); lastDrawMs = 0; return; }
    setStatus("Updating Space Wx..."); draw();
    fetchSpaceWeather();
    lastDrawMs = 0; return;
  }
}

// ===========================================================================
//  Station readiness (SCR_READY), reached with 'r' from About: one glanceable
//  green/red checklist of the state a working pass depends on -- clock, location,
//  GP data and age, WiFi, radio and rotator config, SD card, callsign, battery.
//  Doubles as first-hour onboarding and a pre-pass field check. Read-only.
// ===========================================================================
void App::drawReady() {
  header("Station readiness");
  canvas.setTextSize(1);
  int y = 20; const int LH = 10;
  auto row = [&](const char* k, const String& v, uint16_t vc) {
    canvas.setTextColor(CL_GREY, CL_BLACK);  canvas.setCursor(2, y);  canvas.print(k);
    canvas.setTextColor(vc, CL_BLACK);       canvas.setCursor(86, y); canvas.print(v);
    y += LH;
  };
  // Clock
  row("Clock", timeIsSet() ? "UTC set" : "NOT SET (GPS/NTP)", timeIsSet() ? CL_GREEN : CL_RED);
  // Location
  bool locOk = (cfg.lat != 0.0 || cfg.lon != 0.0);
  row("Location", locOk ? (String(cfg.lat, 2) + ", " + String(cfg.lon, 2)) : String("NOT SET"),
      locOk ? CL_GREEN : CL_RED);
  // GP data + newest element age
  int nSat = db.count();
  if (nSat > 0 && timeIsSet()) {
    double newest = 0;
    for (int i2 = 0; i2 < nSat; ++i2) if (db.at(i2).epochUnix > newest) newest = db.at(i2).epochUnix;
    double ageD = (nowUtc() - newest) / 86400.0;
    row("GP data", String(nSat) + " sats, " + String(ageD, 1) + "d old",
        ageD < 3 ? CL_GREEN : (ageD < 14 ? CL_YELLOW : CL_ORANGE));
  } else {
    row("GP data", nSat > 0 ? String(nSat) + " sats" : String("NONE - run Update"),
        nSat > 0 ? CL_YELLOW : CL_RED);
  }
  // WiFi
  row("WiFi", cfg.ssid[0] ? (net.connected() ? String(cfg.ssid) + " (up)" : String(cfg.ssid))
                          : String("NOT SET"),
      cfg.ssid[0] ? (net.connected() ? CL_GREEN : CL_WHITE) : CL_YELLOW);
  // Radio + rotator (informational: both defaults are valid configurations)
  row("Radio CAT", cfg.catType == CAT_WIRED ? "CI-V wired" : "network (LAN)", CL_WHITE);
  row("Rotator", cfg.rotType == ROT_GS232 ? "GS-232" : "other/rotctld", CL_WHITE);
  // SD (voice memos)
  row("SD card", Store::onSD() ? "present" : "none (memos off)",
      Store::onSD() ? CL_GREEN : CL_GREY);
  // Callsign
  row("Callsign", cfg.myCall[0] ? String(cfg.myCall) : String("NOT SET"),
      cfg.myCall[0] ? CL_GREEN : CL_YELLOW);
  // Battery
  int lvl = M5.Power.getBatteryLevel();
  row("Battery", lvl >= 0 ? String(lvl) + "%" : String("--"),
      lvl < 0 ? CL_GREY : (lvl > 40 ? CL_GREEN : (lvl > 20 ? CL_YELLOW : CL_RED)));
  footer("` back");
}

void App::keyReady(char c, bool enter, bool back) {
  (void)c; (void)enter;
  if (isBack(c, back)) { screen = SCR_ABOUT; lastDrawMs = 0; return; }
}

// ===========================================================================
//  EME 30-day planner (SCR_EMEPLAN), 'p' from the EME screen. One row per day:
//  the Moon's declination at 12:00 UTC and the path degradation vs perigee.
//  A star marks the classic northern-hemisphere "good EME day" heuristic --
//  high declination (long, high Moon tracks) AND a near-perigee Moon (low path
//  loss). Southern-hemisphere operators want negative declination instead; the
//  raw numbers are shown so either reading works.
// ===========================================================================
void App::drawEmePlan() {
  header("EME 30-day plan");
  canvas.setTextSize(1);
  canvas.setTextColor(CL_GREY, CL_BLACK);
  canvas.setCursor(4, 18); canvas.print("Date   Dec     Degr    (12:00 UTC)");
  const int rows = 9, LH = 10;
  if (emePlanScroll > emePlanN - rows) emePlanScroll = emePlanN - rows;
  if (emePlanScroll < 0) emePlanScroll = 0;
  for (int vi = 0; vi < rows && emePlanScroll + vi < emePlanN; ++vi) {
    int d = emePlanScroll + vi;
    time_t tt = emePlanT0 + (time_t)d * 86400;
    struct tm tmv; gmtime_r(&tt, &tmv);
    bool good = (emePlanDec[d] >= 18.0f && emePlanDeg[d] <= 1.0f);
    int y = 30 + vi * LH;
    canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(4, y);
    canvas.printf("%02d-%02d", tmv.tm_mon + 1, tmv.tm_mday);
    canvas.setTextColor(emePlanDec[d] >= 18 ? CL_GREEN
                       : (emePlanDec[d] <= -18 ? CL_CYAN : CL_WHITE), CL_BLACK);
    canvas.setCursor(46, y); canvas.printf("%+5.1f", emePlanDec[d]);
    canvas.setTextColor(emePlanDeg[d] <= 1.0f ? CL_GREEN
                       : (emePlanDeg[d] <= 1.7f ? CL_WHITE : CL_ORANGE), CL_BLACK);
    canvas.setCursor(96, y); canvas.printf("%4.1f dB", emePlanDeg[d]);
    if (good) { canvas.setTextColor(CL_GREEN, CL_BLACK);
                canvas.setCursor(156, y); canvas.print("* good (NH)"); }
  }
  footer(";/. scroll  ` back");
}

void App::keyEmePlan(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { screen = SCR_EME; lastDrawMs = 0; return; }
  if (isUp(c))   { if (--emePlanScroll < 0) emePlanScroll = 0; lastDrawMs = 0; return; }
  if (isDown(c)) { ++emePlanScroll; lastDrawMs = 0; return; }
  if (c == '{')  { emePlanScroll -= 9; if (emePlanScroll < 0) emePlanScroll = 0; lastDrawMs = 0; return; }
  if (c == '}')  { emePlanScroll += 9; lastDrawMs = 0; return; }
}



// ===========================================================================
//  Terrestrial weather screen (off Space Wx, key 'w'). Shows current conditions
//  and a short forecast for the operating site, from Open-Meteo. Refreshes on
//  entry when WiFi is up; otherwise shows the cached values with their age.
// ===========================================================================
void App::drawWeather() {
  header("Weather");
  canvas.setTextSize(1);

  if (wxEpoch == 0) {                       // never fetched and nothing cached
    canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 50);
    canvas.print("No weather data yet.");
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(6, 66);
    canvas.print("Press r on WiFi, or run");
    canvas.setCursor(6, 76); canvas.print("Update. Needs a location set.");
    footer("r refresh  ` back");
    return;
  }

  // --- current conditions (convert cached values to the selected units) ---
  int y = 20;
  float tNow = wxConvTemp(wxTempNow, wxCachedUnits, cfg.wxUnits);
  float windNow = wxConvWind(wxWindNow, wxCachedUnits, cfg.wxUnits);
  if (tNow > -900) {
    canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setTextSize(2);
    canvas.setCursor(6, y);
    canvas.printf("%d%s", (int)lround(tNow), wxTempUnit());
    canvas.setTextSize(1);
    // condition text to the right of the big temperature
    canvas.setTextColor(CL_CYAN, CL_BLACK);
    canvas.setCursor(96, y + 3);
    canvas.print(wxCodeText(wxCodeNow));
    y += 20;
  }
  canvas.setTextColor(CL_GREY, CL_BLACK);
  if (windNow > -900) {
    canvas.setCursor(6, y);
    canvas.printf("Wind %d %s %s", (int)lround(windNow), wxWindUnit(),
                  windDirName(wxWindDirNow));
  }
  if (wxHumidNow >= 0) {
    canvas.setCursor(150, y);
    canvas.printf("RH %d%%", wxHumidNow);
  }
  y += 14;

  // --- forecast: one row per day ---
  static const char* DOW[] = { "Sun","Mon","Tue","Wed","Thu","Fri","Sat" };
  for (int i = 0; i < wxDayCount; ++i) {
    // day label: "Today" for i==0, else weekday from the per-day epoch
    String lbl;
    if (i == 0) lbl = "Today";
    else {
      time_t d = (time_t)wxDayEpoch[i];
      struct tm tmv; gmtime_r(&d, &tmv);
      lbl = DOW[tmv.tm_wday % 7];
    }
    canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(6, y);
    canvas.print(lbl);
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(46, y);
    String cond = wxCodeText(wxDayCode[i]);
    if (cond.length() > 12) cond = cond.substring(0, 12);
    canvas.print(cond);
    canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(150, y);
    canvas.printf("%d/%d", (int)lround(wxConvTemp(wxDayHi[i], wxCachedUnits, cfg.wxUnits)),
                           (int)lround(wxConvTemp(wxDayLo[i], wxCachedUnits, cfg.wxUnits)));
    if (wxDayPop[i] > 0) {
      canvas.setTextColor(wxDayPop[i] >= 50 ? CL_CYAN : CL_GREY, CL_BLACK);
      canvas.setCursor(200, y); canvas.printf("%d%%", wxDayPop[i]);
    }
    y += 11;
  }

  // --- freshness + unit cache note ---
  if (wxEpoch) {
    long ageH = (long)((nowUtc() - wxEpoch) / 3600);
    canvas.setTextColor(CL_GREY, CL_BLACK);
    String age = (ageH < 1) ? String("<1h old")
               : (ageH < 48) ? (String(ageH) + "h old")
               : (String(ageH / 24) + "d old");
    canvas.setCursor(240 - 2 - (int)age.length() * 6, 116); canvas.print(age);
  }
  footer("r refresh  ` back");
}

void App::keyWeather(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { screen = SCR_HOME; lastDrawMs = 0; return; }
  if (c == 'r') { weatherEnter(); return; }   // same show-cache + fetch + result flow
}

// ===========================================================================
//  Transponder database browser (off Satellites, key 't'). Lists every
//  transponder/beacon entry for the selected satellite from the on-device
//  catalog (SatNOGS-sourced) in an easy-to-scan up/down/mode/tone layout.
// ===========================================================================
static String txMHz(uint32_t hz) {
  if (hz == 0) return String("-");
  char b[16]; snprintf(b, sizeof(b), "%.4f", hz / 1.0e6); return String(b);
}

void App::drawTxDb() {
  SatEntry* s = activeSat();
  header(s ? (String(s->name) + " TX") : String("Transponders"));
  canvas.setTextSize(1);
  if (!s) { canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 56);
            canvas.print("No satellite."); footer("` back"); return; }
  if (activeTxCount == 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 52);
    canvas.print("No transponders cached.");
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(6, 66);
    canvas.print("Update GP/Freq with WiFi on.");
    footer("` back"); return;
  }
  // Each entry is a 3-line block: name; DOWN + mode; UP + tone/flags.
  const int BLOCK = 3, LH = 10, ROWS = 10;          // 10 text rows in the safe band
  const int perPage = ROWS / BLOCK;                 // 3 entries per page
  if (txDbScroll >= activeTxCount) txDbScroll = 0;
  int y = 19;
  for (int e = txDbScroll; e < activeTxCount && e < txDbScroll + perPage; ++e) {
    const Transponder& t = activeTx[e];
    bool manual = (strncmp(t.desc, "manual", 6) == 0);
    bool sel = (e == txDbSel);
    // line 1: index + description, in cyan (selected entry marked with '>')
    canvas.setTextColor(sel ? CL_GREEN : CL_CYAN, CL_BLACK); canvas.setCursor(4, y);
    { String d = (sel ? ">" : " ") + String(e + 1) + ". " + String(t.desc);
      if (manual) d += " *";
      if (d.length() > 38) d = d.substring(0, 37) + "~";
      canvas.print(d); }
    y += LH;
    // line 2: downlink (range if linear) + mode
    canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(10, y);
    { String dn = "D " + txMHz(t.downlink);
      if (t.downlinkHigh > t.downlink) dn += "-" + txMHz(t.downlinkHigh);
      dn += " " + String(t.mode);
      canvas.print(dn); }
    y += LH;
    // line 3: uplink (range if linear) + tone / invert flag
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(10, y);
    { String up = "U " + txMHz(t.uplink);
      if (t.uplinkHigh > t.uplink) up += "-" + txMHz(t.uplinkHigh);
      if (t.isLinear) up += t.invert ? " inv" : " lin";
      if (t.toneHz > 0) up += " " + String(t.toneHz, 1) + "Hz";
      canvas.print(up); }
    y += LH + 2;                                     // small gap between entries
  }
  // scrollbar hints + count
  canvas.setTextColor(CL_GREY, CL_BLACK);
  if (txDbScroll > 0)                       { canvas.setCursor(232, 19);  canvas.print("^"); }
  if (txDbScroll + perPage < activeTxCount) { canvas.setCursor(232, 112); canvas.print("v"); }
  { bool selManual = (txDbSel < activeTxCount &&
                      strncmp(activeTx[txDbSel].desc, "manual", 6) == 0);
    char cnt[24]; snprintf(cnt, sizeof(cnt), "%d/%d", txDbSel + 1, activeTxCount);
    footer(String("`bk ;/. sel ") + (selManual ? "x del " : "") + cnt + " (* manual)"); }
}

void App::keyTxDb(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { txDbDelArm = false; screen = SCR_SATLIST; lastDrawMs = 0; return; }
  if (c != 'x') txDbDelArm = false;            // any key other than x disarms the delete
  if (activeTxCount == 0) return;
  const int perPage = 3;
  if (isUp(c))   { if (txDbSel > 0) txDbSel--; txDbDelArm = false; }
  if (isDown(c)) { if (txDbSel < activeTxCount - 1) txDbSel++; txDbDelArm = false; }
  // keep the selected entry on-screen (page of `perPage` blocks)
  if (txDbSel < txDbScroll)            txDbScroll = (txDbSel / perPage) * perPage;
  if (txDbSel >= txDbScroll + perPage) txDbScroll = (txDbSel / perPage) * perPage;
  if (c == 'x') {                                  // delete (manual entries only)
    SatEntry* s = activeSat();
    bool isManual = (strncmp(activeTx[txDbSel].desc, "manual", 6) == 0);
    if (!s || !isManual) { setStatus("Only manual entries can be deleted"); return; }
    if (!txDbDelArm) { txDbDelArm = true; setStatus("Press x again to delete"); return; }
    // manual index = count of manual entries before this one
    int mIdx = 0;
    for (int e = 0; e < txDbSel; ++e)
      if (strncmp(activeTx[e].desc, "manual", 6) == 0) mIdx++;
    txDbDelArm = false;
    if (deleteManualTx(s->norad, mIdx)) {
      ensureTransponders(*s);                      // reload the list
      if (txDbSel >= activeTxCount) txDbSel = activeTxCount > 0 ? activeTxCount - 1 : 0;
      onTransponderChanged();
      setStatus("Transponder deleted");
    } else setStatus("Delete failed");
    lastDrawMs = 0; return;
  }
  lastDrawMs = 0;
}

// ===========================================================================
//  QRZ.com callsign lookup (off Home). Uses the QRZ XML subscription service:
//  log in with the user's QRZ credentials to get a session key, then query a
//  callsign. Requires WiFi and a QRZ XML-data subscription. API spec:
//  https://www.qrz.com/page/current_spec.html
// ===========================================================================
static String qrzTag(const String& xml, const char* tag) {
  String open = String("<") + tag + ">";
  String close = String("</") + tag + ">";
  int a = xml.indexOf(open); if (a < 0) return String("");
  a += open.length();
  int b = xml.indexOf(close, a); if (b < 0) return String("");
  return xml.substring(a, b);
}

static String qrzUrlEnc(const String& s) {
  String o; const char* hex = "0123456789ABCDEF";
  for (size_t i = 0; i < s.length(); ++i) {
    char c = s[i];
    if (isalnum((unsigned char)c) || c == '-' || c == '_' || c == '.' || c == '~') o += c;
    else { o += '%'; o += hex[(c >> 4) & 0xF]; o += hex[c & 0xF]; }
  }
  return o;
}

// Perform a lookup. On success fills the qrz* result fields and returns true.
// On failure returns false and sets err to a user-facing message.
bool App::qrzLookup(const String& call, String& err) {
  const char* base = "https://xmldata.qrz.com/xml/current/";
  // 1. Ensure we have a session key (log in if needed).
  if (qrzSessionKey.length() == 0) {
    String url = String(base) + "?username=" + qrzUrlEnc(cfg.qrzUser) +
                 ";password=" + qrzUrlEnc(cfg.qrzPass) + ";agent=CardSat";
    String body;
    if (!net.httpsGet(url, body, 8000)) { err = "QRZ login: no response"; return false; }
    qrzSessionKey = qrzTag(body, "Key");
    if (qrzSessionKey.length() == 0) {
      String e = qrzTag(body, "Error");
      err = e.length() ? e : "QRZ login failed";
      return false;
    }
  }
  // 2. Query the callsign with the session key.
  String url = String(base) + "?s=" + qrzSessionKey + ";callsign=" + qrzUrlEnc(call);
  String body;
  if (!net.httpsGet(url, body, 16000)) { err = "QRZ query: no response"; return false; }
  // If the key expired, the response carries an Error and no Callsign node; retry once.
  if (body.indexOf("<Callsign>") < 0) {
    String e = qrzTag(body, "Error");
    if (e.indexOf("Session") >= 0 || e.indexOf("Timeout") >= 0 || e.indexOf("invalid") >= 0) {
      qrzSessionKey = "";                       // force re-login and retry
      String url2 = String(base) + "?username=" + qrzUrlEnc(cfg.qrzUser) +
                    ";password=" + qrzUrlEnc(cfg.qrzPass) + ";agent=CardSat";
      String lb;
      if (net.httpsGet(url2, lb, 8000)) qrzSessionKey = qrzTag(lb, "Key");
      if (qrzSessionKey.length()) {
        String q2 = String(base) + "?s=" + qrzSessionKey + ";callsign=" + qrzUrlEnc(call);
        net.httpsGet(q2, body, 16000);
      }
    }
    if (body.indexOf("<Callsign>") < 0) {
      err = e.length() ? e : "Not found";
      return false;
    }
  }
  // 3. Parse the fields we display.
  String fn = qrzTag(body, "fname"), ln = qrzTag(body, "name");
  qrzName = (fn + " " + ln); qrzName.trim();
  if (qrzName.length() == 0) qrzName = qrzTag(body, "name_fmt");
  String a1 = qrzTag(body, "addr1"), a2 = qrzTag(body, "addr2"),
         st = qrzTag(body, "state"), zip = qrzTag(body, "zip");
  qrzAddr = a1;
  { String l2 = a2; if (st.length()) l2 += (l2.length() ? ", " : "") + st;
    if (zip.length()) l2 += " " + zip;
    if (l2.length()) qrzAddr += (qrzAddr.length() ? "\n" : "") + l2; }
  qrzCountry = qrzTag(body, "country");
  qrzGrid    = qrzTag(body, "grid");
  qrzClass   = qrzTag(body, "class");
  qrzCall    = qrzTag(body, "call"); if (qrzCall.length() == 0) qrzCall = call;
  qrzCall.toUpperCase();
  return true;
}

// Backfill missing grids for logged QSOs using the QRZ XML interface. Heap-safe by
// design (see docs/design/GAMES_AND_QRZ_GRID_SCOPE.md): the log is streamed line by
// line to a .tmp and renamed over the original (the same safe-rewrite pattern as
// markLogUploaded), so the whole log is never in RAM -- only one PendingQso at a time.
// Each lookup is the existing capped qrzLookup() (8-16 KB response in one reused
// String), and the QRZ session key is cached so N lookups share one login. To bound
// the number of back-to-back TLS handshakes (each has the ~32 KB-contiguous exposure
// documented in STREAMING_TLS.md), a run processes at most FILL_CAP grid-less QSOs;
// re-run to continue. A single lookup failing (bad call, timeout, cold-handshake miss)
// just skips that QSO -- the run keeps going rather than aborting.
void App::fillGridsQrz() {
  clBusy = true; lastDrawMs = 0;
  screen = SCR_LOG;                                  // stay on the Log screen for status
  if (cfg.qrzUser[0] == 0 || cfg.qrzPass[0] == 0) {
    setStatus("Set QRZ user/pass in Settings first"); clBusy = false; lastDrawMs = 0; draw(); return;
  }
  if (!net.connected()) {
    setStatus("Connecting WiFi..."); draw();
    if (!connectWifiCfg()) { setStatus("WiFi failed"); clBusy = false; lastDrawMs = 0; draw(); return; }
  }
  if (!Store::fs().exists(FILE_LOG)) { setStatus("No log yet"); clBusy = false; lastDrawMs = 0; draw(); return; }

  const int FILL_CAP = 20;                           // max lookups per run (bounds handshakes)
  // IMPORTANT: the QRZ lookups (TLS) must run with NO log/temp files open. Two open VFS
  // file handles hold ~4-5 KB of buffers EACH on this port; with both open, free heap
  // fell from ~69 KB to ~59 KB and mbedTLS could no longer place its second ~16 KB
  // content buffer -- every QRZ connect failed with "SSL - Memory allocation failed"
  // while the largest block still read 31732 and sockets were 0/16. So we split the job:
  //   pass 1  -- open log read-only, collect up to FILL_CAP distinct missing callsigns,
  //              then CLOSE the file;
  //   lookups -- resolve those callsigns to grids with NO files open (full heap for TLS);
  //   pass 2  -- open log + temp, stream-rewrite filling grids from the resolved table,
  //              with NO TLS in flight (both-files-open is fine here).
  static char wantCall[FILL_CAP][14];
  static char gotGrid[FILL_CAP][10];
  int nWant = 0, missing = 0;

  // --- pass 1: scan for distinct callsigns missing a grid (file closed at the end) ---
  {
    File in = Store::fs().open(FILE_LOG, "r");
    if (!in) { setStatus("Log open failed"); clBusy = false; lastDrawMs = 0; draw(); return; }
    while (in.available()) {
      String t = in.readStringUntil('\n'); t.trim();
      if (!t.length() || t.startsWith("utc,")) continue;
      PendingQso q;
      if (!parseQsoCsv(t, q)) continue;
      if (q.grid[0] != 0 || q.call[0] == 0) continue;   // already has a grid / no call
      missing++;
      // distinct-callsign check (case-insensitive) against what we've already queued
      bool seen = false;
      for (int i = 0; i < nWant; ++i) if (strcasecmp(wantCall[i], q.call) == 0) { seen = true; break; }
      if (!seen && nWant < FILL_CAP) {
        strncpy(wantCall[nWant], q.call, 13); wantCall[nWant][13] = 0;
        gotGrid[nWant][0] = 0;
        nWant++;
      }
    }
    in.close();
  }

  if (nWant == 0) {
    setStatus(missing ? "No lookups needed" : "All QSOs already have grids");
    clBusy = false; lastDrawMs = 0; draw(); return;
  }

  // --- lookups: resolve each distinct callsign to a grid, NO files open ---
  int filled = 0, tried = 0;
  for (int i = 0; i < nWant; ++i) {
    setStatus(String("QRZ ") + wantCall[i] + " (" + String(i + 1) + "/" +
              String(nWant) + ")..."); draw();
    String err;
    bool ok = qrzLookup(wantCall[i], err);            // sets qrzGrid on success; reuses session key
    tried++;
    if (ok && qrzGrid.length() >= 4) {
      strncpy(gotGrid[i], qrzGrid.c_str(), 9); gotGrid[i][9] = 0;
    }
  }

  // --- pass 2: stream-rewrite the log, filling grids from the resolved table (no TLS) ---
  String tmp = String(FILE_LOG) + ".gfill";
  File in = Store::fs().open(FILE_LOG, "r");
  File out = Store::fs().open(tmp.c_str(), "w");
  if (!in || !out) {
    if (in) in.close(); if (out) out.close();
    setStatus("Rewrite failed"); clBusy = false; lastDrawMs = 0; draw(); return;
  }
  while (in.available()) {
    String t = in.readStringUntil('\n'); t.trim();
    if (!t.length()) continue;
    if (t.startsWith("utc,")) { out.println(t); continue; }
    PendingQso q;
    if (!parseQsoCsv(t, q)) { out.println(t); continue; }
    if (q.grid[0] == 0 && q.call[0] != 0) {
      for (int i = 0; i < nWant; ++i) {
        if (gotGrid[i][0] && strcasecmp(wantCall[i], q.call) == 0) {
          strncpy(q.grid, gotGrid[i], sizeof(q.grid) - 1); q.grid[sizeof(q.grid) - 1] = 0;
          filled++;
          break;
        }
      }
    }
    writeQsoCsv(out, q);
  }
  in.close(); out.close();

  // Swap the rewritten log in only if we actually opened/wrote it fully.
  Store::fs().remove(FILE_LOG);
  Store::fs().rename(tmp.c_str(), FILE_LOG);

  String msg;
  if (filled == 0)         msg = "No grids found (tried " + String(tried) + ")";
  else                     msg = "Filled " + String(filled) + " of " + String(missing) + " grid(s)";
  if (missing > nWant)     msg += "; re-run for more";
  setStatus(msg);
  clBusy = false; lastDrawMs = 0; draw();
}

void App::drawQrz() {
  header("QRZ Lookup");
  canvas.setTextSize(1);
  // No WiFi: just say so.
  if (!net.connected()) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 50);
    canvas.print("WiFi not connected.");
    canvas.setTextColor(CL_GREY, CL_BLACK); canvas.setCursor(6, 66);
    canvas.print("Connect WiFi (Update or");
    canvas.setCursor(6, 76); canvas.print("Settings) and try again.");
    footer("` back");
    return;
  }
  // No credentials: explain the subscription requirement.
  if (cfg.qrzUser[0] == 0 || cfg.qrzPass[0] == 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 40);
    canvas.print("QRZ credentials needed.");
    canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(6, 58);
    canvas.print("Requires a QRZ XML-data");
    canvas.setCursor(6, 68); canvas.print("subscription. Enter your QRZ");
    canvas.setCursor(6, 78); canvas.print("username & password in");
    canvas.setCursor(6, 88); canvas.print("Settings > Network / data.");
    footer("` back");
    return;
  }
  // Result, or a prompt to enter a callsign.
  if (!qrzHaveResult) {
    canvas.setTextColor(CL_WHITE, CL_BLACK); canvas.setCursor(6, 50);
    canvas.print("Press ENTER to enter a");
    canvas.setCursor(6, 60); canvas.print("callsign to look up.");
    footer("ENTER callsign   ` back");
    return;
  }
  int y = 20;
  canvas.setTextColor(CL_CYAN, CL_BLACK); canvas.setCursor(6, y);
  canvas.print(qrzCall); y += 12;
  auto line = [&](const String& s, uint16_t col) {
    if (s.length() == 0) return;
    canvas.setTextColor(col, CL_BLACK); canvas.setCursor(6, y);
    String t = s; if (t.length() > 38) t = t.substring(0, 37) + "~";
    canvas.print(t); y += 10;
  };
  line(qrzName, CL_WHITE);
  // address may contain a newline (two lines)
  { String a = qrzAddr; int nl = a.indexOf('\n');
    if (nl >= 0) { line(a.substring(0, nl), CL_WHITE); line(a.substring(nl + 1), CL_WHITE); }
    else line(a, CL_WHITE); }
  line(qrzCountry, CL_GREY);
  { String extra; if (qrzGrid.length()) extra = "Grid " + qrzGrid;
    if (qrzClass.length()) extra += (extra.length() ? "   " : "") + String("Class ") + qrzClass;
    line(extra, CL_GREEN); }
  footer("ENTER new   ` back");
}

void App::keyQrz(char c, bool enter, bool back) {
  if (isBack(c, back)) { screen = SCR_HOME; lastDrawMs = 0; return; }
  if (!net.connected()) return;
  if (cfg.qrzUser[0] == 0 || cfg.qrzPass[0] == 0) return;
  if (enter) {                                  // open the text editor for a callsign
    editTarget = 216; editTitle = "Callsign to look up";
    editBuf = ""; screen = SCR_EDIT; lastDrawMs = 0; return;
  }
}

// ===========================================================================
//  Workable grid squares: 4-char Maidenhead grids under the satellite footprint.
//  Off Passes (union over the selected pass) and off Track (live "now"). The
//  footprint half-angle is acos(Re/(Re+h)); a grid counts if its centre is
//  within that great-circle radius of the sub-point. A per-grid bitset is used
//  so it handles any altitude (whole-Earth = 32400 grids) with no cap.
// ===========================================================================
// 4-char Maidenhead <-> packed index 0..32399. Index order matches the
// alphabetical grid string, so iterating set bits yields sorted output.
static inline int gridIdx(double lat, double lon) {
  while (lon < -180) lon += 360; while (lon >= 180) lon -= 360;
  if (lat < -90) lat = -90; if (lat > 89.9999) lat = 89.9999;
  double L = lon + 180.0, B = lat + 90.0;
  int fLon = (int)(L / 20.0), fLat = (int)(B / 10.0);
  int sLon = (int)((L - fLon * 20) / 2.0), sLat = (int)(B - fLat * 10);
  return ((fLon * 18 + fLat) * 10 + sLon) * 10 + sLat;     // 0..32399
}
static void gridStr(int idx, char* out) {
  int sLat = idx % 10; idx /= 10; int sLon = idx % 10; idx /= 10;
  int fLat = idx % 18; idx /= 18; int fLon = idx;
  out[0] = 'A' + fLon; out[1] = 'A' + fLat;
  out[2] = '0' + sLon; out[3] = '0' + sLat; out[4] = 0;
}

// True if grid string g (4 chars) starts with the prefix filter f (0-4 chars).
// f is assumed already upper-cased (the grid-entry capitalization rule); an empty
// filter matches everything. Used to narrow the workable-grids display.
static bool gridMatchPrefix(const char* g, const char* f) {
  for (int i = 0; f[i]; ++i) if (g[i] != f[i]) return false;
  return true;
}

void App::addFootprintGrids(double subLat, double subLon, double altKm) {
  const double D2R = 0.017453292519943295, R2D = 57.29577951308232, Re = 6371.0;
  if (altKm < 1) return;
  double coslam = Re / (Re + altKm);                      // = cos(footprint half-angle)
  double lamDeg = acos(coslam) * R2D;
  double sinSub = sin(subLat * D2R), cosSub = cos(subLat * D2R);
  int latLo = (int)floor(subLat - lamDeg), latHi = (int)ceil(subLat + lamDeg);
  for (int la = latLo; la <= latHi; ++la) {
    if (la < -90 || la >= 90) continue;
    double clat = la + 0.5, clatR = clat * D2R;
    double cl = cos(clatR); if (cl < 0.15) cl = 0.15;
    double lonHalf = lamDeg / cl + 2.0;
    int lonLo = (int)floor((subLon - lonHalf) / 2.0) * 2;
    int lonHi = (int)ceil((subLon + lonHalf) / 2.0) * 2;
    double A = sin(clatR) * sinSub, B = cos(clatR) * cosSub;
    for (int lo = lonLo; lo <= lonHi; lo += 2) {
      double c = lo + 1.0;                                 // grid centre longitude
      if (A + B * cos((c - subLon) * D2R) < coslam) continue;   // outside footprint
      int idx = gridIdx(clat, c);
      if (gridBits) gridBits[idx >> 3] |= (uint8_t)(1 << (idx & 7));
    }
  }
}

void App::buildGrids(time_t a, time_t b) {
  if (!ensureGridBits()) { gridN = 0; return; }
  memset(gridBits, 0, GRID_BITS_LEN);
  SatEntry* s = activeSat();
  if (!s || !timeIsSet()) { gridN = 0; return; }
  pred.setSite(loc.obs()); pred.setSat(*s);
  int samples = (b > a) ? 1 + (int)((b - a) / 60) : 1;     // ~1 sample/min over the pass
  if (samples > 90) samples = 90; if (samples < 1) samples = 1;
  for (int k = 0; k < samples; ++k) {
    time_t t = (samples > 1) ? a + (time_t)((double)(b - a) * k / (samples - 1)) : a;
    LiveLook L = pred.look(t);
    addFootprintGrids(L.subLat, L.subLon, L.satAltKm);
  }
  int cnt = 0;                                             // popcount the bitset
  if (gridBits)
    for (size_t i = 0; i < GRID_BITS_LEN; ++i)
      for (uint8_t v = gridBits[i]; v; v &= (uint8_t)(v - 1)) ++cnt;
  gridN = cnt;
}

void App::drawGrid() {
  if (gridLive) {                                  // live: refresh every ~3 s (grids
    uint32_t ms = millis();                        // change slowly; SGP4 + dedup are
    if (!gridBuiltMs || ms - gridBuiltMs > 3000) { // not worth paying every redraw)
      gridBuiltMs = ms; buildGrids(nowUtc(), nowUtc());
    }
  }
  SatEntry* s = activeSat();
  { String h = (s ? String(s->name) : String("Grids")) +
               (gridLive ? " now" : " pass");
    header(h); }
  canvas.setTextSize(1);
  if (gridN == 0) {
    canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 56);
    canvas.print(timeIsSet() ? "No grids in footprint." : "Clock not set.");
    footer("f filter   ` back"); return;
  }
  bool filt = (gridFilter[0] != 0);
  // Count grids matching the filter (== gridN when no filter). One cheap pass.
  if (filt) {
    int m = 0;
    for (int idx = 0; idx < 32400; ++idx) {
      if (!gridBits || !(gridBits[idx >> 3] & (1 << (idx & 7)))) continue;
      char g[5]; gridStr(idx, g);
      if (gridMatchPrefix(g, gridFilter)) ++m;
    }
    gridShown = m;
  } else {
    gridShown = gridN;
  }
  // Workable-grid count on its own line (no room in the header). Right-aligned,
  // and shows the scroll window position when the list spills past one page.
  const int COLS = 6, ROWS = 8, PER = COLS * ROWS;
  if (gridScroll >= gridShown) gridScroll = 0;
  { char cnt[48];
    if (gridShown > PER) {
      int from = gridScroll + 1, to = gridScroll + PER; if (to > gridShown) to = gridShown;
      if (filt) snprintf(cnt, sizeof(cnt), "%s: %d  (%d-%d)", gridFilter, gridShown, from, to);
      else      snprintf(cnt, sizeof(cnt), "%d workable  (%d-%d)", gridShown, from, to);
    } else {
      if (filt) snprintf(cnt, sizeof(cnt), "%s: %d of %d", gridFilter, gridShown, gridN);
      else      snprintf(cnt, sizeof(cnt), "%d workable", gridShown);
    }
    canvas.setTextColor(CL_CYAN, CL_BLACK);
    int w = (int)strlen(cnt) * 6; int x = 238 - w; if (x < 4) x = 4;
    canvas.setCursor(x, 19); canvas.print(cnt);
  }
  if (gridShown == 0) {                              // filter excludes everything
    canvas.setTextColor(CL_YELLOW, CL_BLACK); canvas.setCursor(6, 56);
    canvas.printf("No workable %s grids.", gridFilter);
    footer("f filter  c clear  ` back"); return;
  }
  int seen = 0, drawn = 0;                          // walk set bits in sorted order
  for (int idx = 0; idx < 32400 && drawn < PER; ++idx) {
    if (!gridBits || !(gridBits[idx >> 3] & (1 << (idx & 7)))) continue;
    char g[5]; gridStr(idx, g);
    if (filt && !gridMatchPrefix(g, gridFilter)) continue;   // filtered out
    if (seen++ < gridScroll) continue;
    canvas.setTextColor(CL_WHITE, CL_BLACK);
    canvas.setCursor(4 + (drawn % COLS) * 40, 31 + (drawn / COLS) * 11);
    canvas.print(g); ++drawn;
  }
  if (filt) footer(gridShown > PER ? "f filt c clr ;/. scrl {} pg ` bk"
                                   : "f filter  c clear  ` back");
  else      footer(gridShown > PER ? "f filt  ;/. scroll  {} page  ` bk"
                                   : "f filter   ` back");
}

void App::keyGrid(char c, bool enter, bool back) {
  (void)enter;
  if (isBack(c, back)) { screen = gridLive ? liveReturn : SCR_PASSES; lastDrawMs = 0; return; }
  if (c == 'f') {                                  // set/replace the prefix filter
    editTarget = 729; editTitle = "Grid filter (e.g. EM, EM2, EM21)";
    editBuf = gridFilter; screen = SCR_EDIT; lastDrawMs = 0; return;
  }
  if (c == 'c') {                                  // clear the filter
    gridFilter[0] = 0; gridScroll = 0; lastDrawMs = 0; return;
  }
  const int PER = 6 * 8;
  if (isDown(c)) { if (gridScroll + PER < gridShown) gridScroll += 6; lastDrawMs = 0; return; }
  if (isUp(c))   { if (gridScroll >= 6) gridScroll -= 6; lastDrawMs = 0; return; }
  if (c == '}')  { if (gridScroll + PER < gridShown) gridScroll += PER; lastDrawMs = 0; return; }
  if (c == '{')  { gridScroll -= PER; if (gridScroll < 0) gridScroll = 0; lastDrawMs = 0; return; }
}

